window.CONTENT = {"meta": {"title": "EgzaminFiR — Trener", "exam": "Licencjat Finanse i Rachunkowosc", "days": 7, "exam_date": "[zweryfikuj]", "groups": {"baza": "Baza", "fib": "Czesc I — Finanse i Bankowosc", "kier": "Czesc II — Kierunkowe"}}, "plan": [{"day": 1, "date": "23.06", "hours": "1,5–2 h", "note": "Fundament + baza ilosciowa", "items": ["fundament", "stopy", "k5"]}, {"day": 2, "date": "24.06", "hours": "~2 h", "note": "Rachunkowosc (ksiegowosc)", "items": ["k1", "k2", "k3", "k4"]}, {"day": 3, "date": "25.06", "hours": "~2 h", "note": "Finanse przedsiebiorstwa", "items": ["k6", "k7", "k8", "k9"]}, {"day": 4, "date": "26.06", "hours": "1,5–2 h", "note": "System bankowy, polityka pieniezna, makro", "items": ["k10", "k11", "k12"]}, {"day": 5, "date": "27.06", "hours": "~2,5 h", "note": "Finanse i Bankowosc — ilosciowe (najwiecej liczenia)", "items": ["t1", "t2", "t5", "t11"]}, {"day": 6, "date": "28.06", "hours": "~2–2,5 h", "note": "Finanse i Bankowosc — przeglad", "items": ["t3", "t4", "t6", "t8", "t9"]}, {"day": 7, "date": "29.06", "hours": "~2,5 h", "note": "Finanse i Bankowosc + WIELKA POWTORKA", "items": ["t7", "t10", "t12"]}], "chapters": [{"id": "fundament", "group": "baza", "num": 0, "title": "Fundament finansow", "day": 1, "minutes": 25, "sections": [{"h": "A. Wartość pieniądza w czasie i ocena inwestycji", "html": "<ul><li><strong>Złotówka dziś &gt; złotówka jutro</strong> (dziś można ją zainwestować). To rdzeń wszystkich finansów.</li><li><strong>Wartość przyszła:</strong> $FV = PV \\cdot (1+r)^n$ — gdzie: $FV$ — wartość przyszła (zł), $PV$ — wartość dziś (zł), $r$ — stopa za okres (ułamek), $n$ — liczba okresów.</li><li><strong>Wartość obecna (dyskontowanie):</strong> $PV = \\frac{FV}{(1+r)^n}$ — „cofamy\" przyszłe pieniądze do dziś.</li><li><strong>Procent prosty</strong> (zawsze od kwoty początkowej) vs <strong>składany</strong> (procent od procentu — rośnie szybciej).</li><li><strong>Renta (płatności okresowe)</strong> — seria równych płatności; PV renty to suma zdyskontowanych rat (np. raty kredytu, kupony).</li><li><strong>Ocena opłacalności inwestycji:</strong></li><li><strong>Metody proste</strong> (bez dyskonta): <strong>okres zwrotu</strong> (po ilu latach wróci nakład), <strong>ARR</strong> (księgowa stopa zwrotu). Proste, ale ignorują wartość pieniądza w czasie.</li><li><strong>Metody dyskontowe</strong> (lepsze): <strong>NPV</strong> — $NPV = \\sum \\frac{CF_t}{(1+r)^t} - I_0$; gdzie: $CF_t$ — przepływ w roku $t$ (zł), $r$ — stopa dyskonta (koszt kapitału), $I_0$ — nakład początkowy (zł). <strong>Reguła: NPV &gt; 0 → inwestycja opłacalna.</strong></li><li><strong>IRR (wewnętrzna stopa zwrotu)</strong> — stopa, przy której $NPV = 0$. <strong>Reguła: IRR &gt; koszt kapitału → opłacalna.</strong></li></ul>"}, {"h": "B. Ryzyko, zwrot, koszt i źródła kapitału", "html": "<ul><li><strong>Większy oczekiwany zwrot = większe ryzyko.</strong> Nie ma wysokiego zysku bez ryzyka.</li><li><strong>Zwrot</strong> mierzy zysk, <strong>odchylenie standardowe $\\sigma$</strong> mierzy ryzyko (jak bardzo wynik „skacze\").</li><li><strong>Dywersyfikacja</strong> — ryzyko portfela &lt; suma ryzyk, gdy aktywa nie są idealnie skorelowane.</li><li><strong>Rodzaje ryzyka finansowego:</strong> rynkowe (ceny, kursy, stopy), kredytowe (niewypłacalność), płynności (brak gotówki na czas), operacyjne (błędy/procesy).</li><li><strong>Koszt kapitału = stopa dyskonta = oczekiwany zwrot dawców kapitału.</strong> Im większe ryzyko, tym wyższy koszt.</li><li><strong>WACC (średni ważony koszt kapitału):</strong> $WACC = \\frac{E}{V}r_e + \\frac{D}{V}r_d(1-T)$ — gdzie: $E$ — kapitał własny, $D$ — dług, $V=E+D$, $r_e$ — koszt kapitału własnego, $r_d$ — koszt długu, $T$ — podatek. <strong>Tarcza podatkowa $(1-T)$ tylko przy długu.</strong></li><li><strong>Źródła finansowania:</strong> <strong>własne</strong> (zysk zatrzymany, emisja akcji — drogie, bez obowiązku zwrotu) vs <strong>obce</strong> (kredyt, obligacje, leasing, faktoring — tańsze przez tarczę, ale trzeba oddać). Krótkoterminowe (obrót) vs długoterminowe (inwestycje).</li><li><strong>Kapitał obrotowy netto (KON)</strong> $= aktywa\\ obrotowe - zobowiazania\\ biezace$. Dodatni = bufor bezpieczeństwa, ale „zamraża\" gotówkę. <strong>Cykl konwersji gotówki</strong> $= DSO + DIO - DPO$ (rotacja należności + zapasów − zobowiązań). Zarządzanie: ściągaj należności szybciej, optymalizuj zapasy, płać dostawcom później (rozsądnie).</li></ul>"}, {"h": "C. Rachunkowość / księgowość — podstawy", "html": "<ul><li><strong>Istota i funkcje rachunkowości:</strong> to system <strong>pomiaru i informacji</strong> o sytuacji majątkowej i wyniku firmy. Funkcje: <strong>informacyjna, kontrolna, sprawozdawcza, dowodowa</strong> (księgi jako dowód).</li><li><strong>Nadrzędne zasady rachunkowości (na pamięć):</strong></li><li><strong>memoriału</strong> — ujmujemy zdarzenie w okresie wystąpienia, nie wpływu gotówki;</li><li><strong>współmierności</strong> — koszty dopasowane do przychodów tego samego okresu;</li><li><strong>ostrożności</strong> — nie zawyżaj aktywów/przychodów, uwzględnij przewidywane straty;</li><li><strong>kontynuacji działania</strong> (going concern) — zakładamy, że firma będzie działać dalej;</li><li><strong>istotności</strong>, <strong>wyższości treści nad formą</strong>, <strong>ciągłości</strong> (te same metody co rok), <strong>indywidualnej wyceny</strong>.</li><li><strong>Zasady wyceny aktywów i pasywów:</strong> <strong>koszt historyczny</strong> (cena nabycia / koszt wytworzenia), <strong>wartość godziwa</strong> (rynkowa), <strong>wartość netto możliwa do uzyskania</strong>; przy spadku wartości → odpis (ostrożność).</li><li><strong>Elementy rocznego sprawozdania finansowego (wg ustawy o rachunkowości):</strong></li></ul><ol><li><strong>Bilans</strong> — $Aktywa = Kapital\\ wlasny + Zobowiazania$ (aktywa: trwałe + obrotowe);</li><li><strong>Rachunek zysków i strat (RZiS)</strong> — przychody − koszty = wynik (warianty: porównawczy i kalkulacyjny);</li><li><strong>Rachunek przepływów pieniężnych</strong> (operacyjne/inwestycyjne/finansowe);</li><li><strong>Zestawienie zmian w kapitale własnym</strong>;</li><li><strong>Informacja dodatkowa</strong> (wprowadzenie + noty). Plus: sporządzenie, badanie, <strong>zatwierdzenie i ogłoszenie</strong> w terminach ustawowych [zweryfikuj].</li></ol><ul><li><strong>Koszty — klasyfikacja:</strong></li><li><strong>układ rodzajowy</strong> (amortyzacja, materiały, wynagrodzenia…) vs <strong>funkcjonalny</strong> (wg miejsc: produkcja, sprzedaż, zarząd);</li><li><strong>stałe vs zmienne</strong> (od wielkości produkcji);</li><li><strong>rachunek kosztów pełnych</strong> (wszystkie koszty na produkt) vs <strong>zmiennych</strong> (tylko zmienne → baza decyzji krótkookresowych).</li><li><strong>Analiza koszt–wolumen–zysk (CVP):</strong> <strong>marża pokrycia</strong> = cena − koszt zmienny jedn.; <strong>próg rentowności (BEP)</strong> = $\\frac{koszty\\ stale}{cena - koszt\\ zmienny\\ jedn.}$ (ilu sztuk trzeba, by wyjść na zero).</li><li><strong>Przychody i koszty: ujęcie księgowe vs podatkowe</strong> — nie wszystkie koszty księgowe są kosztem podatkowym; różnice prowadzą od wyniku księgowego do <strong>dochodu do opodatkowania</strong>.</li></ul>"}, {"h": "D. Analiza wskaźnikowa sprawozdania (4 grupy + upadłość)", "html": "<ul><li><strong>Płynność</strong> — czy firma spłaci na czas: wskaźnik <strong>bieżący</strong> = aktywa obrotowe / zobowiązania bieżące; <strong>szybki</strong> (bez zapasów).</li><li><strong>Zadłużenie / wypłacalność</strong> — ile długu: <strong>ogólnego zadłużenia</strong> = zobowiązania / aktywa; <strong>D/E</strong> = dług / kapitał własny.</li><li><strong>Rentowność</strong> — ile zysku: <strong>ROE</strong> = zysk netto / kapitał własny; <strong>ROA</strong> = zysk / aktywa; <strong>ROS / marża</strong> = zysk / przychody.</li><li><strong>Sprawność (aktywność)</strong> — jak szybko „kręci\" majątkiem: rotacja należności, zapasów, zobowiązań, aktywów.</li><li><strong>Szacowanie upadłości:</strong> <strong>Altman Z-score</strong> $= 1{,}2X_1 + 1{,}4X_2 + 3{,}3X_3 + 0{,}6X_4 + 1{,}0X_5$; strefy: $Z&lt;1{,}81$ zagrożenie, $1{,}81$–$2{,}99$ szara, $&gt;2{,}99$ bezpieczna.</li></ul>"}, {"h": "E. Rynki, polityka i makro (tło)", "html": "<ul><li><strong>Rynki finansowe:</strong> <strong>pieniężny</strong> (do 1 roku: bony, lokaty), <strong>kapitałowy</strong> (&gt;1 rok: akcje, obligacje), <strong>walutowy</strong> (Forex), <strong>terminowy</strong> (pochodne). Funkcje: alokacja kapitału, transfer ryzyka, rozliczenia, informacja przez ceny.</li><li><strong>Polityka monetarna (NBP/RPP):</strong> stopy procentowe, <strong>rezerwa obowiązkowa</strong>, operacje otwartego rynku — steruje ilością pieniądza i inflacją.</li><li><strong>Polityka fiskalna (rząd):</strong> podatki i wydatki budżetowe — steruje popytem; deficyt/nadwyżka.</li><li><strong>Makro w pigułce:</strong> <strong>PKB</strong> (produkcja w kraju) vs <strong>PNB</strong> (dochód obywateli); <strong>inflacja</strong> (wzrost cen), <strong>bezrobocie</strong>, <strong>cykl koniunkturalny</strong> (ekspansja → szczyt → recesja → dno); <strong>bilans płatniczy</strong>, systemy kursu walutowego (stały/płynny).</li><li><strong>Podatki:</strong> istota (przymusowe, bezzwrotne świadczenie na rzecz państwa); podział <strong>bezpośrednie</strong> (PIT, CIT) vs <strong>pośrednie</strong> (VAT, akcyza); funkcje: fiskalna, redystrybucyjna, stymulacyjna.</li></ul>"}, {"h": "F. Ponad podstawy — pytania pogłębione", "html": "<ul><li><strong>CAPM:</strong> $r_e = r_f + \\beta(r_m - r_f)$ — rynek wynagradza tylko <strong>ryzyko systematyczne</strong> ($\\beta$); specyficzne znika w dywersyfikacji.</li><li><strong>Teoria portfela (Markowitz):</strong> granica efektywna; łączenie aktywów o korelacji &lt; 1 obniża ryzyko bez utraty zwrotu.</li><li><strong>Efektywność rynku (EMH):</strong> ceny zawierają informacje (słaba/półsilna/silna) → trudno „pobić rynek\"; główna kontra dla analizy technicznej.</li><li><strong>Struktura kapitału (Modigliani-Miller):</strong> bez podatków struktura nie zmienia wartości; z podatkami dług daje tarczę, ale rośnie ryzyko bankructwa (trade-off). <strong>Dźwignia</strong> podnosi ROE i ryzyko.</li><li><strong>Asymetria informacji:</strong> selekcja negatywna (przed umową) i pokusa nadużycia (po umowie) — dlaczego banki badają zdolność i żądają zabezpieczeń.</li><li><strong>Arbitraż i prawo jednej ceny:</strong> identyczne przepływy = identyczna cena; podstawa wyceny pochodnych (parytety).</li><li><strong>Wycena przedsiębiorstw (3 podejścia):</strong></li><li><strong>dochodowe</strong> (najważniejsze): <strong>DCF</strong> na bazie <strong>FCFF</strong> (przepływy dla wszystkich dawców kapitału, dyskonto = WACC) lub <strong>FCFE</strong> (dla właścicieli, dyskonto = koszt kapitału własnego); <strong>EVA</strong> (ekonomiczna wartość dodana = zysk operacyjny po opodatkowaniu − koszt kapitału);</li><li><strong>majątkowe</strong> (wartość aktywów netto);</li><li><strong>porównawcze / mnożnikowe</strong> (P/E, EV/EBITDA wobec spółek podobnych).</li><li><strong>Zarządzanie przez wartość (VBM):</strong> cel firmy = wzrost wartości dla właścicieli.</li></ul>"}, {"h": "G. Mapa — jak fundament spina 12 tematów", "html": "<ul><li><strong>TVM + NPV/IRR + DCF + wycena firm</strong> → wycena instrumentów (5), koszt kapitału (11), pochodne (12).</li><li><strong>Ryzyko, zwrot, portfel, CAPM</strong> → VaR (1), koszt kapitału (11).</li><li><strong>Rachunkowość + zasady + sprawozdania + analiza wskaźnikowa + koszty/CVP</strong> → rachunkowość bankowa (3), zarządcza (8), planowanie (9), ryzyko kredytowe (2, Altman).</li><li><strong>Asymetria informacji</strong> → zdolność i ryzyko kredytowe (2), produkty bankowe (6), ubezpieczenia (7).</li><li><strong>Arbitraż + prawo jednej ceny</strong> → Forex/parytet stóp (10), pochodne (12).</li><li><strong>Rynki, polityka monetarna, EMH</strong> → VaR/rezerwa (1), analiza techniczna (4).</li></ul>"}], "probes": [], "order": 1}, {"id": "stopy", "group": "baza", "num": 0, "title": "Stopy i liczby na pamiec", "day": 1, "minutes": 10, "sections": [{"h": "Stopy procentowe NBP (ustala Rada Polityki Pieniężnej)", "html": "<ul><li><strong>Referencyjna</strong> — główna stopa, rentowność 7-dniowych operacji otwartego rynku; „cena pieniądza\" w gospodarce. ~5,75% <strong>[zweryfikuj]</strong>.</li><li><strong>Lombardowa</strong> — górny pułap; po niej NBP udziela bankom kredytu pod zastaw papierów. ≈ referencyjna + 1 pp <strong>[zweryfikuj]</strong>.</li><li><strong>Depozytowa</strong> — dolny pułap; oprocentowanie depozytu banków w NBP. ≈ referencyjna − 1 pp <strong>[zweryfikuj]</strong>.</li><li><strong>Redyskontowa weksli</strong> i <strong>dyskontowa</strong> — przy (re)dyskoncie weksli <strong>[zweryfikuj]</strong>.</li><li><strong>Stopa rezerwy obowiązkowej</strong> — % depozytów do utrzymania w NBP. 3,5% <strong>[zweryfikuj]</strong>.</li><li><strong>Stawki międzybankowe:</strong> WIBOR (wygaszany) → <strong>WIRON</strong> (reforma wskaźników) <strong>[zweryfikuj harmonogram]</strong>.</li></ul><p>&gt; Logika korytarza: depozytowa ≤ referencyjna ≤ lombardowa. To „widełki\", w których trzyma się stawka rynkowa overnight.</p>"}, {"h": "Stawki podatkowe", "html": "<ul><li><strong>VAT:</strong> podstawowa <strong>23%</strong>, obniżone <strong>8%</strong> i <strong>5%</strong>, <strong>0%</strong> (eksport, WDT); plus zwolnienia. <strong>[zweryfikuj]</strong>.</li><li><strong>PIT (skala):</strong> <strong>12%</strong> do progu ~<strong>120 000 zł</strong>, <strong>32%</strong> od nadwyżki; kwota wolna ~<strong>30 000 zł</strong>. <strong>[zweryfikuj]</strong>.</li><li><strong>PIT liniowy</strong> (działalność): <strong>19%</strong>.</li><li><strong>CIT:</strong> <strong>19%</strong> (standard), <strong>9%</strong> (mały podatnik / niskie przychody). <strong>[zweryfikuj]</strong>.</li><li><strong>Podatek „Belki\"</strong> (od zysków kapitałowych — odsetki, dywidendy, giełda): <strong>19%</strong>.</li><li><strong>Składki ZUS i zdrowotna:</strong> zmienne co roku <strong>[zweryfikuj]</strong>.</li></ul>"}, {"h": "Gwarancje i nadzór", "html": "<ul><li><strong>BFG</strong> (gwarancja depozytów): równowartość <strong>100 000 EUR</strong> na deponenta w banku <strong>[zweryfikuj]</strong>.</li><li><strong>KNF</strong> — nadzór nad rynkiem finansowym; <strong>UFG</strong> — gwarancje ubezpieczeniowe.</li></ul>"}, {"h": "Statystyka i ryzyko (stałe — wkuj na zawsze)", "html": "<ul><li><strong>Kwantyl normalny $z$:</strong> <strong>1,65</strong> (95%), <strong>2,33</strong> (99%), <strong>1,96</strong> (97,5%; dwustronnie 95%).</li><li>$\\sqrt{10} \\approx 3{,}16$; $\\sqrt{250} \\approx 15{,}8$; $\\sqrt{252} \\approx 15{,}9$.</li><li><strong>Altman Z:</strong> $&lt;1{,}81$ zagrożenie · $1{,}81$–$2{,}99$ szara strefa · $&gt;2{,}99$ bezpieczna.</li><li><strong>Piotroski F-Score:</strong> 0–9 ($\\geq 7$ = mocna firma).</li><li><strong>Bazylea (ryzyko rynkowe):</strong> mnożnik kapitału $\\geq 3 \\times$ VaR; backtesting 99%/250 dni ≈ <strong>2,5 wyjątku</strong> oczekiwane.</li></ul>"}, {"h": "Liczby, które „muszą paść\" na egzaminie", "html": "<ul><li>VaR: pierwiastek czasu <strong>$\\sqrt{t}$</strong>, nie $\\times t$.</li><li>Altman: <strong>X4 = wartość rynkowa</strong> kapitału / zobowiązania (nie księgowa).</li><li>WACC: tarcza podatkowa <strong>tylko przy długu</strong> $r_d(1-T)$.</li><li>Forward FX: liczony z <strong>różnicy stóp</strong> (parytet), nie z prognozy.</li><li>Opcja = <strong>prawo</strong> (premia z góry); forward = <strong>obowiązek</strong> (bez premii).</li></ul>"}], "probes": [], "order": 2}, {"id": "k5", "group": "kier", "num": 5, "title": "Wartosc pieniadza w czasie + ocena inwestycji (NPV/IRR)", "day": 1, "minutes": 22, "sections": [{"h": "0. Cegielki — co znac wczesniej", "html": "<ul><li>Procent prosty i skladany: kapitalizacja odsetek (odsetki od odsetek).</li><li>Stopa procentowa i stopa dyskontowa jako \"cena pieniadza w czasie\".</li><li>Pojecie przeplywu pieniaznego (cash flow) i naklady inwestycyjne ($CF_0$, zwykle ujemne).</li><li>Roznica miedzy zyskiem ksiegowym a przeplywem gotowkowym.</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>Zlotowka dzis jest warta wiecej niz zlotowka jutro, bo dzis mozna ja zainwestowac i pomnozyc, a jutrzejsza jest obarczona ryzykiem i inflacja. <strong>Wartosc pieniadza w czasie (TVM, time value of money)</strong> to mechanizm \"przesuwania\" kwot w czasie: w przod przez procent skladany (kapitalizacja), w tyl przez dyskontowanie. Ocena oplacalnosci inwestycji to porownanie zdyskontowanych wplywow z nakladami. Analogia: czas to winda — kapitalizacja wjezdza kwota w gore, dyskontowanie sprowadza przyszle kwoty na \"parter dzisiejszej wartosci\", gdzie dopiero mozna je uczciwie zsumowac.</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>Wartosc przyszla (FV, future value)</strong> — kwota, do jakiej urosnie dzisiejszy kapital po kapitalizacji odsetek.</li><li><strong>Wartosc biezaca (PV, present value)</strong> — dzisiejsza rownowartosc przyszlej kwoty po zdyskontowaniu.</li><li><strong>Dyskontowanie</strong> — sprowadzanie przyszlych przeplywow do terazniejszosci za pomoca stopy dyskontowej.</li><li><strong>Renta (annuity)</strong> — ciag rownych platnosci w stalych odstepach czasu (np. raty, czynsze).</li><li><strong>Renta wieczysta (perpetuity)</strong> — renta o nieskonczonym horyzoncie platnosci.</li><li><strong>NPV (net present value, wartosc biezaca netto)</strong> — suma zdyskontowanych przeplywow minus naklad poczatkowy.</li><li><strong>IRR (internal rate of return, wewnetrzna stopa zwrotu)</strong> — stopa, przy ktorej $NPV = 0$.</li><li><strong>Okres zwrotu (payback period)</strong> — czas, po ktorym skumulowane wplywy pokryja naklad.</li><li><strong>ARR (accounting rate of return, ksiegowa stopa zwrotu)</strong> — sredni zysk ksiegowy do sredniego/poczatkowego nakladu.</li><li><strong>Wskaznik rentownosci (PI, profitability index)</strong> — relacja zdyskontowanych wplywow do nakladu.</li></ul>"}, {"h": "3. Wzory/zasady i przyklad", "html": "<p><strong>Wartosc przyszla (procent skladany):</strong> $$FV = PV \\cdot (1+r)^{n}$$</p><div class=\"legend\">gdzie: $PV$ — kwota dzis (zl); $r$ — stopa za okres (ulamek); $n$ — liczba okresow (szt.); $FV$ — wartosc przyszla (zl).</div><p><strong>Wartosc biezaca (dyskontowanie):</strong> $$PV = \\frac{FV}{(1+r)^{n}}$$</p><p><strong>Renta zwykla (PV ciagu rownych platnosci $A$):</strong> $$PV = A \\cdot \\frac{1-(1+r)^{-n}}{r}$$</p><div class=\"legend\">gdzie: $A$ — rata (zl); pozostale jak wyzej. Renta wieczysta: $PV = A / r$.</div><p><strong>NPV:</strong> $$NPV = \\sum_{t=0}^{n} \\frac{CF_t}{(1+r)^{t}}$$</p><div class=\"legend\">gdzie: $CF_t$ — przeplyw w okresie $t$ (zl, $CF_0$ zwykle ujemny); $r$ — stopa dyskontowa / koszt kapitalu (ulamek). Kryterium: przyjmij gdy $NPV \\geq 0$.</div><p><strong>Wskaznik rentownosci:</strong> $$PI = \\frac{\\sum_{t=1}^{n} CF_t/(1+r)^{t}}{|CF_0|}$$ Kryterium: przyjmij gdy $PI \\geq 1$ (rownowazne $NPV \\geq 0$).</p><p><strong>Przyklad (NPV):</strong> naklad $CF_0 = -1000$ zl, wplywy $600$ zl i $600$ zl w latach 1 i 2, $r = 10\\%$. $NPV = -1000 + 600/1{,}1 + 600/1{,}21 = -1000 + 545{,}5 + 495{,}9 \\approx 41{,}4$ zl. $NPV &gt; 0$, wiec inwestycja oplacalna. $PI = 1041{,}4/1000 \\approx 1{,}04 &gt; 1$ — ten sam wniosek.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li>Zdefiniuj TVM i uzasadnij, dlaczego pieniadz ma wartosc w czasie (zarobkowanie, ryzyko, inflacja).</li><li>Pokaz dwie operacje: kapitalizacja ($FV$) i dyskontowanie ($PV$), z wzorami.</li><li>Rozroznij platnosc pojedyncza i renty (zwykla, wieczysta) — po co liczymy PV ciagu.</li><li>Wymien metody proste (okres zwrotu, ARR) i dyskontowe (NPV, IRR, PI), zaznaczajac, ze proste pomijaja TVM.</li><li>Podaj kryteria decyzyjne: $NPV \\geq 0$, $IRR \\geq r$, $PI \\geq 1$.</li><li>Oceń zalety/wady i wskaz NPV jako metode nadrzedna (mierzy realny przyrost wartosci).</li><li>Zakoncz: przy wyborze miedzy projektami decyduje NPV, nie sam IRR.</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> dlaczego NPV ponad IRR? IRR moze dawac wiele rozwiazan (zmienne znaki przeplywow) i myli przy projektach o roznej skali; NPV addytywne i jednoznaczne.</li><li><strong>Gdzie komisja dociska:</strong> ARR i okres zwrotu opieraja sie na zysku/wplywach bez dyskontowania (ARR dodatkowo na zysku ksiegowym, nie gotowce) — ignoruja TVM.</li><li>Okres zwrotu pomija przeplywy po terminie zwrotu oraz ryzyko; jest miara plynnosci, nie rentownosci. Istnieje wariant zdyskontowany.</li><li>Stopa $r$ musi byc spojna z okresem (stopa roczna do okresow rocznych); przy kapitalizacji srodrocznej dziel stope i mnoz liczbe okresow.</li><li>IRR zaklada reinwestycje przeplywow po stopie IRR (czesto nierealne) — stad MIRR jako poprawka.</li><li>Nie myl stopy nominalnej z efektywna ani PV renty z FV renty.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ul><li><strong>Czym rozni sie dyskontowanie od kapitalizacji?</strong> Kapitalizacja przesuwa kwote w przyszlosc ($\\times (1+r)^n$), dyskontowanie sprowadza ja do terazniejszosci ($\\div (1+r)^n$).</li><li><strong>Dlaczego NPV jest lepsze od IRR przy wyborze projektow?</strong> NPV jest addytywne, jednoznaczne i mierzy przyrost wartosci w zl, podczas gdy IRR moze byc niejednoznaczne i zawodzi przy roznej skali/strukturze przeplywow.</li><li><strong>Jakie sa wady okresu zwrotu?</strong> Pomija TVM (w wersji prostej), przeplywy po okresie zwrotu i ryzyko; mowi o plynnosci, nie o oplacalnosci.</li><li><strong>Kiedy projekt jest oplacalny wg metod dyskontowych?</strong> Gdy $NPV \\geq 0$, rownowaznie $IRR \\geq r$ (koszt kapitalu) oraz $PI \\geq 1$.</li></ul>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Gdzie komisja dociska: dlaczego NPV ponad IRR? IRR moze dawac wiele rozwiazan (zmienne znaki przeplywow) i myli przy projektach o roznej skali; NPV addytywne i jednoznaczne.", "Gdzie komisja dociska: ARR i okres zwrotu opieraja sie na zysku/wplywach bez dyskontowania (ARR dodatkowo na zysku ksiegowym, nie gotowce) — ignoruja TVM."], "order": 3}, {"id": "k1", "group": "kier", "num": 1, "title": "Rachunkowosc: istota, funkcje i zasady nadrzedne", "day": 2, "minutes": 22, "sections": [{"h": "0. Cegielki — co znac wczesniej", "html": "<ul><li><strong>Jednostka gospodarcza</strong> — wyodrebniony podmiot (firma) prowadzacy dzialalnosc i sporzadzajacy sprawozdania.</li><li><strong>Rok obrotowy / okres sprawozdawczy</strong> — przedzial czasu, za ktory ustala sie wynik finansowy.</li><li><strong>Bilans i rachunek zyskow i strat</strong> — dwa podstawowe elementy sprawozdania finansowego (stan majatku vs. wynik).</li><li><strong>Zasada podwojnego zapisu</strong> — kazda operacja ujeta jednoczesnie po stronie Wn i Ma (rownosc stron).</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>Rachunkowosc to <strong>system pomiaru, ewidencji i komunikowania</strong> sytuacji majatkowej i finansowej jednostki, wyrazony w pieniadzu. Jej sercem jest wierne odzwierciedlenie rzeczywistosci gospodarczej, a nadrzedne zasady to \"reguly gry\", ktore gwarantuja, ze liczby roznych firm sa porownywalne i wiarygodne. Bez nich sprawozdanie byloby tylko zbiorem dowolnych liczb. Analogia: rachunkowosc to <strong>jezyk biznesu</strong> — nadrzedne zasady sa jego gramatyka, dzieki ktorej kazdy (inwestor, bank, urzad) rozumie to samo zdanie tak samo.</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>Rachunkowosc</strong> — system informacyjny mierzacy i komunikujacy w pieniadzu zdarzenia gospodarcze jednostki na podstawie dowodow ksiegowych.</li><li><strong>Funkcja informacyjna</strong> — dostarczanie danych do decyzji wewnetrznym i zewnetrznym uzytkownikom.</li><li><strong>Funkcja kontrolna</strong> — ochrona majatku i wykrywanie nieprawidlowosci przez ewidencje i inwentaryzacje.</li><li><strong>Funkcja sprawozdawcza</strong> — sporzadzanie sprawozdan finansowych dla otoczenia.</li><li><strong>Funkcja dowodowa</strong> — ksiegi i dowody jako material dowodowy (m.in. w sporach, kontrolach <strong>US</strong> — Urzad Skarbowy).</li><li><strong>Wynik finansowy</strong> — roznica miedzy przychodami a kosztami danego okresu (zysk lub strata).</li><li><strong>Memorial vs. kasowo</strong> — ujmowanie skutkow zdarzen w momencie ich wystapienia, niezaleznie od przeplywu gotowki (vs. w momencie zaplaty).</li><li><strong>Sprawozdanie finansowe (SF)</strong> — koncowy produkt rachunkowosci: bilans, RZiS, informacja dodatkowa (i in.).</li><li><strong>Wiarygodny i rzetelny obraz</strong> — naczelny cel: SF ma odzwierciedlac realna sytuacje jednostki (\"true and fair view\").</li><li><strong>UoR</strong> — Ustawa o Rachunkowosci, polskie zrodlo nadrzednych zasad [zweryfikuj aktualna wartosc/numeracje artykulow].</li></ul>"}, {"h": "3. Wzory/zasady i przyklad", "html": "<p>Rachunkowosc nie jest typowo ilosciowa, ale ma fundamentalne <strong>rownanie</strong> i policzalna <strong>zasade memorialu/wspolmiernosci</strong>.</p><p><strong>Rownanie bilansowe:</strong> $$A = K_{w} + Z$$</p><div class=\"legend\">gdzie: $A$ — aktywa (majatek, w zl); $K_{w}$ — kapital wlasny (w zl); $Z$ — zobowiazania, czyli kapital obcy (w zl).</div><p><strong>Wynik finansowy (zasada wspolmiernosci):</strong> $$WF = P - K$$</p><div class=\"legend\">gdzie: $WF$ — wynik finansowy (zysk gdy $WF \\geq 0$, w zl); $P$ — przychody okresu (w zl); $K$ — koszty wspolmierne do tych przychodow (w zl).</div><p><strong>Przyklad (memorial + wspolmiernosc):</strong> Firma sprzedala towar w grudniu 2025 za $10\\,000$ zl, a zaplate otrzyma w styczniu 2026. Koszt zakupu tego towaru to $6\\,000$ zl.</p><ul><li>Zgodnie z <strong>memorialem</strong> przychod $10\\,000$ zl ujmujemy w grudniu (data sprzedazy), nie w styczniu (data zaplaty).</li><li>Zgodnie ze <strong>wspolmiernoscia</strong> w grudniu przypisujemy mu koszt $6\\,000$ zl.</li><li>Wynik grudnia: $WF = 10\\,000 - 6\\,000 = 4\\,000$ zl zysku. Ujecie kasowe blednie pokazaloby grudzien jako $-6\\,000$ zl.</li></ul>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Definicja:</strong> rachunkowosc to system informacyjny mierzacy w pieniadzu zdarzenia gospodarcze jednostki na bazie dowodow ksiegowych.</li><li><strong>Cel nadrzedny:</strong> rzetelny i wierny obraz sytuacji majatkowej, finansowej i wyniku (\"true and fair view\").</li><li><strong>Zadania:</strong> identyfikacja, pomiar, ewidencja, grupowanie i komunikowanie danych.</li><li><strong>Funkcje:</strong> wymien i jednym zdaniem opisz — informacyjna, kontrolna, sprawozdawcza, dowodowa (czesto tez analityczna, statystyczna).</li><li><strong>Nadrzedne zasady:</strong> wylicz wszystkie 8 i podaj 1-zdaniowa istote kazdej (patrz nizej).</li><li><strong>Powiazanie:</strong> pokaz, jak zasady sluza celowi (np. memorial + wspolmiernosc -&gt; poprawny wynik; ostroznosc -&gt; brak zawyzania).</li><li><strong>Zrodlo prawne:</strong> zasady wynikaja z <strong>UoR</strong> (oraz <strong>MSR/MSSF</strong> w jednostkach stosujacych standardy miedzynarodowe).</li></ol><p><strong>Osiem nadrzednych zasad — sciaga:</strong></p><ul><li><strong>Memorialu</strong> — ujmuj zdarzenia w okresie ich wystapienia, niezaleznie od zaplaty.</li><li><strong>Wspolmiernosci</strong> — do przychodow okresu przypisuj wspolmierne koszty ich osiagniecia.</li><li><strong>Ostroznosci</strong> — wyceniaj realistycznie: ujmuj przewidywane straty i spadki wartosci, nie ujmuj niezrealizowanych zyskow.</li><li><strong>Kontynuacji dzialania</strong> — zakladaj, ze jednostka bedzie dzialac w dajacej sie przewidziec przyszlosci (min. 12 mies.).</li><li><strong>Istotnosci</strong> — informacje istotne ujmuj osobno; nieistotne mozna uproscic, jesli nie znieksztalca to obrazu SF.</li><li><strong>Wyzszosci tresci nad forma</strong> — ujmuj ekonomiczna tresc operacji, nie tylko jej forme prawna.</li><li><strong>Ciaglosci</strong> — stosuj te same zasady (polityke) rachunkowosci w kolejnych latach, by zapewnic porownywalnosc.</li><li><strong>Indywidualnej wyceny</strong> — wyceniaj i ewidencjonuj kazdy skladnik aktywow/pasywow osobno (zakaz kompensat).</li></ul>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> nie myl <strong>zasady ciaglosci</strong> (te same metody rok do roku) z <strong>kontynuacja dzialania</strong> (firma bedzie trwac). To dwa rozne pojecia, czesto mylone.</li><li><strong>Gdzie komisja dociska:</strong> memorial vs. kasowo — popros o przyklad; zawsze pokaz, ze przychod/koszt idzie za zdarzeniem, nie za gotowka.</li><li><strong>Gdzie komisja dociska:</strong> wyzszosc tresci nad forma — klasyczny przyklad to <strong>leasing finansowy</strong> (prawnie najem, ekonomicznie zakup -&gt; srodek u korzystajacego).</li><li>Ostroznosc bywa blednie streszczana jako \"zanizaj wszystko\" — chodzi o asymetrie: straty tak, niezrealizowane zyski nie.</li><li>Nie pomijaj <strong>zasady indywidualnej wyceny</strong> = zakaz kompensowania np. naleznosci z zobowiazaniami czy zyskow ze stratami.</li><li>Pamietaj, ze zasada istotnosci nie usprawiedliwia ukrywania bledow — dotyczy proporcjonalnosci, nie manipulacji.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ol><li><strong>Czym rozni sie ujecie memorialowe od kasowego?</strong> Memorialowe ujmuje skutki zdarzen w momencie ich wystapienia (np. sprzedazy), kasowe — w momencie wplywu/wyplywu gotowki; rachunkowosc opiera sie na memoriale.</li><li><strong>Na czym polega zasada wspolmiernosci i z ktora zasada wystepuje w parze?</strong> Nakazuje przypisac do przychodow okresu koszty ich uzyskania; dziala w parze z memorialem, dajac poprawny wynik finansowy.</li><li><strong>Wyjasnij zasade ostroznosci i podaj jej asymetrie.</strong> Nakazuje uwzgledniac przewidywane straty i odpisy, a zakazuje ujmowac niezrealizowane zyski — chroni przed zawyzaniem aktywow i wyniku.</li><li><strong>Czym rozni sie ciaglosc od kontynuacji dzialania?</strong> Ciaglosc = stosowanie tych samych zasad rachunkowosci rok do roku (porownywalnosc); kontynuacja = zalozenie, ze jednostka bedzie dzialac w przewidywalnej przyszlosci.</li></ol>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Gdzie komisja dociska: nie myl zasady ciaglosci (te same metody rok do roku) z kontynuacja dzialania (firma bedzie trwac). To dwa rozne pojecia, czesto mylone.", "Gdzie komisja dociska: memorial vs. kasowo — popros o przyklad; zawsze pokaz, ze przychod/koszt idzie za zdarzeniem, nie za gotowka.", "Gdzie komisja dociska: wyzszosc tresci nad forma — klasyczny przyklad to leasing finansowy (prawnie najem, ekonomicznie zakup -> srodek u korzystajacego)."], "order": 4}, {"id": "k2", "group": "kier", "num": 2, "title": "Wycena aktywow i pasywow + sprawozdanie finansowe", "day": 2, "minutes": 22, "sections": [{"h": "0. Cegielki — co znac wczesniej", "html": "<ul><li>Bilans to zestawienie aktywow (majatek) i pasywow (zrodla finansowania) na dany dzien — zawsze AKTYWA = PASYWA.</li><li>Zasada memorialowa: przychody i koszty ujmuje sie w okresie ich powstania, nie w momencie wplywu/wyplywu gotowki.</li><li>Rok obrotowy i dzien bilansowy (zwykle 31.12) — moment, na ktory robi sie wycene i sporzadza sprawozdanie.</li><li>Podstawa prawna w PL: <strong>UoR</strong> (ustawa o rachunkowosci z 29.09.1994).</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>Wycena to przypisanie pozycjom bilansu wartosci w zlotowkach wedlug ustalonych, ostroznych zasad — tak, by sprawozdanie dawalo \"rzetelny i jasny obraz\" sytuacji firmy. Roznia sie metody: cos wyceniamy po tym, ile kosztowalo (koszt historyczny), a cos po tym, ile dzis jest warte (wartosc godziwa). Sprawozdanie finansowe to \"zdjecie rentgenowskie\" firmy: bilans pokazuje strukture (co ma i komu winna), RZiS — czy zarabia, a rachunek przeplywow — czy ma realna gotowke. Analogia: wycena to wycenianie rzeczy w mieszkaniu do ubezpieczenia — meble po cenie zakupu, ale jesli rynkowo potanialy, wpisujesz wartosc nizsza (ostroznosc).</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>Koszt historyczny</strong> — wycena wedlug ceny z momentu nabycia/wytworzenia, niezmienianej mimo wahania cen rynkowych.</li><li><strong>Cena nabycia</strong> — cena zakupu skladnika powiekszona o koszty bezposrednio zwiazane z zakupem i przystosowaniem do uzywania, pomniejszona o rabaty.</li><li><strong>Koszt wytworzenia</strong> — koszty bezposrednie produktu plus uzasadniona czesc kosztow posrednich produkcji (bez kosztow zarzadu i sprzedazy).</li><li><strong>Wartosc godziwa (fair value)</strong> — kwota, za jaka skladnik moglby byc wymieniony miedzy zainteresowanymi, dobrze poinformowanymi stronami w transakcji rynkowej.</li><li><strong>Zasada ostroznosci</strong> — wycena unikajaca zawyzania aktywow/przychodow i zanizania zobowiazan/kosztow; ujmuje sie przewidywane straty, a zyski dopiero zrealizowane.</li><li><strong>Trwala utrata wartosci</strong> — odpis aktualizujacy obnizajacy wartosc aktywu, gdy istnieje duze prawdopodobienstwo braku korzysci ekonomicznych.</li><li><strong>Zasada wyzszosci tresci nad forma</strong> — operacje ujmuje sie zgodnie z ekonomiczna trescia, nie tylko forma prawna.</li><li><strong>RZiS</strong> (rachunek zyskow i strat) — sprawozdanie pokazujace wynik finansowy jako roznice przychodow i kosztow.</li><li><strong>Zasada kontynuacji dzialalnosci (going concern)</strong> — domniemanie, ze firma bedzie dzialac dalej, co warunkuje sposob wyceny.</li></ul>"}, {"h": "3. Wzory/zasady i przyklad", "html": "<p>Rownanie bilansowe: $$A = K_{w} + Z$$</p><div class=\"legend\">gdzie: $A$ — aktywa razem (PLN); $K_{w}$ — kapital wlasny (PLN); $Z$ — zobowiazania i rezerwy na zobowiazania (PLN).</div><p>Cena nabycia: $$C_{n} = C_{z} + K_{d} - R$$</p><div class=\"legend\">gdzie: $C_{n}$ — cena nabycia (PLN); $C_{z}$ — cena zakupu (PLN); $K_{d}$ — koszty bezposrednie zakupu, np. transport, clo, montaz (PLN); $R$ — rabaty/upusty (PLN).</div><p>Zasada ostroznej wyceny aktywu (nizsza z dwoch): $$W_{b} = \\min(C_{n},\\ W_{r})$$</p><div class=\"legend\">gdzie: $W_{b}$ — wartosc bilansowa (PLN); $C_{n}$ — koszt nabycia/wytworzenia (PLN); $W_{r}$ — wartosc rynkowa/mozliwa do uzyskania (PLN).</div><p>Przyklad: firma kupila maszyne za $C_{z} = 100\\,000$ PLN, transport i montaz $K_{d} = 8\\,000$ PLN, rabat $R = 3\\,000$ PLN. Cena nabycia: $C_{n} = 100\\,000 + 8\\,000 - 3\\,000 = 105\\,000$ PLN. Jesli na dzien bilansowy wartosc mozliwa do uzyskania spadla do $W_{r} = 98\\,000$ PLN, to z ostroznosci $W_{b} = \\min(105\\,000,\\ 98\\,000) = 98\\,000$ PLN, a roznice $7\\,000$ PLN ujmuje sie jako odpis aktualizujacy.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li>Zdefiniuj wycene i wskaz cel: rzetelny i jasny obraz, podstawa = UoR, moment = dzien bilansowy.</li><li>Wymien metody wyceny: koszt historyczny / cena nabycia, koszt wytworzenia, wartosc godziwa — i powiedz, co czym sie wycenia (srodki trwale — cena nabycia/koszt wytworzenia minus umorzenie; inwestycje — czesto wartosc godziwa).</li><li>Podkresl nadrzedne zasady: ostroznosci, memorialowa, kontynuacji, wyzszosci tresci nad forma.</li><li>Przejdz do sprawozdania: wymien 5 elementow rocznego SF i krotko opisz, co kazdy pokazuje.</li><li>Powiedz, kto co sporzadza i obowiazki formalne: sporzadzenie w 3 mies. od dnia bilansowego, podpis kierownika jednostki.</li><li>Badanie (audyt) — dla jednostek przekraczajacych progi; zatwierdzenie w 6 mies. przez organ zatwierdzajacy; ogloszenie/zlozenie do KRS.</li><li>Zamknij przykladem (np. ostrozna wycena z odpisem) — pokazuje, ze rozumiesz mechanizm.</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> roznica cena nabycia vs koszt wytworzenia — cena nabycia dotyczy skladnikow KUPIONYCH, koszt wytworzenia — WYPRODUKOWANYCH we wlasnym zakresie.</li><li><strong>Gdzie komisja dociska:</strong> asymetria ostroznosci — straty/koszty ujmuje sie juz przy przewidywaniu, zyski dopiero gdy zrealizowane (nie odwrotnie).</li><li>Mylenie elementow SF: pelne roczne SF to 5 czesci, ale rachunek przeplywow i zestawienie zmian w kapitale sporzadzaja TYLKO jednostki badane obowiazkowo (mniejsze maja SF okrojone).</li><li>Terminy: sporzadzenie 3 mies., zatwierdzenie 6 mies. od dnia bilansowego — czesto pytane, latwo pomylic.</li><li><strong>Gdzie komisja dociska:</strong> badanie SF wykonuje bieglyrewident (audytor), a NIE urzad skarbowy; obowiazkowe po przekroczeniu progow (zatrudnienie, suma bilansowa, przychody).</li><li>Wartosc godziwa nie jest \"uniwersalna\" — w UoR dominuje koszt historyczny; wartosc godziwa stosuje sie wybiorczo (np. niektore inwestycje, polaczenia jednostek).</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ul><li><strong>Na czym polega zasada ostroznosci?</strong> Na takiej wycenie, ktora nie zawyza aktywow i przychodow ani nie zanizа zobowiazan i kosztow; przewidywane straty ujmuje sie od razu, zyski dopiero po realizacji.</li><li><strong>Wymien elementy rocznego sprawozdania finansowego.</strong> Bilans, rachunek zyskow i strat, informacja dodatkowa (zawsze), a dla jednostek badanych takze rachunek przeplywow pienieznych i zestawienie zmian w kapitale wlasnym.</li><li><strong>Czym rozni sie cena nabycia od kosztu wytworzenia?</strong> Cena nabycia to cena zakupu plus koszty bezposrednie minus rabaty (skladnik kupiony); koszt wytworzenia to koszty bezposrednie plus uzasadniona czesc posrednich kosztow produkcji (skladnik wyprodukowany).</li><li><strong>Jakie sa terminy sporzadzenia i zatwierdzenia SF?</strong> Sporzadzenie w ciagu 3 miesiecy, zatwierdzenie w ciagu 6 miesiecy od dnia bilansowego; po zatwierdzeniu nastepuje zlozenie/ogloszenie (m.in. w KRS).</li></ul>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Gdzie komisja dociska: roznica cena nabycia vs koszt wytworzenia — cena nabycia dotyczy skladnikow KUPIONYCH, koszt wytworzenia — WYPRODUKOWANYCH we wlasnym zakresie.", "Gdzie komisja dociska: asymetria ostroznosci — straty/koszty ujmuje sie juz przy przewidywaniu, zyski dopiero gdy zrealizowane (nie odwrotnie).", "Gdzie komisja dociska: badanie SF wykonuje bieglyrewident (audytor), a NIE urzad skarbowy; obowiazkowe po przekroczeniu progow (zatrudnienie, suma bilansowa, przychody)."], "order": 5}, {"id": "k3", "group": "kier", "num": 3, "title": "Analiza finansowa sprawozdania + ryzyko upadlosci", "day": 2, "minutes": 20, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Sprawozdanie finansowe</strong>: bilans (stan na dzień), rachunek zysków i strat (za okres), rachunek przepływów pieniężnych.</li><li>Różnica między wielkością <strong>zasobową</strong> (bilans, stan na moment) a <strong>strumieniową</strong> (RZiS, przepływy, za okres).</li><li>Podstawowe kategorie: aktywa = pasywa; kapitał własny = aktywa − zobowiązania.</li><li>Wynik finansowy: zysk netto = przychody − koszty − podatek.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Analiza finansowa to \"badanie krwi\" firmy: z liczb sprawozdania wyciągamy diagnozę kondycji. Analiza <strong>wstępna</strong> mówi, *jak* zmieniają się i z czego składają się pozycje (dynamika i struktura), a <strong>wskaźnikowa</strong> odnosi pozycje do siebie nawzajem, dając porównywalne miary. Cztery filary diagnozy to: czy firma <strong>płaci na czas</strong> (płynność), czy <strong>nie jest przelewarowana</strong> (zadłużenie), czy <strong>zarabia</strong> (rentowność) i czy <strong>efektywnie gospodaruje</strong> (sprawność). Model Altmana to syntetyczny \"wynik badania\", łączący kilka wskaźników w jeden sygnał zagrożenia upadłością.</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Analiza pozioma (dynamiki)</strong>: porównuje te same pozycje w czasie (np. rok do roku), licząc zmiany kwotowe i tempo wzrostu.</li><li><strong>Analiza pionowa (struktury)</strong>: pokazuje udział każdej pozycji w sumie (np. udział zapasów w aktywach = 100%).</li><li><strong>Płynność finansowa</strong>: zdolność do terminowego regulowania zobowiązań bieżących.</li><li><strong>Wypłacalność / zadłużenie</strong>: relacja kapitału obcego do majątku i kapitału własnego; zdolność do obsługi długu w długim okresie.</li><li><strong>Rentowność</strong>: zdolność do generowania zysku w relacji do sprzedaży, aktywów lub kapitału.</li><li><strong>Sprawność (aktywności)</strong>: efektywność wykorzystania zasobów, mierzona rotacją (obrotem) składników majątku.</li><li><strong>ROA</strong> (Return on Assets — rentowność aktywów): zysk w relacji do całości majątku.</li><li><strong>ROE</strong> (Return on Equity — rentowność kapitału własnego): zysk w relacji do kapitału właścicieli.</li><li><strong>Kapitał obrotowy netto</strong>: nadwyżka aktywów obrotowych nad zobowiązaniami bieżącymi (bufor płynności).</li><li><strong>Model Altmana Z-score</strong>: wielowymiarowa funkcja dyskryminacyjna szacująca prawdopodobieństwo upadłości.</li></ul>"}, {"h": "3. Wzory/zasady i przykład", "html": "<p><strong>Analiza pozioma</strong> (tempo zmiany): $\\Delta\\% = \\frac{P_{1} - P_{0}}{P_{0}} \\cdot 100\\%$</p><div class=\"legend\">gdzie: $P_{1}$ — wartość pozycji w okresie badanym (zł); $P_{0}$ — wartość w okresie bazowym (zł).</div><p><strong>Płynność bieżąca (current ratio)</strong>: $CR = \\frac{\\text{aktywa obrotowe}}{\\text{zobowiązania bieżące}}$ — norma ok. $1{,}2$–$2{,}0$.</p><p><strong>Płynność szybka (quick ratio)</strong>: $QR = \\frac{\\text{aktywa obrotowe} - \\text{zapasy}}{\\text{zobowiązania bieżące}}$ — norma ok. $1{,}0$.</p><p><strong>Ogólne zadłużenie</strong>: $W_{z} = \\frac{\\text{zobowiązania ogółem}}{\\text{aktywa ogółem}}$ — norma ok. $0{,}57$–$0{,}67$.</p><p><strong>ROA</strong>: $ROA = \\frac{\\text{zysk netto}}{\\text{aktywa ogółem}} \\cdot 100\\%$ &amp;nbsp;&amp;nbsp; <strong>ROE</strong>: $ROE = \\frac{\\text{zysk netto}}{\\text{kapitał własny}} \\cdot 100\\%$</p><p><strong>Rotacja zapasów (w dniach)</strong>: $RZ = \\frac{\\text{średni stan zapasów}}{\\text{koszt sprzedanych}} \\cdot 365$</p><div class=\"legend\">gdzie: $365$ — liczba dni w roku; wynik w dniach (im mniej, tym szybszy obrót).</div><p><strong>Model Altmana (wersja dla spółek giełdowych, 1968)</strong>: $$Z = 1{,}2 X_{1} + 1{,}4 X_{2} + 3{,}3 X_{3} + 0{,}6 X_{4} + 1{,}0 X_{5}$$</p><div class=\"legend\">gdzie: $X_{1}$ — kapitał obrotowy netto / aktywa; $X_{2}$ — zysk zatrzymany / aktywa; $X_{3}$ — zysk operacyjny (EBIT) / aktywa; $X_{4}$ — wartość rynkowa kapitału własnego / zobowiązania ogółem; $X_{5}$ — przychody ze sprzedaży / aktywa (wszystkie bezwymiarowe).</div><p><strong>Interpretacja</strong>: $Z &gt; 2{,}99$ — firma bezpieczna; $1{,}81 \\leq Z \\leq 2{,}99$ — \"szara strefa\" (niepewność); $Z &lt; 1{,}81$ — wysokie zagrożenie upadłością. [zweryfikuj progi dla wersji modelu — istnieje też wariant Z' dla spółek nienotowanych z innymi wagami]</p><p><strong>Przykład policzony</strong>: aktywa obrotowe = 600, zapasy = 200, zobowiązania bieżące = 400.</p><ul><li>$CR = 600 / 400 = 1{,}5$ — w normie.</li><li>$QR = (600 - 200) / 400 = 1{,}0$ — dobra płynność szybka.</li><li>Kapitał obrotowy netto $= 600 - 400 = 200$ (dodatni bufor).</li></ul>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Zdefiniuj cel</strong>: analiza finansowa ocenia kondycję firmy na podstawie sprawozdania (bilans, RZiS, przepływy).</li><li><strong>Analiza wstępna</strong>: rozróżnij poziomą (dynamika w czasie) i pionową (struktura, udziały) — to punkt wyjścia.</li><li><strong>Wymień 4 grupy wskaźników</strong>: płynność, zadłużenie/wypłacalność, rentowność, sprawność — i podaj po 1–2 wskaźniki z każdej z wzorem.</li><li><strong>Zinterpretuj normy</strong>: np. CR ≈ 1,2–2,0; zbyt wysoki = nadpłynność, zbyt niski = ryzyko niewypłacalności.</li><li><strong>Podkreśl analizę porównawczą</strong>: wskaźnik ma sens w odniesieniu do norm, branży i dynamiki w czasie.</li><li><strong>Przejdź do upadłości</strong>: model Altmana jako synteza — podaj postać funkcji, 5 zmiennych i 3 strefy interpretacji.</li><li><strong>Wniosek</strong>: analiza wskaźnikowa + model dyskryminacyjny dają wczesny sygnał ostrzegawczy (early warning).</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> różnica pozioma vs pionowa — pozioma = czas (dynamika), pionowa = struktura (udział %). Mylenie tego to klasyczny błąd.</li><li><strong>Gdzie komisja dociska:</strong> \"więcej znaczy lepiej\" — nieprawda. Zbyt wysoka płynność = zamrożony, nieefektywny kapitał (nadpłynność); zbyt wysokie zadłużenie = ryzyko, ale niskie = niewykorzystana dźwignia finansowa.</li><li><strong>Gdzie komisja dociska:</strong> ROE rośnie przy wyższym zadłużeniu (efekt dźwigni finansowej) — wysokie ROE samo w sobie nie świadczy o sile firmy, trzeba sprawdzić strukturę kapitału.</li><li>Wskaźnik bez <strong>punktu odniesienia</strong> (norma, branża, trend) jest bezwartościowy — nigdy nie interpretuj liczby w próżni.</li><li>Płynność (krótki okres) to nie to samo co wypłacalność (długi okres) — firma rentowna może upaść z braku płynności.</li><li>W modelu Altmana nie myl <strong>wersji</strong>: oryginał (1968) zawiera $X_{4}$ z <strong>wartością rynkową</strong> — działa głównie dla spółek giełdowych; dla nienotowanych stosuje się wariant $Z'$ z wartością księgową i innymi wagami.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ul><li><strong>Czym różni się analiza pozioma od pionowej?</strong> Pozioma bada zmiany tych samych pozycji w czasie (dynamika), pionowa — udział pozycji w sumie (struktura).</li><li><strong>Dlaczego firma rentowna może zbankrutować?</strong> Bo rentowność (zysk) to nie płynność — brak gotówki na bieżące zobowiązania prowadzi do utraty płynności i upadłości mimo dodatniego wyniku.</li><li><strong>Co mierzy ROE i czym różni się od ROA?</strong> ROE to zysk netto do kapitału własnego (perspektywa właściciela), ROA to zysk do całości aktywów (efektywność całego majątku); ROE &gt; ROA przy korzystnej dźwigni finansowej.</li><li><strong>Co oznacza wynik Z-score poniżej 1,81 w modelu Altmana?</strong> Wysokie zagrożenie upadłością w horyzoncie ok. 1–2 lat — firma znajduje się poza \"szarą strefą\", w strefie niewypłacalności.</li></ul>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: różnica pozioma vs pionowa — pozioma = czas (dynamika), pionowa = struktura (udział %). Mylenie tego to klasyczny błąd.", "Gdzie komisja dociska: \"więcej znaczy lepiej\" — nieprawda. Zbyt wysoka płynność = zamrożony, nieefektywny kapitał (nadpłynność); zbyt wysokie zadłużenie = ryzyko, ale niskie = niewykorzystana dźwignia finansowa.", "Gdzie komisja dociska: ROE rośnie przy wyższym zadłużeniu (efekt dźwigni finansowej) — wysokie ROE samo w sobie nie świadczy o sile firmy, trzeba sprawdzić strukturę kapitału."], "order": 6}, {"id": "k4", "group": "kier", "num": 4, "title": "Rachunek kosztow: pelny vs zmienny + CVP", "day": 2, "minutes": 20, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Koszt</strong> to wyrażone w pieniądzu zużycie zasobów dla osiągnięcia przychodu; różny od <strong>wydatku</strong> (rozchód pieniądza) i <strong>straty</strong> (zużycie bez korzyści).</li><li>Podstawowy rachunek wyniku: $\\text{zysk} = \\text{przychody} - \\text{koszty}$, więc sposób ujęcia kosztów wpływa na pokazany wynik.</li><li>Rozróżnienie <strong>produkt vs okres</strong>: koszty produktu „idą\" w zapas i czekają na sprzedaż, koszty okresu obciążają wynik od razu.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Te same koszty można „rozłożyć\" na dwa sposoby: rachunek <strong>pełny</strong> wrzuca do kosztu wyrobu wszystko, co go wytworzyło (także stałe koszty produkcji), a rachunek <strong>zmienny</strong> tylko to, co rośnie z każdą sztuką. Różnica między nimi to los kosztów stałych: aktywowane w zapasie (pełny) albo natychmiast obciążające wynik (zmienny). Analiza CVP to z kolei „kalkulator decyzyjny\": pokazuje, ile sztuk musisz sprzedać, żeby wyjść na zero i jak czuły jest zysk na zmiany sprzedaży. Analogia: rachunek pełny to rachunek za cały lokal podzielony na gości (każdy „nosi\" kawałek czynszu), rachunek zmienny to tylko koszt składników w talerzu gościa — czynsz płacisz i tak.</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Układ rodzajowy</strong> — klasyfikacja kosztów wg natury zużytego zasobu (amortyzacja, materiały, wynagrodzenia, usługi obce), niezależnie od miejsca powstania.</li><li><strong>Układ funkcjonalny (kalkulacyjny)</strong> — klasyfikacja wg funkcji/miejsca: koszt wytworzenia, koszty sprzedaży, koszty ogólnego zarządu.</li><li><strong>Koszty stałe (KS)</strong> — nie zmieniają się wraz z wolumenem produkcji w danym przedziale (np. czynsz, amortyzacja liniowa).</li><li><strong>Koszty zmienne (KZ)</strong> — rosną proporcjonalnie do wolumenu (np. materiały bezpośrednie, akord).</li><li><strong>Koszty bezpośrednie</strong> — dające się wprost i ekonomicznie przypisać do wyrobu (materiał, robocizna bezpośrednia).</li><li><strong>Koszty pośrednie</strong> — wspólne dla wielu wyrobów, wymagające rozliczenia kluczem (koszty wydziałowe).</li><li><strong>Rachunek kosztów pełnych (RKP, absorpcyjny)</strong> — koszt wytworzenia wyrobu obejmuje koszty zmienne ORAZ stałe koszty produkcji.</li><li><strong>Rachunek kosztów zmiennych (RKZ)</strong> — kosztem wyrobu są tylko koszty zmienne; stałe koszty produkcji traktowane jako koszt okresu.</li><li><strong>Marża pokrycia (CM, contribution margin)</strong> — przychód minus koszty zmienne; „pokrywa\" koszty stałe i tworzy zysk.</li><li><strong>Próg rentowności (BEP, break-even point)</strong> — wolumen/przychód, przy którym zysk = 0.</li><li><strong>Dźwignia operacyjna (DOL)</strong> — miara wrażliwości zysku operacyjnego na zmianę sprzedaży, napędzana udziałem kosztów stałych.</li></ul>"}, {"h": "3. Wzory/zasady i przykład", "html": "<p>Marża pokrycia jednostkowa i wskaźnik marży: $$cm = c - kz_j \\qquad wcm = \\frac{cm}{c}$$</p><div class=\"legend\">gdzie: $c$ — cena jednostkowa (zł/szt.); $kz_j$ — jednostkowy koszt zmienny (zł/szt.); $cm$ — marża pokrycia na sztukę (zł/szt.); $wcm$ — wskaźnik marży (bezwymiarowy).</div><p>Próg rentowności ilościowy i wartościowy: $$BEP_{ilosc} = \\frac{KS}{cm} \\qquad BEP_{wartosc} = \\frac{KS}{wcm}$$</p><div class=\"legend\">gdzie: $KS$ — całkowite koszty stałe (zł); $BEP_{ilosc}$ — próg w sztukach; $BEP_{wartosc}$ — próg w zł przychodu.</div><p>Wolumen dla docelowego zysku $Z$: $$Q_{Z} = \\frac{KS + Z}{cm}$$</p><div class=\"legend\">gdzie: $Z$ — zysk operacyjny docelowy (zł); $Q_Z$ — wymagana sprzedaż (szt.).</div><p>Dźwignia operacyjna i kluczowa różnica wyników: $$DOL = \\frac{CM}{CM - KS} = \\frac{\\text{marża pokrycia łączna}}{\\text{zysk operacyjny}}$$ $$Zysk_{RKP} - Zysk_{RKZ} = ks_j \\cdot \\Delta Q_{zapasu}$$</p><div class=\"legend\">gdzie: $CM$ — łączna marża pokrycia (zł); $DOL$ — mnożnik (np. $2$ oznacza: $+10\\%$ sprzedaży $\\to +20\\%$ zysku); $ks_j$ — stały koszt produkcji na sztukę (zł); $\\Delta Q_{zapasu}$ — przyrost zapasu (produkcja − sprzedaż, szt.).</div><p><strong>Przykład.</strong> $c = 100$, $kz_j = 60$, $KS = 80\\,000$.</p><ul><li>$cm = 100 - 60 = 40$ zł; $wcm = 0{,}4$.</li><li>$BEP_{ilosc} = 80\\,000 / 40 = 2\\,000$ szt.; $BEP_{wartosc} = 80\\,000 / 0{,}4 = 200\\,000$ zł.</li><li>Dla $Z = 20\\,000$: $Q_Z = (80\\,000 + 20\\,000)/40 = 2\\,500$ szt.</li><li>Przy sprzedaży $3\\,000$ szt.: $CM = 3\\,000 \\cdot 40 = 120\\,000$; zysk $= 120\\,000 - 80\\,000 = 40\\,000$; $DOL = 120\\,000 / 40\\,000 = 3$.</li></ul>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li>Zacznij od klasyfikacji: pokaż dwa przekroje — rodzajowy vs funkcjonalny oraz stały/zmienny i bezpośredni/pośredni (to fundament obu rachunków).</li><li>Zdefiniuj RKP vs RKZ przez jedno kryterium: co robimy ze <strong>stałymi kosztami produkcji</strong> (koszt wyrobu vs koszt okresu).</li><li>Powiedz, kiedy wyniki się różnią: tylko gdy zmienia się zapas; $\\text{produkcja} &gt; \\text{sprzedaż} \\Rightarrow$ RKP pokazuje wyższy zysk.</li><li>Wprowadź <strong>marżę pokrycia</strong> jako pomost do CVP i podaj wzór na $cm$ oraz $wcm$.</li><li>Wyprowadź <strong>BEP</strong> (ilościowy i wartościowy), narysuj/opisz wykres i zaznacz <strong>margines bezpieczeństwa</strong>.</li><li>Dołóż <strong>dźwignię operacyjną</strong> — wyjaśnij, że wysoki udział kosztów stałych = wysoki DOL = większe ryzyko i większa nagroda.</li><li>Zakończ wnioskiem zarządczym: RKZ lepszy do decyzji krótkookresowych, RKP wymagany w sprawozdawczości (UoR/MSR 2).</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> „Kiedy oba rachunki dają ten sam zysk?\" — gdy produkcja = sprzedaż (brak zmiany zapasu); wtedy żadne stałe koszty nie zostają „uwięzione\" w zapasie.</li><li><strong>Gdzie komisja dociska:</strong> kierunek różnicy. Produkcja &gt; sprzedaż → zysk RKP &gt; RKZ (koszty stałe aktywowane w zapasie); produkcja &lt; sprzedaż → odwrotnie.</li><li>Mylenie <strong>marży pokrycia</strong> z <strong>zyskiem</strong> — marża pokrywa dopiero koszty stałe; zysk pojawia się po ich pokryciu.</li><li>Mylenie podziału stały/zmienny z bezpośredni/pośredni — to dwa NIEZALEŻNE kryteria (koszt może być zmienny i pośredni, np. energia wydziałowa).</li><li><strong>Gdzie komisja dociska:</strong> który rachunek jest zgodny ze sprawozdawczością — do bilansu/RZiS obowiązuje koszt wytworzenia wg RKP (Ustawa o rachunkowości / MSR 2); RKZ to narzędzie wewnętrzne (zarządcze).</li><li>Założenia CVP: liniowość, stała cena i $kz_j$, jeden produkt (lub stała struktura) — komisja lubi pytać „co osłabia ten model\".</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ol><li><strong>Dlaczego RKP może zawyżać zysk przy rosnących zapasach?</strong> Bo część stałych kosztów produkcji zostaje aktywowana w wartości zapasu i nie obciąża wyniku okresu, w którym powstała — wynik jest wyższy niż w RKZ.</li><li><strong>Co pokazuje wskaźnik marży pokrycia i do czego służy?</strong> Pokazuje, jaka część każdej złotówki przychodu zostaje na pokrycie kosztów stałych i zysku; służy do liczenia BEP wartościowego i szybkich symulacji rentowności.</li><li><strong>Firma A ma wysokie koszty stałe, firma B niskie — która ma wyższy DOL i co to znaczy?</strong> Firma A; jej zysk silniej reaguje na zmiany sprzedaży (większy potencjał zysku przy wzroście, większe ryzyko przy spadku).</li><li><strong>Jak policzyć margines bezpieczeństwa?</strong> To różnica między planowaną sprzedażą a progiem rentowności (w szt., zł lub %): $MB\\% = (S - BEP)/S$ — pokazuje, o ile może spaść sprzedaż, zanim pojawi się strata.</li></ol>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: „Kiedy oba rachunki dają ten sam zysk?\" — gdy produkcja = sprzedaż (brak zmiany zapasu); wtedy żadne stałe koszty nie zostają „uwięzione\" w zapasie.", "Gdzie komisja dociska: kierunek różnicy. Produkcja > sprzedaż → zysk RKP > RKZ (koszty stałe aktywowane w zapasie); produkcja < sprzedaż → odwrotnie.", "Gdzie komisja dociska: który rachunek jest zgodny ze sprawozdawczością — do bilansu/RZiS obowiązuje koszt wytworzenia wg RKP (Ustawa o rachunkowości / MSR 2); RKZ to narzędzie wewnętrzne (zarządcze)."], "order": 7}, {"id": "k6", "group": "kier", "num": 6, "title": "Decyzje finansowe: finansowanie, koszt kapitalu, ryzyko", "day": 3, "minutes": 22, "sections": [{"h": "0. Cegielki — co znac wczesniej", "html": "<ul><li><strong>Bilans</strong>: aktywa (majatek) = pasywa (kapital wlasny + zobowiazania); pasywa pokazuja, skad pochodzi finansowanie.</li><li><strong>Wartosc pieniadza w czasie</strong>: zlotowka dzis jest warta wiecej niz jutro — przyszle przeplywy dyskontujemy stopa.</li><li><strong>Stopa zwrotu i dyskonto</strong>: koszt kapitalu to stopa, ktora oczekuja dawcy finansowania.</li><li><strong>Dzwignia</strong>: dlug zwieksza zwrot dla wlascicieli, ale i zmiennosc wyniku (ryzyko).</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>Firma musi sfinansowac swoj majatek — pieniadze pochodza albo od wlascicieli (kapital wlasny), albo od wierzycieli (dlug). Kazde zrodlo ma swoja \"cene\" (koszt kapitalu), a srednia wazona tych cen to <strong>WACC</strong> — minimalna stopa, jaka projekt musi zarobic, by sie oplacac. Dlug jest tanszy (odsetki sa kosztem podatkowym i wierzyciel ryzykuje mniej), ale zwieksza ryzyko niewyplacalnosci. Analogia: finansowanie firmy jak budowa domu — czesc placisz wlasnymi oszczednosciami (drozsze, ale bez rat), czesc kredytem (tansze raty, ale bank moze zlicytowac dom, jesli przestaniesz placic).</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>Kapital wlasny (equity)</strong>: srodki wlascicieli (akcje, udzialy, zysk zatrzymany); brak obowiazku zwrotu, ale uprawnia do udzialu w zysku.</li><li><strong>Kapital obcy (dlug)</strong>: pozyczony, zwrotny i oprocentowany (kredyty, obligacje); ma pierwszenstwo przed wlascicielami.</li><li><strong>Finansowanie krotkoterminowe</strong>: zapadalnosc $\\leq 1$ rok (kredyt obrotowy, kredyt kupiecki, faktoring); finansuje majatek obrotowy.</li><li><strong>Finansowanie dlugoterminowe</strong>: zapadalnosc $&gt; 1$ rok (kredyt inwestycyjny, obligacje, emisja akcji, leasing); finansuje majatek trwaly.</li><li><strong>Koszt kapitalu</strong>: stopa zwrotu wymagana przez dawcow kapitalu; dla firmy — koszt pozyskania finansowania.</li><li><strong>Koszt dlugu ($k_d$)</strong>: efektywne oprocentowanie zobowiazan po uwzglednieniu tarczy podatkowej.</li><li><strong>Koszt kapitalu wlasnego ($k_e$)</strong>: stopa zwrotu oczekiwana przez wlascicieli, zwykle szacowana modelem <strong>CAPM</strong> (Capital Asset Pricing Model).</li><li><strong>WACC</strong> (Weighted Average Cost of Capital): sredni wazony koszt kapitalu — laczny koszt wszystkich zrodel.</li><li><strong>Tarcza podatkowa</strong>: oszczednosc podatkowa, bo odsetki obnizaja podstawe opodatkowania (CIT).</li><li><strong>Ryzyko finansowe</strong>: ryzyko zwiazane ze struktura finansowania (zadluzeniem) — groza niewyplacalnosci i zmiennosc zwrotu dla wlascicieli.</li></ul>"}, {"h": "3. Wzory/zasady i przyklad", "html": "<p><strong>Koszt dlugu po opodatkowaniu:</strong> $$k_d = r_d \\cdot (1 - T)$$</p><div class=\"legend\">gdzie: $r_d$ — nominalne oprocentowanie dlugu (%); $T$ — stopa podatku dochodowego CIT, $19\\%$ lub $9\\%$ dla malych podatnikow [zweryfikuj aktualna wartosc] (ulamek).</div><p><strong>Koszt kapitalu wlasnego (CAPM):</strong> $$k_e = r_f + \\beta \\cdot (r_m - r_f)$$</p><div class=\"legend\">gdzie: $r_f$ — stopa wolna od ryzyka (%, np. rentownosc obligacji skarbowych); $\\beta$ — wrazliwosc akcji na rynek; $(r_m - r_f)$ — premia za ryzyko rynkowe (%).</div><p><strong>WACC:</strong> $$WACC = \\frac{E}{E+D} \\cdot k_e + \\frac{D}{E+D} \\cdot r_d \\cdot (1-T)$$</p><div class=\"legend\">gdzie: $E$ — wartosc kapitalu wlasnego (zl); $D$ — wartosc dlugu (zl); $k_e$ — koszt kapitalu wlasnego (%); $r_d$ — koszt dlugu (%); $T$ — stopa CIT (ulamek).</div><p><strong>Przyklad policzony:</strong> Dane: $E = 600$ tys. zl, $D = 400$ tys. zl, $k_e = 12\\%$, $r_d = 8\\%$, $T = 0{,}19$.</p><ul><li>Wagi: $E/(E+D) = 0{,}6$; $D/(E+D) = 0{,}4$.</li><li>Koszt dlugu po podatku: $8\\% \\cdot (1 - 0{,}19) = 6{,}48\\%$.</li><li>$WACC = 0{,}6 \\cdot 12\\% + 0{,}4 \\cdot 6{,}48\\% = 7{,}2\\% + 2{,}59\\% \\approx 9{,}79\\%$.</li></ul><p>Wniosek: projekt powinien zarabiac wiecej niz $\\approx 9{,}8\\%$, by zwiekszal wartosc firmy.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Punkt wyjscia — bilans</strong>: decyzje dlugofalowe (majatek trwaly, struktura kapitalu) finansujemy zrodlami dlugoterminowymi; krotkofalowe (majatek obrotowy, plynnosc) — krotkoterminowymi (zlota regula bilansowa).</li><li><strong>Podzial zrodel</strong>: wlasne vs obce oraz krotko- vs dlugoterminowe; podaj 1-2 przyklady kazdego.</li><li><strong>Kryteria wyboru zrodla</strong>: koszt, dostepnosc, ryzyko/plynnosc, utrata kontroli, wymogi zabezpieczen, elastycznosc.</li><li><strong>Istota kosztu kapitalu</strong>: to wymagana stopa zwrotu dawcow; sluzy jako stopa dyskontowa i prog oplacalnosci.</li><li><strong>Rodzaje kosztu</strong>: koszt dlugu (z tarcza podatkowa), koszt kapitalu wlasnego (CAPM), ich synteza w WACC — podaj wzory.</li><li><strong>Ryzyko finansowe</strong>: zdefiniuj (efekt zadluzenia/dzwigni), powiaz z ryzykiem operacyjnym i wskaz metody zarzadzania.</li><li><strong>Konkluzja</strong>: optymalna struktura kapitalu minimalizuje WACC i maksymalizuje wartosc firmy.</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska</strong>: dlaczego dlug jest \"tanszy\" niz kapital wlasny? Bo wierzyciel ryzykuje mniej (pierwszenstwo, zabezpieczenia) ORAZ odsetki daja tarcze podatkowa — wlasciciel wymaga wyzszej premii za wyzsze ryzyko.</li><li><strong>Gdzie komisja dociska</strong>: tarcza podatkowa dotyczy TYLKO kosztu dlugu — w koszcie kapitalu wlasnego nie ma czynnika $(1-T)$ (dywidenda nie jest kosztem podatkowym).</li><li><strong>Nie myl ryzyka operacyjnego z finansowym</strong>: operacyjne wynika ze zmiennosci sprzedazy/kosztow (dzwignia operacyjna), finansowe — ze stopnia zadluzenia (dzwignia finansowa).</li><li><strong>Zlota regula bilansowa</strong>: blad to finansowanie majatku trwalego kredytem obrotowym — grozi utrata plynnosci.</li><li><strong>Gdzie komisja dociska</strong>: dlug nie jest \"darmowym\" sposobem na podniesienie zwrotu — do pewnego momentu obniza WACC, ale po przekroczeniu rozsadnego zadluzenia rosnie ryzyko bankructwa i koszt obu zrodel rosnie.</li><li><strong>Wagi w WACC</strong>: licz na wartosciach rynkowych (lub docelowej strukturze), nie ksiegowych — czesty blad.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ul><li><strong>Dlaczego WACC jest minimalna stopa zwrotu projektu?</strong> Bo projekt musi zarobic przynajmniej tyle, ile kosztuje pozyskany kapital; ponizej WACC niszczy wartosc dla dawcow finansowania.</li><li><strong>Jak tarcza podatkowa wplywa na koszt dlugu?</strong> Odsetki obnizaja podstawe opodatkowania, wiec efektywny koszt dlugu to $r_d \\cdot (1-T)$ — jest nizszy niz nominalne oprocentowanie.</li><li><strong>Czym rozni sie ryzyko finansowe od operacyjnego?</strong> Operacyjne wynika z natury dzialalnosci (zmiennosc EBIT), finansowe z poziomu zadluzenia (obsluga dlugu); razem daja ryzyko calkowite.</li><li><strong>Wymien kryteria wyboru zrodla finansowania.</strong> Koszt, dostepnosc, ryzyko i wplyw na plynnosc, utrata kontroli, wymagane zabezpieczenia oraz elastycznosc splaty.</li></ul>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Gdzie komisja dociska: dlaczego dlug jest \"tanszy\" niz kapital wlasny? Bo wierzyciel ryzykuje mniej (pierwszenstwo, zabezpieczenia) ORAZ odsetki daja tarcze podatkowa — wlasciciel wymaga wyzszej premii za wyzsze ryzyko.", "Gdzie komisja dociska: tarcza podatkowa dotyczy TYLKO kosztu dlugu — w koszcie kapitalu wlasnego nie ma czynnika $(1-T)$ (dywidenda nie jest kosztem podatkowym).", "Gdzie komisja dociska: dlug nie jest \"darmowym\" sposobem na podniesienie zwrotu — do pewnego momentu obniza WACC, ale po przekroczeniu rozsadnego zadluzenia rosnie ryzyko bankructwa i koszt obu zrodel rosnie."], "order": 8}, {"id": "k7", "group": "kier", "num": 7, "title": "Kapital obrotowy netto i zarzadzanie nim", "day": 3, "minutes": 18, "sections": [{"h": "0. Cegielki — co znac wczesniej", "html": "<ul><li>Struktura bilansu: aktywa obrotowe vs aktywa trwale; pasywa stale (kapital wlasny + zobowiazania dlugoterminowe) vs zobowiazania krotkoterminowe.</li><li>Pojecie plynnosci finansowej: zdolnosc do terminowego regulowania zobowiazan biezacych.</li><li>Wartosc pieniadza w czasie i koszt kapitalu (kazda zlotowka zamrozona w aktywach obrotowych ma koszt alternatywny).</li><li>Roznica miedzy zyskiem (memorialowo) a gotowka (kasowo) — firma moze byc rentowna i jednoczesnie niewyplacalna.</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p><strong>Kapital obrotowy netto (KON)</strong> to ta czesc aktywow obrotowych, ktora jest finansowana kapitalem stalym (dlugoterminowym), a nie zobowiazaniami biezacymi. To \"poduszka bezpieczenstwa\" plynnosci: bufor miedzy tym, co firma szybko zamieni na gotowke, a tym, co musi szybko splacic. Im wiekszy KON, tym bezpieczniej, ale i drozej (kapital staly kosztuje). Analogia: KON to woda w zbiorniku nad miastem — za malo grozi suszą (utrata plynnosci), za duzo to zamrozony, niepracujacy zasob, ktory kosztuje utrzymanie.</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>Kapital obrotowy netto (KON)</strong> — czesc aktywow obrotowych finansowana kapitalem stalym; bufor plynnosci.</li><li><strong>Kapital staly</strong> — kapital wlasny powiekszony o zobowiazania dlugoterminowe (zrodla finansowania na ponad 1 rok).</li><li><strong>Plynnosc finansowa</strong> — zdolnosc do terminowego regulowania zobowiazan krotkoterminowych.</li><li><strong>Cykl konwersji gotowki (CCC, cash conversion cycle)</strong> — liczba dni od zaplaty za zapasy do inkasa naleznosci od klienta.</li><li><strong>Cykl operacyjny</strong> — suma okresu rotacji zapasow i okresu sciagania naleznosci (od zakupu zapasow do inkasa).</li><li><strong>Naleznosci krotkoterminowe</strong> — kwoty naleznne firmie od odbiorcow (kredyt kupiecki udzielony klientom).</li><li><strong>Zapasy</strong> — materialy, produkcja w toku i wyroby gotowe utrzymywane przez firme.</li><li><strong>Zobowiazania krotkoterminowe</strong> — dlugi firmy wymagalne w ciagu roku (m.in. kredyt kupiecki od dostawcow).</li><li><strong>Strategia agresywna/umiarkowana/konserwatywna</strong> — poziom KON odpowiednio niski (lub ujemny)/sredni/wysoki, czyli zaleznosc od finansowania krotkoterminowego.</li></ul>"}, {"h": "3. Wzory/zasady i przyklad", "html": "<p><strong>Pomiar KON — ujecie majatkowe (od strony aktywow):</strong> $$KON = AO - ZK$$</p><div class=\"legend\">gdzie: $AO$ — aktywa obrotowe (zl); $ZK$ — zobowiazania krotkoterminowe (zl).</div><p><strong>Pomiar KON — ujecie kapitalowe (od strony pasywow):</strong> $$KON = (KW + ZD) - AT$$</p><div class=\"legend\">gdzie: $KW$ — kapital wlasny (zl); $ZD$ — zobowiazania dlugoterminowe (zl); $AT$ — aktywa trwale (zl). Oba ujecia daja ten sam wynik.</div><p><strong>Wskaznik plynnosci biezacej:</strong> $$CR = \\frac{AO}{ZK}$$</p><div class=\"legend\">gdzie: $CR$ — current ratio; norma orientacyjna $1{,}2 \\leq CR \\leq 2{,}0$. Gdy $CR &gt; 1$, to $KON &gt; 0$.</div><p><strong>Cykl konwersji gotowki:</strong> $$CCC = OZ + ON - OZob$$</p><div class=\"legend\">gdzie: $OZ$ — okres rotacji zapasow (dni); $ON$ — okres sciagania naleznosci (dni); $OZob$ — okres splaty zobowiazan (dni).</div><p>Skladowe (przy zalozeniu 365 dni): $$OZ = \\frac{Zapasy}{Koszt\\ sprzedazy} \\cdot 365$$ $$ON = \\frac{Naleznosci}{Przychody} \\cdot 365$$</p><p><strong>Przyklad policzony.</strong> Firma: $AO = 800$, $ZK = 500$ (tys. zl). Zapasy $= 200$, naleznosci $= 300$, koszt sprzedazy $= 1460$, przychody $= 2190$, $OZob = 40$ dni.</p><ul><li>$KON = 800 - 500 = 300$ tys. zl (dodatni — bufor istnieje).</li><li>$CR = 800 / 500 = 1{,}6$ (w normie).</li><li>$OZ = (200 / 1460) \\cdot 365 = 50$ dni; $ON = (300 / 2190) \\cdot 365 = 50$ dni.</li><li>$CCC = 50 + 50 - 40 = 60$ dni. Gotowka jest zamrozona srednio przez 60 dni — tyle dni firma musi sfinansowac z wlasnych zrodel.</li></ul>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li>Zdefiniuj KON i podaj oba sposoby pomiaru (majatkowy i kapitalowy) — zaznacz, ze daja ten sam wynik.</li><li>Wyjasnij sens ekonomiczny: KON jako bufor plynnosci finansowany kapitalem stalym.</li><li>Omow zwiazek z plynnoscia: $KON &gt; 0$ oznacza nadwyzke aktywow obrotowych nad zobowiazaniami biezacymi (zwykle $CR &gt; 1$).</li><li>Przedstaw trzy strategie (agresywna/umiarkowana/konserwatywna) i ich trade-off rentownosc vs ryzyko.</li><li>Omow zarzadzanie elementami: zapasy, naleznosci, inwestycje krotkoterminowe, zobowiazania.</li><li>Wprowadz cykl konwersji gotowki jako miare efektywnosci i wyjasnij, ze celem jest jego skracanie.</li><li>Wniosek: optymalny KON balansuje bezpieczenstwo plynnosci z kosztem zamrozonego kapitalu.</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> ujemny KON nie zawsze jest zly — firmy o szybkim obrocie (sieci handlowe) finansuja aktywa krotkim, tanim kredytem kupieckim i celowo utrzymuja $KON &lt; 0$ (strategia agresywna).</li><li><strong>Gdzie komisja dociska:</strong> nie myl cyklu operacyjnego z CCC — cykl operacyjny to $OZ + ON$ (bez odejmowania zobowiazan); CCC dodatkowo odejmuje $OZob$.</li><li><strong>Gdzie komisja dociska:</strong> wyzszy KON to wieksze bezpieczenstwo, ale NIZSZA rentownosc kapitalu — to trade-off, nie \"im wiecej tym lepiej\".</li><li>Nie utozsamiaj zysku z gotowka: firma rentowna moze stracic plynnosc przy zlym zarzadzaniu kapitalem obrotowym.</li><li>Strategie poziomu KON dotycza struktury finansowania (ile krotkim, ile stalym), a nie tylko wielkosci aktywow.</li><li>Skracanie CCC: przyspieszaj inkaso naleznosci i rotacje zapasow, ale wydluzanie splaty zobowiazan ma granice (ryzyko utraty dostawcow, rabatow za szybka platnosc).</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ol><li><strong>Czym jest KON i jak go mierzymy?</strong> To czesc aktywow obrotowych finansowana kapitalem stalym; mierzymy go jako $AO - ZK$ (ujecie majatkowe) lub $(KW + ZD) - AT$ (kapitalowe) — oba daja ten sam wynik.</li><li><strong>Jaki jest zwiazek KON z plynnoscia?</strong> Dodatni KON oznacza nadwyzke aktywow obrotowych nad zobowiazaniami biezacymi, czyli bufor bezpieczenstwa plynnosci; zwykle towarzyszy mu $CR &gt; 1$.</li><li><strong>Czym roznia sie trzy strategie KON?</strong> Agresywna utrzymuje KON niski/ujemny (tani, ryzykowny kredyt krotki, wysoka rentownosc), konserwatywna wysoki (drogie bezpieczenstwo, niska rentownosc), umiarkowana posrednia.</li><li><strong>Co to cykl konwersji gotowki i po co go liczyc?</strong> $CCC = OZ + ON - OZob$ — liczba dni zamrozenia gotowki; im krotszy, tym mniej kapitalu obrotowego trzeba finansowac i tym lepsza efektywnosc.</li></ol>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Gdzie komisja dociska: ujemny KON nie zawsze jest zly — firmy o szybkim obrocie (sieci handlowe) finansuja aktywa krotkim, tanim kredytem kupieckim i celowo utrzymuja $KON < 0$ (strategia agresywna).", "Gdzie komisja dociska: nie myl cyklu operacyjnego z CCC — cykl operacyjny to $OZ + ON$ (bez odejmowania zobowiazan); CCC dodatkowo odejmuje $OZob$.", "Gdzie komisja dociska: wyzszy KON to wieksze bezpieczenstwo, ale NIZSZA rentownosc kapitalu — to trade-off, nie \"im wiecej tym lepiej\"."], "order": 9}, {"id": "k8", "group": "kier", "num": 8, "title": "Wycena przedsiebiorstw (FCFF/FCFE/EVA)", "day": 3, "minutes": 22, "sections": [{"h": "0. Cegielki — co znac wczesniej", "html": "<ul><li><strong>Wartosc pieniadza w czasie</strong> i dyskontowanie: $PV = \\frac{CF}{(1+r)^{t}}$.</li><li><strong>Sprawozdania finansowe</strong> (bilans, RZiS, cash flow) — zrodlo danych do prognozy.</li><li><strong>Koszt kapitalu</strong>: stopa zwrotu wymagana przez dawcow kapitalu (wlasciciele + wierzyciele).</li><li><strong>Roznica wartosc vs cena</strong>: wartosc to szacunek analityka, cena to wynik transakcji rynkowej.</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>Wartosc przedsiebiorstwa to dzisiejsza wartosc gotowki, ktora firma wygeneruje w przyszlosci dla swoich dawcow kapitalu, skorygowana o ryzyko. Wyceniamy roznymi obiektywami: ile firma zarobi (dochodowe), ile jest warty jej majatek (majatkowe), za ile sprzedaja sie podobne firmy (porownawcze). Wynik to przedzial, nie jedna liczba — bo zalozenia sa subiektywne. Analogia: wycena to jak oszacowanie wartosci jabloni — patrzysz na ile owocow wyda (dochodowe), ile warte jest samo drewno (majatkowe) i za ile sprzedano sasiednie sady (porownawcze).</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>FCFF</strong> (Free Cash Flow to Firm) — wolne przeplywy dla wszystkich dawcow kapitalu (przed splata dlugu), dyskontowane WACC.</li><li><strong>FCFE</strong> (Free Cash Flow to Equity) — wolne przeplywy dostepne dla wlascicieli (po odsetkach i splacie/zaciagnieciu dlugu), dyskontowane kosztem kapitalu wlasnego.</li><li><strong>WACC</strong> (Weighted Average Cost of Capital) — sredni wazony koszt kapitalu, stopa dyskontowa dla FCFF.</li><li><strong>CAPM</strong> (Capital Asset Pricing Model) — model szacujacy koszt kapitalu wlasnego: $r_e = r_f + \\beta \\cdot (r_m - r_f)$.</li><li><strong>EVA</strong> (Economic Value Added) — ekonomiczna wartosc dodana: zysk operacyjny po opodatkowaniu pomniejszony o koszt zaangazowanego kapitalu.</li><li><strong>VBM</strong> (Value Based Management) — zarzadzanie przez wartosc; nadrzedny cel firmy to maksymalizacja wartosci dla wlascicieli.</li><li><strong>EV</strong> (Enterprise Value) — wartosc calego przedsiebiorstwa (kapital wlasny + dlug netto).</li><li><strong>Wartosc rezydualna</strong> (TV, terminal value) — wartosc przeplywow po okresie szczegolowej prognozy, zwykle wedlug modelu Gordona.</li><li><strong>Mnoznik</strong> — wskaznik rynkowy (np. P/E, EV/EBITDA) odnoszacy cene/wartosc do miary wyniku, sluzacy wycenie porownawczej.</li></ul>"}, {"h": "3. Wzory/zasady i przyklad", "html": "<p><strong>FCFF:</strong> $$FCFF = EBIT \\cdot (1 - T) + A - \\Delta KON - CAPEX$$</p><div class=\"legend\">gdzie: $EBIT$ — zysk operacyjny (zl), $T$ — stopa podatku CIT (19%, dla malych 9% — [zweryfikuj aktualna wartosc]), $A$ — amortyzacja (zl), $\\Delta KON$ — zmiana kapitalu obrotowego netto (zl), $CAPEX$ — naklady inwestycyjne (zl).</div><p><strong>WACC:</strong> $$WACC = \\frac{E}{E+D} \\cdot r_e + \\frac{D}{E+D} \\cdot r_d \\cdot (1 - T)$$</p><div class=\"legend\">gdzie: $E$ — wartosc kapitalu wlasnego (zl), $D$ — wartosc dlugu (zl), $r_e$ — koszt kapitalu wlasnego (%), $r_d$ — koszt dlugu (%), $T$ — stopa podatkowa (tarcza podatkowa).</div><p><strong>Wartosc rezydualna (Gordon):</strong> $$TV = \\frac{FCFF_{n} \\cdot (1+g)}{WACC - g}$$</p><div class=\"legend\">gdzie: $FCFF_{n}$ — przeplyw ostatniego roku prognozy (zl), $g$ — stala stopa wzrostu (%), warunek: $g \\leq$ dlugookresowy wzrost gospodarki.</div><p><strong>EVA:</strong> $$EVA = NOPAT - WACC \\cdot IC$$</p><div class=\"legend\">gdzie: $NOPAT$ — zysk operacyjny po opodatkowaniu (zl), $IC$ — kapital zaangazowany/invested capital (zl). EVA $&gt; 0$ oznacza tworzenie wartosci.</div><p><strong>Przyklad (uproszczony DCF):</strong> Firma generuje stale $FCFF = 100$ tys. zl rocznie, $WACC = 10\\%$, $g = 2\\%$. Wartosc (renta wieczysta rosnaca): $$EV = \\frac{100 \\cdot (1{,}02)}{0{,}10 - 0{,}02} = \\frac{102}{0{,}08} = 1275 \\text{ tys. zl}.$$ Po odjeciu dlugu netto (np. 275 tys.) wartosc kapitalu wlasnego = 1000 tys. zl.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Cel i standard wyceny</strong> — po co wyceniamy (transakcja, sprawozdawczosc, sad) i jaki standard wartosci (godziwa, rynkowa, inwestycyjna).</li><li><strong>Trzy grupy metod</strong> — dochodowe, majatkowe, porownawcze; wskaz, ze dochodowe sa nadrzedne dla firm dzialajacych (going concern).</li><li><strong>Metody dochodowe</strong> — opisz FCFF (dyskonto WACC) vs FCFE (dyskonto $r_e$); podkresl role wartosci rezydualnej i kosztu kapitalu.</li><li><strong>Koszt kapitalu</strong> — WACC z CAPM dla $r_e$; to kluczowy i najbardziej wrazliwy parametr.</li><li><strong>Metody majatkowe i porownawcze</strong> — aktywa netto / wartosc skorygowana; mnozniki P/E, EV/EBITDA z grupy porownawczej.</li><li><strong>Analiza ryzyka i triangulacja</strong> — analiza wrazliwosci/scenariuszy; wycena to przedzial, krzyzowo weryfikowany roznymi metodami.</li><li><strong>Powiazanie z VBM</strong> — wycena to narzedzie zarzadzania przez wartosc (mierzenie tworzenia wartosci, np. EVA).</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> mylenie EV z wartoscia kapitalu wlasnego. $EV - dlug\\ netto = wartosc\\ equity$. P/E dotyczy equity, EV/EBITDA — calej firmy.</li><li><strong>Gdzie komisja dociska:</strong> dobor stopy dyskontowej. FCFF dyskontujemy WACC, FCFE — kosztem kapitalu wlasnego $r_e$. Pomylka = blad metodologiczny.</li><li><strong>Gdzie komisja dociska:</strong> wartosc rezydualna stanowi czesto 60-80% wyceny — male zmiany $g$ lub WACC mocno zmieniaja wynik (stad analiza wrazliwosci); warunek $g &lt; WACC$.</li><li><strong>Tarcza podatkowa</strong> w WACC wystepuje tylko przy koszcie dlugu $r_d \\cdot (1-T)$, nigdy przy $r_e$.</li><li><strong>Mnozniki</strong> wymagaja porownywalnej grupy (branza, wielkosc, rentownosc); zywcem przeniesiony mnoznik z innej branzy zafalszowuje wycene.</li><li><strong>Metody majatkowe</strong> ignoruja zdolnosc do generowania zysku i wartosci niematerialne (marka, know-how) — zanizaja wartosc firm uslugowych.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ul><li><strong>Czym rozni sie FCFF od FCFE i jaka stope dyskonta stosujemy do kazdego?</strong> FCFF to przeplyw dla wszystkich dawcow kapitalu, dyskontowany WACC; FCFE to przeplyw tylko dla wlascicieli (po dlugu), dyskontowany kosztem kapitalu wlasnego.</li><li><strong>Co mierzy EVA i kiedy firma tworzy wartosc?</strong> EVA = NOPAT minus koszt zaangazowanego kapitalu; wartosc powstaje, gdy EVA &gt; 0, czyli stopa zwrotu z kapitalu przewyzsza WACC.</li><li><strong>Kiedy stosujesz EV/EBITDA, a kiedy P/E?</strong> EV/EBITDA wycenia cale przedsiebiorstwo (niezalezne od struktury finansowania i amortyzacji), P/E odnosi sie do kapitalu wlasnego i zysku netto, wrazliwego na dlug i podatki.</li><li><strong>Dlaczego wycena to przedzial, a nie jedna liczba?</strong> Bo opiera sie na zalozeniach (prognozy, g, koszt kapitalu) obarczonych niepewnoscia — stad analiza wrazliwosci i triangulacja metod.</li></ul>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Gdzie komisja dociska: mylenie EV z wartoscia kapitalu wlasnego. $EV - dlug\\ netto = wartosc\\ equity$. P/E dotyczy equity, EV/EBITDA — calej firmy.", "Gdzie komisja dociska: dobor stopy dyskontowej. FCFF dyskontujemy WACC, FCFE — kosztem kapitalu wlasnego $r_e$. Pomylka = blad metodologiczny.", "Gdzie komisja dociska: wartosc rezydualna stanowi czesto 60-80% wyceny — male zmiany $g$ lub WACC mocno zmieniaja wynik (stad analiza wrazliwosci); warunek $g < WACC$."], "order": 10}, {"id": "k9", "group": "kier", "num": 9, "title": "Rynki finansowe i instrumenty", "day": 3, "minutes": 20, "sections": [{"h": "0. Cegielki — co znac wczesniej", "html": "<ul><li><strong>Wartosc pieniadza w czasie</strong> (dyskontowanie, wartosc obecna) — fundament wyceny kazdego instrumentu.</li><li><strong>Stopa procentowa</strong> jako cena pieniadza i miernik ryzyka.</li><li><strong>Ryzyko vs stopa zwrotu</strong> — wyzsze ryzyko = oczekiwana wyzsza premia.</li><li><strong>Plynnosc</strong> — zdolnosc szybkiej zamiany aktywa na gotowke bez utraty wartosci.</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p><strong>Rynek finansowy</strong> to miejsce (fizyczne lub elektroniczne), gdzie spotykaja sie podmioty z nadwyzkami kapitalu (oszczedzajacy) z tymi, ktorzy kapitalu potrzebuja (inwestujacy, panstwo). Przedmiotem obrotu sa instrumenty finansowe — kontrakty przenoszace kapital i ryzyko miedzy stronami. Rynek dzielimy wedlug terminu (pieniezny do 1 roku, kapitalowy powyzej), przedmiotu (walutowy, terminowy) i etapu obrotu (pierwotny vs wtorny). Analogia: rynek finansowy to \"krwiobieg gospodarki\" — przepompowuje oszczednosci tam, gdzie najefektywniej zamienia sie je na inwestycje.</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>Instrument finansowy</strong> — kontrakt, ktory u jednej strony tworzy aktywo finansowe, a u drugiej zobowiazanie lub instrument kapitalowy.</li><li><strong>Rynek pieniezny</strong> — segment instrumentow krotkoterminowych (do 1 roku), o wysokiej plynnosci i niskim ryzyku (np. bony skarbowe, lokaty miedzybankowe).</li><li><strong>Rynek kapitalowy</strong> — segment instrumentow dlugoterminowych (powyzej 1 roku): akcje i obligacje, finansuje rozwoj.</li><li><strong>Rynek pierwotny</strong> — emitent sprzedaje instrument po raz pierwszy i pozyskuje kapital (np. IPO).</li><li><strong>Rynek wtorny</strong> — obrot juz wyemitowanymi instrumentami miedzy inwestorami; zapewnia plynnosc (np. GPW).</li><li><strong>Instrument dluzny</strong> — potwierdza wierzytelnosc; emitent (dluznik) zobowiazuje sie do zwrotu kapitalu i odsetek (obligacja, bon).</li><li><strong>Instrument udzialowy</strong> — daje prawo wlasnosci i udzial w zysku (<strong>akcja</strong>, dywidenda).</li><li><strong>Instrument pochodny (derywat)</strong> — jego wartosc zalezy od ceny <strong>instrumentu bazowego</strong> (akcji, waluty, indeksu, surowca).</li><li><strong>Rynek walutowy (FOREX)</strong> — obrot walutami; ustala kurs wymiany jednej waluty na druga.</li><li><strong>Kurs walutowy</strong> — cena jednej waluty wyrazona w innej (np. EUR/PLN).</li></ul>"}, {"h": "3. Wzory/zasady i przyklad", "html": "<p><strong>Cena (rentownosc) instrumentu dyskontowego</strong> — np. bonu skarbowego, sprzedawanego ponizej nominalu: $$P = \\frac{N}{1 + r \\cdot \\frac{d}{365}}$$</p><div class=\"legend\">gdzie: $P$ — cena zakupu (PLN); $N$ — wartosc nominalna (PLN); $r$ — rentownosc roczna (ulamek dziesietny); $d$ — liczba dni do wykupu (dni).</div><p><strong>Wartosc obligacji</strong> = suma zdyskontowanych przeplywow (kuponow i nominalu): $$P = \\sum_{t=1}^{n} \\frac{C}{(1+r)^{t}} + \\frac{N}{(1+r)^{n}}$$</p><div class=\"legend\">gdzie: $C$ — kupon okresowy (PLN); $r$ — stopa dyskontowa/wymagana (ulamek); $n$ — liczba okresow; $N$ — nominal (PLN).</div><p><strong>Wynik na opcji kupna (call) w terminie</strong> dla nabywcy: $$Z = \\max(S_T - K,\\ 0) - p$$</p><div class=\"legend\">gdzie: $S_T$ — cena bazowego w terminie (PLN); $K$ — cena wykonania/strike (PLN); $p$ — zaplacona premia (PLN); $Z$ — wynik (PLN).</div><p><strong>Przyklad (bon skarbowy):</strong> Nominal $N = 1000$ PLN, $r = 5\\% = 0{,}05$, $d = 182$ dni. $$P = \\frac{1000}{1 + 0{,}05 \\cdot \\frac{182}{365}} = \\frac{1000}{1{,}02493} \\approx 975{,}68 \\text{ PLN}$$ Inwestor placi dzis ok. 975,68 PLN, a po pol roku otrzymuje 1000 PLN — zarabia ~24,32 PLN na dyskoncie.</p><p>&gt; Uwaga: podatek od zyskow kapitalowych (\"podatek Belki\") wynosi <strong>19%</strong> [zweryfikuj aktualna wartosc].</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Definicja:</strong> rynek finansowy to mechanizm przeplywu kapitalu od oszczedzajacych do inwestujacych za posrednictwem instrumentow finansowych.</li><li><strong>Funkcje</strong> (wymien 4-5): mobilizacja kapitalu, alokacja (efektywne kierowanie srodkow), transformacja (terminow i ryzyka), wycena aktywow, zapewnienie plynnosci.</li><li><strong>Podzialy:</strong> wg terminu (pieniezny / kapitalowy), wg etapu (pierwotny / wtorny), oraz rynek walutowy i terminowy.</li><li><strong>Instrumenty:</strong> krotko — pieniezne (bony, lokaty), kapitalowe (akcje, obligacje), dluzne vs udzialowe.</li><li><strong>Instrumenty pochodne:</strong> wymien kontrakty terminowe (forward, futures), swapy i opcje; podkresl funkcje zabezpieczajaca i spekulacyjna.</li><li><strong>Rynek walutowy:</strong> funkcja wymiany walut i ustalania kursu; uczestnicy (banki, NBP, inwestorzy).</li><li><strong>Puenta:</strong> sprawnie dzialajacy rynek finansowy obniza koszt kapitalu i wspiera wzrost gospodarczy.</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> roznica <strong>pierwotny vs wtorny</strong> — na pierwotnym kapital trafia do emitenta, na wtornym tylko zmienia wlasciciela (emitent NIE dostaje srodkow). To czesty blad.</li><li><strong>Gdzie komisja dociska:</strong> <strong>forward vs futures</strong> — forward jest pozagieldowy (OTC), niestandaryzowany, bez rozliczen dziennych; futures jest gieldowy, standaryzowany, z depozytem zabezpieczajacym i codziennym rozliczeniem (marking-to-market).</li><li><strong>Gdzie komisja dociska:</strong> <strong>opcja vs kontrakt terminowy</strong> — opcja daje nabywcy PRAWO (nie obowiazek) i kosztuje premie; kontrakt terminowy to OBOWIAZEK realizacji dla obu stron.</li><li><strong>Akcja a obligacja:</strong> akcja to wspolwlasnosc i ryzyko (dywidenda niegwarantowana), obligacja to dlug (odsetki gwarantowane umowa, pierwszenstwo przy upadlosci).</li><li><strong>Cena obligacji a stopa procentowa</strong> — relacja ODWROTNA: gdy stopy rosna, cena obligacji o stalym kuponie spada (i odwrotnie).</li><li>Nie myl rynku <strong>pienieznego</strong> (krotki termin, plynnosc) z <strong>kapitalowym</strong> (dlugi termin, finansowanie rozwoju) — granica to 1 rok.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<p><strong>P1: Czym rozni sie rynek pierwotny od wtornego?</strong> Na rynku pierwotnym emitent sprzedaje instrument po raz pierwszy i pozyskuje kapital; na wtornym inwestorzy handluja juz istniejacymi instrumentami, co zapewnia plynnosc, ale nie zasila emitenta.</p><p><strong>P2: Wymien glowne funkcje rynku finansowego.</strong> Mobilizacja i alokacja kapitalu, transformacja terminow i ryzyka, wycena aktywow oraz zapewnienie plynnosci obrotu.</p><p><strong>P3: Czym rozni sie opcja od kontraktu futures?</strong> Opcja daje nabywcy prawo (nie obowiazek) wykonania za cene premii; futures to wzajemne zobowiazanie obu stron, standaryzowane i rozliczane codziennie na gieldzie z depozytem zabezpieczajacym.</p><p><strong>P4: Jak zmiana stop procentowych wplywa na cene obligacji o stalym kuponie?</strong> Odwrotnie — wzrost stop obniza cene obligacji (przyszle kupony dyskontowane sa wyzsza stopa), a spadek stop ja podnosi.</p>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Gdzie komisja dociska: roznica pierwotny vs wtorny — na pierwotnym kapital trafia do emitenta, na wtornym tylko zmienia wlasciciela (emitent NIE dostaje srodkow). To czesty blad.", "Gdzie komisja dociska: forward vs futures — forward jest pozagieldowy (OTC), niestandaryzowany, bez rozliczen dziennych; futures jest gieldowy, standaryzowany, z depozytem zabezpieczajacym i codziennym rozliczeniem (marking-to-market).", "Gdzie komisja dociska: opcja vs kontrakt terminowy — opcja daje nabywcy PRAWO (nie obowiazek) i kosztuje premie; kontrakt terminowy to OBOWIAZEK realizacji dla obu stron."], "order": 11}, {"id": "k10", "group": "kier", "num": 10, "title": "System bankowy, NBP, polityka monetarna i fiskalna", "day": 4, "minutes": 22, "sections": [{"h": "0. Cegielki — co znac wczesniej", "html": "<ul><li><strong>Pieniadz</strong> i jego funkcje (miernik wartosci, srodek wymiany, tezauryzacji) oraz roznica miedzy gotowka a pieniadzem bezgotowkowym.</li><li><strong>Inflacja</strong> — trwaly wzrost przecietnego poziomu cen, mierzony wskaznikiem CPI.</li><li><strong>Budzet panstwa</strong> — plan dochodow i wydatkow; pojecia deficytu i dlugu publicznego.</li><li><strong>Stopa procentowa</strong> jako cena pieniadza w czasie.</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>System bankowy to dwa pietra: na gorze jeden <strong>bank centralny</strong> (NBP), ktory nie obsluguje zwyklego Kowalskiego, lecz dba o wartosc pieniadza i stabilnosc systemu; na dole banki komercyjne, ktore obsluguja firmy i ludzi. Panstwo wplywa na gospodarke dwoma deznami: polityka pieniezna (bank centralny steruje iloscia i cena pieniadza) oraz polityka fiskalna (rzad steruje podatkami i wydatkami). Analogia: bank centralny to termostat ogrzewania gospodarki — gdy \"za goraco\" (inflacja), podnosi stopy i schladza; gdy \"za zimno\" (recesja), obniza stopy i dogrzewa.</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>System dwuszczeblowy</strong> — model bankowosci, w ktorym oddzielono bank centralny (I szczebel) od bankow komercyjnych (II szczebel).</li><li><strong>NBP (Narodowy Bank Polski)</strong> — bank centralny RP, niezalezny od rzadu, odpowiedzialny za polityke pieniezna i emisje pieniadza.</li><li><strong>RPP (Rada Polityki Pienieznej)</strong> — organ NBP ustalajacy wysokosc stop procentowych i zalozenia polityki pienieznej.</li><li><strong>Emisja pieniadza</strong> — wylaczne prawo banku centralnego do wprowadzania do obiegu znakow pienieznych (monopol emisyjny).</li><li><strong>Stopa referencyjna</strong> — podstawowa stopa NBP wyznaczajaca rentownosc operacji otwartego rynku i poziom rynkowych stop (np. WIBOR).</li><li><strong>Rezerwa obowiazkowa</strong> — czesc depozytow, ktora bank komercyjny musi utrzymywac na rachunku w NBP (nie moze jej pozyczyc dalej).</li><li><strong>Operacje otwartego rynku (OOR)</strong> — kupno/sprzedaz papierow wartosciowych przez bank centralny w celu sterowania plynnoscia sektora bankowego.</li><li><strong>Polityka pieniezna (monetarna)</strong> — oddzialywanie banku centralnego na podaz pieniadza i stopy procentowe.</li><li><strong>Polityka fiskalna (budzetowa)</strong> — oddzialywanie rzadu na gospodarke przez podatki i wydatki budzetowe.</li><li><strong>Mnoznik kreacji pieniadza</strong> — wskaznik mowiacy, ile razy depozyt poczatkowy mnozy sie w systemie bankowym.</li></ul>"}, {"h": "3. Wzory/zasady i przyklad", "html": "<p><strong>Funkcje banku centralnego (3 role):</strong></p><ul><li><strong>bank emisyjny</strong> — monopol na emisje pieniadza;</li><li><strong>bank bankow</strong> — prowadzi rachunki bankow komercyjnych, jest pozyczkodawca ostatniej instancji;</li><li><strong>bank panstwa</strong> — obsluguje budzet, zarzadza rezerwami dewizowymi.</li></ul><p><strong>Mnoznik kreacji pieniadza (uproszczony):</strong></p><p>$$m = \\frac{1}{r}$$</p><div class=\"legend\">gdzie: $m$ — mnoznik (ile razy rosnie podaz pieniadza, bez jednostki); $r$ — stopa rezerwy obowiazkowej (ulamek, np. $0{,}035$).</div><p><strong>Maksymalny przyrost depozytow:</strong></p><p>$$\\Delta D = \\Delta R \\cdot \\frac{1}{r}$$</p><div class=\"legend\">gdzie: $\\Delta D$ — przyrost depozytow (zl); $\\Delta R$ — przyrost rezerw/wkladu poczatkowego (zl); $r$ — stopa rezerwy obowiazkowej (ulamek).</div><p><strong>Przyklad.</strong> Stopa rezerwy obowiazkowej $r = 3{,}5\\%$ [zweryfikuj aktualna wartosc] = $0{,}035$. Mnoznik:</p><p>$$m = \\frac{1}{0{,}035} \\approx 28{,}6$$</p><p>Wklad poczatkowy $\\Delta R = 1000$ zl daje maksymalnie:</p><p>$$\\Delta D = 1000 \\cdot 28{,}6 = 28\\,600 \\text{ zl}$$</p><p>Wniosek: im wyzsza rezerwa obowiazkowa, tym mniejszy mnoznik i mniej kreowanego pieniadza (narzedzie restrykcyjne).</p><p><strong>Typowe stawki/stopy do podania na egzaminie</strong> [wszystkie: zweryfikuj aktualna wartosc]:</p><ul><li>Stopa referencyjna NBP: rzedu $5{,}75\\%$.</li><li>Stopa rezerwy obowiazkowej: $3{,}5\\%$.</li><li>Cel inflacyjny NBP: $2{,}5\\%$ z pasmem $\\pm 1$ pkt proc.</li></ul>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Zdefiniuj system dwuszczeblowy</strong>: bank centralny + banki komercyjne, rozdzial funkcji.</li><li><strong>Omow funkcje banku centralnego (NBP)</strong>: bank emisyjny, bank bankow, bank panstwa; dodaj cel — stabilnosc cen.</li><li><strong>Wymien narzedzia polityki pienieznej</strong>: stopy procentowe NBP, rezerwa obowiazkowa, operacje otwartego rynku.</li><li><strong>Pokaz mechanizm</strong>: jak zmiana stopy/rezerwy/OOR wplywa na podaz pieniadza i koszt kredytu, a przez to na inflacje i koniunkture.</li><li><strong>Przejdz do polityki fiskalnej</strong>: instrumenty = podatki (dochody) i wydatki budzetowe; rzad jako podmiot.</li><li><strong>Skontrastuj ekspansje vs restrykcje</strong> w obu politykach (luzowanie kontra zacisniecie).</li><li><strong>Podsumuj koordynacje</strong>: obie polityki moga dzialac zgodnie lub w opozycji (policy mix).</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> mylenie polityki pienieznej (bank centralny, stopy/podaz pieniadza) z fiskalna (rzad, podatki/wydatki). To dwa rozne podmioty i narzedzia — nie wolno ich mieszac.</li><li><strong>Gdzie komisja dociska:</strong> kierunek dzialania. Podniesienie stop procentowych i rezerwy = polityka <strong>restrykcyjna</strong> (schladza); obnizenie = <strong>ekspansywna</strong> (pobudza). Czesto myli sie strony.</li><li><strong>Gdzie komisja dociska:</strong> przy OOR — sprzedaz papierow przez NBP <strong>sciaga</strong> pieniadz z rynku (restrykcja), kupno <strong>dostarcza</strong> plynnosc (ekspansja).</li><li>NBP nie obsluguje klientow indywidualnych ani firm — robia to banki komercyjne; bank centralny to \"bank bankow\".</li><li>Niezaleznosc NBP od rzadu — RPP ustala stopy autonomicznie; to gwarancja wiarygodnosci antyinflacyjnej.</li><li>Nie myl <strong>deficytu budzetowego</strong> (roczna nadwyzka wydatkow nad dochodami) z <strong>dlugiem publicznym</strong> (skumulowane zadluzenie).</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ol><li><strong>Czym rozni sie polityka monetarna od fiskalnej?</strong> Monetarna prowadzona jest przez bank centralny (NBP) za pomoca stop procentowych, rezerwy obowiazkowej i OOR; fiskalna przez rzad za pomoca podatkow i wydatkow budzetowych.</li><li><strong>Wymien i opisz trzy podstawowe funkcje banku centralnego.</strong> Bank emisyjny (monopol emisji), bank bankow (rachunki bankow, pozyczkodawca ostatniej instancji), bank panstwa (obsluga budzetu, rezerwy dewizowe).</li><li><strong>Jak wzrost stopy rezerwy obowiazkowej wplywa na podaz pieniadza?</strong> Zmniejsza mnoznik kreacji pieniadza ($m = 1/r$), wiec banki moga udzielic mniej kredytow — podaz pieniadza spada (dzialanie restrykcyjne).</li><li><strong>Na czym polegaja operacje otwartego rynku jako narzedzie ekspansywne?</strong> Bank centralny <strong>kupuje</strong> papiery wartosciowe od bankow, dostarczajac im plynnosc; rosnie podaz pieniadza i spadaja stopy rynkowe, co pobudza akcje kredytowa.</li></ol>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Gdzie komisja dociska: mylenie polityki pienieznej (bank centralny, stopy/podaz pieniadza) z fiskalna (rzad, podatki/wydatki). To dwa rozne podmioty i narzedzia — nie wolno ich mieszac.", "Gdzie komisja dociska: kierunek dzialania. Podniesienie stop procentowych i rezerwy = polityka restrykcyjna (schladza); obnizenie = ekspansywna (pobudza). Czesto myli sie strony.", "Gdzie komisja dociska: przy OOR — sprzedaz papierow przez NBP sciaga pieniadz z rynku (restrykcja), kupno dostarcza plynnosc (ekspansja)."], "order": 12}, {"id": "k11", "group": "kier", "num": 11, "title": "Finanse publiczne, budzet i podatki", "day": 4, "minutes": 22, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Sektor publiczny</strong> to wszystkie podmioty kontrolowane przez państwo (w tym spółki Skarbu Państwa); <strong>sektor finansów publicznych</strong> to jego węższa, ustawowo wyliczona część.</li><li><strong>Budżet</strong> = roczny plan dochodów i wydatków (instrument polityki fiskalnej państwa).</li><li><strong>Podatek</strong> = nieodpłatne, przymusowe, bezzwrotne świadczenie pieniężne na rzecz związku publicznoprawnego.</li><li><strong>Deficyt</strong> to nadwyżka wydatków nad dochodami; <strong>dług publiczny</strong> to skumulowane zadłużenie sektora.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Finanse publiczne to gospodarka pieniężna państwa: skąd bierze pieniądze (głównie podatki) i na co je wydaje (administracja, obrona, zdrowie, transfery). Budżet jest jak roczny domowy plan wydatków, tylko głosowany w ustawie i obowiązkowy do wykonania. Podatki są krwiobiegiem tego systemu — bez nich nie ma wydatków publicznych. <strong>Analogia:</strong> sektor finansów publicznych to \"portfel rodziny\", a sektor publiczny to cały \"dom z firmą rodzinną w garażu\" — portfel jest tylko częścią majątku domu.</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Sektor finansów publicznych (SFP)</strong> — zamknięty, ustawowy katalog podmiotów: organy władzy, jednostki samorządu terytorialnego (<strong>JST</strong>), ZUS, KRUS, NFZ, uczelnie publiczne, jednostki i zakłady budżetowe.</li><li><strong>Dochody budżetowe</strong> — wpływy bezzwrotne i definitywne (głównie podatki, cła, opłaty); nie trzeba ich oddawać.</li><li><strong>Przychody budżetowe</strong> — wpływy zwrotne, finansujące deficyt (emisja obligacji, kredyty, prywatyzacja).</li><li><strong>Wydatki budżetowe</strong> — kwoty przeznaczone na realizację zadań państwa (bieżące, majątkowe, transfery, obsługa długu).</li><li><strong>Procedura budżetowa</strong> — całość czynności tworzenia, uchwalania, wykonania i kontroli budżetu w cyklu rocznym.</li><li><strong>Podatki bezpośrednie</strong> — obciążają wprost dochód/majątek podatnika (<strong>PIT</strong>, <strong>CIT</strong>, podatek od nieruchomości).</li><li><strong>Podatki pośrednie</strong> — wliczone w cenę, płaci je konsument (<strong>VAT</strong> — podatek od towarów i usług, akcyza).</li><li><strong>Funkcje podatków</strong> — fiskalna (dochody budżetu), redystrybucyjna (podział dochodów), stymulacyjna (zachęty/ulgi).</li><li><strong>Zasady podatkowe (A. Smith)</strong> — równość, pewność, dogodność, taniość poboru.</li><li><strong>Deficyt budżetowy</strong> — ujemna różnica między dochodami a wydatkami w danym roku.</li></ul>"}, {"h": "3. Wzory/zasady i przykład", "html": "<p><strong>Wynik budżetu:</strong> $$W = D - Wy$$</p><div class=\"legend\">gdzie: $W$ — wynik budżetu (zł); $D$ — dochody (zł); $Wy$ — wydatki (zł). Gdy $W &lt; 0$ → deficyt, gdy $W &gt; 0$ → nadwyżka.</div><p><strong>Reguła długu (konstytucyjny limit):</strong> $$\\frac{DP}{PKB} \\leq 0{,}6$$</p><div class=\"legend\">gdzie: $DP$ — państwowy dług publiczny (zł); $PKB$ — produkt krajowy brutto (zł). Limit 60% wynika z art. 216 Konstytucji.</div><p><strong>Podatek liniowy CIT:</strong> $$T = p \\cdot D_{p}$$</p><div class=\"legend\">gdzie: $T$ — kwota podatku (zł); $p$ — stawka (%); $D_{p}$ — podstawa opodatkowania, czyli dochód (zł).</div><p><strong>Zasady podatkowe</strong> (najważniejsze do wymienienia): równość (sprawiedliwość), pewność, dogodność poboru, taniość (efektywność) poboru.</p><p><strong>Przykład (CIT):</strong> Spółka osiągnęła dochód $D_{p} = 500\\,000$ zł, stawka podstawowa $p = 19\\%$ [zweryfikuj aktualną wartość]. $$T = 0{,}19 \\cdot 500\\,000 = 95\\,000 \\text{ zł}$$ Przy stawce dla małego podatnika $p = 9\\%$ [zweryfikuj] byłoby to $45\\,000$ zł.</p><p><strong>Typowe stawki (wszystkie [zweryfikuj aktualną wartość] — zmienne):</strong></p><ul><li><strong>VAT:</strong> podstawowa $23\\%$, obniżone $8\\%$ i $5\\%$, oraz $0\\%$.</li><li><strong>PIT (skala):</strong> $12\\%$ do progu ~$120\\,000$ zł, $32\\%$ powyżej; kwota wolna ~$30\\,000$ zł. Podatek liniowy $19\\%$.</li><li><strong>CIT:</strong> $19\\%$ standardowo, $9\\%$ dla małych podatników/startujących.</li><li><strong>Podatek Belki</strong> (od zysków kapitałowych): $19\\%$.</li></ul>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Zdefiniuj finanse publiczne</strong> jako gospodarkę pieniężną państwa (gromadzenie i wydatkowanie środków publicznych).</li><li><strong>Rozróżnij sektor publiczny od SFP</strong> — SFP to węższy, ustawowo zamknięty katalog (wymień: organy władzy, JST, ZUS, NFZ).</li><li><strong>Omów budżet</strong> — roczny plan, uchwalany ustawą; rozdziel dochody (bezzwrotne) od przychodów (zwrotne).</li><li><strong>Wskaż etapy procedury budżetowej</strong> — przygotowanie (RM), uchwalenie (Sejm/Senat), wykonanie, kontrola (NIK).</li><li><strong>Zdefiniuj podatek</strong> i podaj cechy (przymusowy, nieodpłatny, bezzwrotny, pieniężny).</li><li><strong>Przeprowadź podział</strong> na bezpośrednie (PIT, CIT) i pośrednie (VAT, akcyza) + wymień funkcje (fiskalna, redystrybucyjna, stymulacyjna).</li><li><strong>Scharakteryzuj PIT/CIT/VAT</strong> z przykładowymi stawkami (zaznaczając, że są zmienne w czasie).</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> mylenie <strong>dochodów</strong> z <strong>przychodami</strong> — przychody są zwrotne (długi, obligacje) i służą finansowaniu deficytu; dochody są definitywne. To klasyczne pytanie dobijające.</li><li><strong>Gdzie komisja dociska:</strong> różnica <strong>sektor publiczny ≠ SFP</strong> — spółki Skarbu Państwa są w sektorze publicznym, ale NIE w SFP (działają na zasadach rynkowych).</li><li><strong>Gdzie komisja dociska:</strong> kto faktycznie ponosi ciężar <strong>VAT</strong> — formalnie płaci przedsiębiorca, ale ekonomicznie obciąża konsumenta (przerzucalność podatku pośredniego).</li><li>Nie myl <strong>deficytu budżetowego</strong> (zjawisko roczne, strumień) z <strong>długiem publicznym</strong> (stan skumulowany, zasób).</li><li>Pamiętaj o limicie <strong>60% PKB</strong> dla długu (art. 216 Konstytucji) i progach ostrożnościowych z ustawy o finansach publicznych.</li><li>Podając stawki, ZAWSZE zaznacz, że są aktualne na dany rok i podlegają zmianom — komisja docenia tę ostrożność.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<p>   Dochód to wpływ bezzwrotny i definitywny (podatki, cła), natomiast przychód jest zwrotny (kredyty, obligacje) i służy sfinansowaniu deficytu — nie zwiększa trwale zasobów państwa.</p><ol><li><strong>Czym różni się dochód budżetowy od przychodu budżetowego?</strong></li></ol><p>   Fiskalna — dostarcza dochodów budżetowi; redystrybucyjna — przesuwa dochody między grupami społecznymi; stymulacyjna — zachęca lub zniechęca do określonych zachowań (ulgi, wyższe stawki).</p><ol><li><strong>Wymień i krótko scharakteryzuj funkcje podatków.</strong></li></ol><p>   Bezpośredni obciąża wprost dochód lub majątek podatnika (PIT, CIT) i jest nieprzerzucalny; pośredni jest wliczony w cenę towaru (VAT, akcyza) i ekonomicznie ponosi go konsument.</p><ol><li><strong>Na czym polega różnica między podatkiem bezpośrednim a pośrednim?</strong></li></ol><p>   Przygotowanie projektu przez Radę Ministrów, uchwalenie ustawy budżetowej przez Sejm i Senat, wykonanie budżetu przez rząd oraz kontrola wykonania (m.in. przez NIK i absolutorium Sejmu).</p><ol><li><strong>Jakie są główne etapy procedury budżetowej?</strong></li></ol>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: mylenie dochodów z przychodami — przychody są zwrotne (długi, obligacje) i służą finansowaniu deficytu; dochody są definitywne. To klasyczne pytanie dobijające.", "Gdzie komisja dociska: różnica sektor publiczny ≠ SFP — spółki Skarbu Państwa są w sektorze publicznym, ale NIE w SFP (działają na zasadach rynkowych).", "Gdzie komisja dociska: kto faktycznie ponosi ciężar VAT — formalnie płaci przedsiębiorca, ale ekonomicznie obciąża konsumenta (przerzucalność podatku pośredniego)."], "order": 13}, {"id": "k12", "group": "kier", "num": 12, "title": "Makroekonomia dla finansisty", "day": 4, "minutes": 18, "sections": [{"h": "0. Cegielki — co znac wczesniej", "html": "<ul><li><strong>Ruch okrezny dochodu</strong>: gospodarstwa, firmy, panstwo i zagranica wymieniaja sie dobrami i pieniadzem.</li><li><strong>Agregaty pieniezne i stopy procentowe</strong> (rola NBP) — koszt pieniadza.</li><li><strong>Popyt i podaz</strong> na poziomie calej gospodarki (zagregowany).</li><li>Rozroznienie wielkosci <strong>nominalnych</strong> (w cenach biezacych) od <strong>realnych</strong> (skorygowanych o inflacje).</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>Makroekonomia patrzy na gospodarke \"z lotu ptaka\": ile kraj wytwarza (PKB), jak rosnie i drozeje, ile osob pracuje, jak rozlicza sie ze swiatem. Dla finansisty to nie teoria — to <strong>otoczenie, w ktorym podejmuje decyzje</strong>: inflacja zjada realne stopy zwrotu, kurs walutowy zmienia wartosc kontraktow, faza cyklu decyduje o ryzyku kredytowym. Analogia: makroekonomia to <strong>pogoda dla zeglarza</strong> — nie sterujesz wiatrem, ale jak go zignorujesz, zatoniesz; dobry finansista czyta prognoze i ustawia zagle (portfel, hedging, dlug).</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>PKB (Produkt Krajowy Brutto)</strong> — wartosc dobr i uslug finalnych wytworzonych na <strong>terytorium</strong> kraju w danym okresie (kryterium geograficzne).</li><li><strong>PNB / DNB (Produkt/Dochod Narodowy Brutto)</strong> — dochod wytworzony przez <strong>obywateli/rezydentow</strong> kraju, niezaleznie od miejsca (kryterium wlasnosciowe).</li><li><strong>Bilans platniczy</strong> — zestawienie wszystkich transakcji rezydentow z zagranica (rachunek biezacy + kapitalowy + finansowy).</li><li><strong>Kurs walutowy</strong> — cena jednej waluty wyrazona w drugiej; <strong>deprecjacja</strong> to spadek wartosci waluty, <strong>aprecjacja</strong> to wzrost.</li><li><strong>Cykl koniunkturalny</strong> — wahania aktywnosci gospodarczej wokol trendu: ozywienie, szczyt (boom), recesja, dno.</li><li><strong>Inflacja</strong> — trwaly wzrost ogolnego poziomu cen; <strong>deflacja</strong> to jego spadek; mierzona indeksem <strong>CPI (Consumer Price Index)</strong>.</li><li><strong>Bezrobocie</strong> — odsetek osob aktywnych zawodowo bez pracy, ale jej poszukujacych.</li><li><strong>Stopa oszczednosci</strong> — czesc dochodu nieprzeznaczona na konsumpcje; zrodlo finansowania <strong>inwestycji</strong>.</li><li><strong>Gospodarka otwarta</strong> — gospodarka prowadzaca wymiane handlowa i kapitalowa z zagranica (eksport, import, przeplywy kapitalu).</li></ul>"}, {"h": "3. Wzory/zasady i przyklad", "html": "<p><strong>PKB metoda wydatkowa (gospodarka otwarta):</strong> $$Y = C + I + G + (X - M)$$</p><div class=\"legend\">gdzie: $Y$ — PKB (zl); $C$ — konsumpcja (zl); $I$ — inwestycje (zl); $G$ — wydatki rzadowe (zl); $X$ — eksport (zl); $M$ — import (zl); $(X-M)$ — eksport netto (zl).</div><p><strong>Zwiazek PKB i PNB:</strong> $$PNB = PKB + \\text{dochody netto z zagranicy}$$ gdzie dochody netto z zagranicy = dochody rezydentow za granica $-$ dochody nierezydentow w kraju (zl).</p><p><strong>Rownowaga oszczednosci i inwestycji</strong> (gospodarka zamknieta): $S = I$; w otwartej: $S - I = X - M$, czyli nadwyzka oszczednosci nad inwestycjami zasila eksport netto.</p><p><strong>Realna stopa procentowa (efekt Fishera):</strong> $$r \\approx i - \\pi$$</p><div class=\"legend\">gdzie: $r$ — realna stopa procentowa (%); $i$ — nominalna stopa procentowa (%); $\\pi$ — stopa inflacji (%).</div><p><strong>Przyklad (liczony).</strong> Lokata oprocentowana nominalnie $i = 6\\%$, inflacja $\\pi = 5\\%$. Realna stopa: $r \\approx 6\\% - 5\\% = 1\\%$. Po podatku Belki (<strong>19%</strong> [zweryfikuj aktualna wartosc]) odsetki netto $\\approx 6\\% \\cdot (1 - 0{,}19) = 4{,}86\\%$, wiec realnie po podatku $r \\approx 4{,}86\\% - 5\\% = -0{,}14\\%$ — kapital realnie <strong>traci</strong>. Wniosek: finansista patrzy na stope realna po opodatkowaniu, nie nominalna.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Zdefiniuj PKB i odroznij od PNB</strong> (terytorium vs wlasnosc/rezydentura) — podaj wzor wydatkowy.</li><li><strong>Wymien skladniki bilansu platniczego</strong>: rachunek biezacy (handel, dochody, transfery), kapitalowy, finansowy; suma daze do zera.</li><li><strong>Systemy kursowe</strong>: kurs st_y (peg), plynny, oraz posrednie (np. pasmo wahan / crawling peg) — kto ustala kurs i jakie sa skutki.</li><li><strong>Cykl koniunkturalny</strong>: opisz cztery fazy i wskaz, jak panstwo lagodzi wahania (polityka fiskalna i monetarna — antycykliczna).</li><li><strong>Inflacja i bezrobocie</strong>: rodzaje i skutki, krotko o zaleznosci (krzywa Phillipsa w krotkim okresie).</li><li><strong>Oszczednosci a inwestycje</strong>: zaleznosc $S=I$ i jej rola w finansowaniu wzrostu; luka zasilana kapitalem zagranicznym.</li><li><strong>Puenta — zwiazek z finansami</strong>: jak te wielkosci wplywaja na stopy, kurs, ryzyko i wycene aktywow (decyzje finansowe).</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> roznica PKB vs PNB. PKB = gdzie wytworzono (terytorium); PNB/DNB = kto wytworzyl (rezydenci). Kraj z duzym kapitalem zagranicznym ma zwykle <strong>PKB &gt; PNB</strong> (zyski transferowane za granice).</li><li><strong>Gdzie komisja dociska:</strong> kierunek wplywu kursu. <strong>Deprecjacja</strong> (slabsza waluta) sprzyja <strong>eksporterom</strong> i podraza import; aprecjacja odwrotnie. Nie mylic deprecjacji (rynek) z dewaluacja (decyzja administracyjna w kursie stalym).</li><li><strong>Rodzaje inflacji</strong>: popytowa (zbyt duzy popyt), kosztowa/podazowa (wzrost kosztow, np. surowcow). Skutek dla finansisty: inflacja obniza <strong>realna</strong> stope zwrotu i wartosc naleznosci o stalym oprocentowaniu.</li><li><strong>Rodzaje bezrobocia</strong>: frykcyjne (zmiana pracy), strukturalne (niedopasowanie kwalifikacji), cykliczne (recesja). <strong>Bezrobocie naturalne</strong> = frykcyjne + strukturalne; przy nim gospodarka jest \"przy pelnym zatrudnieniu\".</li><li><strong>Gdzie komisja dociska:</strong> $S=I$ to <strong>tozsamosc ex post</strong>, nie postulat \"oszczedzaj wiecej\". Wysokie oszczednosci finansuja inwestycje, ale nadmierne (paradoks zapobiegliwosci) moga oslabiac popyt.</li><li>Nie myl <strong>inflacji</strong> (wzrost cen) z <strong>dezinflacja</strong> (spadek tempa inflacji) ani z <strong>deflacja</strong> (spadek cen).</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ol><li><strong>Czym rozni sie PKB od PNB?</strong> PKB mierzy produkcje na terytorium kraju (kryterium geograficzne), PNB — dochody rezydentow niezaleznie od miejsca; roznica to dochody netto z zagranicy.</li><li><strong>Jak inflacja wplywa na realna stope zwrotu inwestora?</strong> Obniza ja: realna stopa $\\approx$ nominalna minus inflacja; przy wysokiej inflacji nominalny zysk moze oznaczac realna strate (zwlaszcza po podatku).</li><li><strong>Jak deprecjacja waluty dziala na bilans handlowy?</strong> Czyni eksport tanszym, a import drozszym, co zwykle poprawia eksport netto (z opoznieniem — efekt krzywej J).</li><li><strong>Wymien fazy cyklu koniunkturalnego i znaczenie dla finansisty.</strong> Ozywienie, szczyt, recesja, dno; faza decyduje o ryzyku kredytowym, popycie na finansowanie i wycenie aktywow — w recesji rosnie ryzyko, w boomie ryzyko przegrzania.</li></ol>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Gdzie komisja dociska: roznica PKB vs PNB. PKB = gdzie wytworzono (terytorium); PNB/DNB = kto wytworzyl (rezydenci). Kraj z duzym kapitalem zagranicznym ma zwykle PKB > PNB (zyski transferowane za granice).", "Gdzie komisja dociska: kierunek wplywu kursu. Deprecjacja (slabsza waluta) sprzyja eksporterom i podraza import; aprecjacja odwrotnie. Nie mylic deprecjacji (rynek) z dewaluacja (decyzja administracyjna w kursie stalym).", "Gdzie komisja dociska: $S=I$ to tozsamosc ex post, nie postulat \"oszczedzaj wiecej\". Wysokie oszczednosci finansuja inwestycje, ale nadmierne (paradoks zapobiegliwosci) moga oslabiac popyt."], "order": 14}, {"id": "t1", "group": "fib", "num": 1, "title": "Value at Risk i ryzyka rynkowe banku", "day": 5, "minutes": 30, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Stopa zwrotu</strong> — o ile % zmieniła się wartość pozycji: $R = \\frac{P_1 - P_0}{P_0}$ (wersja logarytmiczna $\\ln\\frac{P_1}{P_0}$ ładnie dodaje się w czasie).</li><li><strong>Zmienność $\\sigma$</strong> (sigma) — odchylenie standardowe stóp zwrotu; im większe, tym większe ryzyko.</li><li><strong>Rozkład normalny (Gauss)</strong> — „dzwon\", opisany w pełni przez średnią $\\mu$ i odchylenie $\\sigma$; realne rynki mają jednak grubsze ogony.</li><li><strong>Kwantyl / wartość $z$</strong> — punkt odcinający najgorszy procent wyników; na pamięć: $z \\approx 1{,}65$ (95%), $z \\approx 2{,}33$ (99%), $z = 1{,}96$ (97,5%).</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>VaR (Value at Risk — wartość zagrożona ryzykiem) zamienia mgliste „rynek jest ryzykowny\" w jedną liczbę: „z prawdopodobieństwem 99% jutro nie stracę więcej niż X zł\". To nie środek dzwonu, lecz <strong>linia odcięcia w lewym ogonie</strong> — granica najgorszego 1% przypadków. <strong>Analogia:</strong> prognoza pogody z prawdopodobieństwem — „z 99% pewnością nie spadnie poniżej −5°C\". Nie obiecuje, że nie będzie −20°C; mówi tylko, że to rzadkie.</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>VaR (wartość zagrożona ryzykiem)</strong> — maksymalna oczekiwana strata portfela w danym <strong>horyzoncie</strong> i przy danym <strong>poziomie ufności</strong>, w normalnych warunkach rynkowych (formalnie: kwantyl rozkładu strat).</li><li><strong>Poziom ufności $(1-\\alpha)$</strong> — jak rzadkie zdarzenie odcinamy (99% → $\\alpha=1\\%$); wyższa ufność = wyższy VaR.</li><li><strong>Ryzyko rynkowe</strong> — ryzyko straty z wahań cen: walutowe (<strong>FX</strong>), stopy procentowej, akcji (<strong>equity</strong>), towarowe; dotyczy <strong>księgi handlowej</strong> (wycenianej do rynku).</li><li><strong>Expected Shortfall (ES, CVaR)</strong> — średnia strata w ogonie, gdy strata przekroczy VaR; mówi, <strong>jak głęboki</strong> jest ogon (VaR mówi tylko <strong>gdzie</strong> się zaczyna).</li><li><strong>Miara koherentna</strong> — spełnia m.in. subaddytywność ($\\rho(A+B) \\leq \\rho(A)+\\rho(B)$); ES ją spełnia, VaR dla grubych ogonów łamie.</li><li><strong>Backtesting</strong> — porównanie liczby przekroczeń VaR (wyjątków) z oczekiwaną; przy 99%/250 dni oczekujemy ~2,5 wyjątku (traffic-light: zielona/żółta/czerwona → mnożnik 3,0–4,0).</li><li><strong>Duracja modyfikowana / PV01</strong> — wrażliwość ceny obligacji na zmianę stopy (PV01 = zmiana wartości przy ruchu o 1 punkt bazowy).</li><li><strong>Rezerwa obowiązkowa</strong> — część depozytów, którą bank musi trzymać na rachunku w banku centralnym (NBP); instrument polityki pieniężnej, nie bufor płynności ani kapitał.</li><li><strong>Osad depozytów</strong> — stabilna część depozytów bieżących, która mimo formy „na żądanie\" zostaje w banku latami; pozwala finansować dłuższe aktywa.</li></ul>"}, {"h": "3. Wzory i przyklad", "html": "<p><strong>VaR parametryczny (krok bazowy):</strong> $$VaR = z_{\\alpha} \\cdot \\sigma \\cdot V$$</p><div class=\"legend\">gdzie: $VaR$ — wartość zagrożona (zł); $z_{\\alpha}$ — kwantyl normalny (1,65 dla 95%, 2,33 dla 99%); $\\sigma$ — dzienna zmienność (ułamek, np. 0,02 = 2%); $V$ — wartość pozycji (zł).</div><p><strong>Skalowanie w czasie na $t$ dni:</strong> $$VaR_{t} = VaR \\cdot \\sqrt{t}$$</p><div class=\"legend\">gdzie: $VaR_t$ — VaR za $t$ dni (zł); $\\sqrt{t}$ — pierwiastek z liczby dni ($\\sqrt{10} \\approx 3{,}16$); $t$ — horyzont w dniach. Reguła $\\sqrt{t}$ (nie $\\times t$) wynika z dodawania się wariancji niezależnych zwrotów.</div><p><strong>Agregacja dwóch ryzyk z korelacją:</strong> $$VaR_{port} = \\sqrt{VaR_1^2 + VaR_2^2 + 2\\rho \\cdot VaR_1 \\cdot VaR_2}$$</p><div class=\"legend\">gdzie: $VaR_{port}$ — VaR portfela (zł); $VaR_1, VaR_2$ — VaR składników (zł); $\\rho$ (ro) — korelacja od −1 do +1. Przy $\\rho &lt; 1$ wynik jest niższy od sumy prostej — to <strong>efekt dywersyfikacji</strong>.</div><p><strong>Przykład (kanoniczny ze skryptu).</strong> Portfel $V = 1\\,000\\,000$ zł, $\\sigma = 2\\% = 0{,}02$, ufność 99% ($z = 2{,}33$):</p><ul><li>VaR jednodniowy: $VaR_{1d} = 2{,}33 \\cdot 0{,}02 \\cdot 1\\,000\\,000 = 46\\,600$ zł.</li><li>VaR na 10 dni: $VaR_{10d} = 46\\,600 \\cdot \\sqrt{10} \\approx 46\\,600 \\cdot 3{,}16 \\approx 147\\,300$ zł.</li><li><strong>Interpretacja:</strong> w 99 dniach na 100 dzienna strata nie powinna przekroczyć ~46,6 tys. zł.</li></ul>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Definicja VaR</strong> z trzema parametrami (strata, horyzont, ufność) + zdanie interpretacyjne + uwaga, że to kwantyl rozkładu strat (nie strata maksymalna).</li><li><strong>Wzór</strong> $VaR = z_{\\alpha}\\sigma V$, a osobno skalowanie $\\sqrt{t}$.</li><li><strong>Trzy metody</strong> (parametryczna / historyczna / Monte Carlo) + jedna wada każdej.</li><li><strong>Cztery ryzyka</strong> (FX, stopa, akcje, towary) i mapowanie (FX → pozycja netto; stopa → duracja/PV01; akcje → beta/korelacje).</li><li><strong>Przykład liczbowy</strong> ($z = 2{,}33$, reguła $\\sqrt{t}$ na 10 dni) + <strong>efekt dywersyfikacji</strong> (suma prosta przeszacowuje).</li><li><strong>Wady VaR + ES</strong> (miara koherentna, średnia z ogona) + <strong>backtesting</strong> (~2,5 wyjątku/250 dni, mnożnik).</li><li><strong>Druga strona bilansu:</strong> portfel depozytowy (tani, stabilny funding, GAP, osad) i rezerwa obowiązkowa (polityka pieniężna, mnożnik $m=1/r$, NBP/RPP, stopa [zweryfikuj]).</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Mylenie $z=1{,}65$ (95%) z $2{,}33$ (99%).</strong> Najczęstszy błąd liczbowy. <strong>Gdzie komisja dociska:</strong> skrypt wprost każe zapamiętać obie liczby — komisja prawie zawsze sprawdza ten odruch i potrafi zapytać „dlaczego 2,33?\" (bo $P(R &lt; -2{,}33\\sigma) = 1\\%$).</li><li><strong>VaR = strata maksymalna.</strong> Błąd: VaR mówi o normalnych warunkach do progu; za progiem strata bywa wielokrotnie wyższa (od tego jest ES). <strong>Gdzie komisja dociska:</strong> jeśli powiesz „maksymalna strata\", padnie pytanie „a w tym 1%?\".</li><li><strong>VaR jest zawsze subaddytywny.</strong> Błąd: dla grubych ogonów VaR potrafi „karać dywersyfikację\". <strong>Gdzie komisja dociska:</strong> zrozumienie hasła „VaR karze dywersyfikację\" to punkt za poziom rozszerzony i główny powód przejścia FRTB na ES.</li><li><strong>Skalowanie przez $t$ zamiast $\\sqrt{t}$.</strong> Zakłada idealną kumulację ruchów; przeszacowuje ryzyko. Poprawnie: wariancje sumują się liniowo, więc VaR rośnie jak $\\sqrt{t}$.</li><li><strong>Stosowanie delta-normal do opcji.</strong> Opcje są nieliniowe (gamma); liniowa delta drastycznie zaniża VaR — używaj symulacji z pełną rewyceną.</li><li><strong>Mylenie rezerwy obowiązkowej z LCR/NSFR i kapitałem.</strong> To trzy różne reżimy: rezerwa = polityka pieniężna (NBP); LCR/NSFR = normy płynności; wymóg kapitałowy = absorpcja strat.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ol><li><strong>Co znaczy „VaR = 1 mln, 99%, 1 dzień\"?</strong> Z prawdopodobieństwem 99% strata dzienna nie przekroczy 1 mln zł; równoważnie średnio 1 dzień na 100 będzie gorszy. To kwantyl rozkładu strat, nie strata maksymalna.</li><li><strong>Po co Expected Shortfall, skoro mamy VaR?</strong> Bo VaR podaje tylko próg, a milczy, jak głęboki jest ogon. ES = średnia strata po przekroczeniu VaR i jest miarą koherentną (subaddytywną) — dlatego FRTB przechodzi z VaR na ES (97,5%).</li><li><strong>Jak rezerwa obowiązkowa wpływa na kreację pieniądza?</strong> Zamrożone w NBP środki nie mogą być pożyczone dalej; im wyższa stopa $r$, tym mniejszy mnożnik $m = 1/r$ i mniejsza akcja kredytowa. To instrument polityki pieniężnej RPP (stopa [zweryfikuj]).</li><li><strong>Trzy metody VaR i ich wady?</strong> Parametryczna (szybka, zaniża grube ogony, zawodzi przy opcjach); historyczna (zero założeń o rozkładzie, ale zakłada powtórkę przeszłości); Monte Carlo (najogólniejsza, radzi sobie z opcjami, ale kosztowna i wrażliwa na model).</li></ol>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Mylenie $z=1{,}65$ (95%) z $2{,}33$ (99%). Najczęstszy błąd liczbowy. Gdzie komisja dociska: skrypt wprost każe zapamiętać obie liczby — komisja prawie zawsze sprawdza ten odruch i potrafi zapytać „dlaczego 2,33?\" (bo $P(R < -2{,}33\\sigma) = 1\\%$).", "VaR = strata maksymalna. Błąd: VaR mówi o normalnych warunkach do progu; za progiem strata bywa wielokrotnie wyższa (od tego jest ES). Gdzie komisja dociska: jeśli powiesz „maksymalna strata\", padnie pytanie „a w tym 1%?\".", "VaR jest zawsze subaddytywny. Błąd: dla grubych ogonów VaR potrafi „karać dywersyfikację\". Gdzie komisja dociska: zrozumienie hasła „VaR karze dywersyfikację\" to punkt za poziom rozszerzony i główny powód przejścia FRTB na ES."], "order": 15}, {"id": "t2", "group": "fib", "num": 2, "title": "Zdolnosc kredytowa i ryzyko kredytowe", "day": 5, "minutes": 30, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Bank lewarowany</strong>: na ~100 zł aktywów ma tylko ~8–10 zł kapitału własnego, więc nawet mały procent strat może wymazać cały kapitał.</li><li><strong>Wartość oczekiwana</strong>: dla zdarzenia „strata $S$ z prawdopodobieństwem $p$\" to po prostu $p \\times S$ — na tym stoi cały wzór EL.</li><li><strong>Prawdopodobieństwo</strong> to liczba z przedziału od 0 do 1; funkcja logistyczna $\\frac{1}{1+e^{-z}}$ ściska dowolną liczbę do tego przedziału.</li><li><strong>Stopa odzysku (RR)</strong>: frakcja ekspozycji odzyskana z zabezpieczenia po defaulcie; reszta to strata.</li><li><strong>Analiza wskaźnikowa</strong>: płynność, zadłużenie, rentowność, przepływy — narzędzia do jednego celu: czy z tej działalności da się obsłużyć dług.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Zdolność kredytowa odpowiada na jedno pytanie: <strong>czy klient odda dług w terminie i w pełnej kwocie</strong>. Cała maszyneria (wskaźniki, scoring, Z-Score, PD/LGD) to sposoby skompresowania ryzyka klienta do jednej liczby, na podstawie której bank decyduje: dać, na jakich warunkach, kiedy uciekać. Najgłębsza idea: bank nie minimalizuje strat, lecz <strong>maksymalizuje zysk skorygowany o ryzyko</strong> — zero strat oznaczałoby zero kredytów.</p><p><strong>Analogia (bukmacher):</strong> bank obstawia, że klient spłaci; oprocentowanie to kurs zakładu. Klient ryzykowny → wyższy kurs (marża). Banki przegrywają pojedyncze zakłady cały czas — sztuką jest, by <strong>portfel</strong> jako całość był dochodowy.</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Zdolność kredytowa</strong> — wg art. 70 ust. 1 Prawa bankowego: zdolność do spłaty kapitału wraz z odsetkami w terminach umowy, z własnych przyszłych przepływów (pojęcie prospektywne). [zweryfikuj numer ustępu]</li><li><strong>Ryzyko kredytowe</strong> — niebezpieczeństwo, że kredytobiorca nie spłaci, oraz wynikająca z tego strata; dzieli się na ryzyko niewypłacalności (PD) i ryzyko odzysku/ekspozycji (LGD, EAD).</li><li><strong>Niewypłacalność (default)</strong> — status wg CRR/Bazylei, gdy spełniony <strong>co najmniej jeden</strong> warunek: opóźnienie istotnej kwoty &gt; 90 dni LUB ocena „prawdopodobnie nie spłaci\" (UTP — unlikeliness to pay).</li><li><strong>Miernik syntetyczny</strong> — jedna liczba agregująca wiele wskaźników w łączną ocenę ryzyka (scoring, rating, Altman Z-Score), pozwalająca uszeregować i porównać kredytobiorców.</li><li><strong>PD</strong> (Probability of Default) — prawdopodobieństwo defaultu w horyzoncie (zwykle 12 mies.), liczba od 0 do 1.</li><li><strong>LGD</strong> (Loss Given Default) — frakcja ekspozycji nieodzyskana po defaulcie; $LGD = 1 - RR$.</li><li><strong>EAD</strong> (Exposure at Default) — kwota zaangażowania w chwili defaultu (zł); dla limitów uwzględnia <strong>CCF</strong> (współczynnik konwersji niewykorzystanego limitu).</li><li><strong>EL vs UL</strong> — strata oczekiwana (EL) pokrywana rezerwami i marżą; strata <strong>nieoczekiwana</strong> (UL, ogon rozkładu) pokrywana <strong>kapitałem</strong> — fundament Bazylei.</li><li><strong>Zdolność pierwotna vs wtórna</strong> — pierwotna = spłata z bieżących przepływów (główna podstawa decyzji); wtórna = z realizacji zabezpieczeń („plan B\", kanał LGD).</li><li><strong>Zdolność vs wypłacalność vs płynność</strong> — zdolność jest prospektywna i dotyczy konkretnego długu; wypłacalność to dodatni kapitał (bilans); płynność to bieżąca gotówka. Firma wypłacalna może zdefaultować z braku płynności.</li></ul>"}, {"h": "3. Wzory i przykład", "html": "<p><strong>Oczekiwana strata:</strong> $$EL = PD \\times LGD \\times EAD$$</p><div class=\"legend\">gdzie: $PD$ — prawdopodobieństwo defaultu (0–1); $LGD$ — frakcja nieodzyskana po defaulcie (0–1); $EAD$ — ekspozycja w chwili defaultu (zł); $EL$ — strata oczekiwana (zł/rok).</div><p><strong>Strata nieoczekiwana (pojedyncza ekspozycja):</strong> $$UL = EAD \\times LGD \\times \\sqrt{PD \\cdot (1-PD)}$$</p><div class=\"legend\">gdzie: $UL$ — strata nieoczekiwana (zł); $\\sqrt{PD \\cdot (1-PD)}$ — odchylenie standardowe zdarzenia „default/brak defaultu\" (największe przy $PD = 0{,}5$).</div><p><strong>Altman Z-Score (spółki giełdowe produkcyjne):</strong> $$Z = 1{,}2 X_1 + 1{,}4 X_2 + 3{,}3 X_3 + 0{,}6 X_4 + 1{,}0 X_5$$</p><div class=\"legend\">gdzie: $X_1$ — kapitał obrotowy/aktywa (płynność); $X_2$ — zyski zatrzymane/aktywa (skumulowana rentowność); $X_3$ — EBIT/aktywa (rentowność operacyjna, najwyższa waga); $X_4$ — wartość rynkowa kapitału/zobowiązania; $X_5$ — przychody/aktywa (sprawność). Strefy: $Z &gt; 2{,}99$ bezpieczna; $1{,}81 \\leq Z \\leq 2{,}99$ szara; $Z &lt; 1{,}81$ zagrożenie. [zweryfikuj wagi/progi]</div><p><strong>DSCR i DStI:</strong> $$DSCR = \\frac{CFADS}{\\text{rata kapitałowa} + \\text{odsetki}}, \\qquad DStI = \\frac{\\text{raty}}{\\text{dochód netto}}$$</p><div class=\"legend\">gdzie: $DSCR$ — ile razy gotówka operacyjna pokrywa obsługę długu (kowenant zwykle $\\geq 1{,}2$); $CFADS$ — przepływy dostępne na obsługę długu (zł/rok); $DStI$ — część dochodu idąca na raty (osoba fizyczna).</div><p><strong>Przykład policzony (mini-case, firma niegiełdowa).</strong> Kredyt 2 000 000 zł; $PD = 0{,}03$, $EAD = 2\\,000\\,000$ zł, zabezpieczenie hipoteczne $RR = 0{,}55$; CFADS = 650 000 zł, obsługa długu = 520 000 zł.</p><ol><li>$LGD = 1 - RR = 1 - 0{,}55 = 0{,}45$</li><li>$EL = 0{,}03 \\times 0{,}45 \\times 2\\,000\\,000 = 27\\,000$ zł rocznie (1,35% ekspozycji).</li><li>$DSCR = \\frac{650\\,000}{520\\,000} = 1{,}25$ — powyżej kowenantu 1,2, bufor 25%.</li></ol><p><strong>Wniosek:</strong> mierniki spójne i umiarkowanie pozytywne → udzielić kredytu z kowenantem $DSCR \\geq 1{,}2$ i marżą pokrywającą EL + zwrot na kapitale. Decyzja opiera się na zdolności pierwotnej (CFADS), hipoteka to tylko plan B (obniża LGD).</p><p><strong>Drobny test wrażliwości:</strong> gdyby zabezpieczenia nie było ($RR = 0{,}20$, $LGD = 0{,}80$), $EL = 0{,}03 \\times 0{,}80 \\times 2\\,000\\,000 = 48\\,000$ zł — prawie ×2. PD bez zmian: dowód, że <strong>zabezpieczenie tnie LGD, nie PD</strong>.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Definicja</strong> — zdolność kredytowa wg art. 70 ust. 1 Prawa bankowego (spłata kapitału + odsetek w terminach umowy, z przyszłych przepływów).</li><li><strong>Po co</strong> — ustawowy obowiązek banku + ochrona kapitału przy wysokiej dźwigni; sens: maksymalizacja zysku skorygowanego o ryzyko.</li><li><strong>Jak badamy</strong> — dwa wymiary: <strong>ilościowy</strong> (wskaźniki, przepływy, DSCR/ICR dla firmy; DStI + scoring dla osoby) i <strong>jakościowy</strong> (rama <strong>5 C</strong>: Character, Capacity, Capital, Collateral, Conditions; przypisz każde C do PD lub LGD).</li><li><strong>Miernik syntetyczny</strong> — kompresja wskaźników do jednej liczby: scoring/rating oraz Altman Z-Score (wzór + strefy 1,81 / 2,99).</li><li><strong>Modele pomiaru ryzyka</strong> — 4 klasy: scoringowe (logit, $PD = \\frac{1}{1+e^{-z}}$), dyskryminacyjne (Altman), strukturalne/rynkowe (Merton/KMV — default gdy aktywa &lt; dług), portfelowe (CreditMetrics, korelacje). Rozłóż $EL = PD \\times LGD \\times EAD$; odróżnij EL (rezerwy) od UL (kapitał).</li><li><strong>Regulacje</strong> — Prawo bankowe (art. 70), KNF (Rekomendacje S, T), Bazylea III/CRR (standardowa vs IRB), MSSF 9 (ECL, 3 stage'e).</li><li><strong>Puenta</strong> — decyzja kredytowa to nie minimum strat, lecz maksimum zysku skorygowanego o ryzyko (RAROC).</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Zabezpieczenie obniża LGD, nie PD.</strong> Hipoteka nie sprawia, że klient częściej spłaca — zmniejsza stratę, gdy nie spłaci. Klasyczny błąd punktowany ujemnie.</li><li><strong>EL ≠ UL.</strong> Stratę oczekiwaną pokrywają rezerwy i marża; stratę <strong>nieoczekiwaną</strong> (ogon) — <strong>kapitał</strong>. „Kapitał pokrywa EL\" to błąd merytoryczny.</li><li><strong>Zdolność kredytowa ≠ wypłacalność ≠ płynność</strong>, i zdolność pierwotna ≠ wtórna. Spłata ma iść z przepływów, nie z licytacji zabezpieczenia (to model lombardowy).</li><li><strong>Gdzie komisja dociska:</strong> różnica <strong>scoring vs rating</strong> — scoring to ocena masowa, detaliczna, automatyczna (point-in-time); rating to pojedynczy duży kredytobiorca, ocena ekspercka + modelowa (through-the-cycle).</li><li><strong>Gdzie komisja dociska:</strong> <strong>procykliczność</strong> — modele uczone na danych z dobrych czasów zaniżają PD przed kryzysem i zawyżają w kryzysie, pogłębiając cykl (odpowiedź regulatora: bufory antycykliczne, PD through-the-cycle).</li><li><strong>Gdzie komisja dociska:</strong> <strong>granica modelu</strong> — PD, LGD, EAD to *oszacowania*, nie fakty; błąd w nich wprost przekłada się na błąd EL i błędną wycenę marży (zbyt tania → bank dopłaca; zbyt droga → traci klientów).</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<p>   Character (wiarygodność) → PD; Capacity (zdolność spłaty z przepływów) → PD; Capital („skóra w grze\") → bufor; Collateral (zabezpieczenie) → LGD; Conditions (otoczenie makro) → ryzyko systemowe.</p><ol><li><strong>Wymień 5 C kredytu i przypisz do parametru ryzyka.</strong></li></ol><p>   $EL = 0{,}03 \\times 0{,}40 \\times 1\\,000\\,000 = 12\\,000$ zł rocznie. Pokrywa się ją rezerwą i marżą, a stratę nieoczekiwaną — kapitałem.</p><ol><li><strong>Policz EL dla PD = 3%, LGD = 40%, EAD = 1 mln zł.</strong></li></ol><p>   <strong>Kapitał</strong> banku (nie rezerwa). Rezerwy i marża pokrywają tylko stratę oczekiwaną (EL); kapitał pokrywa ogon rozkładu strat (UL, Credit VaR) — to fundament Bazylei.</p><ol><li><strong>Co pokrywa stratę nieoczekiwaną?</strong></li></ol><p>   Scoringowy jest statystyczny — uczy się z historycznych danych o klientach i przewiduje default, nie tłumacząc przyczyny ($PD = \\frac{1}{1+e^{-z}}$). Strukturalny (Merton/KMV) wyprowadza PD z przyczyny ekonomicznej: default, gdy rynkowa wartość aktywów spada poniżej długu; wymaga notowanej spółki.</p><ol><li><strong>Czym model strukturalny różni się od scoringowego?</strong></li></ol>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: różnica scoring vs rating — scoring to ocena masowa, detaliczna, automatyczna (point-in-time); rating to pojedynczy duży kredytobiorca, ocena ekspercka + modelowa (through-the-cycle).", "Gdzie komisja dociska: procykliczność — modele uczone na danych z dobrych czasów zaniżają PD przed kryzysem i zawyżają w kryzysie, pogłębiając cykl (odpowiedź regulatora: bufory antycykliczne, PD through-the-cycle).", "Gdzie komisja dociska: granica modelu — PD, LGD, EAD to *oszacowania*, nie fakty; błąd w nich wprost przekłada się na błąd EL i błędną wycenę marży (zbyt tania → bank dopłaca; zbyt droga → traci klientów)."], "order": 16}, {"id": "t5", "group": "fib", "num": 5, "title": "Wycena instrumentow finansowych", "day": 5, "minutes": 28, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Wartość pieniądza w czasie (TVM):</strong> złotówka dziś jest warta więcej niż jutro — bo dzisiejszą można od razu zainwestować.</li><li><strong>Wartość bieżąca:</strong> cały temat sprowadza się do $PV = \\frac{FV}{(1+r)^t}$ — przyszła kwota podzielona przez czynnik dyskontowy.</li><li><strong>Stopa dyskontowa $r$:</strong> to koszt kapitału / oczekiwany zwrot; im wyższe ryzyko, tym wyższe $r$ i niższa dzisiejsza wartość.</li><li><strong>Procent prosty vs składany:</strong> krótkie terminy (rynek pieniężny) liczymy procentem prostym, dłuższe (obligacje, akcje) — składanym.</li><li><strong>Kupon vs YTM:</strong> kupon to stały % od nominału; YTM to rynkowa stopa zrównująca cenę z przepływami (mylenie ich to klasyczny błąd).</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>Każdy instrument finansowy to obietnica przyszłych przepływów pieniężnych obarczona ryzykiem. Wycena = sprowadzenie tych przepływów do „dziś\" przez dyskontowanie. Im wyższe ryzyko lub im dalej w przyszłość, tym mocniej dyskontujemy. Jedno zdanie na cały temat: <strong>wartość = suma zdyskontowanych przepływów</strong>.</p><p><strong>Analogia:</strong> instrument to drzewo owocowe. Owoce (kupony, dywidendy, nominał) spadną w różnych latach. Płacisz dziś tyle, ile dziś warte są wszystkie przyszłe owoce razem — ale owoc za 5 lat „ważysz\" mniej niż ten za rok. Gdy rynek bardziej się boi, $r$ rośnie i cena drzewa spada.</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>Instrument finansowy</strong> — kontrakt tworzący aktywo finansowe u jednej strony, a zobowiązanie lub instrument kapitałowy u drugiej (to relacja prawna, nie rzecz).</li><li><strong>Instrument udziałowy (kapitałowy)</strong> — akcja/udział; roszczenie <strong>rezydualne</strong> (po wierzycielach), bezterminowe.</li><li><strong>Instrument dłużny</strong> — obligacja, bon, weksel; roszczenie <strong>uprzywilejowane</strong>, z terminem wykupu.</li><li><strong>Instrument pochodny (derywat)</strong> — instrument, którego wartość zależy od <strong>instrumentu bazowego</strong>, z niewielkim nakładem początkowym i rozliczeniem w przyszłości.</li><li><strong>Wartość godziwa (fair value, MSSF 13)</strong> — cena sprzedaży (exit price) w uporządkowanej transakcji rynkowej; przy aktywnym rynku równa wartości rynkowej.</li><li><strong>Zamortyzowany koszt</strong> — wartość początkowa korygowana efektywną stopą i odpisem na straty kredytowe; nie reaguje na wahania rynku.</li><li><strong>YTM (rentowność do wykupu)</strong> — rynkowa stopa dyskontowa zrównująca cenę z przepływami (wewnętrzna stopa zwrotu obligacji).</li><li><strong>Duration zmodyfikowana</strong> — miara wrażliwości ceny na zmianę stóp: o ile % spada cena przy wzroście stopy o 1 pkt proc.</li><li><strong>Rynek pieniężny</strong> — instrumenty $\\leq 1$ rok (bony skarbowe, bony NBP), cel: płynność.</li><li><strong>Rynek kapitałowy / terminowy</strong> — $&gt; 1$ rok (akcje, obligacje, pozyskanie kapitału) / obrót derywatami (transfer ryzyka, arbitraż).</li></ul><p><strong>Klasyfikacja MSSF 9:</strong> aktywa wycenia się wg modelu biznesowego + testu <strong>SPPI</strong> na trzy kategorie: <strong>zamortyzowany koszt</strong> (trzymaj do wykupu), <strong>FVOCI</strong> (trzymaj i sprzedawaj), <strong>FVTPL</strong> (reszta, w tym derywaty).</p>"}, {"h": "3. Wzory i przyklad", "html": "<p><strong>Bon skarbowy (rynek pieniężny, procent prosty):</strong> $$P = \\frac{FV}{1 + r \\cdot \\frac{d}{360}}$$</p><div class=\"legend\">gdzie: $P$ — cena dziś (zł); $FV$ — nominał wykupu (zł); $r$ — roczna stopa rynkowa (ułamek); $d$ — dni do wykupu; $360$ — umowna liczba dni w roku.</div><p><strong>Obligacja kuponowa (rynek kapitałowy, procent składany):</strong> $$P = \\sum_{t=1}^{n} \\frac{C}{(1+r)^t} + \\frac{FV}{(1+r)^n}$$</p><div class=\"legend\">gdzie: $P$ — cena obligacji (zł); $C$ — kupon za okres (zł); $FV$ — nominał na koniec (zł); $r$ — YTM za okres (ułamek); $n$ — liczba okresów; $t$ — numer okresu.</div><p><strong>Akcja (model Gordona):</strong> $$P_0 = \\frac{D_1}{r - g}$$</p><div class=\"legend\">gdzie: $P_0$ — cena akcji dziś (zł); $D_1$ — dywidenda za rok 1 (zł); $r$ — koszt kapitału własnego (ułamek); $g$ — stała stopa wzrostu dywidendy (ułamek). Warunek: $r &gt; g$.</div><p><strong>Forward (brak arbitrażu):</strong> $$F_0 = S_0 \\cdot (1 + r)^T$$</p><div class=\"legend\">gdzie: $F_0$ — cena forward (zł); $S_0$ — cena spot bazy (zł); $r$ — stopa wolna od ryzyka (ułamek); $T$ — czas do rozliczenia (lata). Korekta: dochód z bazy (dywidenda) obniża $F_0$, koszt magazynowania go podnosi.</div><p><strong>Przyklad (obligacja).</strong> Nominał 1000 zł, kupon roczny 6% (= 60 zł), 3 lata, YTM = 8%: $$P = \\frac{60}{1{,}08} + \\frac{60}{1{,}08^2} + \\frac{60}{1{,}08^3} + \\frac{1000}{1{,}08^3}$$ $$P = 55{,}56 + 51{,}44 + 47{,}63 + 793{,}83 = 948{,}46 \\text{ zł}$$ Cena &lt; nominał, bo YTM (8%) &gt; kupon (6%) — obligacja <strong>z dyskontem</strong>. Gdyby YTM spadło do 4%, cena wzrosłaby do 1055,50 zł (z premią) — to ta sama obligacja, różni ją tylko stopa dyskontowa.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Definicja</strong> instrumentu finansowego (kontrakt: aktywo u jednej strony / zobowiązanie lub kapitał u drugiej).</li><li><strong>Trzy klasy</strong> — udziałowe, dłużne, pochodne — przykład i natura roszczenia (rezydualne / uprzywilejowane / warunkowe); dodaj, że bony to dłużne krótkoterminowe rynku pieniężnego.</li><li><strong>Zasady wyceny</strong> — wartość godziwa vs zamortyzowany koszt; MSSF 9 (model biznesowy + SPPI → AC/FVOCI/FVTPL); hierarchia wartości godziwej (3 poziomy, MSSF 13).</li><li><strong>Wspólny mianownik</strong> — dyskontowanie przyszłych przepływów (DCF); stopa = czas + ryzyko.</li><li><strong>Metody per rynek</strong> — pieniężny (dyskonto proste), dłużny (suma zdyskontowanych kuponów + nominał, YTM), udziałowy (Gordon / mnożniki), terminowy (forward przez brak arbitrażu, opcja przez Black-Scholes).</li><li><strong>Jeden przykład liczbowy</strong> (obligacja) + zdanie o odwrotnej relacji cena–stopa.</li><li><strong>Zakotwiczenie w realiach</strong> — GPW, KNF, NBP, MSSF, reforma WIBOR→WIRON.</li></ol><p><strong>Gdzie komisja dociska:</strong> najmocniejsze zdanie — „wszystkie te metody to jeden mechanizm: dyskontowanie przyszłych przepływów; klasy różnią się tylko *kształtem i pewnością* przepływów, a derywaty wyceniamy dodatkowo przez brak arbitrażu, nie przez prognozę\".</p>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Mylenie kuponu z YTM.</strong> Kupon stały (cecha emisji), YTM zmienna rynkowa. Reguła: kupon = YTM → cena = nominał; kupon &lt; YTM → dyskonto; kupon &gt; YTM → premia.</li><li><strong>Odwracanie relacji cena–stopa.</strong> Gdy stopy rosną, ceny obligacji <strong>spadają</strong> — bo stopa siedzi w mianowniku czynnika dyskontowego. <strong>Gdzie komisja dociska:</strong> relacja jest nie tylko odwrotna, ale <strong>wypukła</strong> (convexity) — spadek YTM podnosi cenę nieco mocniej, niż ten sam wzrost ją obniża.</li><li><strong>Ignorowanie częstotliwości kuponu i konwencji dni.</strong> Kupon półroczny → stopa okresowa = YTM/2 i podwojona liczba okresów; bon: 360 vs 365 dni zmienia wynik.</li><li><strong>Model Gordona bez warunku $r &gt; g$.</strong> Jeśli $g \\geq r$, wzór nie ma sensu. <strong>Gdzie komisja dociska:</strong> przy $g \\geq r$ NIE licz — powiedz, że trzeba modelu wielofazowego (faza wysokiego wzrostu + Gordon na końcu).</li><li><strong>Forward ≠ futures.</strong> Forward: OTC, niestandaryzowany, ryzyko kontrahenta. Futures: giełdowy, z depozytem i codziennym mark-to-market. <strong>Gdzie komisja dociska:</strong> teoretyczna cena obu jest ta sama ($S_0(1+r)^T$); różni je mechanika rozliczeń i ryzyko kontrahenta.</li><li><strong>Cena forwardu zależna od oczekiwań?</strong> NIE — wynika z arbitrażu (spot + carry); oczekiwania są już w cenie spot.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<p><strong>1. Dlaczego cena obligacji spada, gdy rosną stopy?</strong> Bo cena to suma przepływów zdyskontowanych stopą rynkową, a stopa jest w mianowniku $\\frac{1}{(1+r)^t}$. Wzrost $r$ powiększa mianownik → maleje wartość bieżąca każdego przepływu → spada cena. Relacja odwrotna i wypukła.</p><p><strong>2. Wyceń obligację 2-letnią, kupon 4%, YTM 5% (nominał 1000 zł):</strong> $$P = \\frac{40}{1{,}05} + \\frac{40}{1{,}05^2} + \\frac{1000}{1{,}05^2} = 38{,}10 + 36{,}28 + 907{,}03 = 981{,}41 \\text{ zł}$$ Poniżej nominału, bo YTM (5%) &gt; kupon (4%) — z dyskontem.</p><p><strong>3. Od czego zależy cena opcji?</strong> Od pięciu czynników (Black-Scholes): ceny bazy $S_0$, wykonania $K$, czasu $T$, zmienności $\\sigma$, stopy $r$. Dla call wartość rośnie z $S_0$, $T$, $\\sigma$, a maleje z $K$. Cena = wartość wewnętrzna ($\\max(S_0-K,0)$) + wartość czasowa; kluczowe: wyższa zmienność = wyższa cena opcji.</p><p><strong>4. Jak wyznacza się wartość instrumentów rynku terminowego?</strong> Przez <strong>zasadę braku arbitrażu</strong>, nie prognozę. Forward: $F_0 = S_0(1+r)^T$ (cena spot rolowana stopą wolną od ryzyka), korygowana o dochód z bazy lub koszt utrzymania. Opcje: Black-Scholes / drzewa dwumianowe oparte na portfelu replikującym. Sedno: dwie strategie dające ten sam efekt muszą kosztować dziś tyle samo.</p>"}], "probes": ["Gdzie komisja dociska: najmocniejsze zdanie — „wszystkie te metody to jeden mechanizm: dyskontowanie przyszłych przepływów; klasy różnią się tylko *kształtem i pewnością* przepływów, a derywaty wyceniamy dodatkowo przez brak arbitrażu, nie przez prognozę\".", "## 5. Pulapki i gdzie komisja dociska", "Odwracanie relacji cena–stopa. Gdy stopy rosną, ceny obligacji spadają — bo stopa siedzi w mianowniku czynnika dyskontowego. Gdzie komisja dociska: relacja jest nie tylko odwrotna, ale wypukła (convexity) — spadek YTM podnosi cenę nieco mocniej, niż ten sam wzrost ją obniża.", "Model Gordona bez warunku $r > g$. Jeśli $g \\geq r$, wzór nie ma sensu. Gdzie komisja dociska: przy $g \\geq r$ NIE licz — powiedz, że trzeba modelu wielofazowego (faza wysokiego wzrostu + Gordon na końcu).", "Forward ≠ futures. Forward: OTC, niestandaryzowany, ryzyko kontrahenta. Futures: giełdowy, z depozytem i codziennym mark-to-market. Gdzie komisja dociska: teoretyczna cena obu jest ta sama ($S_0(1+r)^T$); różni je mechanika rozliczeń i ryzyko kontrahenta."], "order": 17}, {"id": "t11", "group": "fib", "num": 11, "title": "Koszt kapitalu przedsiebiorstwa miedzynarodowego", "day": 5, "minutes": 25, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Dyskontowanie:</strong> złotówka dziś &gt; złotówka za rok; przyszłe przepływy „cofamy\" dzieląc przez $(1+r)^t$, gdzie $r$ to koszt kapitału.</li><li><strong>Dwa źródła finansowania:</strong> kapitał własny (właściciele, bez gwarancji) i dług (wierzyciele, odsetki z pierwszeństwem); dług jest tańszy, ale podnosi ryzyko bankructwa.</li><li><strong>WACC (W27):</strong> średni ważony koszt całego koszyka finansowania — to bazę tu tylko rozszerzamy.</li><li><strong>CAPM (W27):</strong> $K_e = R_f + \\beta \\cdot (R_m - R_f)$ — wycenia koszt kapitału własnego przez ryzyko rynkowe.</li><li><strong>Tarcza podatkowa:</strong> odsetki obniżają podatek, więc efektywny koszt długu to $K_d \\cdot (1-T)$, nie $K_d$.</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>Koszt kapitału to minimalna stopa zwrotu, jaką firma musi wypracować, by nie niszczyć wartości — zarazem stopa, którą dyskontuje przyszłe przepływy. To <strong>koszt alternatywny</strong>: cena rezygnacji inwestora z najlepszej innej możliwości o tym samym ryzyku. W firmie międzynarodowej dochodzą dwa „podatki od niepewności\": ryzyko kraju i ryzyko walutowe. <strong>Analogia — poprzeczka na skoku wzwyż:</strong> WACC to wysokość poprzeczki, zwrot projektu to skoczek; przeskoczył (zwrot &gt; WACC) → tworzy wartość, strącił → niszczy ją, choćby księgowo był zysk. Ryzyko podnosi poprzeczkę.</p>"}, {"h": "2. Kluczowe pojecia", "html": "<ul><li><strong>Koszt kapitału</strong> — wymagana stopa zwrotu = stopa dyskontowa = koszt alternatywny (nie wydatek księgowy).</li><li><strong>WACC</strong> (*Weighted Average Cost of Capital*, średni ważony koszt kapitału) — średnia kosztu equity i długu (po tarczy) ważona udziałami rynkowymi; stopa dyskontowa dla FCFF (przepływów dla całej firmy).</li><li><strong>$K_e$</strong> (koszt kapitału własnego, *cost of equity*) — zwrot wymagany przez właścicieli, szacowany CAPM-em; stopa dla FCFE i dywidend.</li><li><strong>$K_d$</strong> (koszt długu) — efektywne oprocentowanie nowego (marginalnego) długu, liczone po tarczy jako $K_d(1-T)$; zależy od waluty finansowania.</li><li><strong>CAPM</strong> (*Capital Asset Pricing Model*) — model wyceniający $K_e$ przez stopę wolną od ryzyka plus betę razy premia rynkowa.</li><li><strong>Beta ($\\beta$)</strong> — miara ryzyka <strong>systematycznego</strong> (niedywersyfikowalnego); $\\beta = 1$ jak rynek, $&gt; 1$ ostrzej, $&lt; 1$ defensywnie.</li><li><strong>MRP</strong> (*Market Risk Premium*, premia za ryzyko rynkowe, $R_m - R_f$) — nadwyżka zwrotu rynku akcji nad stopą wolną od ryzyka (USA hist. ok. 4,5–6% [zweryfikuj]).</li><li><strong>CRP</strong> (*Country Risk Premium*, premia za ryzyko kraju) — dodatkowy zwrot za inwestowanie w kraju o wyższym ryzyku politycznym/gospodarczym, doliczany do $K_e$.</li><li><strong>Segmentacja vs integracja rynków</strong> — rynek <strong>zintegrowany</strong>: liczy się globalna beta i MRP; <strong>segmentowany</strong>: lokalna beta i MRP. Wybór reżimu zmienia same parametry CAPM.</li><li><strong>Ryzyko walutowe</strong> — dzieli się na <strong>transakcyjne</strong> (zakontraktowane przepływy), <strong>translacyjne</strong> (księgowe, konsolidacja, MSR 21) i <strong>ekonomiczne</strong> (długoterminowy wpływ kursu na konkurencyjność).</li></ul>"}, {"h": "3. Wzory i przyklad", "html": "<p>$$K_e = R_f + \\beta \\cdot (R_m - R_f) + CRP$$</p><div class=\"legend\">gdzie: $K_e$ — koszt kapitału własnego (%), $R_f$ — stopa wolna od ryzyka (% rocznie), $\\beta$ — beta (liczba bez jednostki), $(R_m - R_f)$ — premia za ryzyko rynkowe MRP (%), $CRP$ — premia za ryzyko kraju (%).</div><p>$$WACC = \\frac{E}{V} \\cdot K_e + \\frac{D}{V} \\cdot K_d \\cdot (1 - T)$$</p><div class=\"legend\">gdzie: $E$ — wartość rynkowa kapitału własnego (zł), $D$ — wartość rynkowa długu (zł), $V = E + D$ — łączna wartość firmy (zł), $K_d$ — koszt długu przed podatkiem (%), $T$ — stawka podatku (ułamek, np. 0,19).</div><p>$$CRP = \\text{spread}_{default} \\cdot \\frac{\\sigma_{akcje}}{\\sigma_{obligacje}}$$</p><div class=\"legend\">gdzie: $\\text{spread}_{default}$ — spread niewypłacalności kraju (%), $\\sigma_{akcje}$ — zmienność lokalnego rynku akcji (%), $\\sigma_{obligacje}$ — zmienność obligacji rządowych (%). Skalujemy, bo akcje są ryzykowniejsze niż dług.</div><p>$$\\beta_L = \\beta_U \\cdot \\left[1 + (1 - T) \\cdot \\frac{D}{E}\\right]$$</p><div class=\"legend\">gdzie: $\\beta_L$ — beta lewarowana (z długiem), $\\beta_U$ — beta nielewarowana (czysty biznes), $\\frac{D}{E}$ — dźwignia. To <strong>wzór Hamady</strong> — przelicza betę między poziomami zadłużenia.</div><p><strong>Przykład (rynek wschodzący).</strong> Dane: $R_f = 4{,}0\\%$; $\\beta = 1{,}2$; $MRP = 5{,}5\\%$; $CRP = 2{,}5\\%$; $K_d = 7{,}0\\%$; $T = 19\\%$; struktura $E/V = 0{,}6$, $D/V = 0{,}4$.</p><ul><li>Krok 1 — $K_e$: $\\quad 4{,}0\\% + 1{,}2 \\cdot 5{,}5\\% + 2{,}5\\% = 13{,}1\\%$</li><li>Krok 2 — koszt długu po podatku: $\\quad 7{,}0\\% \\cdot 0{,}81 = 5{,}67\\%$</li><li>Krok 3 — WACC: $\\quad 0{,}6 \\cdot 13{,}1\\% + 0{,}4 \\cdot 5{,}67\\% = 7{,}86\\% + 2{,}27\\% = 10{,}13\\%$</li></ul><p>Projekt musi zarabiać $\\geq 10{,}13\\%$ (w walucie przepływów). Bez CRP byłoby $WACC \\approx 8{,}63\\%$ — premia za kraj podniosła koszt o ok. <strong>1,5 p.p.</strong> Dla renty wieczystej $V = CF/WACC$ ta różnica obcina wartość o ok. <strong>15%</strong> ($987$ vs $1159$ mln zł przy $CF = 100$ mln) — dlatego CRP realnie decyduje o opłacalności.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Zdefiniuj koszt kapitału</strong> — wymagana stopa zwrotu = stopa dyskontowa = koszt alternatywny.</li><li><strong>Podaj wzór WACC</strong> — zaznacz: wagi rynkowe, koszt długu po tarczy podatkowej.</li><li><strong>Rozwiń $K_e$ przez CAPM</strong> — nazwij człony i podkreśl, że CAPM wycenia tylko ryzyko systematyczne (betę), nie specyficzne.</li><li><strong>Dołóż wymiar międzynarodowy</strong> — CRP (spread obligacji/CDS skorygowany relatywną zmiennością akcji), gdzie wchodzi; jedno zdanie o segmentacji vs integracji (lokalna vs globalna premia).</li><li><strong>Ryzyko walutowe</strong> — trzy rodzaje ekspozycji + zasada spójności waluty przepływów i stopy; koszt długu zależny od waluty; hedging zamiast podbijania stopy.</li><li><strong>Policz krótki przykład</strong> ($K_e$ i WACC na okrągłych liczbach) + zdanie o wpływie na wycenę DCF.</li><li><strong>Zamknij wnioskiem dwukierunkowym</strong> — wyższe ryzyko → wyższy WACC → niższa wycena; ale firma międzynarodowa bywa <strong>tańsza</strong> dzięki globalnemu kapitałowi. Wynik to bilans sił.</li></ol>"}, {"h": "5. Pulapki i gdzie komisja dociska", "html": "<ul><li><strong>Wagi księgowe zamiast rynkowych</strong> — $E$ to kapitalizacja (cena × liczba akcji), nie bilans; księgowa wartość equity bywa wielokrotnie zaniżona.</li><li><strong>Tarcza $(1-T)$ przy kapitale własnym</strong> — błąd; czynnik stosuje się tylko do $K_d$, bo dywidendy nie są kosztem uzyskania przychodu.</li><li><strong>Niespójność walutowa</strong> — przepływy EUR dyskontuj WACC-iem w EUR; przeliczenie między walutami przez parytet stóp procentowych (IRP). <strong>Gdzie komisja dociska:</strong> końcową wartość projektu przewalutuj po kursie <strong>spot</strong>, nie po stopie — stopy dyskontują w obrębie jednej waluty.</li><li><strong>Podwójne liczenie ryzyka walutowego</strong> — raz w CRP i drugi raz jako osobna „premia walutowa\" zawyża WACC; wybierz jedno albo hedging.</li><li><strong>Beta bez relewarowania</strong> — cudza $\\beta_L$ zależy od cudzego $D/E$; odlewaruj do $\\beta_U$, relewaruj do własnej dźwigni (Hamada).</li><li><strong>Gdzie komisja dociska — „czym międzynarodowa różni się od krajowej?\"</strong> — słaba odpowiedź: „jest wyższa o ryzyko kraju\". Mocna jest <strong>dwukierunkowa</strong>: w górę CRP + ryzyko waluty, w dół dostęp do tańszego globalnego kapitału; plus wątek segmentacja/integracja tłumaczący, *dlaczego* parametry się zmieniają.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<p><strong>1. Z czego składa się WACC?</strong> Z kosztu kapitału własnego $K_e$ (waga $E/V$) i kosztu długu po tarczy $K_d(1-T)$ (waga $D/V$), gdzie $V = E+D$ a wagi liczone rynkowo. W wersji międzynarodowej do $K_e$ dochodzi CRP.</p><p><strong>2. Policz WACC dla $E/V = 0{,}5$, $D/V = 0{,}5$, $K_e = 10\\%$, $K_d = 6\\%$, $T = 19\\%$.</strong> $WACC = 0{,}5 \\cdot 10\\% + 0{,}5 \\cdot 6\\% \\cdot 0{,}81 = 5\\% + 2{,}43\\% = \\mathbf{7{,}43\\%}$.</p><p><strong>3. Skąd bierze się premia za ryzyko kraju?</strong> Ze spreadu niewypłacalności kraju (rentowność jego obligacji ponad bund/treasury, lub spread CDS), skalowanego dla equity relatywną zmiennością akcji do obligacji: $CRP = \\text{spread} \\cdot \\sigma_{akcje}/\\sigma_{obligacje}$ (metoda Damodarana).</p><p><strong>4. Dlaczego do dyskontowania przepływów w EUR nie wolno użyć WACC w PLN?</strong> Bo stopa dyskontowa zawiera oczekiwaną inflację swojej waluty; mieszanie przepływów EUR ze stopą PLN daje systematyczny błąd równy różnicy inflacji obu walut.</p>"}], "probes": ["## 5. Pulapki i gdzie komisja dociska", "Niespójność walutowa — przepływy EUR dyskontuj WACC-iem w EUR; przeliczenie między walutami przez parytet stóp procentowych (IRP). Gdzie komisja dociska: końcową wartość projektu przewalutuj po kursie spot, nie po stopie — stopy dyskontują w obrębie jednej waluty.", "Gdzie komisja dociska — „czym międzynarodowa różni się od krajowej?\" — słaba odpowiedź: „jest wyższa o ryzyko kraju\". Mocna jest dwukierunkowa: w górę CRP + ryzyko waluty, w dół dostęp do tańszego globalnego kapitału; plus wątek segmentacja/integracja tłumaczący, *dlaczego* parametry się zmieniają."], "order": 18}, {"id": "t3", "group": "fib", "num": 3, "title": "Rachunkowosc bankowa (ustawa vs MSR)", "day": 6, "minutes": 22, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Instrument finansowy</strong> — umowa rodząca aktywo finansowe u jednej strony i zobowiązanie lub instrument kapitałowy u drugiej (akcje, obligacje, kredyty, depozyty).</li><li><strong>Aktywo a pasywo w banku „na opak\"</strong> — Twój depozyt to dług banku wobec Ciebie (pasywo), więc bilans banku wygląda odwrotnie niż w firmie produkcyjnej.</li><li><strong>Równanie bilansowe</strong> — suma aktywów = suma pasywów (zawsze się równa).</li><li><strong>Zasady nadrzędne rachunkowości</strong> — memoriał, ostrożność, kontynuacja działania, współmierność, treść nad formą (banki ich nie zmieniają, tylko stosują w trudniejszym otoczeniu ryzyka).</li><li><strong>Wartość pieniądza w czasie / dyskontowanie</strong> — złotówka dziś jest warta więcej niż za rok; przyszły przepływ sprowadzamy do dziś dzieląc przez $(1 + r)^{t}$.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Bank to nie zwykła firma — jego „towarem\" są pieniądze, a bilans w 80–90% to instrumenty finansowe (kredyty, depozyty, papiery). Po stronie aktywów ma głównie obietnice spłaty, których wartość zależy od przyszłości; po stronie pasywów — cudze pieniądze. Rachunkowość bankowa istnieje po to, by sprawozdanie było wiarygodne i porównywalne mimo ogromnej dźwigni i ryzyka kredytowego.</p><p><strong>Analogia (lustro odwrócone w czasie):</strong> zwykła firma to magazyn towarów, które można policzyć; bank to przeciwieństwo — aktywa to obietnice spłaty zależne od tego, co dopiero się wydarzy. Bank zarabia na różnicy między tym, czego się spodziewa, a tym, co się wydarzy. Stąd cały aparat oczekiwanej straty (ECL).</p><p>Skrót egzaminacyjny: <strong>rachunkowość bankowa = rachunkowość ogólna + nadbudowa ryzyka + wymóg nadzorczy.</strong></p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>MSR/MSSF</strong> (Międzynarodowe Standardy Rachunkowości / Sprawozdawczości Finansowej, ang. IAS/IFRS) — w UE obowiązkowe dla skonsolidowanych sprawozdań spółek notowanych, w tym banków giełdowych.</li><li><strong>MSSF 9</strong> (IFRS 9) — standard o instrumentach finansowych (od 1.01.2018); wprowadził model oczekiwanej straty kredytowej w miejsce dawnej straty poniesionej z MSR 39.</li><li><strong>ECL</strong> (ang. *Expected Credit Loss*) — oczekiwana strata kredytowa: strata, której bank spodziewa się statystycznie, zanim faktycznie nastąpi.</li><li><strong>Odpis na oczekiwane straty kredytowe</strong> — pomniejszenie wartości kredytu o spodziewaną stratę; siedzi po stronie aktywów ze znakiem minus (nie mylić z rezerwą MSR 37, która jest zobowiązaniem w pasywach).</li><li><strong>Zamortyzowany koszt</strong> (ang. *amortised cost*) — wartość rozliczana do wykupu metodą efektywnej stopy; stabilna, narasta w czasie wg EIR (typowy kredyt trzymany do spłaty).</li><li><strong>Wartość godziwa</strong> (ang. *fair value*) — cena rynkowa „tu i teraz\" za sprzedaż aktywa na dzień wyceny (MSSF 13); zmienna.</li><li><strong>SPPI</strong> (ang. *Solely Payments of Principal and Interest*) — test, czy umowne przepływy to wyłącznie spłata kapitału i odsetek; jeden z dwóch testów klasyfikacyjnych obok <strong>modelu biznesowego</strong> (sposób zarządzania portfelem: trzymanie / trzymanie i sprzedaż / handel).</li><li><strong>SICR</strong> (ang. *Significant Increase in Credit Risk*) — istotny wzrost ryzyka od ujęcia kredytu; próg przejścia ze Stage 1 do Stage 2 (mierzony zmianą PD lifetime, nie jego poziomem).</li><li><strong>PD, LGD, EAD</strong> — parametry ryzyka: <strong>PD</strong> prawdopodobieństwo defaultu, <strong>LGD</strong> strata na jednostkę ekspozycji przy defaulcie, <strong>EAD</strong> kwota „na ryzyku\" w momencie defaultu.</li><li><strong>OCI</strong> (ang. *Other Comprehensive Income*, inne całkowite dochody) — pozycje wpływające na kapitał z pominięciem rachunku wyników; wynik netto + OCI = całkowity dochód.</li><li><strong>FINREP / COREP</strong> — pakiety sprawozdawczości nadzorczej w UE: FINREP (dane finansowe wg MSSF), COREP (adekwatność kapitałowa wg CRR).</li></ul>"}, {"h": "3. Wzory i przykład", "html": "<p><strong>Wzór podstawowy ECL:</strong></p><p>$$ECL = PD \\cdot LGD \\cdot EAD$$</p><div class=\"legend\">gdzie: $PD$ — prawdopodobieństwo defaultu (ułamek, np. $0{,}02$ = 2%; 12-miesięczne dla Stage 1, lifetime dla Stage 2/3); $LGD$ — strata na jednostkę ekspozycji przy defaulcie (ułamek, $LGD = 1 - RR$, gdzie $RR$ — stopa odzysku); $EAD$ — ekspozycja w chwili defaultu (zł).</div><p><strong>Wzór ECL lifetime (dyskontowany):</strong></p><p>$$ECL_{lifetime} = \\sum_{t=1}^{T} \\frac{PD_t \\cdot LGD_t \\cdot EAD_t}{(1 + EIR)^{t}}$$</p><div class=\"legend\">gdzie: $T$ — liczba okresów do końca kredytu; $t$ — numer okresu; $PD_t$ — marginalne prawdopodobieństwo defaultu w okresie $t$ (ułamek); $EIR$ — efektywna stopa procentowa, służy do dyskontowania (ułamek); $(1 + EIR)^{t}$ — czynnik dyskontujący do dziś.</div><p><strong>Wzór odpisu Stage 3</strong> (default już zaszedł, $PD = 100\\%$):</p><p>$$ECL_{Stage\\,3} = EAD_{brutto} - \\sum_{t=1}^{T} \\frac{CF_t}{(1 + EIR)^{t}}$$</p><div class=\"legend\">gdzie: $EAD_{brutto}$ — ekspozycja brutto, kapitał + odsetki przed odpisem (zł); $CF_t$ — oczekiwany odzysk w okresie $t$ (zł).</div><p><strong>Przykład (trzy ekspozycje przez wszystkie etapy):</strong></p><p>  $$ECL = 0{,}015 \\cdot 0{,}45 \\cdot 2\\,000\\,000 = 13\\,500$$</p><p>  $$ECL = 0{,}12 \\cdot 0{,}50 \\cdot 1\\,500\\,000 = 90\\,000$$</p><p>  $$PV = \\frac{470\\,000}{1{,}09^{3}} = \\frac{470\\,000}{1{,}295029} \\approx 362\\,927$$   $$ECL = 800\\,000 - 362\\,927 = 437\\,073$$</p><ul><li><strong>ALFA — Stage 1:</strong> $EAD = 2\\,000\\,000$, $PD_{12m} = 1{,}5\\%$, $LGD = 45\\%$</li><li><strong>BETA — Stage 2 (lifetime):</strong> $EAD = 1\\,500\\,000$, $PD_{lifetime} = 12\\%$, $LGD = 50\\%$</li><li><strong>GAMMA — Stage 3:</strong> $EAD = 800\\,000$, odzysk 500 000 za 3 lata, koszty 30 000, $EIR = 9\\%$. Odzysk netto $= 470\\,000$:</li></ul><p><strong>Razem:</strong> odpis $13\\,500 + 90\\,000 + 437\\,073 = 540\\,573$ zł na ekspozycję brutto $4\\,300\\,000$ zł (pokrycie ~12,6%). Wniosek: GAMMA to ~19% portfela, ale ~81% odpisu — garstka defaultów decyduje o kosztach ryzyka. Łańcuch: wycena kredytu → odpis → wynik → kapitał (CET1).</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Specyfika banku</strong> — bilans w 80–90% to instrumenty finansowe, wysoka dźwignia, wymóg nadzorczy, wielu odbiorców sprawozdania; <strong>depozyt = pasywo banku</strong>.</li><li><strong>Dwa reżimy prawne</strong> — UoR z 1994 + rozporządzenie MF dla banków <strong>vs</strong> MSSF (obowiązek dla skonsolidowanych sprawozdań banków giełdowych — rozp. UE 1606/2002); zaznacz hierarchię.</li><li><strong>Zasady nadrzędne</strong> — wymień 4–5 (memoriał, ostrożność, kontynuacja, współmierność, treść nad formą).</li><li><strong>Elementy sprawozdania + nazewnictwo</strong> — bilans (UoR) = sprawozdanie z sytuacji finansowej (MSR 1); P&amp;L wchodzi w sprawozdanie z całkowitych dochodów (obok OCI); układ pozycji banku (należności od klientów, depozyty, wynik odsetkowy).</li><li><strong>Sedno MSSF 9</strong> — model oczekiwanej straty (ECL, 3 stage, forward-looking) zamiast straty poniesionej MSR 39; geneza: kryzys 2008, „too little, too late\".</li><li><strong>Wzór</strong> $ECL = PD \\cdot LGD \\cdot EAD$ z krótkim przykładem (np. 8 000 zł przy 1 mln × 2% × 40%).</li><li><strong>Instytucje</strong> — KNF (nadzór), NBP (sprawozdawczość FINREP/COREP), biegły rewident (audyt), BFG (gwarancje depozytów + resolution); rozróżnij nadzór od audytu.</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Strata poniesiona vs oczekiwana</strong> — MSR 39 = *incurred* (strata musiała już zaistnieć); MSSF 9 = *expected* z wyprzedzeniem. To istota reformy po 2008.</li><li><strong>Pomijanie dyskonta w Stage 3</strong> — odpis to brutto minus *zdyskontowana* (po EIR) wartość odzysków, nie nominalny niedobór; pominięcie zaniża stratę.</li><li><strong>Mylenie OCI z wynikiem</strong> — przeszacowanie FVOCI nie przechodzi przez P&amp;L, ląduje w kapitale; zysk netto ≠ całkowity dochód.</li><li><strong>Depozyt jako aktywo banku</strong> — najczęstszy błąd „od zera\"; depozyt to zobowiązanie banku, aktywem stają się dopiero kredyty z tych środków.</li><li><strong>Gdzie komisja dociska:</strong> *„Czy bank z GPW może raportować tylko po UoR?\"* — nie, skonsolidowane obowiązkowo MSSF; dodaj, że UoR jest bardziej regułowa, a MSSF bardziej oparte na osądzie i wartości godziwej (bank giełdowy prowadzi de facto dwa ujęcia).</li><li><strong>Gdzie komisja dociska:</strong> *„Dlaczego ECL, a nie strata poniesiona?\"* — stary model reagował za późno; hasło „too little, too late\" i procykliczność dają punkt za kontekst. Pamiętaj o efekcie klifu na progu SICR (Stage 1 → 2 zwielokrotnia odpis, choć klient nie spóźnił się z ratą).</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<p><strong>1. Dlaczego depozyt to pasywo banku?</strong> Bo deponent powierza bankowi pieniądze, które bank musi oddać (na żądanie lub w terminie) — to dług banku, a nie majątek. Aktywem stają się dopiero kredyty udzielone z tych środków.</p><p><strong>2. Czym różni się zamortyzowany koszt od wartości godziwej?</strong> Zamortyzowany koszt to wartość rozliczana do wykupu metodą efektywnej stopy — stabilna, dla instrumentów trzymanych dla przepływów (typowy kredyt). Wartość godziwa to zmienna cena rynkowa „tu i teraz\", dla instrumentów do obrotu/sprzedaży (zmiany przez wynik FVTPL albo przez kapitał FVOCI).</p><p><strong>3. Co to model ECL?</strong> Model oczekiwanych strat kredytowych z MSSF 9 — bank zawiązuje odpisy z wyprzedzeniem. Trzy etapy: Stage 1 (ECL 12-miesięczny, ekspozycja zdrowa), Stage 2 (ECL lifetime po istotnym wzroście ryzyka SICR), Stage 3 (default). Wzór $ECL = PD \\cdot LGD \\cdot EAD$. Zastąpił model straty poniesionej, który reagował za późno.</p><p><strong>4. Jakie są podstawy prawne rachunkowości bankowej?</strong> Trzy warstwy: (1) UoR z 1994 — rama prawa bilansowego, obejmuje banki (art. 2); (2) rozporządzenie MF o szczególnych zasadach rachunkowości banków [zweryfikuj akt na isap.sejm.gov.pl]; (3) MSR/MSSF — obowiązkowe dla skonsolidowanych sprawozdań banków giełdowych (rozp. UE 1606/2002), kluczowy MSSF 9. Dla skonsolidowanego sprawozdania banku giełdowego MSSF ma prymat w ujęciu i wycenie; UoR reguluje kwestie formalno-proceduralne.</p>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: *„Czy bank z GPW może raportować tylko po UoR?\"* — nie, skonsolidowane obowiązkowo MSSF; dodaj, że UoR jest bardziej regułowa, a MSSF bardziej oparte na osądzie i wartości godziwej (bank giełdowy prowadzi de facto dwa ujęcia).", "Gdzie komisja dociska: *„Dlaczego ECL, a nie strata poniesiona?\"* — stary model reagował za późno; hasło „too little, too late\" i procykliczność dają punkt za kontekst. Pamiętaj o efekcie klifu na progu SICR (Stage 1 → 2 zwielokrotnia odpis, choć klient nie spóźnił się z ratą)."], "order": 19}, {"id": "t4", "group": "fib", "num": 4, "title": "Analiza techniczna", "day": 6, "minutes": 20, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Świeca japońska</strong> zapisuje cztery liczby sesji: <strong>O</strong> (otwarcie), <strong>H</strong> (maksimum), <strong>L</strong> (minimum), <strong>C</strong> (zamknięcie) — wszystkie w zł.</li><li><strong>Wolumen</strong> to liczba walorów (obrót) w danym okresie — miara zaangażowania kapitału za ruchem ceny.</li><li><strong>Trend</strong> to dominujący kierunek ceny, definiowany przez strukturę szczytów i dołków (nie przez „wrażenie\").</li><li><strong>Średnia arytmetyczna</strong> i <strong>odchylenie standardowe</strong> ($\\sigma$) — bazowa statystyka pod średnie ruchome i Wstęgi Bollingera.</li><li><strong>Trzy podejścia do rynku:</strong> fundamentalne (bada firmę), techniczne (bada wykres), ilościowe/quant (testuje reguły) — AT jest jednym z trzech.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Analiza techniczna zakłada, że wszystko, co warto wiedzieć o spółce, jest już zawarte w cenie — więc badamy sam wykres ceny i wolumenu, by znaleźć trend oraz moment wejścia i wyjścia. AT nie przewiduje przyszłości; daje tylko przewagę probabilistyczną z powtarzalnych układów popytu i podaży. To narzędzie *timingu* (KIEDY), a fundamentalna to narzędzie *wyceny* (ILE) — są komplementarne. <strong>Analogia: wykres to termometr nastrojów tłumu</strong> — pokazuje temperaturę starcia popytu i podaży, ostrzega kiedy działać, ale sam nie leczy.</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Analiza techniczna (AT)</strong> — prognozowanie cen z historycznych danych o cenie i wolumenie; ignoruje fundamenty, bo zakłada że są już w cenie.</li><li><strong>Analiza fundamentalna (FA)</strong> — szacuje wartość wewnętrzną spółki ze sprawozdań; AT bada *cenę*, FA — *wartość*.</li><li><strong>Trend</strong> — kierunek ceny: wzrostowy (coraz wyższe szczyty i dołki), spadkowy (coraz niższe), boczny (konsolidacja).</li><li><strong>Wsparcie / opór</strong> — poziom, gdzie popyt zatrzymuje spadki / podaż zatrzymuje wzrosty; po przebiciu zamieniają się rolami.</li><li><strong>LOP (liczba otwartych pozycji, *open interest*)</strong> — liczba nierozliczonych kontraktów na rynku pochodnych; rosnący LOP potwierdza napływ kapitału.</li><li><strong>Wskaźnik (indicator)</strong> — dowolna wartość liczona z ceny lub wolumenu (SMA, RSI, OBV) — pojęcie najszersze.</li><li><strong>Oscylator</strong> — podzbiór wskaźników wahający się w ograniczonym przedziale, mierzy momentum i wykupienie/wyprzedanie (każdy oscylator jest wskaźnikiem, nie odwrotnie).</li><li><strong>Momentum (pęd)</strong> — tempo zmiany ceny; spadające momentum przy rosnącej cenie ostrzega, że trend się męczy.</li><li><strong>Dywergencja</strong> — rozbieżność kierunku ceny i oscylatora; sygnał ostrzegawczy przed odwróceniem.</li><li><strong>Lag (opóźnienie)</strong> — wskaźniki z przeszłych cen reagują *po* zmianie ceny, nie przed — kluczowe ograniczenie AT.</li></ul>"}, {"h": "3. Wzory i przykład", "html": "<p><strong>SMA — prosta średnia ruchoma:</strong> $$SMA_n = \\frac{P_1 + P_2 + \\dots + P_n}{n}$$</p><div class=\"legend\">gdzie: $SMA_n$ — średnia z $n$ okresów (zł); $P_i$ — cena zamknięcia okresu (zł); $n$ — liczba sesji w oknie. (Przecięcie $SMA_{50}$ i $SMA_{200}$ od dołu = złoty krzyż / od góry = krzyż śmierci.)</div><p><strong>RSI — wskaźnik siły względnej:</strong> $$RSI = 100 - \\frac{100}{1 + RS}, \\qquad RS = \\frac{\\overline{U}}{\\overline{D}}$$</p><div class=\"legend\">gdzie: $RSI$ — skala 0–100; $RS$ — siła względna; $\\overline{U}$ — średni wzrost (zł); $\\overline{D}$ — średni spadek (zł). Progi: &gt;70 wykupienie, &lt;30 wyprzedanie, 50 = równowaga.</div><p><strong>Wstęgi Bollingera:</strong> $$gorna = SMA_n + k\\sigma, \\qquad dolna = SMA_n - k\\sigma$$</p><div class=\"legend\">gdzie: $SMA_n$ — wstęga środkowa (zł); $\\sigma$ — odchylenie standardowe cen (zł); $k$ — mnożnik, standardowo $k = 2$, $n = 20$.</div><p><strong>Przykład (RSI krok po kroku).</strong> W oknie 14 sesji: 9 sesji wzrostowych o łącznej zmianie $+14{,}0$ zł i 5 spadkowych o $-3{,}5$ zł. $$\\overline{U} = \\frac{14{,}0}{14} = 1{,}00 \\qquad \\overline{D} = \\frac{3{,}5}{14} = 0{,}25$$ $$RS = \\frac{1{,}00}{0{,}25} = 4{,}0 \\quad\\Rightarrow\\quad RSI = 100 - \\frac{100}{1 + 4} = 100 - 20 = 80{,}0$$ RSI = 80 → strefa silnego wykupienia (próg 70): trend rozgrzany, rośnie ryzyko korekty — ale w mocnym trendzie RSI potrafi tkwić powyżej 70 tygodniami.</p><p><strong>Dla zapamiętania (zarządzanie ryzykiem):</strong> stop-loss ustawia się np. $1{,}5 \\cdot ATR$ poniżej wejścia, a wielkość pozycji = (dopuszczalna strata, np. 2% kapitału) / (ryzyko na akcję). Przy trafności 40%, zysku 18 zł i stracie 6 zł: $EV = 0{,}40 \\cdot 18 + 0{,}60 \\cdot (-6) = +3{,}60$ zł/akcję — <strong>przewaga bierze się z asymetrii zysk/strata, nie z trafiania</strong>.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Definicja AT</strong> + odróżnienie od FA (AT = cena i wolumen, timing; FA = sprawozdania, wartość).</li><li><strong>Trzy filary teorii Dowa:</strong> cena dyskontuje wszystko / ceny poruszają się w trendach / historia się powtarza (powtarzalna psychologia tłumu).</li><li><strong>Wskaźniki pogrupowane:</strong> trendu (SMA, EMA — złoty krzyż), momentum (RSI 30/70, MACD), zmienności (Bollinger $\\pm 2\\sigma$, ATR), wolumenu (OBV).</li><li><strong>Formacje pogrupowane:</strong> odwrócenia (głowa z ramionami, podwójny szczyt/dno), kontynuacji (flagi, trójkąty), świecowe (młot, doji, objęcie).</li><li><strong>Zarządzanie ryzykiem:</strong> stop-loss, position sizing, stosunek zysk/ryzyko, dodatnia wartość oczekiwana z asymetrii.</li><li><strong>Krytyka:</strong> lag, fałszywe sygnały w rynku bocznym (whipsaws), konflikt z hipotezą rynku efektywnego (forma słaba).</li><li><strong>Polskie realia:</strong> GPW, nadzór KNF, reżim MAR (zakaz manipulacji kursem).</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>„Wskaźniki przewidują przyszłość\".</strong> Błąd — są liczone z przeszłych cen, więc spóźnione (lagging); mówimy o przewadze probabilistycznej, nie prognozie pewnej.</li><li><strong>„RSI &gt; 70 = automatyczna sprzedaż\".</strong> W silnym trendzie RSI tkwi powyżej 70 tygodniami; to sygnał uwagi w kontekście trendu, a dywergencja jest mocniejsza niż samo przekroczenie progu.</li><li><strong>Mylenie formacji odwrócenia z kontynuacją</strong> — flagi i trójkąty to kontynuacja; głowa z ramionami i podwójny szczyt to odwrócenie.</li><li><strong>Ignorowanie wolumenu</strong> — wybicie bez wolumenu jest niewiarygodne (często *fakeout*); potwierdzeniem jest skok wolumenu.</li><li><strong>Gdzie komisja dociska (konflikt z EMH):</strong> najważniejszy zarzut wobec AT to <strong>słaba forma hipotezy rynku efektywnego</strong> — skoro cała informacja z przeszłych cen jest już w cenie, AT (bazująca wyłącznie na przeszłych cenach) nie powinna dawać trwałej przewagi. To *słaba* forma (nie półsilna/silna). AT odpowiada finansami behawioralnymi.</li><li><strong>Gdzie komisja dociska (krytyka metodologiczna):</strong> formacje bywają rozpoznawane „po fakcie\", trudno je obiektywnie zdefiniować i przetestować — zarzut o brak falsyfikowalności. Uczciwe przyznanie tej słabości podnosi ocenę.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ol><li><strong>Wymień 3 założenia analizy technicznej.</strong> Cena dyskontuje wszystko (informacja jest już w cenie); ceny poruszają się w trendach (mają kierunek i trwają, dopóki się nie odwrócą); historia się powtarza (bo powtarza się psychologia inwestorów) — to trzy aksjomaty teorii Dowa.</li></ol><ol><li><strong>Czym formacja odwrócenia różni się od kontynuacji?</strong> Odwrócenia kończą dotychczasowy trend i zmieniają kierunek (głowa z ramionami, podwójny szczyt/dno); kontynuacji to przystanek „na oddech\" w trwającym trendzie (flagi, trójkąty), który z definicji zakłada wcześniejszy trend.</li></ol><ol><li><strong>Co mierzy RSI i co znaczą poziomy 30/70?</strong> RSI mierzy momentum, normalizując stosunek średnich wzrostów do spadków do skali 0–100 ($RSI = 100 - 100/(1+RS)$). Umownie &gt;70 = wykupienie, &lt;30 = wyprzedanie, 50 = linia podziału; progi są umowne i czyta się je w kontekście trendu.</li></ol><ol><li><strong>Czy AT da się pogodzić z hipotezą rynku efektywnego?</strong> W formie słabej EMH — nie: skoro cała informacja z przeszłych cen jest już w cenie, AT nie powinna dawać trwałej przewagi (najważniejszy zarzut). Pogodzenie możliwe tylko, gdy rynek nie jest w pełni efektywny — co uzasadniają finanse behawioralne (powtarzalne błędy poznawcze tłumu) i samospełniająca się przepowiednia; rynki mniej płynne jak GPW bywają uznawane za mniej efektywne [zweryfikuj].</li></ol>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska (konflikt z EMH): najważniejszy zarzut wobec AT to słaba forma hipotezy rynku efektywnego — skoro cała informacja z przeszłych cen jest już w cenie, AT (bazująca wyłącznie na przeszłych cenach) nie powinna dawać trwałej przewagi. To *słaba* forma (nie półsilna/silna). AT odpowiada finansami behawioralnymi.", "Gdzie komisja dociska (krytyka metodologiczna): formacje bywają rozpoznawane „po fakcie\", trudno je obiektywnie zdefiniować i przetestować — zarzut o brak falsyfikowalności. Uczciwe przyznanie tej słabości podnosi ocenę."], "order": 20}, {"id": "t6", "group": "fib", "num": 6, "title": "Produkty i uslugi bankowe", "day": 6, "minutes": 18, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Operacja bankowa</strong> — czynność banku tworząca stosunek prawny (prawa i obowiązki) z klientem.</li><li><strong>Bilans banku:</strong> aktywa = co bank ma i co mu „pracuje\" (kredyty); pasywa = skąd ma pieniądze (depozyty, kapitał).</li><li><strong>Depozyt jest dla banku tani, kredyt drogi</strong> — bank żyje z różnicy (zalążek marży odsetkowej).</li><li><strong>Pieniądz gotówkowy</strong> (fizyczne banknoty/monety) vs <strong>bezgotówkowy</strong> (zapis na rachunku przesuwany przelewem/kartą) — dwa różne światy ryzyka.</li><li><strong>Emisja</strong> = pozyskanie kapitału przez sprzedaż akcji/obligacji inwestorom; bank może w niej pośredniczyć i ją gwarantować.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Bank to nie sejf, lecz <strong>pośrednik finansowy</strong>: „kupuje\" płynność od deponentów (płaci niskie oprocentowanie depozytu) i „sprzedaje\" ją kredytobiorcom (pobiera wyższe oprocentowanie kredytu). Różnica — <strong>marża odsetkowa</strong> — to jego wynagrodzenie za transformację terminu, wielkości i ryzyka. Pytając „o produkty\", komisja w istocie sprawdza, czy rozumiesz logikę bilansu banku. <strong>Analogia: bank jest hurtownią płynności w czasie — kupuje tanio, sprzedaje drożej, a różnica to cena za zdjęcie z klienta ryzyka.</strong></p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Operacje bierne (pasywne)</strong> — gromadzenie środków; bank jest <strong>dłużnikiem</strong> klienta (lokaty, rachunki, emisja własnych papierów); po stronie pasywów.</li><li><strong>Operacje czynne (aktywne)</strong> — wykorzystanie środków; bank jest <strong>wierzycielem</strong> (kredyty, pożyczki, gwarancje); po stronie aktywów.</li><li><strong>Operacje pośredniczące</strong> — przepływ pieniędzy za prowizję, neutralne bilansowo (przelewy, karty, wymiana walut, usługi inwestycyjne).</li><li><strong>Produkt bankowy</strong> — wystandaryzowana, powtarzalna oferta zostawiająca ślad w bilansie (kredyt, lokata, karta).</li><li><strong>Usługa bankowa</strong> — czynność na zlecenie klienta dająca zwykle dochód prowizyjny (rozliczenia, doradztwo, przechowanie).</li><li><strong>Czynności bankowe</strong> — kategoria prawna: <strong>sensu stricto</strong> (art. 5 ust. 1 — zastrzeżone dla banków: wkłady, rachunki, kredyty, gwarancje, e-pieniądz) i <strong>sensu largo</strong> (art. 5 ust. 2 — bankowe tylko, gdy wykonuje je bank: pożyczki, karty, nabywanie wierzytelności).</li><li><strong>Pieniądz elektroniczny</strong> — przedpłacona wartość przechowywana elektronicznie, wydana w zamian za środki, akceptowana przez podmioty inne niż wydawca, z obowiązkiem wykupu po nominale (EMD2; ustawa o usługach płatniczych [zweryfikuj akt]).</li><li><strong>SCA</strong> (*Strong Customer Authentication*, silne uwierzytelnianie) — wymóg <strong>PSD2</strong>: co najmniej <strong>dwa z trzech</strong> niezależnych elementów (wiedza / posiadanie / cecha).</li><li><strong>Underwriting (gwarantowanie emisji)</strong> — organizacja emisji + zobowiązanie do objęcia papierów; <strong>subemisja inwestycyjna</strong> (bank obejmuje resztę nieobjętą) lub <strong>usługowa</strong> (obejmuje całość i odsprzedaje).</li><li><strong>NIM</strong> (*Net Interest Margin*, marża odsetkowa netto) — relacja wyniku odsetkowego do średnich aktywów pracujących; główna miara rentowności pośrednictwa.</li></ul>"}, {"h": "3. Wzory i przykład", "html": "<p><strong>Opłata za zarządzanie (management fee):</strong> $$Oplata = WAN \\cdot s \\cdot \\frac{d}{365}$$</p><div class=\"legend\">gdzie: $WAN$ — wartość portfela klienta (zł); $s$ — stawka roczna (ułamek, np. 1,5% = 0,015); $d$ — liczba dni naliczania (dni); $365$ — rok bazowy (actual/365).</div><p><strong>Marża odsetkowa netto:</strong> $$NIM = \\frac{przychody\\ odsetkowe - koszty\\ odsetkowe}{A}$$</p><div class=\"legend\">gdzie: licznik — wynik odsetkowy (zł); $A$ — średnie aktywa pracujące generujące odsetki (zł); wynik w %.</div><p><strong>Skuteczność dwóch składników SCA (czynniki niezależne):</strong> $$P_{atak} = p_1 \\cdot p_2$$</p><div class=\"legend\">gdzie: $P_{atak}$ — prawdopodobieństwo złamania obu naraz (0–1); $p_1, p_2$ — prawdopodobieństwa złamania każdego czynnika. Dla $p_1 = p_2 = 0{,}01$: $P_{atak} = 0{,}0001$ → ryzyko spada 100-krotnie.</div><p><strong>Przykład — NIM:</strong> bank ma średnie aktywa pracujące $A = 10$ mld zł, przychody odsetkowe $600$ mln zł, koszty odsetkowe $250$ mln zł.</p><ol><li>Wynik odsetkowy: $600 - 250 = 350$ mln zł.</li><li>$NIM = \\frac{350\\,000\\,000}{10\\,000\\,000\\,000} = 0{,}035 = 3{,}5\\%$.</li></ol><p><strong>Wynik:</strong> na każdej złotówce aktywów pracujących bank zarabia 3,5 gr rocznie — liczbowa odpowiedź na „skąd zysk banku\".</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Otwórz porządkiem ze skryptu:</strong> bank robi trzy rzeczy — gromadzi (bierne), pożycza (czynne), pośredniczy (pośredniczące) + usługi inwestycyjne.</li><li><strong>Produkt vs usługa</strong> + zakotwiczenie prawne: czynności bankowe sensu stricto/largo (art. 5–6 Prawa bankowego); sensu largo zależy od podmiotu.</li><li><strong>Klasyfikacja wg bilansu</strong> z logiką: czynne (należność, bank wierzycielem) / bierne (zobowiązanie, bank dłużnikiem) / pośredniczące (prowizja).</li><li><strong>Skąd zysk banku:</strong> marża odsetkowa (czynne drogie − bierne tanie) + prowizje z pośredniczących.</li><li><strong>Pieniądz elektroniczny:</strong> trzy cechy, mechanizm emisja–płatność–wykup po nominale, różnica vs ROR (BFG vs brak BFG / segregacja).</li><li><strong>Bezpieczeństwo:</strong> osobno gotówkowy (zabezpieczenia banknotów, AML) i bezgotówkowy (ELIXIR/SWIFT, SCA z PSD2, tokenizacja) — bo dwie różne logiki ryzyka.</li><li><strong>Usługi inwestycyjne:</strong> drabina doradztwo → zarządzanie → underwriting; subemisja inwestycyjna vs usługowa. Zamknij wzmianką o KNF, NBP, BFG, CRR/Bazylea III.</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> „skąd zysk banku?\" — odpowiedz: głównie różnica oprocentowania (wynik odsetkowy/marża) plus prowizje. Sama lista produktów bez wskazania zysku traci najwyżej punktowaną pointę.</li><li><strong>Gdzie komisja dociska:</strong> „e-pieniądz ≠ depozyt\" — trzy słowa-klucze: <strong>przedpłacona wartość</strong>, u <strong>instytucji pieniądza elektronicznego</strong>, <strong>bez gwarancji BFG</strong> (ochrona przez segregację, nie fundusz). E-pieniądz jest też nieoprocentowany.</li><li><strong>Gdzie komisja dociska:</strong> subemisja inwestycyjna (bank obejmuje resztę nieobjętą) vs usługowa (obejmuje całość i odsprzedaje) — różnica nie w wyniku, lecz w <strong>ekspozycji kapitałowej</strong> (np. 3 mln vs 20 mln zł); underwriting = przejęcie ryzyka nieuplasowania za prowizję, bank może wyjść na minus.</li><li><strong>Nie myl „czynne\" z aktywnością klienta</strong> — „czynne\" odnosi się do banku (bank wierzycielem); kredyt = czynna. Przyporządkowanie kredytu do biernych to sygnał, że mylisz stronę bilansu.</li><li><strong>Asset management ≠ doradztwo:</strong> w zarządzaniu decyduje zarządzający (mandat, *suitability*), w doradztwie decyduje klient.</li><li><strong>SCA nie gwarantuje pełnego bezpieczeństwa:</strong> chroni przed przejęciem tożsamości, ale nie przed oszustwem socjotechnicznym (ofiara sama autoryzuje przelew); ma też wyłączenia (niskie kwoty, TRA).</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<p>   Lokata = bierna (bank dłużnikiem); kredyt = czynna (bank wierzycielem); przelew = pośrednicząca (prowizja, neutralny bilansowo).</p><ol><li><strong>Przyporządkuj do bierne/czynne/pośredniczące: lokata, kredyt, przelew.</strong></li></ol><p>   Organizacja emisji + zobowiązanie do objęcia papierów. Subemisja inwestycyjna — bank obejmuje papiery nieobjęte przez inwestorów; usługowa — obejmuje całość i odsprzedaje (większa ekspozycja kapitałowa). Istota: za prowizję przejmuje ryzyko nieuplasowania.</p><ol><li><strong>Co to underwriting emisji?</strong></li></ol><p>   E-pieniądz to przedpłacona wartość u IPE, z wykupem po nominale, chroniona segregacją, nieoprocentowana, bez BFG. Depozyt to roszczenie wobec banku, którym bank obraca w rezerwie cząstkowej, oprocentowane i objęte gwarancjami BFG.</p><ol><li><strong>Czym e-pieniądz różni się od depozytu?</strong></li></ol><p>   Głównie z marży odsetkowej (oprocentowanie kredytów wyższe niż depozytów → wynik odsetkowy) oraz z prowizji za operacje pośredniczące — stabilnego, nieobciążającego kapitału ryzykiem kredytowym filaru dochodu.</p><ol><li><strong>Skąd pochodzi zysk banku?</strong></li></ol>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: „skąd zysk banku?\" — odpowiedz: głównie różnica oprocentowania (wynik odsetkowy/marża) plus prowizje. Sama lista produktów bez wskazania zysku traci najwyżej punktowaną pointę.", "Gdzie komisja dociska: „e-pieniądz ≠ depozyt\" — trzy słowa-klucze: przedpłacona wartość, u instytucji pieniądza elektronicznego, bez gwarancji BFG (ochrona przez segregację, nie fundusz). E-pieniądz jest też nieoprocentowany.", "Gdzie komisja dociska: subemisja inwestycyjna (bank obejmuje resztę nieobjętą) vs usługowa (obejmuje całość i odsprzedaje) — różnica nie w wyniku, lecz w ekspozycji kapitałowej (np. 3 mln vs 20 mln zł); underwriting = przejęcie ryzyka nieuplasowania za prowizję, bank może wyjść na minus."], "order": 21}, {"id": "t8", "group": "fib", "num": 8, "title": "Rachunkowosc zarzadcza i controlling", "day": 6, "minutes": 22, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Koszt</strong> to memoriałowe (w chwili zużycia) zużycie zasobów; <strong>wydatek</strong> to kasowy rozchód pieniądza — bywają w innym czasie (amortyzacja = koszt bez wydatku).</li><li><strong>Koszt stały</strong> nie zależy od wielkości produkcji (czynsz), <strong>zmienny</strong> rośnie z produkcją (materiały bezpośrednie).</li><li><strong>Koszt bezpośredni</strong> przypiszesz wprost do produktu, <strong>pośredni</strong> wymaga klucza rozliczeniowego.</li><li>Przychód = cena $\\times$ ilość; wynik = przychód $-$ koszty całkowite (z tego wyprowadza się próg rentowności).</li><li><strong>Sprawozdanie finansowe</strong> = bilans (stan na dzień) + RZiS (wynik za okres) + rachunek przepływów pieniężnych.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Firma nie ma jednej prawdy o kosztach — ma kilka obrazów tej samej rzeczywistości, każdy pod inne pytanie: finansowa odpowiada „ile było?\", zarządcza „co się opłaca?\", controlling „czy idziemy zgodnie z planem?\". Dlatego ten sam koszt bywa raz „pełny\" (do bilansu), raz „zmienny\" (do decyzji) — to skryptowe <strong>„ta sama liczba, inny cel\"</strong>. Najlepsza analogia: rachunkowość finansowa to <strong>lusterko wsteczne</strong> (droga przebyta, dla banku i fiskusa), a controlling to <strong>autopilot z czujnikiem odchylenia</strong> — controller jest nawigatorem, nie kapitanem ani policjantem.</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Rachunkowość finansowa</strong> — obligatoryjny, regulowany (ustawa o rachunkowości / MSR-MSSF) system ewidencji dla odbiorców zewnętrznych; wyłącznie miernik pieniężny, dane historyczne.</li><li><strong>Rachunkowość zarządcza</strong> — wewnętrzny, fakultatywny (dobrowolny) system informacji pod decyzje menedżerskie; nieregulowana, zorientowana na przyszłość, używa też danych niepieniężnych.</li><li><strong>Controlling</strong> — proces koordynacji <strong>planowania, sterowania i kontroli</strong> oraz zasilania w informacje; strategiczny („robić właściwe rzeczy\") vs operacyjny („robić rzeczy właściwie\").</li><li><strong>Controlling finansowy</strong> — odmiana skupiona na <strong>płynności, wyniku, strukturze kapitału, rentowności</strong> (cash flow, EBIT, ROI), obejmuje budżetowanie, analizę odchyleń, KPI i sprawozdania pro forma.</li><li><strong>Rachunek kosztów</strong> — system gromadzenia i kalkulacji kosztów w przekrojach: rodzajowym, miejsc powstawania (<strong>MPK</strong>), nośników/produktów.</li><li><strong>Marża pokrycia</strong> (contribution margin) — cena $-$ koszt zmienny jednostkowy; ile sztuka „dokłada\" na koszty stałe i zysk.</li><li><strong>Próg rentowności (BEP)</strong> — wielkość sprzedaży, przy której wynik = 0 (to NIE punkt maksymalnego zysku).</li><li><strong>Margines bezpieczeństwa</strong> — o ile sprzedaż może spaść względem planu, zanim pojawi się strata.</li><li><strong>Odchylenie (variance)</strong> — różnica plan/standard a rzeczywistość; rozkładana na część cenową i ilościową.</li><li><strong>Koszt utopiony</strong> (sunk) — już poniesiony, w decyzji ignorowany; <strong>koszt utraconych korzyści</strong> (opportunity) — wartość najlepszej odrzuconej alternatywy, w decyzji uwzględniany.</li><li><strong>Koszt istotny (relevant)</strong> — taki, który różni się między wariantami i jest przyszły; tylko on wchodzi do rachunku decyzyjnego.</li></ul>"}, {"h": "3. Wzory i przykład", "html": "<p><strong>Wynik:</strong> $$Wynik = (c - kz) \\cdot Q - KS$$</p><div class=\"legend\">gdzie: $c$ — cena jednostkowa (zł/szt.), $kz$ — koszt zmienny jednostkowy (zł/szt.), $Q$ — ilość (szt.), $KS$ — koszty stałe okresu (zł).</div><p><strong>Próg rentowności (ilościowy):</strong> $$Q^{*} = \\frac{KS}{mj}$$</p><div class=\"legend\">gdzie: $mj = c - kz$ — marża pokrycia jednostkowa (zł/szt.), $KS$ — koszty stałe (zł), $Q^{*}$ — próg w sztukach (szt.).</div><p><strong>Ilość przy zysku docelowym</strong> $Z$: $$Q_{Z} = \\frac{KS + Z}{mj}$$</p><div class=\"legend\">gdzie: $Z$ — docelowy zysk operacyjny (zł), pozostałe jak wyżej.</div><p><strong>Różnica wyniku: koszt pełny vs zmienny:</strong> $$Roznica = \\Delta Zapas \\cdot ks_{prod}$$</p><div class=\"legend\">gdzie: $\\Delta Zapas$ — zmiana zapasu wyrobów (produkcja $-$ sprzedaż, szt.), $ks_{prod}$ — stały koszt produkcji na jednostkę (zł/szt.).</div><p><strong>Przykład (próg rentowności + margines):</strong> $c = 50$ zł, $kz = 30$ zł, $KS = 100\\,000$ zł, plan $Q = 8\\,000$ szt.</p><ul><li>Marża: $mj = 50 - 30 = 20$ zł/szt.</li><li>BEP ilościowy: $Q^{*} = 100\\,000 / 20 = 5\\,000$ szt.</li><li>BEP wartościowy: $5\\,000 \\times 50 = 250\\,000$ zł.</li><li>Wynik przy planie: $20 \\times 8\\,000 - 100\\,000 = 60\\,000$ zł zysku.</li><li>Margines bezpieczeństwa: $(8\\,000 - 5\\,000)/8\\,000 = 37{,}5\\%$.</li></ul><p><strong>Przykład (decyzja brzegowa — cena specjalna):</strong> firma ma moce 12 000 szt., sprzedaje 8 000. Zapytanie na 3 000 szt. po 35 zł. Koszt pełny = $30 + 100\\,000/8\\,000 = 42{,}5$ zł — wygląda na stratę, ale to pułapka. Koszty stałe i tak ponosimy; jest wolna moc, więc liczy się tylko marża: $35 - 30 = 5$ zł $\\times 3\\,000 = +15\\,000$ zł. <strong>Decyzja: przyjąć</strong> (zysk rośnie z 60 000 do 75 000 zł). Cena progowa = koszt zmienny 30 zł. Bez wolnych mocy dodaj koszt utraconych korzyści ($mj = 20$ zł) → próg rośnie do 50 zł.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Postaw oś:</strong> finansowa = na zewnątrz/wstecz/obligatoryjna; zarządcza = do wewnątrz/w przód/fakultatywna. Uzasadnij *dlaczego* (zewnętrzny odbiorca → porównywalność → sztywność).</li><li><strong>Umieść controlling</strong> jako spinacz: pętla plan–wykonanie–pomiar–odchylenia–korekta; controller = nawigator; podział strategiczny/operacyjny.</li><li><strong>Controlling finansowy</strong> — płynność, wynik, struktura kapitału, budżetowanie, KPI, sprawozdania pro forma.</li><li><strong>Rachunek kosztów</strong> — układy rodzajowy/MPK/nośniki + para <strong>pełne vs zmienne</strong> (sprawozdanie vs decyzja).</li><li><strong>Pokaż ilościowo</strong> — policz marżę i BEP albo rozbij odchylenie na cenowe/ilościowe; jak starczy czasu, dorzuć decyzję cenową przy wolnych mocach.</li><li><strong>Planowanie sprawozdań</strong> — pro forma RZiS/bilans/cash flow, serce = <strong>budżet gotówki</strong> (memoriał ≠ kasa).</li><li><strong>Regulacje</strong> — ustawa o rachunkowości (finansowa), brak regulacji dla zarządczej, MSR 2 przy wycenie zapasów.</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Nie myl „pełne/zmienne\" ze „stałe/zmienne\"</strong> — pierwsze to *systemy rachunku kosztów* (sposób przypisania), drugie to *rodzaje kosztów* (reakcja na wolumen). To różne poziomy pojęciowe.</li><li><strong>Nie myl „bezpośredni/pośredni\" ze „stały/zmienny\"</strong> — niezależne wymiary; amortyzacja maszyny dedykowanej jest bezpośrednia i stała.</li><li><strong>BEP to nie punkt maksymalnego zysku</strong>, tylko zerowego wyniku.</li><li>Gdzie komisja dociska: *„ta sama liczba, inny cel\"* — koszt jednostkowy pełny (do bilansu) różni się od zmiennego (do decyzji); zawsze pytaj „do czego liczę?\".</li><li>Gdzie komisja dociska: *„controlling to nie kontrola\"* — to sterowanie z wyprzedzeniem w pętli, a kontrola to tylko jeden jego element; controller koryguje kurs, nie audytuje przeszłości.</li><li>Gdzie komisja dociska: w odchyleniach *„czemu cenowe liczycie ilością rzeczywistą, a ilościowe ceną standardową?\"* — by odizolować efekty i nie policzyć podwójnie odchylenia łącznego cena×ilość. Przy cash budżecie: amortyzacji NIE wpisujemy (koszt bezgotówkowy).</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ol><li><strong>Czym różni się rachunkowość finansowa od zarządczej?</strong> Finansowa: obligatoryjna, regulowana, na zewnątrz, wstecz, tylko pieniądz; zarządcza: fakultatywna, nieregulowana, do wewnątrz, w przód, też dane niepieniężne — wybiera trafność i szybkość zamiast maksymalnej precyzji.</li><li><strong>Dlaczego wynik różni się między kosztem pełnym a zmiennym?</strong> Bo gdy produkcja &gt; sprzedaży, koszt pełny „parkuje\" część kosztów stałych w wartości zapasu (różnica = $\\Delta Zapas \\cdot ks_{prod}$); przy produkcja = sprzedaż wyniki są równe.</li><li><strong>Czy przyjąć zamówienie poniżej kosztu pełnego?</strong> Przy wolnych mocach tak, jeśli cena przewyższa koszt zmienny jednostkowy — koszty stałe są nieistotne, liczy się marża pokrycia.</li><li><strong>Dlaczego budżet gotówki jest sercem planowania?</strong> Bo wynik liczony memoriałowo nie równa się przepływowi gotówki — firma rentowna może utracić płynność, a budżet gotówki ostrzega o luce, zanim ona nastąpi.</li></ol>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: *„ta sama liczba, inny cel\"* — koszt jednostkowy pełny (do bilansu) różni się od zmiennego (do decyzji); zawsze pytaj „do czego liczę?\".", "Gdzie komisja dociska: *„controlling to nie kontrola\"* — to sterowanie z wyprzedzeniem w pętli, a kontrola to tylko jeden jego element; controller koryguje kurs, nie audytuje przeszłości.", "Gdzie komisja dociska: w odchyleniach *„czemu cenowe liczycie ilością rzeczywistą, a ilościowe ceną standardową?\"* — by odizolować efekty i nie policzyć podwójnie odchylenia łącznego cena×ilość. Przy cash budżecie: amortyzacji NIE wpisujemy (koszt bezgotówkowy)."], "order": 22}, {"id": "t9", "group": "fib", "num": 9, "title": "Planowanie, budzetowanie i analiza odchylen", "day": 6, "minutes": 22, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Memoriał vs kasa:</strong> memoriałowo przychód/koszt księgujesz w momencie sprzedaży/poniesienia, kasowo — dopiero gdy gotówka realnie wpłynie/wypłynie.</li><li><strong>RZiS vs cash flow:</strong> RZiS pokazuje wynik (memoriał), cash flow — realny ruch gotówki; budżet ma odpowiednik obu.</li><li><strong>Koszty zmienne / stałe / mieszane:</strong> zmienne rosną z wolumenem, stałe są krótkookresowo niewrażliwe, mieszane mają obie części — bez tego nie ma marży pokrycia ani progu rentowności.</li><li><strong>Kapitał obrotowy netto (KON):</strong> $KON = aktywa\\ obrotowe - zobowiazania\\ krotkoterminowe$ — część majątku obrotowego finansowana kapitałem stałym (definicja skryptu, kanoniczna).</li><li><strong>DSO / DIO / DPO i tożsamość cena × ilość = wartość:</strong> trzy „prędkości obrotu\" w dniach plus tożsamość, na której stoi cała dekompozycja odchyleń.</li></ul>"}, {"h": "1. Intuicja — w pigulce", "html": "<p>Plan finansowy to przełożenie strategii na liczby: ile zarobimy, ile wydamy i — najważniejsze — czy starczy gotówki, by dożyć do zarobku. Kluczowa teza: <strong>zysk to nie gotówka</strong> — rentowna firma może zbankrutować, bo rosnące należności i zapasy zamrażają gotówkę szybciej, niż marża ją wygeneruje (*profitable but broke*). Analogia: firma to <strong>wanna</strong> — przychody wlewa kran, koszty wypływają odpływem, ale część wody „wisi w rurach\" (należności, zapasy), więc licznik pokazuje zysk, a dno wanny (saldo gotówki) bywa suche; dostawcy odraczając płatność „pożyczają ci wodę\" za darmo.</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Budżet</strong> — plan finansowy ujęty ilościowo i wartościowo, przypisany ośrodkom odpowiedzialności na dany okres; narzędzie alokacji i kontroli.</li><li><strong>Budżet wiodący (master budget)</strong> — zintegrowany zestaw budżetów cząstkowych: część operacyjna (sprzedaż → produkcja → koszty → prognozowany RZiS) i finansowa (budżet kasowy + prognozowany bilans).</li><li><strong>Prognoza (*forecast*) vs budżet</strong> — budżet to zatwierdzony cel/zobowiązanie (stały), prognoza to bieżące najlepsze oszacowanie (aktualizowane); mylenie ich to klasyczny błąd.</li><li><strong>WCR (*working capital requirement*, zapotrzebowanie operacyjne)</strong> — $(naleznosci + zapasy) - zobowiazania\\ handlowe$; realne zamrożenie gotówki w cyklu, węższe niż KON.</li><li><strong>ΔKON (nakład na kapitał obrotowy)</strong> — przyrost kapitału obrotowego ($\\Delta$ = zmiana); w przepływach to wypływ gotówki przy wzroście, wpływ przy spadku.</li><li><strong>CCC (cykl konwersji gotówki)</strong> — $DSO + DIO - DPO$; liczba dni od zapłaty za surowiec do inkasa od klienta.</li><li><strong>DSO / DIO / DPO</strong> — w dniach: ściąganie należności, rotacja zapasów, spłata zobowiązań.</li><li><strong>Próg rentowności (BEP)</strong> — sprzedaż, przy której marża pokrycia dokładnie pokrywa koszty stałe (wynik = 0); <strong>marża pokrycia</strong> = przychód − koszty zmienne.</li><li><strong>Analiza odchyleń</strong> — porównanie planu z wykonaniem i rozbicie różnicy na <strong>odchylenie cenowe</strong> i <strong>ilościowe</strong>; korzystne (F) poprawia wynik, niekorzystne (U) pogarsza.</li><li><strong>Budżet sztywny vs elastyczny / przyrostowy vs ZBB</strong> — sztywny dla jednego poziomu, elastyczny przeskalowany do faktycznego wolumenu; przyrostowy wychodzi od ubiegłego okresu ± korekta, <strong>ZBB</strong> (*zero-based budgeting*) każe uzasadnić każdą pozycję od zera.</li></ul>"}, {"h": "3. Wzory i przykład", "html": "<p><strong>Cykl i kapitał obrotowy:</strong> $$CCC = DSO + DIO - DPO$$</p><div class=\"legend\">gdzie: $CCC$ — cykl konwersji gotówki (dni); $DSO$ — dni inkasa należności; $DIO$ — dni rotacji zapasów; $DPO$ — dni spłaty zobowiązań.</div><p>$$WCR = naleznosci + zapasy - zobowiazania\\ handlowe$$</p><div class=\"legend\">gdzie: $WCR$ — operacyjne zamrożenie gotówki (zł); pozycje w zł.</div><p><strong>Wolny przepływ pieniężny:</strong> $$FCF = NOPAT + D\\&amp;A - CapEx - \\Delta KON$$</p><div class=\"legend\">gdzie: $FCF$ — wolny przepływ pieniężny (zł); $NOPAT$ — zysk operacyjny po opodatkowaniu (zł); $D\\&amp;A$ — amortyzacja (zł); $CapEx$ — nakłady inwestycyjne (zł); $\\Delta KON$ — nakład na kapitał obrotowy (zł).</div><p><strong>Próg rentowności i odchylenia:</strong> $$BEP = \\frac{KS}{c - kz} \\qquad odchylenie\\ ceny = (c_{rz} - c_{pl}) \\cdot q_{rz} \\qquad odchylenie\\ ilosci = (q_{rz} - q_{pl}) \\cdot c_{pl}$$</p><div class=\"legend\">gdzie: $KS$ — koszty stałe (zł); $c$ — cena (zł/szt.); $kz$ — koszt zmienny jednostkowy (zł/szt.); indeks $rz$ — rzeczywiste, $pl$ — planowane; $q$ — ilość (szt.).</div><p><strong>Przykład — ΔKON „zjada\" zysk (profitable but broke).</strong> Firma rośnie z 12 do 18 mln zł przychodu (+50%), KWS z 8 do 12 mln zł, marża NOPAT 8%, dni bez zmian (DSO 45, DIO 60, DPO 30), $D\\&amp;A$ = 200 tys., CapEx = 500 tys.</p><ul><li>WCR bazowy $= 1\\ 479\\ 452 + 1\\ 315\\ 068 - 657\\ 534 = 2\\ 136\\ 986$ zł</li><li>WCR po wzroście: należności $18\\ mln \\cdot 45/365 = 2\\ 219\\ 178$; zapasy $12\\ mln \\cdot 60/365 = 1\\ 972\\ 603$; zobowiązania $12\\ mln \\cdot 30/365 = 986\\ 301$ → $WCR_1 = 3\\ 205\\ 480$ zł</li><li>$\\Delta KON = 3\\ 205\\ 480 - 2\\ 136\\ 986 = 1\\ 068\\ 494$ zł</li><li>$NOPAT = 0{,}08 \\cdot 18\\ 000\\ 000 = 1\\ 440\\ 000$ zł</li><li>$FCF = 1\\ 440\\ 000 + 200\\ 000 - 500\\ 000 - 1\\ 068\\ 494 = 71\\ 506$ zł</li></ul><p>Firma wyraźnie rentowna (NOPAT 1,44 mln), a generuje niemal zero gotówki — sam ΔKON pochłonął ~74% NOPAT. Stąd: finansowanie wzrostu trzeba zabezpieczyć <strong>z góry</strong>.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Teza:</strong> plan to strategia w liczbach; sedno — „zysk to nie gotówka\", więc planujemy wynik ORAZ kapitał obrotowy i płynność.</li><li><strong>Sekwencja (za skryptem):</strong> start od prognozy sprzedaży (driverowo) → koszty (zmienne/stałe) → należności (DSO) → zapasy (DIO) → zobowiązania (DPO) → ΔKON → budżet kasowy. Podkreśl, że kolejność wynika z zależności pozycji.</li><li><strong>Master budget:</strong> część operacyjna (kończy się prognozowanym RZiS) + finansowa (budżet kasowy, peak funding need, prognozowany bilans).</li><li><strong>Kapitał obrotowy:</strong> policz WCR/CCC, pokaż, że wzrost zamraża gotówkę, a ΔKON to wypływ w FCF (mechanizm *profitable but broke*).</li><li><strong>Analiza odchyleń:</strong> odchylenie całkowite = rzeczywiste − planowane; rozbij na cenowe $(c_{rz}-c_{pl})q_{rz}$ i ilościowe $(q_{rz}-q_{pl})c_{pl}$; zaznacz kontrolę krzyżową (suma = całość).</li><li><strong>Metody i narzędzia:</strong> sztywny vs elastyczny, przyrostowy vs ZBB, rolling forecast — kiedy które.</li><li><strong>Pointa:</strong> plan pełni funkcję alokacyjną, koordynacyjną, kontrolną i motywacyjną; bez planu nie ma odchylenia, bez odchylenia nie ma sygnału do działania.</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Mylenie zysku z gotówką</strong> — najczęstszy błąd; zawsze dodaj, że rentowność nie gwarantuje płynności.</li><li><strong>Gdzie komisja dociska:</strong> rozróżnienie <strong>KON vs WCR</strong> — KON to kategoria bilansowo-finansowa (jak finansowany jest majątek obrotowy), WCR to kategoria operacyjna (ile gotówki zżera cykl). Skrypt operuje samym KON (z zobowiązaniami krótkoterminowymi); WCR podawaj jako precyzyjniejsze ujęcie.</li><li><strong>Gdzie komisja dociska:</strong> dekompozycja odchyleń — umieć wyprowadzić rozbicie przez człon pomostowy $c_{pl}\\,q_{rz}$ i wiedzieć, że odchylenie łączne (interakcyjne) konwencyjnie przypisuje się <strong>cenie</strong> (stąd cena × ilość rzeczywista).</li><li><strong>Dodatnie odchylenie ceny ≠ sukces</strong> — wyższa cena mogła zdławić wolumen; trzeba czytać oba odchylenia łącznie.</li><li><strong>Gdzie komisja dociska:</strong> budżet sztywny vs elastyczny — bez elastycznego obwinia się menedżera za całe przekroczenie, choć część to zdrowy efekt większej skali (rozdziel odchylenie wolumenu od efektywności).</li><li><strong>Biznes sezonowy</strong> — finansowanie wymiaruj pod <strong>peak funding need</strong> (najgłębszy dołek), nie pod średnią; prognoza vs budżet to różne pojęcia.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ul><li><strong>Dlaczego rentowna firma może zbankrutować?</strong> Bo zysk jest memoriałowy, a wzrost zamraża gotówkę w należnościach i zapasach (ΔKON to wypływ); jeśli nie zabezpieczy finansowania kapitału obrotowego, brakuje płynności mimo dodatniego wyniku.</li><li><strong>Czym różni się KON od WCR?</strong> KON = aktywa obrotowe − zobowiązania krótkoterminowe (struktura finansowania majątku), WCR = należności + zapasy − zobowiązania handlowe (operacyjne zamrożenie gotówki); WCR jest węższy, bo pomija gotówkę i kredyty pozaoperacyjne.</li><li><strong>Jak rozłożyć odchylenie wartości na cenę i ilość?</strong> Odchylenie ceny $=(c_{rz}-c_{pl})q_{rz}$, ilości $=(q_{rz}-q_{pl})c_{pl}$; suma równa się odchyleniu całkowitemu (kontrola krzyżowa), a odchylenie interakcyjne konwencyjnie idzie do ceny.</li><li><strong>Czym różni się budżet przyrostowy od ZBB?</strong> Przyrostowy bazuje na poprzednim okresie ± korekta (szybki, ale utrwala marnotrawstwo); ZBB uzasadnia każdą pozycję od zera (pracochłonny, ale tnie zbędne koszty).</li></ul>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: rozróżnienie KON vs WCR — KON to kategoria bilansowo-finansowa (jak finansowany jest majątek obrotowy), WCR to kategoria operacyjna (ile gotówki zżera cykl). Skrypt operuje samym KON (z zobowiązaniami krótkoterminowymi); WCR podawaj jako precyzyjniejsze ujęcie.", "Gdzie komisja dociska: dekompozycja odchyleń — umieć wyprowadzić rozbicie przez człon pomostowy $c_{pl}\\,q_{rz}$ i wiedzieć, że odchylenie łączne (interakcyjne) konwencyjnie przypisuje się cenie (stąd cena × ilość rzeczywista).", "Gdzie komisja dociska: budżet sztywny vs elastyczny — bez elastycznego obwinia się menedżera za całe przekroczenie, choć część to zdrowy efekt większej skali (rozdziel odchylenie wolumenu od efektywności)."], "order": 23}, {"id": "t7", "group": "fib", "num": 7, "title": "Ubezpieczenia i OFE", "day": 7, "minutes": 18, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Zdarzenie losowe</strong> — coś, co może zajść albo nie, i czego dla pojedynczej osoby nie da się pewnie przewidzieć (pożar, śmierć, wypadek).</li><li><strong>Ryzyko</strong> — możliwość zajścia zdarzenia losowego powodującego stratę; da się je opisać liczbowo prawdopodobieństwem.</li><li><strong>Prawdopodobieństwo $q$</strong> — liczba z przedziału $0 \\leq q \\leq 1$ mówiąca, jak często zdarzenie zachodzi w dużej grupie (np. z tablic trwania życia).</li><li><strong>Wartość oczekiwana $E[X]$</strong> — przeciętny wynik losowy ważony prawdopodobieństwami; dla wypłaty $S$ z szansą $q$ wynosi $q \\cdot S$.</li><li><strong>Awersja do ryzyka</strong> — wolimy pewne 100 zł niż loterię o tej samej wartości oczekiwanej; to dlatego płacimy składkę.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Ubezpieczenie to <strong>transfer ryzyka</strong> od jednostki do dużej zbiorowości: płacisz małą, pewną składkę w zamian za ochronę przed wielką, niepewną stratą. Ryzyko nie znika — zostaje <strong>rozsmarowane</strong> po wielu osobach i statystycznie ujarzmione (prawo wielkich liczb). <strong>Analogia:</strong> wioska, w której co roku jednej z dziesięciu rodzin spłonie stodoła; każda wrzuca do wspólnego garnka 1/10 wartości, a poszkodowany odbudowuje się ze wspólnej puli — katastrofa jednostki zamienia się w znośny drobny koszt dla każdego.</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Ubezpieczenie</strong> — gromadzenie funduszu ze składek wielu podmiotów narażonych na podobne ryzyko i wypłacanie świadczeń tym, których dotknęło zdarzenie losowe (transfer i rozłożenie ryzyka).</li><li><strong>Składka</strong> — cena ochrony; ekwiwalent przyjętego ryzyka (skryptowo: „powinna odpowiadać wielkości ryzyka\").</li><li><strong>Suma ubezpieczenia</strong> — górna granica odpowiedzialności zakładu (maksymalna wypłata).</li><li><strong>Świadczenie / odszkodowanie</strong> — wypłata po zdarzeniu (świadczenie = ubezpieczenia osobowe; odszkodowanie = majątkowe, kompensuje realną stratę).</li><li><strong>Zasada ekwiwalentności</strong> — łączne składki muszą w wartości oczekiwanej pokryć łączne świadczenia + koszty + zysk.</li><li><strong>Rezerwy techniczno-ubezpieczeniowe</strong> — zobowiązania zakładu wobec przyszłych świadczeń; główny składnik pasywów i podstawa jego siły inwestycyjnej.</li><li><strong>Antyselekcja (selekcja negatywna)</strong> — przy uśrednionej cenie pulę zalewają klienci o ryzyku wyższym niż średnia (problem <strong>przed</strong> umową); lekarstwo: underwriting i obowiązkowość OC.</li><li><strong>Hazard moralny (pokusa nadużycia)</strong> — ubezpieczenie obniża koszt nieostrożności, więc spada ostrożność (problem <strong>po</strong> umowie); lekarstwo: franszyza i bonus-malus.</li><li><strong>Float</strong> — kapitał z różnicy czasowej między poborem składki a wypłatą, inwestowany przez zakład; dochód z lokat obniża składkę.</li><li><strong>OFE (Otwarty Fundusz Emerytalny)</strong> — kapitałowy II filar, zarządzany przez <strong>PTE (Powszechne Towarzystwo Emerytalne)</strong>.</li></ul>"}, {"h": "3. Wzory i przykład", "html": "<p><strong>Składka czysta (zasada ekwiwalentności):</strong> $$P_{czysta} = q \\cdot S$$</p><div class=\"legend\">gdzie: $P_{czysta}$ — składka czysta / netto (zł), sam ekwiwalent ryzyka; $q$ — prawdopodobieństwo szkody (bez jednostki); $S$ — suma ubezpieczenia / wypłaty (zł).</div><p><strong>Składka brutto (narzut $\\lambda$ liczony od brutto):</strong> $$P_{brutto} = \\frac{P_{czysta}}{1-\\lambda}$$</p><div class=\"legend\">gdzie: $P_{brutto}$ — składka faktycznie płacona (zł); $\\lambda$ — udział narzutu w składce brutto (np. 0,25); $1-\\lambda$ — część brutto na czyste ryzyko. Uwaga: <strong>dzielimy</strong>, nie mnożymy.</div><p><strong>Redukcja względnej zmienności puli:</strong> $$CV = \\frac{\\sigma_X}{\\mu} \\cdot \\frac{1}{\\sqrt{n}}$$</p><div class=\"legend\">gdzie: $CV$ — współczynnik zmienności łącznej wypłaty (bez jednostki); $\\sigma_X/\\mu$ — względna zmienność jednej polisy (stała); $n$ — liczba polis (sztuk). Im większa pula, tym mniejszy procentowy rozrzut — i mniejszy narzut bezpieczeństwa.</div><p><strong>Niedoubezpieczenie (zasada proporcji):</strong> $$wyplata = szkoda \\cdot \\frac{suma\\ ubezpieczenia}{wartosc\\ mienia}$$</p><div class=\"legend\">gdzie: $szkoda$ — rzeczywista wartość szkody (zł); ułamek — stopień pokrycia (np. 0,75).</div><p><strong>Przykład (krok po kroku).</strong> Ubezpieczenie na życie, $S = 200\\,000$ zł, $q = 0{,}002$, narzut $\\lambda = 25\\%$ od brutto.</p><ul><li>Składka czysta: $P_{czysta} = 0{,}002 \\cdot 200\\,000 = 400$ zł.</li><li>Składka brutto: $P_{brutto} = \\frac{400}{1-0{,}25} = \\frac{400}{0{,}75} \\approx 533{,}33$ zł.</li></ul><p>Gdyby błędnie liczyć narzut od czystej: $400 \\cdot 1{,}25 = 500$ zł — to częsta pułapka.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Istota</strong> — transfer ryzyka z ubezpieczającego na ubezpieczyciela za składkę; mechanizm to rozłożenie skutków zdarzeń losowych na wspólnotę ryzyka (mutualizacja), działające dzięki prawu wielkich liczb. To zdanie kupuje połowę punktów.</li><li><strong>Cechy</strong> — losowość, wzajemność, ekwiwalentność (ewentualnie planowość, realność).</li><li><strong>Funkcje</strong> — ochronna (główna), finansowa/akumulacyjna, prewencyjna, redystrybucyjna (i kontrolna).</li><li><strong>Podział</strong> — obowiązkowe/dobrowolne, społeczne/gospodarcze, <strong>Dział I (życie) vs Dział II (majątek)</strong> — ustawowy zakaz łączenia w jednym zakładzie.</li><li><strong>Strona aktuarialna</strong> — składka czysta $P = q \\cdot S$, narzuty na koszty i bezpieczeństwo, dyskontowanie przy umowach długoterminowych.</li><li><strong>System emerytalny</strong> — 3 filary (ZUS / OFE-PTE / IKE-IKZE-PPK), reforma 2014 i „suwak\".</li><li><strong>Otoczenie</strong> — KNF, UFG, PIU, Rzecznik Finansowy, Solvency II; Polska: niska penetracja i dominacja Działu II.</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Narzut: dzielić, nie mnożyć</strong> — $P_{brutto}=P_{czysta}/(1-\\lambda)$, nie $P_{czysta}\\cdot(1+\\lambda)$.</li><li><strong>Składka czysta $\\ne$ wszystko</strong> — $q\\cdot S$ to dopiero netto; klient płaci brutto z narzutami.</li><li><strong>OFE to II filar kapitałowy, NIE ZUS</strong> — nie mylić repartycji (ZUS) z kapitałem (OFE/PPK).</li><li><strong>Odszkodowanie (majątek) $\\ne$ świadczenie (osobowe)</strong> — kompensata realnej straty vs umówiona suma.</li><li><strong>Gdzie komisja dociska:</strong> przy niedoubezpieczeniu z franszyzą sprawdza <strong>kolejność</strong> — proporcję stosuje się <strong>przed</strong> franszyzą, nie po.</li><li><strong>Gdzie komisja dociska:</strong> każe nazwać, dlaczego prawo wielkich liczb <strong>nie</strong> działa przy powodzi/pandemii — odpowiedź: szkody są skorelowane, człon kowariancji rośnie jak $n^2$ i dominuje; stąd reasekuracja i cat bonds. Pula redukuje ryzyko dywersyfikowalne, nie systematyczne.</li><li><strong>Gdzie komisja dociska:</strong> „Dlaczego Dział I i II są rozdzielone?\" — różne ryzyka, rezerwy i regulacje; długoterminowe rezerwy życiowe nie mogą być „przejadane\" przez zmienne ryzyka majątkowe. Status prawny OFE podawaj na dzień egzaminu, nie z pamięci.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<p><strong>1. Wymień funkcje ubezpieczeń.</strong> Ochronna (kompensacja szkód — podstawowa), finansowa/akumulacyjna (gromadzenie i lokowanie kapitału), prewencyjna (ograniczanie ryzyka, np. zniżki za zabezpieczenia), redystrybucyjna (rozłożenie skutków na wspólnotę); dodatkowo kontrolna.</p><p><strong>2. Czym Dział I różni się od Działu II?</strong> Dział I to ubezpieczenia na życie (długoterminowe, z elementem oszczędnościowym); Dział II to pozostałe osobowe i majątkowe (komunikacja, mieszkania, OC). Rozdzielone ustawowo — jeden zakład co do zasady nie prowadzi obu działów, by chronić długoterminowe rezerwy życiowe przed zmiennymi ryzykami majątkowymi.</p><p><strong>3. Czym jest OFE i jakie miejsce zajmuje w systemie emerytalnym?</strong> OFE to II, kapitałowy filar zarządzany przez PTE, inwestujący środki członków na rynku kapitałowym (głównie akcje GPW). Stoi obok I filara (ZUS, repartycyjny, obowiązkowy) i III (dobrowolny: IKE/IKZE/PPK). Sens: dywersyfikacja źródła emerytury — demografia (ZUS) plus realny kapitał (OFE). Status prawny zmienny (reforma 2014: przeniesienie części aktywów do ZUS, „suwak bezpieczeństwa\") — [zweryfikuj aktualny stan na dzień egzaminu].</p><p><strong>4. Dlaczego potrzebna jest franszyza i obowiązkowe OC?</strong> Franszyza (udział własny) zwalcza hazard moralny — przywraca ubezpieczonemu część kosztu szkody, więc bodziec do ostrożności. Obowiązkowe OC zatrzymuje w puli dobre ryzyka i łamie spiralę antyselekcji.</p>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: przy niedoubezpieczeniu z franszyzą sprawdza kolejność — proporcję stosuje się przed franszyzą, nie po.", "Gdzie komisja dociska: każe nazwać, dlaczego prawo wielkich liczb nie działa przy powodzi/pandemii — odpowiedź: szkody są skorelowane, człon kowariancji rośnie jak $n^2$ i dominuje; stąd reasekuracja i cat bonds. Pula redukuje ryzyko dywersyfikowalne, nie systematyczne.", "Gdzie komisja dociska: „Dlaczego Dział I i II są rozdzielone?\" — różne ryzyka, rezerwy i regulacje; długoterminowe rezerwy życiowe nie mogą być „przejadane\" przez zmienne ryzyka majątkowe. Status prawny OFE podawaj na dzień egzaminu, nie z pamięci."], "order": 24}, {"id": "t10", "group": "fib", "num": 10, "title": "Ryzyko walutowe, kurs wymienny i Forex", "day": 7, "minutes": 25, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Kurs walutowy = cena waluty.</strong> „EUR/PLN = 4,30\" znaczy: za 1 euro płacisz 4,30 zł.</li><li><strong>Bilans płatniczy = rachunek kraju z zagranicą</strong> — kto chce kupić nasze towary, musi najpierw kupić naszą walutę (popyt podbija kurs).</li><li><strong>Stopa procentowa = cena pieniądza w czasie</strong> — kapitał płynie tam, gdzie wyższy zwrot, a żeby tam wpłynąć, trzeba kupić tamtejszą walutę.</li><li><strong>Wartość pieniądza w czasie</strong> — 1 zł dziś urośnie do $1 \\cdot (1 + r \\cdot \\frac{t}{360})$; cały wzór na forward to porównanie dwóch takich „urośnięć\".</li><li><strong>Forward</strong> = obowiązek wymiany po umówionej dziś cenie; <strong>opcja</strong> = prawo (nie obowiązek) wymiany za z góry zapłaconą premię.</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Firma importuje za euro, sprzedaje za złote i czeka 3 miesiące na zapłatę — w tym czasie kurs się rusza i zysk handlowy może zamienić się w stratę kursową. <strong>Ryzyko walutowe</strong> to ryzyko, że *liczba* w umowie zostanie ta sama, a jej *wartość w mojej walucie* — inna. Hedging oddziela zysk handlowy (na czym firma się zna) od wyniku kursowego (czego nie kontroluje).</p><p><strong>Analogia:</strong> umawiasz się dziś na zakup za 100 sztabek złota z dostawą za rok, płacąc złotymi. Liczba sztabek pewna, cena złota za rok — nie. Waluta obca = to złoto; hedging = umówienie się dziś na cenę złota za rok (rezygnujesz z szansy, że potanieje, w zamian za pewność, że nie zdrożeje).</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Kurs walutowy</strong> — cena jednej waluty w jednostkach drugiej; w EUR/PLN euro jest <strong>bazowe</strong> (kupujemy 1 sztukę), złoty <strong>kwotowany</strong> (w nim podajemy cenę).</li><li><strong>Kurs realny</strong> — kurs nominalny skorygowany o różnice poziomów cen; mierzy faktyczną siłę nabywczą i konkurencyjność, nie samą cyfrę.</li><li><strong>Aprecjacja/deprecjacja</strong> — rynkowy wzrost/spadek wartości waluty w kursie <strong>płynnym</strong>; <strong>rewaluacja/dewaluacja</strong> — administracyjna zmiana parytetu w kursie <strong>stałym</strong>.</li><li><strong>Ryzyko walutowe</strong> — dzieli się na <strong>transakcyjne</strong> (realne, zakontraktowane przepływy), <strong>przeliczeniowe/translacyjne</strong> (księgowe, przy konsolidacji spółek) i <strong>ekonomiczne</strong> (długookresowa konkurencyjność).</li><li><strong>Pozycja walutowa</strong> — różnica między aktywami a pasywami w danej walucie: <strong>długa</strong> (nadwyżka aktywów, zyskuje na aprecjacji), <strong>krótka</strong> (nadwyżka pasywów, zyskuje na deprecjacji), <strong>zamknięta</strong> (równe → brak ryzyka).</li><li><strong>Hedging</strong> — zajęcie pozycji przeciwnej do pierwotnej; cel to redukcja zmienności wyniku, nie maksymalizacja zysku.</li><li><strong>Spekulant</strong> świadomie otwiera pozycję (bierze ryzyko za zysk); <strong>arbitrażysta</strong> wykorzystuje rozbieżności cen bez ryzyka i bez kapitału netto.</li><li><strong>Forex (FX)</strong> — globalny, zdecentralizowany rynek walutowy <strong>OTC</strong> (poza giełdą); największy na świecie, handel 24h/5 dni, wysoka dźwignia i wysokie ryzyko.</li><li><strong>Kurs spot</strong> — rozliczenie natychmiastowe (T+2); <strong>kurs forward</strong> — ustalony dziś na dostawę w przyszłości. <strong>Punkty swapowe</strong> = $F - S$.</li></ul>"}, {"h": "3. Wzory i przykład", "html": "<p><strong>Kurs forward (parytet stóp procentowych, CIP):</strong></p><p>$$F = S \\cdot \\frac{1 + r_{kw} \\cdot \\frac{t}{360}}{1 + r_{baz} \\cdot \\frac{t}{360}}$$</p><div class=\"legend\">gdzie: $F$ — kurs forward (PLN za 1 EUR), $S$ — kurs spot (PLN za 1 EUR), $r_{kw}$ — roczna stopa waluty kwotowanej (PLN, ułamek dziesiętny), $r_{baz}$ — roczna stopa waluty bazowej (EUR, ułamek), $t$ — liczba dni, $360$ — umowna liczba dni w roku.</div><p><strong>VaR walutowy (1 dzień) i skalowanie w czasie:</strong></p><p>$$VaR_{1d} = W \\cdot \\sigma \\cdot z \\qquad VaR_{Nd} = VaR_{1d} \\cdot \\sqrt{N}$$</p><div class=\"legend\">gdzie: $VaR_{1d}$ — strata, której z danym prawdopodobieństwem nie przekroczymy w 1 dzień (PLN), $W$ — wartość pozycji (PLN), $\\sigma$ — dzienna zmienność kursu (odchylenie standardowe), $z$ — mnożnik z rozkładu normalnego ($2{,}33$ dla 99%, $1{,}645$ dla 95%), $N$ — liczba dni horyzontu, $\\sqrt{N}$ — reguła pierwiastka czasu.</div><p><strong>Przykład — forward EUR/PLN.</strong> Dane: $S = 4{,}30$; $r_{PLN} = 6\\%$; $r_{EUR} = 3\\%$; $t = 90$ dni ($\\frac{90}{360} = 0{,}25$).</p><p>$$F = 4{,}30 \\cdot \\frac{1 + 0{,}06 \\cdot 0{,}25}{1 + 0{,}03 \\cdot 0{,}25} = 4{,}30 \\cdot \\frac{1{,}015}{1{,}0075} = 4{,}3320$$</p><p>Waluta o wyższej stopie (PLN) jest <strong>na termin słabsza</strong> (forward EUR/PLN &gt; spot) — dyskonto kompensuje różnicę stóp, inaczej istniałby darmowy arbitraż.</p><p>Importer (zobowiązanie 1 mln EUR za 90 dni, pozycja krótka, boi się aprecjacji EUR) <strong>kupuje EUR na termin</strong> po 4,3320 → koszt zamrożony na <strong>4 332 000 PLN</strong>. Gdyby kurs wzrósł do 4,45, bez hedgingu zapłaciłby 4 450 000 PLN. Gdyby spadł do 4,20 — forward odebrałby ten zysk (koszt alternatywny, nie strata księgowa).</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Zdefiniuj kurs walutowy</strong>; odróżnij nominalny/realny oraz aprecjację/deprecjację od rewaluacji/dewaluacji.</li><li><strong>Wymień instytucje</strong> (MFW, Bank Światowy, BIS, EBC; skryptowo też OECD) z jednozdaniową rolą i kluczową różnicą: MFW = płynność/bilans płatniczy krótkoterminowo, Bank Światowy = rozwój długoterminowo.</li><li><strong>Podaj uwarunkowania kursu</strong>: stopy (IRP), inflacja (PPP), bilans płatniczy, oczekiwania/sentyment.</li><li><strong>Sklasyfikuj ryzyko</strong> na 3 typy: transakcyjne, przeliczeniowe, ekonomiczne.</li><li><strong>Wyjaśnij pozycję walutową</strong> (długa/krótka/netto) — ogniwo spinające ryzyko z zabezpieczeniem.</li><li><strong>Wymień instrumenty</strong>: wewnętrzne (netting, matching, hedging naturalny, fakturowanie we własnej walucie, leading/lagging) i zewnętrzne (forward, futures, opcja, swap/CIRS).</li><li><strong>Pokaż przykład liczbowy</strong> (forward importera/eksportera; jak masz czas — VaR) i <strong>zakończ Forexem</strong> (OTC, 24/5, dźwignia, spread).</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Aprecjacja ≠ rewaluacja</strong> — pierwsze to ruch rynkowy (kurs płynny), drugie to akt władzy (kurs stały). Nazwa zależy od reżimu kursowego.</li><li><strong>Odwrócony kierunek pozycji</strong> — importer ma pozycję krótką i boi się aprecjacji waluty obcej; eksporter odwrotnie. Pomyłka „podwaja\" ryzyko zamiast je znosić.</li><li><strong>„Wyższa stopa = mocniejsza waluta na termin\"</strong> — na spocie tak, ale na *forwardzie* waluta o wyższej stopie jest na <strong>dyskoncie</strong> (wprost z CIP).</li><li><strong>Gdzie komisja dociska:</strong> „forward jest zawsze lepszy\" to błąd — ulubiona dogrywka brzmi „a co, jeśli kurs pójdzie w drugą stronę?\". Wzorcowo: forward zamraża wynik (oddajesz zysk), opcja zostawia korzyść kosztem przepalonej premii.</li><li><strong>Gdzie komisja dociska:</strong> hierarchia zabezpieczeń — *najpierw narzędzia wewnętrzne* (netting, matching, hedging naturalny, fakturowanie), bo nie kosztują premii ani spreadu, a dopiero na nadwyżkę netto — pochodne. Kto od razu skacze do forwardu, traci punkt.</li><li><strong>Gdzie komisja dociska:</strong> kluczowe zdanie „poziomu profesora\" — *„Zabezpieczenie kosztuje pewność, nie pieniądze.\"* Hedging to świadoma wymiana zmienności na pewność, nie darmowe zarabianie.</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<p><strong>1. Wymień trzy rodzaje ryzyka walutowego.</strong> Transakcyjne (realne, zakontraktowane przepływy), przeliczeniowe/translacyjne (księgowe, przy konsolidacji), ekonomiczne (długookresowa konkurencyjność).</p><p><strong>2. Co mówi parytet siły nabywczej (PPP)?</strong> W długim okresie kursy dążą do wyrównania siły nabywczej walut (prawo jednej ceny); waluta kraju o wyższej inflacji deprecjonuje się. To grawitacja długoterminowa, nie prognoza na jutro.</p><p><strong>3. Jaką rolę pełni MFW?</strong> Czuwa nad stabilnością międzynarodowego systemu walutowego, prowadzi nadzór makro (art. IV) i udziela warunkowych pożyczek (conditionality) krajom z problemami bilansu płatniczego; operuje jednostką SDR. „Strażak płynności\" — w odróżnieniu od Banku Światowego, który finansuje rozwój.</p><p><strong>4. Dlaczego waluta o wyższej stopie jest na termin słabsza?</strong> Wymaga tego brak arbitrażu (CIP): zysk z lokowania w wyżej oprocentowanej walucie musi zostać „odebrany\" przez niższy kurs terminowy, inaczej istniałby darmowy zysk bez ryzyka — stąd forward tej waluty jest na dyskoncie.</p><p>Plik źródłowy: C:/Users/grzes/Documents/Agents/ecosystem/reference/work/egzamin_finanse/temat_10_ryzyko_walutowe_i_forex.md (kondensacja z ~7000-8000 do ~1450 słów; nie zapisano na dysku zgodnie z poleceniem).</p>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: „forward jest zawsze lepszy\" to błąd — ulubiona dogrywka brzmi „a co, jeśli kurs pójdzie w drugą stronę?\". Wzorcowo: forward zamraża wynik (oddajesz zysk), opcja zostawia korzyść kosztem przepalonej premii.", "Gdzie komisja dociska: hierarchia zabezpieczeń — *najpierw narzędzia wewnętrzne* (netting, matching, hedging naturalny, fakturowanie), bo nie kosztują premii ani spreadu, a dopiero na nadwyżkę netto — pochodne. Kto od razu skacze do forwardu, traci punkt.", "Gdzie komisja dociska: kluczowe zdanie „poziomu profesora\" — *„Zabezpieczenie kosztuje pewność, nie pieniądze.\"* Hedging to świadoma wymiana zmienności na pewność, nie darmowe zarabianie."], "order": 25}, {"id": "t12", "group": "fib", "num": 12, "title": "Instrumenty pochodne: forward, futures, opcje, swapy", "day": 7, "minutes": 30, "sections": [{"h": "0. Cegiełki — co znać wcześniej", "html": "<ul><li><strong>Instrument bazowy (underlying)</strong> — aktywo, od którego zależy wartość pochodnej (akcja, waluta, stopa, surowiec).</li><li><strong>Long vs short</strong> — long (kupujący) zyskuje, gdy cena rośnie; short (sprzedający) zyskuje, gdy spada.</li><li><strong>Cena spot</strong> — bieżąca cena „na już\": $S_0$ dziś, $S_T$ w przyszłej dacie $T$.</li><li><strong>Wartość pieniądza w czasie</strong> — kapitalizacja $(1+r)^{T}$ przesuwa wartość w przyszłość, dyskontowanie $e^{-rT}$ ściąga ją do dziś.</li><li><strong>Trzy cele derywatu</strong> — hedging (zabezpieczenie), spekulacja (otwarcie ekspozycji), arbitraż (bezryzykowy zysk z różnicy cen).</li></ul>"}, {"h": "1. Intuicja — w pigułce", "html": "<p>Instrument pochodny to kontrakt, którego wartość <strong>wynika z ceny innego aktywa</strong> — to „zakład o przyszłą cenę czegoś innego\". Sam nie ma wartości użytkowej; handlujesz przyszłą ceną lub przepływem pieniężnym. Cała sztuka to ustalić: kto ma OBOWIĄZEK, kto PRAWO, i jak wygląda WYPŁATA przy różnych cenach bazy.</p><p><strong>Analogia (rezerwacja stolika):</strong> opcja to rezerwacja za bezzwrotną kaucję 20 zł — masz <strong>prawo</strong> przyjść, ale nie musisz (max strata = kaucja). Forward to zamówiony catering — <strong>musisz</strong> zapłacić i odebrać, choćby impreza się nie odbyła.</p>"}, {"h": "2. Kluczowe pojęcia", "html": "<ul><li><strong>Forward</strong> — niestandaryzowana umowa <strong>OTC</strong> (poza giełdą) zobowiązująca obie strony do transakcji po cenie $F$ w dacie $T$; elastyczna, ale obarczona ryzykiem kontrahenta.</li><li><strong>Futures</strong> — wystandaryzowany forward notowany na giełdzie, z izbą rozliczeniową, depozytem i codziennym mark-to-market.</li><li><strong>Opcja</strong> — daje nabywcy <strong>prawo (nie obowiązek)</strong> kupna (<strong>call</strong>) lub sprzedaży (<strong>put</strong>) po cenie wykonania $K$; wystawca ma obowiązek, nabywca płaci premię.</li><li><strong>Premia</strong> — cena opcji płacona z góry, zawsze przepada (w odróżnieniu od depozytu w futures, który wraca).</li><li><strong>Strike ($K$)</strong> — cena wykonania opcji.</li><li><strong>ITM/ATM/OTM</strong> — opcja w pieniądzu (opłacalna), przy pieniądzu ($S \\approx K$), poza pieniądzem (nieopłacalna).</li><li><strong>Wartość wewnętrzna + czasowa</strong> — wewnętrzna to zysk z natychmiastowego wykonania $\\max(S-K,0)$; czasowa to zapłata za szansę dalszego korzystnego ruchu (maleje do zera w dniu wygaśnięcia).</li><li><strong>Swap</strong> — umowa wymiany strumieni płatności; najczęściej <strong>IRS</strong> (interest rate swap — wymiana odsetek stałych na zmienne), też CIRS (walutowy) i CDS (ryzyka kredytowego).</li><li><strong>Nominał (notional)</strong> — kwota, od której liczy się odsetki; w IRS <strong>nie podlega wymianie</strong>.</li><li><strong>Cena forward ($F$) vs wartość kontraktu ($V$)</strong> — $F$ to umówiona cena dostawy (stała), $V$ to bieżąca wartość kontraktu (zmienna, na starcie $V_0 = 0$).</li></ul>"}, {"h": "3. Wzory i przykład", "html": "<p><strong>Cena forward (cost-of-carry):</strong> $$F = S_0 \\cdot (1 + r)^{T}$$</p><div class=\"legend\">gdzie: $F$ — uczciwa cena forward (zł), $S_0$ — cena spot dziś (zł), $r$ — stopa wolna od ryzyka rocznie (np. 0,05), $T$ — czas do dostawy w latach.</div><p><strong>Wypłata forward/futures (long):</strong> $$\\text{Wyplata} = S_T - F$$</p><div class=\"legend\">gdzie: $S_T$ — cena spot w dacie $T$ (zł), $F$ — umówiona cena forward (zł); wynik dodatni = zysk longa, ujemny = strata. Profil <strong>symetryczny i liniowy</strong>.</div><p><strong>Wypłata opcji (nabywca):</strong> $$\\text{Call} = \\max(S_T - K, 0) - \\text{premia} \\qquad \\text{Put} = \\max(K - S_T, 0) - \\text{premia}$$</p><div class=\"legend\">gdzie: $S_T$ — cena spot w dniu wygaśnięcia (zł), $K$ — strike (zł), $\\max(\\cdot,0)$ — wartość nigdy poniżej zera. Profil <strong>asymetryczny</strong> (złamany w punkcie $K$).</div><p><strong>5 czynników wartości opcji:</strong> cena spot $S$, strike $K$, czas $T$, zmienność $\\sigma$, stopa $r$. Kluczowa zależność: <strong>wzrost $\\sigma$ podnosi wartość KAŻDEJ opcji</strong> (call i put), bo strata nabywcy i tak ograniczona do premii, a większy rozrzut zwiększa szansę dużego zysku.</p><p><strong>Przykład (call krok po kroku).</strong> $K = 105$ zł, premia $= 4$ zł:</p><ul><li>$S_T = 120$: $\\max(120-105,0) - 4 = 15 - 4 = +11$ zł.</li><li>$S_T = 109$: $4 - 4 = 0$ zł — to <strong>break-even</strong> $= K + \\text{premia} = 109$ zł.</li><li>$S_T = 100$: $0 - 4 = -4$ zł (nie wykonuję, tracę tylko premię).</li></ul><p>Wniosek: max strata nabywcy = premia (4 zł), zysk teoretycznie nieograniczony.</p><p><strong>Przykład (IRS — zabezpieczenie kredytu).</strong> Firma ma kredyt WIBOR + 1,5% marży; wchodzi w IRS: płaci stałe 6%, otrzymuje WIBOR. Gdy WIBOR = 8%: z kredytu płaci 9,5%, ze swapa otrzymuje netto +2% → koszt łączny 7,5%. Gdy WIBOR = 4%: z kredytu 5,5%, ze swapa dopłaca 2% → znów 7,5%. Efekt: koszt zawsze <strong>stały 7,5%</strong> (stałe 6% + marża 1,5%), niezależnie od stóp. Wymieniana jest tylko różnica odsetek (netto), nominał nigdy nie zmienia rąk.</p>"}, {"h": "4. Model odpowiedzi egzaminacyjnej", "html": "<ol><li><strong>Definicja derywatu</strong> — wartość pochodna od bazy („zakład o przyszłą cenę\"); cele: hedging / spekulacja / arbitraż.</li><li><strong>Forward</strong> — OTC, obie strony zobowiązane, ryzyko kontrahenta, $F = S_0(1+r)^T$, wypłata $S_T - F$; rozróżnij cenę $F$ od wartości $V$.</li><li><strong>Futures</strong> — „forward na giełdzie\": standaryzacja, izba rozliczeniowa (CCP), depozyt, mark-to-market, margin call, konwergencja $F_T \\to S_T$. Podkreśl różnicę z forwardem.</li><li><strong>Opcje</strong> — call/put, prawo vs obowiązek, premia, strike, wartość wewnętrzna + czasowa, 5 czynników, asymetria wypłaty.</li><li><strong>Swapy</strong> — IRS (stałe ↔ zmienne), wymiana strumieni netto, nominał bez wymiany; wspomnij CIRS i CDS.</li><li><strong>Profile wypłat</strong> — forward: prosta 45° przez $F$ (symetria); opcja: „kolano\" w $K$ (asymetria).</li><li><strong>Domknięcie</strong> — derywat nie jest dobry ani zły; liczy się, czy zmniejsza (hedging), czy zwiększa (spekulacja) ekspozycję.</li></ol>"}, {"h": "5. Pułapki i gdzie komisja dociska", "html": "<ul><li><strong>Gdzie komisja dociska:</strong> „Proszę porównać forward i futures\" — to ulubione pytanie dobijające. Wymień CZTERY osie naraz: standaryzacja (futures tak), miejsce obrotu (giełda vs OTC), ryzyko kontrahenta (futures eliminuje przez izbę), depozyt + mark-to-market (tylko futures). Samo „jeden jest na giełdzie\" = utrata punktów.</li><li><strong>Gdzie komisja dociska:</strong> „Opcja vs forward\" — forward zobowiązuje obie strony, wypłata symetryczna; opcja daje jednej stronie prawo wyboru za premię, wypłata asymetryczna (złamana w $K$). Wypowiedz to wprost.</li><li><strong>Gdzie komisja dociska:</strong> profil wypłat — kluczowe wizualnie jest <strong>złamanie linii w punkcie $K$</strong> dla opcji versus prosta 45° dla forward. To złamanie = asymetria = sedno różnicy.</li><li><strong>Mylenie ceny $F$ z wartością $V$</strong> — $F$ ustalana raz na starcie ($V_0 = 0$); $V$ zmienia się w czasie wraz ze spotem.</li><li><strong>Mylenie depozytu z premią</strong> — depozyt (futures) to zabezpieczenie, wraca; premia (opcja) to cena, przepada w całości.</li><li><strong>Pominięcie kierunku zależności $\\sigma$</strong> — wzrost zmienności podnosi wartość zarówno calla, jak i puta (nie tylko calla).</li></ul>"}, {"h": "6. Pytania kontrolne", "html": "<ol><li><strong>Czym różni się forward od futures?</strong> Ekonomicznie identyczne (obowiązek dostawy po umówionej cenie), ale futures jest standaryzowany, notowany na giełdzie, z izbą rozliczeniową (eliminuje ryzyko kontrahenta), depozytem i codziennym mark-to-market — kosztem ryzyka płynności (margin call).</li><li><strong>Dlaczego wypłata opcji jest asymetryczna, a forwardu symetryczna?</strong> Bo nabywca opcji ma prawo, nie obowiązek — wykona ją tylko, gdy się opłaca, więc strata ogranicza się do premii. Forward zobowiązuje obie strony, więc zysk longa = strata shorta (gra o sumie zero).</li><li><strong>Jak swap IRS zabezpiecza firmę przed wzrostem stóp?</strong> Firma płaci w swapie stałą stopę, a otrzymuje zmienną (WIBOR), którą przekazuje na kredyt; zmienne nogi się znoszą i zostaje przewidywalny koszt stały. Rozliczana jest tylko różnica odsetek, nominał nie jest wymieniany.</li><li><strong>Co podnosi wartość opcji?</strong> Pięć czynników ($S, K, T, \\sigma, r$); w szczególności wzrost zmienności $\\sigma$ i czasu $T$ podnosi wartość każdej opcji, bo zwiększa szansę dużego korzystnego ruchu przy stracie ograniczonej do premii.</li></ol>"}], "probes": ["## 5. Pułapki i gdzie komisja dociska", "Gdzie komisja dociska: „Proszę porównać forward i futures\" — to ulubione pytanie dobijające. Wymień CZTERY osie naraz: standaryzacja (futures tak), miejsce obrotu (giełda vs OTC), ryzyko kontrahenta (futures eliminuje przez izbę), depozyt + mark-to-market (tylko futures). Samo „jeden jest na giełdzie\" = utrata punktów.", "Gdzie komisja dociska: „Opcja vs forward\" — forward zobowiązuje obie strony, wypłata symetryczna; opcja daje jednej stronie prawo wyboru za premię, wypłata asymetryczna (złamana w $K$). Wypowiedz to wprost.", "Gdzie komisja dociska: profil wypłat — kluczowe wizualnie jest złamanie linii w punkcie $K$ dla opcji versus prosta 45° dla forward. To złamanie = asymetria = sedno różnicy."], "order": 26}], "flashcards": [{"id": "f_fundament_0", "chapter": "fundament", "front": "Renta (płatności okresowe)", "back": "seria równych płatności; PV renty to suma zdyskontowanych rat (np. raty kredytu, kupony).", "tag": "pojecie"}, {"id": "f_fundament_1", "chapter": "fundament", "front": "Ocena opłacalności inwestycji:", "back": "Metody proste (bez dyskonta): okres zwrotu (po ilu latach wróci nakład), ARR (księgowa stopa zwrotu). Proste, ale ignorują wartość pieniądza w czasie.", "tag": "pojecie"}, {"id": "f_fundament_2", "chapter": "fundament", "front": "Metody dyskontowe** (lepsze): **NPV", "back": "NPV = \\sum \\frac{CF_t}{(1+r)^t} - I_0; gdzie: CF_t — przepływ w roku t (zł), r — stopa dyskonta (koszt kapitału), I_0 — nakład początkowy (zł). Reguła: NPV > 0 → inwestycja opłacalna.", "tag": "pojecie"}, {"id": "f_fundament_3", "chapter": "fundament", "front": "IRR (wewnętrzna stopa zwrotu)", "back": "stopa, przy której NPV = 0. Reguła: IRR > koszt kapitału → opłacalna.", "tag": "pojecie"}, {"id": "f_fundament_4", "chapter": "fundament", "front": "Dywersyfikacja", "back": "ryzyko portfela < suma ryzyk, gdy aktywa nie są idealnie skorelowane.", "tag": "pojecie"}, {"id": "f_fundament_5", "chapter": "fundament", "front": "Nadrzędne zasady rachunkowości (na pamięć):", "back": "memoriału — ujmujemy zdarzenie w okresie wystąpienia, nie wpływu gotówki;", "tag": "pojecie"}, {"id": "f_fundament_6", "chapter": "fundament", "front": "współmierności", "back": "koszty dopasowane do przychodów tego samego okresu;", "tag": "pojecie"}, {"id": "f_fundament_7", "chapter": "fundament", "front": "ostrożności", "back": "nie zawyżaj aktywów/przychodów, uwzględnij przewidywane straty;", "tag": "pojecie"}, {"id": "f_fundament_8", "chapter": "fundament", "front": "Koszty — klasyfikacja:", "back": "układ rodzajowy (amortyzacja, materiały, wynagrodzenia…) vs funkcjonalny (wg miejsc: produkcja, sprzedaż, zarząd);", "tag": "pojecie"}, {"id": "f_fundament_9", "chapter": "fundament", "front": "Przychody i koszty: ujęcie księgowe vs podatkowe", "back": "nie wszystkie koszty księgowe są kosztem podatkowym; różnice prowadzą od wyniku księgowego do dochodu do opodatkowania.", "tag": "pojecie"}, {"id": "f_fundament_10", "chapter": "fundament", "front": "Płynność", "back": "czy firma spłaci na czas: wskaźnik bieżący = aktywa obrotowe / zobowiązania bieżące; szybki (bez zapasów).", "tag": "pojecie"}, {"id": "f_fundament_11", "chapter": "fundament", "front": "Zadłużenie / wypłacalność", "back": "ile długu: ogólnego zadłużenia = zobowiązania / aktywa; D/E = dług / kapitał własny.", "tag": "pojecie"}, {"id": "f_t1_0", "chapter": "t1", "front": "Stopa zwrotu", "back": "o ile % zmieniła się wartość pozycji: R = \\frac{P_1 - P_0}{P_0} (wersja logarytmiczna \\ln\\frac{P_1}{P_0} ładnie dodaje się w czasie).", "tag": "pojecie"}, {"id": "f_t1_1", "chapter": "t1", "front": "Rozkład normalny (Gauss)", "back": "„dzwon\", opisany w pełni przez średnią \\mu i odchylenie \\sigma; realne rynki mają jednak grubsze ogony.", "tag": "pojecie"}, {"id": "f_t1_2", "chapter": "t1", "front": "Kwantyl / wartość $z$", "back": "punkt odcinający najgorszy procent wyników; na pamięć: z \\approx 1{,}65 (95%), z \\approx 2{,}33 (99%), z = 1{,}96 (97,5%).", "tag": "pojecie"}, {"id": "f_t1_3", "chapter": "t1", "front": "VaR (wartość zagrożona ryzykiem)", "back": "maksymalna oczekiwana strata portfela w danym horyzoncie i przy danym poziomie ufności, w normalnych warunkach rynkowych (formalnie: kwantyl rozkładu strat).", "tag": "pojecie"}, {"id": "f_t1_4", "chapter": "t1", "front": "Poziom ufności $(1-\\alpha)$", "back": "jak rzadkie zdarzenie odcinamy (99% → \\alpha=1\\%); wyższa ufność = wyższy VaR.", "tag": "pojecie"}, {"id": "f_t1_5", "chapter": "t1", "front": "Ryzyko rynkowe", "back": "ryzyko straty z wahań cen: walutowe (FX), stopy procentowej, akcji (equity), towarowe; dotyczy księgi handlowej (wycenianej do rynku).", "tag": "pojecie"}, {"id": "f_t1_6", "chapter": "t1", "front": "Expected Shortfall (ES, CVaR)", "back": "średnia strata w ogonie, gdy strata przekroczy VaR; mówi, jak głęboki jest ogon (VaR mówi tylko gdzie się zaczyna).", "tag": "pojecie"}, {"id": "f_t1_7", "chapter": "t1", "front": "Miara koherentna", "back": "spełnia m.in. subaddytywność (\\rho(A+B) \\leq \\rho(A)+\\rho(B)); ES ją spełnia, VaR dla grubych ogonów łamie.", "tag": "pojecie"}, {"id": "f_t1_8", "chapter": "t1", "front": "Backtesting", "back": "porównanie liczby przekroczeń VaR (wyjątków) z oczekiwaną; przy 99%/250 dni oczekujemy ~2,5 wyjątku (traffic-light: zielona/żółta/czerwona → mnożnik 3,0–4,0).", "tag": "pojecie"}, {"id": "f_t1_9", "chapter": "t1", "front": "Duracja modyfikowana / PV01", "back": "wrażliwość ceny obligacji na zmianę stopy (PV01 = zmiana wartości przy ruchu o 1 punkt bazowy).", "tag": "pojecie"}, {"id": "f_t1_10", "chapter": "t1", "front": "Rezerwa obowiązkowa", "back": "część depozytów, którą bank musi trzymać na rachunku w banku centralnym (NBP); instrument polityki pieniężnej, nie bufor płynności ani kapitał.", "tag": "pojecie"}, {"id": "f_t1_11", "chapter": "t1", "front": "Osad depozytów", "back": "stabilna część depozytów bieżących, która mimo formy „na żądanie\" zostaje w banku latami; pozwala finansować dłuższe aktywa.", "tag": "pojecie"}, {"id": "f_t2_0", "chapter": "t2", "front": "Bank lewarowany", "back": "na ~100 zł aktywów ma tylko ~8–10 zł kapitału własnego, więc nawet mały procent strat może wymazać cały kapitał.", "tag": "pojecie"}, {"id": "f_t2_1", "chapter": "t2", "front": "Wartość oczekiwana", "back": "dla zdarzenia „strata S z prawdopodobieństwem p\" to po prostu p \\times S — na tym stoi cały wzór EL.", "tag": "pojecie"}, {"id": "f_t2_2", "chapter": "t2", "front": "Stopa odzysku (RR)", "back": "frakcja ekspozycji odzyskana z zabezpieczenia po defaulcie; reszta to strata.", "tag": "pojecie"}, {"id": "f_t2_3", "chapter": "t2", "front": "Analiza wskaźnikowa", "back": "płynność, zadłużenie, rentowność, przepływy — narzędzia do jednego celu: czy z tej działalności da się obsłużyć dług.", "tag": "pojecie"}, {"id": "f_t2_4", "chapter": "t2", "front": "Zdolność kredytowa", "back": "wg art. 70 ust. 1 Prawa bankowego: zdolność do spłaty kapitału wraz z odsetkami w terminach umowy, z własnych przyszłych przepływów (pojęcie prospektywne). [zweryfikuj numer ustępu]", "tag": "pojecie"}, {"id": "f_t2_5", "chapter": "t2", "front": "Ryzyko kredytowe", "back": "niebezpieczeństwo, że kredytobiorca nie spłaci, oraz wynikająca z tego strata; dzieli się na ryzyko niewypłacalności (PD) i ryzyko odzysku/ekspozycji (LGD, EAD).", "tag": "pojecie"}, {"id": "f_t2_6", "chapter": "t2", "front": "Niewypłacalność (default)", "back": "status wg CRR/Bazylei, gdy spełniony co najmniej jeden warunek: opóźnienie istotnej kwoty > 90 dni LUB ocena „prawdopodobnie nie spłaci\" (UTP — unlikeliness to pay).", "tag": "pojecie"}, {"id": "f_t2_7", "chapter": "t2", "front": "Miernik syntetyczny", "back": "jedna liczba agregująca wiele wskaźników w łączną ocenę ryzyka (scoring, rating, Altman Z-Score), pozwalająca uszeregować i porównać kredytobiorców.", "tag": "pojecie"}, {"id": "f_t2_8", "chapter": "t2", "front": "EL vs UL", "back": "strata oczekiwana (EL) pokrywana rezerwami i marżą; strata nieoczekiwana (UL, ogon rozkładu) pokrywana kapitałem — fundament Bazylei.", "tag": "pojecie"}, {"id": "f_t2_9", "chapter": "t2", "front": "Zdolność pierwotna vs wtórna", "back": "pierwotna = spłata z bieżących przepływów (główna podstawa decyzji); wtórna = z realizacji zabezpieczeń („plan B\", kanał LGD).", "tag": "pojecie"}, {"id": "f_t2_10", "chapter": "t2", "front": "Zdolność vs wypłacalność vs płynność", "back": "zdolność jest prospektywna i dotyczy konkretnego długu; wypłacalność to dodatni kapitał (bilans); płynność to bieżąca gotówka. Firma wypłacalna może zdefaultować z braku płynności.", "tag": "pojecie"}, {"id": "f_t2_11", "chapter": "t2", "front": "Gdzie komisja dociska:** różnica **scoring vs rating", "back": "scoring to ocena masowa, detaliczna, automatyczna (point-in-time); rating to pojedynczy duży kredytobiorca, ocena ekspercka + modelowa (through-the-cycle).", "tag": "pojecie"}, {"id": "f_t3_0", "chapter": "t3", "front": "Instrument finansowy", "back": "umowa rodząca aktywo finansowe u jednej strony i zobowiązanie lub instrument kapitałowy u drugiej (akcje, obligacje, kredyty, depozyty).", "tag": "pojecie"}, {"id": "f_t3_1", "chapter": "t3", "front": "Aktywo a pasywo w banku „na opak\"", "back": "Twój depozyt to dług banku wobec Ciebie (pasywo), więc bilans banku wygląda odwrotnie niż w firmie produkcyjnej.", "tag": "pojecie"}, {"id": "f_t3_2", "chapter": "t3", "front": "Równanie bilansowe", "back": "suma aktywów = suma pasywów (zawsze się równa).", "tag": "pojecie"}, {"id": "f_t3_3", "chapter": "t3", "front": "Zasady nadrzędne rachunkowości", "back": "memoriał, ostrożność, kontynuacja działania, współmierność, treść nad formą (banki ich nie zmieniają, tylko stosują w trudniejszym otoczeniu ryzyka).", "tag": "pojecie"}, {"id": "f_t3_4", "chapter": "t3", "front": "Wartość pieniądza w czasie / dyskontowanie", "back": "złotówka dziś jest warta więcej niż za rok; przyszły przepływ sprowadzamy do dziś dzieląc przez (1 + r)^{t}.", "tag": "pojecie"}, {"id": "f_t3_5", "chapter": "t3", "front": "Odpis na oczekiwane straty kredytowe", "back": "pomniejszenie wartości kredytu o spodziewaną stratę; siedzi po stronie aktywów ze znakiem minus (nie mylić z rezerwą MSR 37, która jest zobowiązaniem w pasywach).", "tag": "pojecie"}, {"id": "f_t3_6", "chapter": "t3", "front": "PD, LGD, EAD", "back": "parametry ryzyka: PD prawdopodobieństwo defaultu, LGD strata na jednostkę ekspozycji przy defaulcie, EAD kwota „na ryzyku\" w momencie defaultu.", "tag": "pojecie"}, {"id": "f_t3_7", "chapter": "t3", "front": "FINREP / COREP", "back": "pakiety sprawozdawczości nadzorczej w UE: FINREP (dane finansowe wg MSSF), COREP (adekwatność kapitałowa wg CRR).", "tag": "pojecie"}, {"id": "f_t3_8", "chapter": "t3", "front": "Strata poniesiona vs oczekiwana", "back": "MSR 39 = *incurred* (strata musiała już zaistnieć); MSSF 9 = *expected* z wyprzedzeniem. To istota reformy po 2008.", "tag": "pojecie"}, {"id": "f_t3_9", "chapter": "t3", "front": "Pomijanie dyskonta w Stage 3", "back": "odpis to brutto minus *zdyskontowana* (po EIR) wartość odzysków, nie nominalny niedobór; pominięcie zaniża stratę.", "tag": "pojecie"}, {"id": "f_t3_10", "chapter": "t3", "front": "Mylenie OCI z wynikiem", "back": "przeszacowanie FVOCI nie przechodzi przez P&L, ląduje w kapitale; zysk netto ≠ całkowity dochód.", "tag": "pojecie"}, {"id": "f_t3_11", "chapter": "t3", "front": "Depozyt jako aktywo banku", "back": "najczęstszy błąd „od zera\"; depozyt to zobowiązanie banku, aktywem stają się dopiero kredyty z tych środków.", "tag": "pojecie"}, {"id": "f_t4_0", "chapter": "t4", "front": "Analiza techniczna (AT)", "back": "prognozowanie cen z historycznych danych o cenie i wolumenie; ignoruje fundamenty, bo zakłada że są już w cenie.", "tag": "pojecie"}, {"id": "f_t4_1", "chapter": "t4", "front": "Analiza fundamentalna (FA)", "back": "szacuje wartość wewnętrzną spółki ze sprawozdań; AT bada *cenę*, FA — *wartość*.", "tag": "pojecie"}, {"id": "f_t4_2", "chapter": "t4", "front": "Trend", "back": "kierunek ceny: wzrostowy (coraz wyższe szczyty i dołki), spadkowy (coraz niższe), boczny (konsolidacja).", "tag": "pojecie"}, {"id": "f_t4_3", "chapter": "t4", "front": "Wsparcie / opór", "back": "poziom, gdzie popyt zatrzymuje spadki / podaż zatrzymuje wzrosty; po przebiciu zamieniają się rolami.", "tag": "pojecie"}, {"id": "f_t4_4", "chapter": "t4", "front": "LOP (liczba otwartych pozycji, *open interest*)", "back": "liczba nierozliczonych kontraktów na rynku pochodnych; rosnący LOP potwierdza napływ kapitału.", "tag": "pojecie"}, {"id": "f_t4_5", "chapter": "t4", "front": "Wskaźnik (indicator)", "back": "dowolna wartość liczona z ceny lub wolumenu (SMA, RSI, OBV) — pojęcie najszersze.", "tag": "pojecie"}, {"id": "f_t4_6", "chapter": "t4", "front": "Oscylator", "back": "podzbiór wskaźników wahający się w ograniczonym przedziale, mierzy momentum i wykupienie/wyprzedanie (każdy oscylator jest wskaźnikiem, nie odwrotnie).", "tag": "pojecie"}, {"id": "f_t4_7", "chapter": "t4", "front": "Momentum (pęd)", "back": "tempo zmiany ceny; spadające momentum przy rosnącej cenie ostrzega, że trend się męczy.", "tag": "pojecie"}, {"id": "f_t4_8", "chapter": "t4", "front": "Dywergencja", "back": "rozbieżność kierunku ceny i oscylatora; sygnał ostrzegawczy przed odwróceniem.", "tag": "pojecie"}, {"id": "f_t4_9", "chapter": "t4", "front": "Lag (opóźnienie)", "back": "wskaźniki z przeszłych cen reagują *po* zmianie ceny, nie przed — kluczowe ograniczenie AT.", "tag": "pojecie"}, {"id": "f_t4_10", "chapter": "t4", "front": "Mylenie formacji odwrócenia z kontynuacją", "back": "flagi i trójkąty to kontynuacja; głowa z ramionami i podwójny szczyt to odwrócenie.", "tag": "pojecie"}, {"id": "f_t4_11", "chapter": "t4", "front": "Ignorowanie wolumenu", "back": "wybicie bez wolumenu jest niewiarygodne (często *fakeout*); potwierdzeniem jest skok wolumenu.", "tag": "pojecie"}, {"id": "f_t5_0", "chapter": "t5", "front": "Instrument finansowy", "back": "kontrakt tworzący aktywo finansowe u jednej strony, a zobowiązanie lub instrument kapitałowy u drugiej (to relacja prawna, nie rzecz).", "tag": "pojecie"}, {"id": "f_t5_1", "chapter": "t5", "front": "Instrument udziałowy (kapitałowy)", "back": "akcja/udział; roszczenie rezydualne (po wierzycielach), bezterminowe.", "tag": "pojecie"}, {"id": "f_t5_2", "chapter": "t5", "front": "Instrument dłużny", "back": "obligacja, bon, weksel; roszczenie uprzywilejowane, z terminem wykupu.", "tag": "pojecie"}, {"id": "f_t5_3", "chapter": "t5", "front": "Instrument pochodny (derywat)", "back": "instrument, którego wartość zależy od instrumentu bazowego, z niewielkim nakładem początkowym i rozliczeniem w przyszłości.", "tag": "pojecie"}, {"id": "f_t5_4", "chapter": "t5", "front": "Wartość godziwa (fair value, MSSF 13)", "back": "cena sprzedaży (exit price) w uporządkowanej transakcji rynkowej; przy aktywnym rynku równa wartości rynkowej.", "tag": "pojecie"}, {"id": "f_t5_5", "chapter": "t5", "front": "Zamortyzowany koszt", "back": "wartość początkowa korygowana efektywną stopą i odpisem na straty kredytowe; nie reaguje na wahania rynku.", "tag": "pojecie"}, {"id": "f_t5_6", "chapter": "t5", "front": "YTM (rentowność do wykupu)", "back": "rynkowa stopa dyskontowa zrównująca cenę z przepływami (wewnętrzna stopa zwrotu obligacji).", "tag": "pojecie"}, {"id": "f_t5_7", "chapter": "t5", "front": "Duration zmodyfikowana", "back": "miara wrażliwości ceny na zmianę stóp: o ile % spada cena przy wzroście stopy o 1 pkt proc.", "tag": "pojecie"}, {"id": "f_t5_8", "chapter": "t5", "front": "Rynek pieniężny", "back": "instrumenty \\leq 1 rok (bony skarbowe, bony NBP), cel: płynność.", "tag": "pojecie"}, {"id": "f_t5_9", "chapter": "t5", "front": "Rynek kapitałowy / terminowy", "back": "> 1 rok (akcje, obligacje, pozyskanie kapitału) / obrót derywatami (transfer ryzyka, arbitraż).", "tag": "pojecie"}, {"id": "f_t6_0", "chapter": "t6", "front": "Operacja bankowa", "back": "czynność banku tworząca stosunek prawny (prawa i obowiązki) z klientem.", "tag": "pojecie"}, {"id": "f_t6_1", "chapter": "t6", "front": "Depozyt jest dla banku tani, kredyt drogi", "back": "bank żyje z różnicy (zalążek marży odsetkowej).", "tag": "pojecie"}, {"id": "f_t6_2", "chapter": "t6", "front": "Operacje bierne (pasywne)", "back": "gromadzenie środków; bank jest dłużnikiem klienta (lokaty, rachunki, emisja własnych papierów); po stronie pasywów.", "tag": "pojecie"}, {"id": "f_t6_3", "chapter": "t6", "front": "Operacje czynne (aktywne)", "back": "wykorzystanie środków; bank jest wierzycielem (kredyty, pożyczki, gwarancje); po stronie aktywów.", "tag": "pojecie"}, {"id": "f_t6_4", "chapter": "t6", "front": "Operacje pośredniczące", "back": "przepływ pieniędzy za prowizję, neutralne bilansowo (przelewy, karty, wymiana walut, usługi inwestycyjne).", "tag": "pojecie"}, {"id": "f_t6_5", "chapter": "t6", "front": "Produkt bankowy", "back": "wystandaryzowana, powtarzalna oferta zostawiająca ślad w bilansie (kredyt, lokata, karta).", "tag": "pojecie"}, {"id": "f_t6_6", "chapter": "t6", "front": "Usługa bankowa", "back": "czynność na zlecenie klienta dająca zwykle dochód prowizyjny (rozliczenia, doradztwo, przechowanie).", "tag": "pojecie"}, {"id": "f_t6_7", "chapter": "t6", "front": "Czynności bankowe", "back": "kategoria prawna: sensu stricto (art. 5 ust. 1 — zastrzeżone dla banków: wkłady, rachunki, kredyty, gwarancje, e-pieniądz) i sensu largo (art. 5 ust. 2 — bankowe tylko, gdy wykonuje je bank: pożyczki, karty, nabywanie wierzytelności).", "tag": "pojecie"}, {"id": "f_t6_8", "chapter": "t6", "front": "Pieniądz elektroniczny", "back": "przedpłacona wartość przechowywana elektronicznie, wydana w zamian za środki, akceptowana przez podmioty inne niż wydawca, z obowiązkiem wykupu po nominale (EMD2; ustawa o usługach płatniczych [zweryfikuj akt]).", "tag": "pojecie"}, {"id": "f_t6_9", "chapter": "t6", "front": "Underwriting (gwarantowanie emisji)", "back": "organizacja emisji + zobowiązanie do objęcia papierów; subemisja inwestycyjna (bank obejmuje resztę nieobjętą) lub usługowa (obejmuje całość i odsprzedaje).", "tag": "pojecie"}, {"id": "f_t6_10", "chapter": "t6", "front": "Nie myl „czynne\" z aktywnością klienta", "back": "„czynne\" odnosi się do banku (bank wierzycielem); kredyt = czynna. Przyporządkowanie kredytu do biernych to sygnał, że mylisz stronę bilansu.", "tag": "pojecie"}, {"id": "f_t7_0", "chapter": "t7", "front": "Zdarzenie losowe", "back": "coś, co może zajść albo nie, i czego dla pojedynczej osoby nie da się pewnie przewidzieć (pożar, śmierć, wypadek).", "tag": "pojecie"}, {"id": "f_t7_1", "chapter": "t7", "front": "Ryzyko", "back": "możliwość zajścia zdarzenia losowego powodującego stratę; da się je opisać liczbowo prawdopodobieństwem.", "tag": "pojecie"}, {"id": "f_t7_2", "chapter": "t7", "front": "Prawdopodobieństwo $q$", "back": "liczba z przedziału 0 \\leq q \\leq 1 mówiąca, jak często zdarzenie zachodzi w dużej grupie (np. z tablic trwania życia).", "tag": "pojecie"}, {"id": "f_t7_3", "chapter": "t7", "front": "Wartość oczekiwana $E[X]$", "back": "przeciętny wynik losowy ważony prawdopodobieństwami; dla wypłaty S z szansą q wynosi q \\cdot S.", "tag": "pojecie"}, {"id": "f_t7_4", "chapter": "t7", "front": "Awersja do ryzyka", "back": "wolimy pewne 100 zł niż loterię o tej samej wartości oczekiwanej; to dlatego płacimy składkę.", "tag": "pojecie"}, {"id": "f_t7_5", "chapter": "t7", "front": "Ubezpieczenie", "back": "gromadzenie funduszu ze składek wielu podmiotów narażonych na podobne ryzyko i wypłacanie świadczeń tym, których dotknęło zdarzenie losowe (transfer i rozłożenie ryzyka).", "tag": "pojecie"}, {"id": "f_t7_6", "chapter": "t7", "front": "Składka", "back": "cena ochrony; ekwiwalent przyjętego ryzyka (skryptowo: „powinna odpowiadać wielkości ryzyka\").", "tag": "pojecie"}, {"id": "f_t7_7", "chapter": "t7", "front": "Suma ubezpieczenia", "back": "górna granica odpowiedzialności zakładu (maksymalna wypłata).", "tag": "pojecie"}, {"id": "f_t7_8", "chapter": "t7", "front": "Świadczenie / odszkodowanie", "back": "wypłata po zdarzeniu (świadczenie = ubezpieczenia osobowe; odszkodowanie = majątkowe, kompensuje realną stratę).", "tag": "pojecie"}, {"id": "f_t7_9", "chapter": "t7", "front": "Zasada ekwiwalentności", "back": "łączne składki muszą w wartości oczekiwanej pokryć łączne świadczenia + koszty + zysk.", "tag": "pojecie"}, {"id": "f_t7_10", "chapter": "t7", "front": "Rezerwy techniczno-ubezpieczeniowe", "back": "zobowiązania zakładu wobec przyszłych świadczeń; główny składnik pasywów i podstawa jego siły inwestycyjnej.", "tag": "pojecie"}, {"id": "f_t7_11", "chapter": "t7", "front": "Antyselekcja (selekcja negatywna)", "back": "przy uśrednionej cenie pulę zalewają klienci o ryzyku wyższym niż średnia (problem przed umową); lekarstwo: underwriting i obowiązkowość OC.", "tag": "pojecie"}, {"id": "f_t8_0", "chapter": "t8", "front": "Rachunkowość finansowa", "back": "obligatoryjny, regulowany (ustawa o rachunkowości / MSR-MSSF) system ewidencji dla odbiorców zewnętrznych; wyłącznie miernik pieniężny, dane historyczne.", "tag": "pojecie"}, {"id": "f_t8_1", "chapter": "t8", "front": "Rachunkowość zarządcza", "back": "wewnętrzny, fakultatywny (dobrowolny) system informacji pod decyzje menedżerskie; nieregulowana, zorientowana na przyszłość, używa też danych niepieniężnych.", "tag": "pojecie"}, {"id": "f_t8_2", "chapter": "t8", "front": "Controlling", "back": "proces koordynacji planowania, sterowania i kontroli oraz zasilania w informacje; strategiczny („robić właściwe rzeczy\") vs operacyjny („robić rzeczy właściwie\").", "tag": "pojecie"}, {"id": "f_t8_3", "chapter": "t8", "front": "Controlling finansowy", "back": "odmiana skupiona na płynności, wyniku, strukturze kapitału, rentowności (cash flow, EBIT, ROI), obejmuje budżetowanie, analizę odchyleń, KPI i sprawozdania pro forma.", "tag": "pojecie"}, {"id": "f_t8_4", "chapter": "t8", "front": "Rachunek kosztów", "back": "system gromadzenia i kalkulacji kosztów w przekrojach: rodzajowym, miejsc powstawania (MPK), nośników/produktów.", "tag": "pojecie"}, {"id": "f_t8_5", "chapter": "t8", "front": "Próg rentowności (BEP)", "back": "wielkość sprzedaży, przy której wynik = 0 (to NIE punkt maksymalnego zysku).", "tag": "pojecie"}, {"id": "f_t8_6", "chapter": "t8", "front": "Margines bezpieczeństwa", "back": "o ile sprzedaż może spaść względem planu, zanim pojawi się strata.", "tag": "pojecie"}, {"id": "f_t8_7", "chapter": "t8", "front": "Odchylenie (variance)", "back": "różnica plan/standard a rzeczywistość; rozkładana na część cenową i ilościową.", "tag": "pojecie"}, {"id": "f_t8_8", "chapter": "t8", "front": "Koszt istotny (relevant)", "back": "taki, który różni się między wariantami i jest przyszły; tylko on wchodzi do rachunku decyzyjnego.", "tag": "pojecie"}, {"id": "f_t8_9", "chapter": "t8", "front": "Nie myl „pełne/zmienne\" ze „stałe/zmienne\"", "back": "pierwsze to *systemy rachunku kosztów* (sposób przypisania), drugie to *rodzaje kosztów* (reakcja na wolumen). To różne poziomy pojęciowe.", "tag": "pojecie"}, {"id": "f_t8_10", "chapter": "t8", "front": "Nie myl „bezpośredni/pośredni\" ze „stały/zmienny\"", "back": "niezależne wymiary; amortyzacja maszyny dedykowanej jest bezpośrednia i stała.", "tag": "pojecie"}, {"id": "f_t9_0", "chapter": "t9", "front": "Budżet", "back": "plan finansowy ujęty ilościowo i wartościowo, przypisany ośrodkom odpowiedzialności na dany okres; narzędzie alokacji i kontroli.", "tag": "pojecie"}, {"id": "f_t9_1", "chapter": "t9", "front": "Budżet wiodący (master budget)", "back": "zintegrowany zestaw budżetów cząstkowych: część operacyjna (sprzedaż → produkcja → koszty → prognozowany RZiS) i finansowa (budżet kasowy + prognozowany bilans).", "tag": "pojecie"}, {"id": "f_t9_2", "chapter": "t9", "front": "Prognoza (*forecast*) vs budżet", "back": "budżet to zatwierdzony cel/zobowiązanie (stały), prognoza to bieżące najlepsze oszacowanie (aktualizowane); mylenie ich to klasyczny błąd.", "tag": "pojecie"}, {"id": "f_t9_3", "chapter": "t9", "front": "ΔKON (nakład na kapitał obrotowy)", "back": "przyrost kapitału obrotowego (\\Delta = zmiana); w przepływach to wypływ gotówki przy wzroście, wpływ przy spadku.", "tag": "pojecie"}, {"id": "f_t9_4", "chapter": "t9", "front": "CCC (cykl konwersji gotówki)", "back": "DSO + DIO - DPO; liczba dni od zapłaty za surowiec do inkasa od klienta.", "tag": "pojecie"}, {"id": "f_t9_5", "chapter": "t9", "front": "DSO / DIO / DPO", "back": "w dniach: ściąganie należności, rotacja zapasów, spłata zobowiązań.", "tag": "pojecie"}, {"id": "f_t9_6", "chapter": "t9", "front": "Próg rentowności (BEP)", "back": "sprzedaż, przy której marża pokrycia dokładnie pokrywa koszty stałe (wynik = 0); marża pokrycia = przychód − koszty zmienne.", "tag": "pojecie"}, {"id": "f_t9_7", "chapter": "t9", "front": "Analiza odchyleń", "back": "porównanie planu z wykonaniem i rozbicie różnicy na odchylenie cenowe i ilościowe; korzystne (F) poprawia wynik, niekorzystne (U) pogarsza.", "tag": "pojecie"}, {"id": "f_t9_8", "chapter": "t9", "front": "Budżet sztywny vs elastyczny / przyrostowy vs ZBB", "back": "sztywny dla jednego poziomu, elastyczny przeskalowany do faktycznego wolumenu; przyrostowy wychodzi od ubiegłego okresu ± korekta, ZBB (*zero-based budgeting*) każe uzasadnić każdą pozycję od zera.", "tag": "pojecie"}, {"id": "f_t9_9", "chapter": "t9", "front": "Mylenie zysku z gotówką", "back": "najczęstszy błąd; zawsze dodaj, że rentowność nie gwarantuje płynności.", "tag": "pojecie"}, {"id": "f_t9_10", "chapter": "t9", "front": "Gdzie komisja dociska:** rozróżnienie **KON vs WCR", "back": "KON to kategoria bilansowo-finansowa (jak finansowany jest majątek obrotowy), WCR to kategoria operacyjna (ile gotówki zżera cykl). Skrypt operuje samym KON (z zobowiązaniami krótkoterminowymi); WCR podawaj jako precyzyjniejsze ujęcie.", "tag": "pojecie"}, {"id": "f_t9_11", "chapter": "t9", "front": "Dodatnie odchylenie ceny ≠ sukces", "back": "wyższa cena mogła zdławić wolumen; trzeba czytać oba odchylenia łącznie.", "tag": "pojecie"}, {"id": "f_t10_0", "chapter": "t10", "front": "Bilans płatniczy = rachunek kraju z zagranicą", "back": "kto chce kupić nasze towary, musi najpierw kupić naszą walutę (popyt podbija kurs).", "tag": "pojecie"}, {"id": "f_t10_1", "chapter": "t10", "front": "Stopa procentowa = cena pieniądza w czasie", "back": "kapitał płynie tam, gdzie wyższy zwrot, a żeby tam wpłynąć, trzeba kupić tamtejszą walutę.", "tag": "pojecie"}, {"id": "f_t10_2", "chapter": "t10", "front": "Wartość pieniądza w czasie", "back": "1 zł dziś urośnie do 1 \\cdot (1 + r \\cdot \\frac{t}{360}); cały wzór na forward to porównanie dwóch takich „urośnięć\".", "tag": "pojecie"}, {"id": "f_t10_3", "chapter": "t10", "front": "Kurs walutowy", "back": "cena jednej waluty w jednostkach drugiej; w EUR/PLN euro jest bazowe (kupujemy 1 sztukę), złoty kwotowany (w nim podajemy cenę).", "tag": "pojecie"}, {"id": "f_t10_4", "chapter": "t10", "front": "Kurs realny", "back": "kurs nominalny skorygowany o różnice poziomów cen; mierzy faktyczną siłę nabywczą i konkurencyjność, nie samą cyfrę.", "tag": "pojecie"}, {"id": "f_t10_5", "chapter": "t10", "front": "Aprecjacja/deprecjacja", "back": "rynkowy wzrost/spadek wartości waluty w kursie płynnym; rewaluacja/dewaluacja — administracyjna zmiana parytetu w kursie stałym.", "tag": "pojecie"}, {"id": "f_t10_6", "chapter": "t10", "front": "Ryzyko walutowe", "back": "dzieli się na transakcyjne (realne, zakontraktowane przepływy), przeliczeniowe/translacyjne (księgowe, przy konsolidacji spółek) i ekonomiczne (długookresowa konkurencyjność).", "tag": "pojecie"}, {"id": "f_t10_7", "chapter": "t10", "front": "Pozycja walutowa", "back": "różnica między aktywami a pasywami w danej walucie: długa (nadwyżka aktywów, zyskuje na aprecjacji), krótka (nadwyżka pasywów, zyskuje na deprecjacji), zamknięta (równe → brak ryzyka).", "tag": "pojecie"}, {"id": "f_t10_8", "chapter": "t10", "front": "Hedging", "back": "zajęcie pozycji przeciwnej do pierwotnej; cel to redukcja zmienności wyniku, nie maksymalizacja zysku.", "tag": "pojecie"}, {"id": "f_t10_9", "chapter": "t10", "front": "Forex (FX)", "back": "globalny, zdecentralizowany rynek walutowy OTC (poza giełdą); największy na świecie, handel 24h/5 dni, wysoka dźwignia i wysokie ryzyko.", "tag": "pojecie"}, {"id": "f_t10_10", "chapter": "t10", "front": "Kurs spot", "back": "rozliczenie natychmiastowe (T+2); kurs forward — ustalony dziś na dostawę w przyszłości. Punkty swapowe = F - S.", "tag": "pojecie"}, {"id": "f_t10_11", "chapter": "t10", "front": "Aprecjacja ≠ rewaluacja", "back": "pierwsze to ruch rynkowy (kurs płynny), drugie to akt władzy (kurs stały). Nazwa zależy od reżimu kursowego.", "tag": "pojecie"}, {"id": "f_t11_0", "chapter": "t11", "front": "Koszt kapitału", "back": "wymagana stopa zwrotu = stopa dyskontowa = koszt alternatywny (nie wydatek księgowy).", "tag": "pojecie"}, {"id": "f_t11_1", "chapter": "t11", "front": "Beta ($\\beta$)", "back": "miara ryzyka systematycznego (niedywersyfikowalnego); \\beta = 1 jak rynek, > 1 ostrzej, < 1 defensywnie.", "tag": "pojecie"}, {"id": "f_t11_2", "chapter": "t11", "front": "Segmentacja vs integracja rynków", "back": "rynek zintegrowany: liczy się globalna beta i MRP; segmentowany: lokalna beta i MRP. Wybór reżimu zmienia same parametry CAPM.", "tag": "pojecie"}, {"id": "f_t11_3", "chapter": "t11", "front": "Ryzyko walutowe", "back": "dzieli się na transakcyjne (zakontraktowane przepływy), translacyjne (księgowe, konsolidacja, MSR 21) i ekonomiczne (długoterminowy wpływ kursu na konkurencyjność).", "tag": "pojecie"}, {"id": "f_t11_4", "chapter": "t11", "front": "Wagi księgowe zamiast rynkowych", "back": "E to kapitalizacja (cena × liczba akcji), nie bilans; księgowa wartość equity bywa wielokrotnie zaniżona.", "tag": "pojecie"}, {"id": "f_t11_5", "chapter": "t11", "front": "Tarcza $(1-T)$ przy kapitale własnym", "back": "błąd; czynnik stosuje się tylko do K_d, bo dywidendy nie są kosztem uzyskania przychodu.", "tag": "pojecie"}, {"id": "f_t11_6", "chapter": "t11", "front": "Niespójność walutowa", "back": "przepływy EUR dyskontuj WACC-iem w EUR; przeliczenie między walutami przez parytet stóp procentowych (IRP). Gdzie komisja dociska: końcową wartość projektu przewalutuj po kursie spot, nie po stopie — stopy dyskontują w obrębie jednej waluty.", "tag": "pojecie"}, {"id": "f_t11_7", "chapter": "t11", "front": "Podwójne liczenie ryzyka walutowego", "back": "raz w CRP i drugi raz jako osobna „premia walutowa\" zawyża WACC; wybierz jedno albo hedging.", "tag": "pojecie"}, {"id": "f_t11_8", "chapter": "t11", "front": "Beta bez relewarowania", "back": "cudza \\beta_L zależy od cudzego D/E; odlewaruj do \\beta_U, relewaruj do własnej dźwigni (Hamada).", "tag": "pojecie"}, {"id": "f_t12_0", "chapter": "t12", "front": "Instrument bazowy (underlying)", "back": "aktywo, od którego zależy wartość pochodnej (akcja, waluta, stopa, surowiec).", "tag": "pojecie"}, {"id": "f_t12_1", "chapter": "t12", "front": "Long vs short", "back": "long (kupujący) zyskuje, gdy cena rośnie; short (sprzedający) zyskuje, gdy spada.", "tag": "pojecie"}, {"id": "f_t12_2", "chapter": "t12", "front": "Cena spot", "back": "bieżąca cena „na już\": S_0 dziś, S_T w przyszłej dacie T.", "tag": "pojecie"}, {"id": "f_t12_3", "chapter": "t12", "front": "Wartość pieniądza w czasie", "back": "kapitalizacja (1+r)^{T} przesuwa wartość w przyszłość, dyskontowanie e^{-rT} ściąga ją do dziś.", "tag": "pojecie"}, {"id": "f_t12_4", "chapter": "t12", "front": "Trzy cele derywatu", "back": "hedging (zabezpieczenie), spekulacja (otwarcie ekspozycji), arbitraż (bezryzykowy zysk z różnicy cen).", "tag": "pojecie"}, {"id": "f_t12_5", "chapter": "t12", "front": "Forward", "back": "niestandaryzowana umowa OTC (poza giełdą) zobowiązująca obie strony do transakcji po cenie F w dacie T; elastyczna, ale obarczona ryzykiem kontrahenta.", "tag": "pojecie"}, {"id": "f_t12_6", "chapter": "t12", "front": "Futures", "back": "wystandaryzowany forward notowany na giełdzie, z izbą rozliczeniową, depozytem i codziennym mark-to-market.", "tag": "pojecie"}, {"id": "f_t12_7", "chapter": "t12", "front": "Opcja", "back": "daje nabywcy prawo (nie obowiązek) kupna (call) lub sprzedaży (put) po cenie wykonania K; wystawca ma obowiązek, nabywca płaci premię.", "tag": "pojecie"}, {"id": "f_t12_8", "chapter": "t12", "front": "Premia", "back": "cena opcji płacona z góry, zawsze przepada (w odróżnieniu od depozytu w futures, który wraca).", "tag": "pojecie"}, {"id": "f_t12_9", "chapter": "t12", "front": "Strike ($K$)", "back": "cena wykonania opcji.", "tag": "pojecie"}, {"id": "f_t12_10", "chapter": "t12", "front": "ITM/ATM/OTM", "back": "opcja w pieniądzu (opłacalna), przy pieniądzu (S \\approx K), poza pieniądzem (nieopłacalna).", "tag": "pojecie"}, {"id": "f_t12_11", "chapter": "t12", "front": "Wartość wewnętrzna + czasowa", "back": "wewnętrzna to zysk z natychmiastowego wykonania \\max(S-K,0); czasowa to zapłata za szansę dalszego korzystnego ruchu (maleje do zera w dniu wygaśnięcia).", "tag": "pojecie"}, {"id": "f_k1_0", "chapter": "k1", "front": "Jednostka gospodarcza", "back": "wyodrebniony podmiot (firma) prowadzacy dzialalnosc i sporzadzajacy sprawozdania.", "tag": "pojecie"}, {"id": "f_k1_1", "chapter": "k1", "front": "Rok obrotowy / okres sprawozdawczy", "back": "przedzial czasu, za ktory ustala sie wynik finansowy.", "tag": "pojecie"}, {"id": "f_k1_2", "chapter": "k1", "front": "Bilans i rachunek zyskow i strat", "back": "dwa podstawowe elementy sprawozdania finansowego (stan majatku vs. wynik).", "tag": "pojecie"}, {"id": "f_k1_3", "chapter": "k1", "front": "Zasada podwojnego zapisu", "back": "kazda operacja ujeta jednoczesnie po stronie Wn i Ma (rownosc stron).", "tag": "pojecie"}, {"id": "f_k1_4", "chapter": "k1", "front": "Rachunkowosc", "back": "system informacyjny mierzacy i komunikujacy w pieniadzu zdarzenia gospodarcze jednostki na podstawie dowodow ksiegowych.", "tag": "pojecie"}, {"id": "f_k1_5", "chapter": "k1", "front": "Funkcja informacyjna", "back": "dostarczanie danych do decyzji wewnetrznym i zewnetrznym uzytkownikom.", "tag": "pojecie"}, {"id": "f_k1_6", "chapter": "k1", "front": "Funkcja kontrolna", "back": "ochrona majatku i wykrywanie nieprawidlowosci przez ewidencje i inwentaryzacje.", "tag": "pojecie"}, {"id": "f_k1_7", "chapter": "k1", "front": "Funkcja sprawozdawcza", "back": "sporzadzanie sprawozdan finansowych dla otoczenia.", "tag": "pojecie"}, {"id": "f_k1_8", "chapter": "k1", "front": "Funkcja dowodowa", "back": "ksiegi i dowody jako material dowodowy (m.in. w sporach, kontrolach US — Urzad Skarbowy).", "tag": "pojecie"}, {"id": "f_k1_9", "chapter": "k1", "front": "Wynik finansowy", "back": "roznica miedzy przychodami a kosztami danego okresu (zysk lub strata).", "tag": "pojecie"}, {"id": "f_k1_10", "chapter": "k1", "front": "Memorial vs. kasowo", "back": "ujmowanie skutkow zdarzen w momencie ich wystapienia, niezaleznie od przeplywu gotowki (vs. w momencie zaplaty).", "tag": "pojecie"}, {"id": "f_k1_11", "chapter": "k1", "front": "Sprawozdanie finansowe (SF)", "back": "koncowy produkt rachunkowosci: bilans, RZiS, informacja dodatkowa (i in.).", "tag": "pojecie"}, {"id": "f_k2_0", "chapter": "k2", "front": "Koszt historyczny", "back": "wycena wedlug ceny z momentu nabycia/wytworzenia, niezmienianej mimo wahania cen rynkowych.", "tag": "pojecie"}, {"id": "f_k2_1", "chapter": "k2", "front": "Cena nabycia", "back": "cena zakupu skladnika powiekszona o koszty bezposrednio zwiazane z zakupem i przystosowaniem do uzywania, pomniejszona o rabaty.", "tag": "pojecie"}, {"id": "f_k2_2", "chapter": "k2", "front": "Koszt wytworzenia", "back": "koszty bezposrednie produktu plus uzasadniona czesc kosztow posrednich produkcji (bez kosztow zarzadu i sprzedazy).", "tag": "pojecie"}, {"id": "f_k2_3", "chapter": "k2", "front": "Wartosc godziwa (fair value)", "back": "kwota, za jaka skladnik moglby byc wymieniony miedzy zainteresowanymi, dobrze poinformowanymi stronami w transakcji rynkowej.", "tag": "pojecie"}, {"id": "f_k2_4", "chapter": "k2", "front": "Zasada ostroznosci", "back": "wycena unikajaca zawyzania aktywow/przychodow i zanizania zobowiazan/kosztow; ujmuje sie przewidywane straty, a zyski dopiero zrealizowane.", "tag": "pojecie"}, {"id": "f_k2_5", "chapter": "k2", "front": "Trwala utrata wartosci", "back": "odpis aktualizujacy obnizajacy wartosc aktywu, gdy istnieje duze prawdopodobienstwo braku korzysci ekonomicznych.", "tag": "pojecie"}, {"id": "f_k2_6", "chapter": "k2", "front": "Zasada wyzszosci tresci nad forma", "back": "operacje ujmuje sie zgodnie z ekonomiczna trescia, nie tylko forma prawna.", "tag": "pojecie"}, {"id": "f_k2_7", "chapter": "k2", "front": "Zasada kontynuacji dzialalnosci (going concern)", "back": "domniemanie, ze firma bedzie dzialac dalej, co warunkuje sposob wyceny.", "tag": "pojecie"}, {"id": "f_k3_0", "chapter": "k3", "front": "Sprawozdanie finansowe", "back": "bilans (stan na dzień), rachunek zysków i strat (za okres), rachunek przepływów pieniężnych.", "tag": "pojecie"}, {"id": "f_k3_1", "chapter": "k3", "front": "Analiza pozioma (dynamiki)", "back": "porównuje te same pozycje w czasie (np. rok do roku), licząc zmiany kwotowe i tempo wzrostu.", "tag": "pojecie"}, {"id": "f_k3_2", "chapter": "k3", "front": "Analiza pionowa (struktury)", "back": "pokazuje udział każdej pozycji w sumie (np. udział zapasów w aktywach = 100%).", "tag": "pojecie"}, {"id": "f_k3_3", "chapter": "k3", "front": "Płynność finansowa", "back": "zdolność do terminowego regulowania zobowiązań bieżących.", "tag": "pojecie"}, {"id": "f_k3_4", "chapter": "k3", "front": "Wypłacalność / zadłużenie", "back": "relacja kapitału obcego do majątku i kapitału własnego; zdolność do obsługi długu w długim okresie.", "tag": "pojecie"}, {"id": "f_k3_5", "chapter": "k3", "front": "Rentowność", "back": "zdolność do generowania zysku w relacji do sprzedaży, aktywów lub kapitału.", "tag": "pojecie"}, {"id": "f_k3_6", "chapter": "k3", "front": "Sprawność (aktywności)", "back": "efektywność wykorzystania zasobów, mierzona rotacją (obrotem) składników majątku.", "tag": "pojecie"}, {"id": "f_k3_7", "chapter": "k3", "front": "Kapitał obrotowy netto", "back": "nadwyżka aktywów obrotowych nad zobowiązaniami bieżącymi (bufor płynności).", "tag": "pojecie"}, {"id": "f_k3_8", "chapter": "k3", "front": "Model Altmana Z-score", "back": "wielowymiarowa funkcja dyskryminacyjna szacująca prawdopodobieństwo upadłości.", "tag": "pojecie"}, {"id": "f_k4_0", "chapter": "k4", "front": "Układ rodzajowy", "back": "klasyfikacja kosztów wg natury zużytego zasobu (amortyzacja, materiały, wynagrodzenia, usługi obce), niezależnie od miejsca powstania.", "tag": "pojecie"}, {"id": "f_k4_1", "chapter": "k4", "front": "Układ funkcjonalny (kalkulacyjny)", "back": "klasyfikacja wg funkcji/miejsca: koszt wytworzenia, koszty sprzedaży, koszty ogólnego zarządu.", "tag": "pojecie"}, {"id": "f_k4_2", "chapter": "k4", "front": "Koszty stałe (KS)", "back": "nie zmieniają się wraz z wolumenem produkcji w danym przedziale (np. czynsz, amortyzacja liniowa).", "tag": "pojecie"}, {"id": "f_k4_3", "chapter": "k4", "front": "Koszty zmienne (KZ)", "back": "rosną proporcjonalnie do wolumenu (np. materiały bezpośrednie, akord).", "tag": "pojecie"}, {"id": "f_k4_4", "chapter": "k4", "front": "Koszty bezpośrednie", "back": "dające się wprost i ekonomicznie przypisać do wyrobu (materiał, robocizna bezpośrednia).", "tag": "pojecie"}, {"id": "f_k4_5", "chapter": "k4", "front": "Koszty pośrednie", "back": "wspólne dla wielu wyrobów, wymagające rozliczenia kluczem (koszty wydziałowe).", "tag": "pojecie"}, {"id": "f_k4_6", "chapter": "k4", "front": "Rachunek kosztów pełnych (RKP, absorpcyjny)", "back": "koszt wytworzenia wyrobu obejmuje koszty zmienne ORAZ stałe koszty produkcji.", "tag": "pojecie"}, {"id": "f_k4_7", "chapter": "k4", "front": "Rachunek kosztów zmiennych (RKZ)", "back": "kosztem wyrobu są tylko koszty zmienne; stałe koszty produkcji traktowane jako koszt okresu.", "tag": "pojecie"}, {"id": "f_k4_8", "chapter": "k4", "front": "Marża pokrycia (CM, contribution margin)", "back": "przychód minus koszty zmienne; „pokrywa\" koszty stałe i tworzy zysk.", "tag": "pojecie"}, {"id": "f_k4_9", "chapter": "k4", "front": "Próg rentowności (BEP, break-even point)", "back": "wolumen/przychód, przy którym zysk = 0.", "tag": "pojecie"}, {"id": "f_k4_10", "chapter": "k4", "front": "Dźwignia operacyjna (DOL)", "back": "miara wrażliwości zysku operacyjnego na zmianę sprzedaży, napędzana udziałem kosztów stałych.", "tag": "pojecie"}, {"id": "f_k5_0", "chapter": "k5", "front": "Wartosc przyszla (FV, future value)", "back": "kwota, do jakiej urosnie dzisiejszy kapital po kapitalizacji odsetek.", "tag": "pojecie"}, {"id": "f_k5_1", "chapter": "k5", "front": "Wartosc biezaca (PV, present value)", "back": "dzisiejsza rownowartosc przyszlej kwoty po zdyskontowaniu.", "tag": "pojecie"}, {"id": "f_k5_2", "chapter": "k5", "front": "Dyskontowanie", "back": "sprowadzanie przyszlych przeplywow do terazniejszosci za pomoca stopy dyskontowej.", "tag": "pojecie"}, {"id": "f_k5_3", "chapter": "k5", "front": "Renta (annuity)", "back": "ciag rownych platnosci w stalych odstepach czasu (np. raty, czynsze).", "tag": "pojecie"}, {"id": "f_k5_4", "chapter": "k5", "front": "Renta wieczysta (perpetuity)", "back": "renta o nieskonczonym horyzoncie platnosci.", "tag": "pojecie"}, {"id": "f_k5_5", "chapter": "k5", "front": "NPV (net present value, wartosc biezaca netto)", "back": "suma zdyskontowanych przeplywow minus naklad poczatkowy.", "tag": "pojecie"}, {"id": "f_k5_6", "chapter": "k5", "front": "IRR (internal rate of return, wewnetrzna stopa zwrotu)", "back": "stopa, przy ktorej NPV = 0.", "tag": "pojecie"}, {"id": "f_k5_7", "chapter": "k5", "front": "Okres zwrotu (payback period)", "back": "czas, po ktorym skumulowane wplywy pokryja naklad.", "tag": "pojecie"}, {"id": "f_k5_8", "chapter": "k5", "front": "ARR (accounting rate of return, ksiegowa stopa zwrotu)", "back": "sredni zysk ksiegowy do sredniego/poczatkowego nakladu.", "tag": "pojecie"}, {"id": "f_k5_9", "chapter": "k5", "front": "Wskaznik rentownosci (PI, profitability index)", "back": "relacja zdyskontowanych wplywow do nakladu.", "tag": "pojecie"}, {"id": "f_k6_0", "chapter": "k6", "front": "Bilans", "back": "aktywa (majatek) = pasywa (kapital wlasny + zobowiazania); pasywa pokazuja, skad pochodzi finansowanie.", "tag": "pojecie"}, {"id": "f_k6_1", "chapter": "k6", "front": "Wartosc pieniadza w czasie", "back": "zlotowka dzis jest warta wiecej niz jutro — przyszle przeplywy dyskontujemy stopa.", "tag": "pojecie"}, {"id": "f_k6_2", "chapter": "k6", "front": "Stopa zwrotu i dyskonto", "back": "koszt kapitalu to stopa, ktora oczekuja dawcy finansowania.", "tag": "pojecie"}, {"id": "f_k6_3", "chapter": "k6", "front": "Dzwignia", "back": "dlug zwieksza zwrot dla wlascicieli, ale i zmiennosc wyniku (ryzyko).", "tag": "pojecie"}, {"id": "f_k6_4", "chapter": "k6", "front": "Kapital wlasny (equity)", "back": "srodki wlascicieli (akcje, udzialy, zysk zatrzymany); brak obowiazku zwrotu, ale uprawnia do udzialu w zysku.", "tag": "pojecie"}, {"id": "f_k6_5", "chapter": "k6", "front": "Kapital obcy (dlug)", "back": "pozyczony, zwrotny i oprocentowany (kredyty, obligacje); ma pierwszenstwo przed wlascicielami.", "tag": "pojecie"}, {"id": "f_k6_6", "chapter": "k6", "front": "Finansowanie krotkoterminowe", "back": "zapadalnosc \\leq 1 rok (kredyt obrotowy, kredyt kupiecki, faktoring); finansuje majatek obrotowy.", "tag": "pojecie"}, {"id": "f_k6_7", "chapter": "k6", "front": "Finansowanie dlugoterminowe", "back": "zapadalnosc > 1 rok (kredyt inwestycyjny, obligacje, emisja akcji, leasing); finansuje majatek trwaly.", "tag": "pojecie"}, {"id": "f_k6_8", "chapter": "k6", "front": "Koszt kapitalu", "back": "stopa zwrotu wymagana przez dawcow kapitalu; dla firmy — koszt pozyskania finansowania.", "tag": "pojecie"}, {"id": "f_k6_9", "chapter": "k6", "front": "Koszt dlugu ($k_d$)", "back": "efektywne oprocentowanie zobowiazan po uwzglednieniu tarczy podatkowej.", "tag": "pojecie"}, {"id": "f_k6_10", "chapter": "k6", "front": "Koszt kapitalu wlasnego ($k_e$)", "back": "stopa zwrotu oczekiwana przez wlascicieli, zwykle szacowana modelem CAPM (Capital Asset Pricing Model).", "tag": "pojecie"}, {"id": "f_k6_11", "chapter": "k6", "front": "Tarcza podatkowa", "back": "oszczednosc podatkowa, bo odsetki obnizaja podstawe opodatkowania (CIT).", "tag": "pojecie"}, {"id": "f_k7_0", "chapter": "k7", "front": "Kapital obrotowy netto (KON)", "back": "czesc aktywow obrotowych finansowana kapitalem stalym; bufor plynnosci.", "tag": "pojecie"}, {"id": "f_k7_1", "chapter": "k7", "front": "Kapital staly", "back": "kapital wlasny powiekszony o zobowiazania dlugoterminowe (zrodla finansowania na ponad 1 rok).", "tag": "pojecie"}, {"id": "f_k7_2", "chapter": "k7", "front": "Plynnosc finansowa", "back": "zdolnosc do terminowego regulowania zobowiazan krotkoterminowych.", "tag": "pojecie"}, {"id": "f_k7_3", "chapter": "k7", "front": "Cykl konwersji gotowki (CCC, cash conversion cycle)", "back": "liczba dni od zaplaty za zapasy do inkasa naleznosci od klienta.", "tag": "pojecie"}, {"id": "f_k7_4", "chapter": "k7", "front": "Cykl operacyjny", "back": "suma okresu rotacji zapasow i okresu sciagania naleznosci (od zakupu zapasow do inkasa).", "tag": "pojecie"}, {"id": "f_k7_5", "chapter": "k7", "front": "Naleznosci krotkoterminowe", "back": "kwoty naleznne firmie od odbiorcow (kredyt kupiecki udzielony klientom).", "tag": "pojecie"}, {"id": "f_k7_6", "chapter": "k7", "front": "Zapasy", "back": "materialy, produkcja w toku i wyroby gotowe utrzymywane przez firme.", "tag": "pojecie"}, {"id": "f_k7_7", "chapter": "k7", "front": "Zobowiazania krotkoterminowe", "back": "dlugi firmy wymagalne w ciagu roku (m.in. kredyt kupiecki od dostawcow).", "tag": "pojecie"}, {"id": "f_k7_8", "chapter": "k7", "front": "Strategia agresywna/umiarkowana/konserwatywna", "back": "poziom KON odpowiednio niski (lub ujemny)/sredni/wysoki, czyli zaleznosc od finansowania krotkoterminowego.", "tag": "pojecie"}, {"id": "f_k8_0", "chapter": "k8", "front": "Koszt kapitalu", "back": "stopa zwrotu wymagana przez dawcow kapitalu (wlasciciele + wierzyciele).", "tag": "pojecie"}, {"id": "f_k8_1", "chapter": "k8", "front": "Roznica wartosc vs cena", "back": "wartosc to szacunek analityka, cena to wynik transakcji rynkowej.", "tag": "pojecie"}, {"id": "f_k8_2", "chapter": "k8", "front": "Mnoznik", "back": "wskaznik rynkowy (np. P/E, EV/EBITDA) odnoszacy cene/wartosc do miary wyniku, sluzacy wycenie porownawczej.", "tag": "pojecie"}, {"id": "f_k9_0", "chapter": "k9", "front": "Ryzyko vs stopa zwrotu", "back": "wyzsze ryzyko = oczekiwana wyzsza premia.", "tag": "pojecie"}, {"id": "f_k9_1", "chapter": "k9", "front": "Plynnosc", "back": "zdolnosc szybkiej zamiany aktywa na gotowke bez utraty wartosci.", "tag": "pojecie"}, {"id": "f_k9_2", "chapter": "k9", "front": "Instrument finansowy", "back": "kontrakt, ktory u jednej strony tworzy aktywo finansowe, a u drugiej zobowiazanie lub instrument kapitalowy.", "tag": "pojecie"}, {"id": "f_k9_3", "chapter": "k9", "front": "Rynek pieniezny", "back": "segment instrumentow krotkoterminowych (do 1 roku), o wysokiej plynnosci i niskim ryzyku (np. bony skarbowe, lokaty miedzybankowe).", "tag": "pojecie"}, {"id": "f_k9_4", "chapter": "k9", "front": "Rynek kapitalowy", "back": "segment instrumentow dlugoterminowych (powyzej 1 roku): akcje i obligacje, finansuje rozwoj.", "tag": "pojecie"}, {"id": "f_k9_5", "chapter": "k9", "front": "Rynek pierwotny", "back": "emitent sprzedaje instrument po raz pierwszy i pozyskuje kapital (np. IPO).", "tag": "pojecie"}, {"id": "f_k9_6", "chapter": "k9", "front": "Rynek wtorny", "back": "obrot juz wyemitowanymi instrumentami miedzy inwestorami; zapewnia plynnosc (np. GPW).", "tag": "pojecie"}, {"id": "f_k9_7", "chapter": "k9", "front": "Instrument dluzny", "back": "potwierdza wierzytelnosc; emitent (dluznik) zobowiazuje sie do zwrotu kapitalu i odsetek (obligacja, bon).", "tag": "pojecie"}, {"id": "f_k9_8", "chapter": "k9", "front": "Instrument udzialowy", "back": "daje prawo wlasnosci i udzial w zysku (akcja, dywidenda).", "tag": "pojecie"}, {"id": "f_k9_9", "chapter": "k9", "front": "Instrument pochodny (derywat)", "back": "jego wartosc zalezy od ceny instrumentu bazowego (akcji, waluty, indeksu, surowca).", "tag": "pojecie"}, {"id": "f_k9_10", "chapter": "k9", "front": "Rynek walutowy (FOREX)", "back": "obrot walutami; ustala kurs wymiany jednej waluty na druga.", "tag": "pojecie"}, {"id": "f_k9_11", "chapter": "k9", "front": "Kurs walutowy", "back": "cena jednej waluty wyrazona w innej (np. EUR/PLN).", "tag": "pojecie"}, {"id": "f_k10_0", "chapter": "k10", "front": "Inflacja", "back": "trwaly wzrost przecietnego poziomu cen, mierzony wskaznikiem CPI.", "tag": "pojecie"}, {"id": "f_k10_1", "chapter": "k10", "front": "Budzet panstwa", "back": "plan dochodow i wydatkow; pojecia deficytu i dlugu publicznego.", "tag": "pojecie"}, {"id": "f_k10_2", "chapter": "k10", "front": "System dwuszczeblowy", "back": "model bankowosci, w ktorym oddzielono bank centralny (I szczebel) od bankow komercyjnych (II szczebel).", "tag": "pojecie"}, {"id": "f_k10_3", "chapter": "k10", "front": "NBP (Narodowy Bank Polski)", "back": "bank centralny RP, niezalezny od rzadu, odpowiedzialny za polityke pieniezna i emisje pieniadza.", "tag": "pojecie"}, {"id": "f_k10_4", "chapter": "k10", "front": "RPP (Rada Polityki Pienieznej)", "back": "organ NBP ustalajacy wysokosc stop procentowych i zalozenia polityki pienieznej.", "tag": "pojecie"}, {"id": "f_k10_5", "chapter": "k10", "front": "Emisja pieniadza", "back": "wylaczne prawo banku centralnego do wprowadzania do obiegu znakow pienieznych (monopol emisyjny).", "tag": "pojecie"}, {"id": "f_k10_6", "chapter": "k10", "front": "Stopa referencyjna", "back": "podstawowa stopa NBP wyznaczajaca rentownosc operacji otwartego rynku i poziom rynkowych stop (np. WIBOR).", "tag": "pojecie"}, {"id": "f_k10_7", "chapter": "k10", "front": "Rezerwa obowiazkowa", "back": "czesc depozytow, ktora bank komercyjny musi utrzymywac na rachunku w NBP (nie moze jej pozyczyc dalej).", "tag": "pojecie"}, {"id": "f_k10_8", "chapter": "k10", "front": "Operacje otwartego rynku (OOR)", "back": "kupno/sprzedaz papierow wartosciowych przez bank centralny w celu sterowania plynnoscia sektora bankowego.", "tag": "pojecie"}, {"id": "f_k10_9", "chapter": "k10", "front": "Polityka pieniezna (monetarna)", "back": "oddzialywanie banku centralnego na podaz pieniadza i stopy procentowe.", "tag": "pojecie"}, {"id": "f_k10_10", "chapter": "k10", "front": "Polityka fiskalna (budzetowa)", "back": "oddzialywanie rzadu na gospodarke przez podatki i wydatki budzetowe.", "tag": "pojecie"}, {"id": "f_k10_11", "chapter": "k10", "front": "Mnoznik kreacji pieniadza", "back": "wskaznik mowiacy, ile razy depozyt poczatkowy mnozy sie w systemie bankowym.", "tag": "pojecie"}, {"id": "f_k11_0", "chapter": "k11", "front": "Sektor finansów publicznych (SFP)", "back": "zamknięty, ustawowy katalog podmiotów: organy władzy, jednostki samorządu terytorialnego (JST), ZUS, KRUS, NFZ, uczelnie publiczne, jednostki i zakłady budżetowe.", "tag": "pojecie"}, {"id": "f_k11_1", "chapter": "k11", "front": "Dochody budżetowe", "back": "wpływy bezzwrotne i definitywne (głównie podatki, cła, opłaty); nie trzeba ich oddawać.", "tag": "pojecie"}, {"id": "f_k11_2", "chapter": "k11", "front": "Przychody budżetowe", "back": "wpływy zwrotne, finansujące deficyt (emisja obligacji, kredyty, prywatyzacja).", "tag": "pojecie"}, {"id": "f_k11_3", "chapter": "k11", "front": "Wydatki budżetowe", "back": "kwoty przeznaczone na realizację zadań państwa (bieżące, majątkowe, transfery, obsługa długu).", "tag": "pojecie"}, {"id": "f_k11_4", "chapter": "k11", "front": "Procedura budżetowa", "back": "całość czynności tworzenia, uchwalania, wykonania i kontroli budżetu w cyklu rocznym.", "tag": "pojecie"}, {"id": "f_k11_5", "chapter": "k11", "front": "Podatki bezpośrednie", "back": "obciążają wprost dochód/majątek podatnika (PIT, CIT, podatek od nieruchomości).", "tag": "pojecie"}, {"id": "f_k11_6", "chapter": "k11", "front": "Podatki pośrednie", "back": "wliczone w cenę, płaci je konsument (VAT — podatek od towarów i usług, akcyza).", "tag": "pojecie"}, {"id": "f_k11_7", "chapter": "k11", "front": "Funkcje podatków", "back": "fiskalna (dochody budżetu), redystrybucyjna (podział dochodów), stymulacyjna (zachęty/ulgi).", "tag": "pojecie"}, {"id": "f_k11_8", "chapter": "k11", "front": "Zasady podatkowe (A. Smith)", "back": "równość, pewność, dogodność, taniość poboru.", "tag": "pojecie"}, {"id": "f_k11_9", "chapter": "k11", "front": "Deficyt budżetowy", "back": "ujemna różnica między dochodami a wydatkami w danym roku.", "tag": "pojecie"}, {"id": "f_k11_10", "chapter": "k11", "front": "Gdzie komisja dociska:** różnica **sektor publiczny ≠ SFP", "back": "spółki Skarbu Państwa są w sektorze publicznym, ale NIE w SFP (działają na zasadach rynkowych).", "tag": "pojecie"}, {"id": "f_k11_11", "chapter": "k11", "front": "Gdzie komisja dociska:** kto faktycznie ponosi ciężar **VAT", "back": "formalnie płaci przedsiębiorca, ale ekonomicznie obciąża konsumenta (przerzucalność podatku pośredniego).", "tag": "pojecie"}, {"id": "f_k12_0", "chapter": "k12", "front": "Ruch okrezny dochodu", "back": "gospodarstwa, firmy, panstwo i zagranica wymieniaja sie dobrami i pieniadzem.", "tag": "pojecie"}, {"id": "f_k12_1", "chapter": "k12", "front": "PKB (Produkt Krajowy Brutto)", "back": "wartosc dobr i uslug finalnych wytworzonych na terytorium kraju w danym okresie (kryterium geograficzne).", "tag": "pojecie"}, {"id": "f_k12_2", "chapter": "k12", "front": "PNB / DNB (Produkt/Dochod Narodowy Brutto)", "back": "dochod wytworzony przez obywateli/rezydentow kraju, niezaleznie od miejsca (kryterium wlasnosciowe).", "tag": "pojecie"}, {"id": "f_k12_3", "chapter": "k12", "front": "Bilans platniczy", "back": "zestawienie wszystkich transakcji rezydentow z zagranica (rachunek biezacy + kapitalowy + finansowy).", "tag": "pojecie"}, {"id": "f_k12_4", "chapter": "k12", "front": "Kurs walutowy", "back": "cena jednej waluty wyrazona w drugiej; deprecjacja to spadek wartosci waluty, aprecjacja to wzrost.", "tag": "pojecie"}, {"id": "f_k12_5", "chapter": "k12", "front": "Cykl koniunkturalny", "back": "wahania aktywnosci gospodarczej wokol trendu: ozywienie, szczyt (boom), recesja, dno.", "tag": "pojecie"}, {"id": "f_k12_6", "chapter": "k12", "front": "Inflacja", "back": "trwaly wzrost ogolnego poziomu cen; deflacja to jego spadek; mierzona indeksem CPI (Consumer Price Index).", "tag": "pojecie"}, {"id": "f_k12_7", "chapter": "k12", "front": "Bezrobocie", "back": "odsetek osob aktywnych zawodowo bez pracy, ale jej poszukujacych.", "tag": "pojecie"}, {"id": "f_k12_8", "chapter": "k12", "front": "Stopa oszczednosci", "back": "czesc dochodu nieprzeznaczona na konsumpcje; zrodlo finansowania inwestycji.", "tag": "pojecie"}, {"id": "f_k12_9", "chapter": "k12", "front": "Gospodarka otwarta", "back": "gospodarka prowadzaca wymiane handlowa i kapitalowa z zagranica (eksport, import, przeplywy kapitalu).", "tag": "pojecie"}, {"id": "f_k12_10", "chapter": "k12", "front": "Rodzaje inflacji", "back": "popytowa (zbyt duzy popyt), kosztowa/podazowa (wzrost kosztow, np. surowcow). Skutek dla finansisty: inflacja obniza realna stope zwrotu i wartosc naleznosci o stalym oprocentowaniu.", "tag": "pojecie"}, {"id": "f_k12_11", "chapter": "k12", "front": "Rodzaje bezrobocia", "back": "frykcyjne (zmiana pracy), strukturalne (niedopasowanie kwalifikacji), cykliczne (recesja). Bezrobocie naturalne = frykcyjne + strukturalne; przy nim gospodarka jest \"przy pelnym zatrudnieniu\".", "tag": "pojecie"}], "quiz": [{"id": "q_t1_0", "chapter": "t1", "q": "Co znaczy „VaR = 1 mln, 99%, 1 dzień\"?", "a": "Z prawdopodobieństwem 99% strata dzienna nie przekroczy 1 mln zł; równoważnie średnio 1 dzień na 100 będzie gorszy. To kwantyl rozkładu strat, nie strata maksymalna.", "type": "open"}, {"id": "q_t1_1", "chapter": "t1", "q": "Po co Expected Shortfall, skoro mamy VaR?", "a": "Bo VaR podaje tylko próg, a milczy, jak głęboki jest ogon. ES = średnia strata po przekroczeniu VaR i jest miarą koherentną (subaddytywną) — dlatego FRTB przechodzi z VaR na ES (97,5%).", "type": "open"}, {"id": "q_t1_2", "chapter": "t1", "q": "Jak rezerwa obowiązkowa wpływa na kreację pieniądza?", "a": "Zamrożone w NBP środki nie mogą być pożyczone dalej; im wyższa stopa r, tym mniejszy mnożnik m = 1/r i mniejsza akcja kredytowa. To instrument polityki pieniężnej RPP (stopa [zweryfikuj]).", "type": "open"}, {"id": "q_t1_3", "chapter": "t1", "q": "Trzy metody VaR i ich wady?", "a": "Parametryczna (szybka, zaniża grube ogony, zawodzi przy opcjach); historyczna (zero założeń o rozkładzie, ale zakłada powtórkę przeszłości); Monte Carlo (najogólniejsza, radzi sobie z opcjami, ale kosztowna i wrażliwa na model).", "type": "open"}, {"id": "q_t2_4", "chapter": "t2", "q": "Wymień 5 C kredytu i przypisz do parametru ryzyka.", "a": "Character (wiarygodność) → PD; Capacity (zdolność spłaty z przepływów) → PD; Capital („skóra w grze\") → bufor; Collateral (zabezpieczenie) → LGD; Conditions (otoczenie makro) → ryzyko systemowe.", "type": "open"}, {"id": "q_t2_5", "chapter": "t2", "q": "Policz EL dla PD = 3%, LGD = 40%, EAD = 1 mln zł.", "a": "EL = 0{,}03 \\times 0{,}40 \\times 1\\,000\\,000 = 12\\,000 zł rocznie. Pokrywa się ją rezerwą i marżą, a stratę nieoczekiwaną — kapitałem.", "type": "open"}, {"id": "q_t2_6", "chapter": "t2", "q": "Co pokrywa stratę nieoczekiwaną?", "a": "**Kapitał** banku (nie rezerwa). Rezerwy i marża pokrywają tylko stratę oczekiwaną (EL); kapitał pokrywa ogon rozkładu strat (UL, Credit VaR) — to fundament Bazylei.", "type": "open"}, {"id": "q_t2_7", "chapter": "t2", "q": "Czym model strukturalny różni się od scoringowego?", "a": "Scoringowy jest statystyczny — uczy się z historycznych danych o klientach i przewiduje default, nie tłumacząc przyczyny (PD = \\frac{1}{1+e^{-z}}). Strukturalny (Merton/KMV) wyprowadza PD z przyczyny ekonomicznej: default, gdy rynkowa wartość aktywów spada poniżej długu; wymaga notowanej spółki.", "type": "open"}, {"id": "q_t4_8", "chapter": "t4", "q": "Wymień 3 założenia analizy technicznej.", "a": "Cena dyskontuje wszystko (informacja jest już w cenie); ceny poruszają się w trendach (mają kierunek i trwają, dopóki się nie odwrócą); historia się powtarza (bo powtarza się psychologia inwestorów) — to trzy aksjomaty teorii Dowa.", "type": "open"}, {"id": "q_t4_9", "chapter": "t4", "q": "Czym formacja odwrócenia różni się od kontynuacji?", "a": "Odwrócenia kończą dotychczasowy trend i zmieniają kierunek (głowa z ramionami, podwójny szczyt/dno); kontynuacji to przystanek „na oddech\" w trwającym trendzie (flagi, trójkąty), który z definicji zakłada wcześniejszy trend.", "type": "open"}, {"id": "q_t4_10", "chapter": "t4", "q": "Co mierzy RSI i co znaczą poziomy 30/70?", "a": "RSI mierzy momentum, normalizując stosunek średnich wzrostów do spadków do skali 0–100 (RSI = 100 - 100/(1+RS)). Umownie >70 = wykupienie, <30 = wyprzedanie, 50 = linia podziału; progi są umowne i czyta się je w kontekście trendu.", "type": "open"}, {"id": "q_t4_11", "chapter": "t4", "q": "Czy AT da się pogodzić z hipotezą rynku efektywnego?", "a": "W formie słabej EMH — nie: skoro cała informacja z przeszłych cen jest już w cenie, AT nie powinna dawać trwałej przewagi (najważniejszy zarzut). Pogodzenie możliwe tylko, gdy rynek nie jest w pełni efektywny — co uzasadniają finanse behawioralne (powtarzalne błędy poznawcze tłumu) i samospełniająca się przepowiednia; rynki mniej płynne jak GPW bywają uznawane za mniej efektywne [zweryfikuj].", "type": "open"}, {"id": "q_t6_12", "chapter": "t6", "q": "Przyporządkuj do bierne/czynne/pośredniczące: lokata, kredyt, przelew.", "a": "Lokata = bierna (bank dłużnikiem); kredyt = czynna (bank wierzycielem); przelew = pośrednicząca (prowizja, neutralny bilansowo).", "type": "open"}, {"id": "q_t6_13", "chapter": "t6", "q": "Co to underwriting emisji?", "a": "Organizacja emisji + zobowiązanie do objęcia papierów. Subemisja inwestycyjna — bank obejmuje papiery nieobjęte przez inwestorów; usługowa — obejmuje całość i odsprzedaje (większa ekspozycja kapitałowa). Istota: za prowizję przejmuje ryzyko nieuplasowania.", "type": "open"}, {"id": "q_t6_14", "chapter": "t6", "q": "Czym e-pieniądz różni się od depozytu?", "a": "E-pieniądz to przedpłacona wartość u IPE, z wykupem po nominale, chroniona segregacją, nieoprocentowana, bez BFG. Depozyt to roszczenie wobec banku, którym bank obraca w rezerwie cząstkowej, oprocentowane i objęte gwarancjami BFG.", "type": "open"}, {"id": "q_t6_15", "chapter": "t6", "q": "Skąd pochodzi zysk banku?", "a": "Głównie z marży odsetkowej (oprocentowanie kredytów wyższe niż depozytów → wynik odsetkowy) oraz z prowizji za operacje pośredniczące — stabilnego, nieobciążającego kapitału ryzykiem kredytowym filaru dochodu.", "type": "open"}, {"id": "q_t8_16", "chapter": "t8", "q": "Czym różni się rachunkowość finansowa od zarządczej?", "a": "Finansowa: obligatoryjna, regulowana, na zewnątrz, wstecz, tylko pieniądz; zarządcza: fakultatywna, nieregulowana, do wewnątrz, w przód, też dane niepieniężne — wybiera trafność i szybkość zamiast maksymalnej precyzji.", "type": "open"}, {"id": "q_t8_17", "chapter": "t8", "q": "Dlaczego wynik różni się między kosztem pełnym a zmiennym?", "a": "Bo gdy produkcja > sprzedaży, koszt pełny „parkuje\" część kosztów stałych w wartości zapasu (różnica = \\Delta Zapas \\cdot ks_{prod}); przy produkcja = sprzedaż wyniki są równe.", "type": "open"}, {"id": "q_t8_18", "chapter": "t8", "q": "Czy przyjąć zamówienie poniżej kosztu pełnego?", "a": "Przy wolnych mocach tak, jeśli cena przewyższa koszt zmienny jednostkowy — koszty stałe są nieistotne, liczy się marża pokrycia.", "type": "open"}, {"id": "q_t8_19", "chapter": "t8", "q": "Dlaczego budżet gotówki jest sercem planowania?", "a": "Bo wynik liczony memoriałowo nie równa się przepływowi gotówki — firma rentowna może utracić płynność, a budżet gotówki ostrzega o luce, zanim ona nastąpi.", "type": "open"}, {"id": "q_t12_20", "chapter": "t12", "q": "Czym różni się forward od futures?", "a": "Ekonomicznie identyczne (obowiązek dostawy po umówionej cenie), ale futures jest standaryzowany, notowany na giełdzie, z izbą rozliczeniową (eliminuje ryzyko kontrahenta), depozytem i codziennym mark-to-market — kosztem ryzyka płynności (margin call).", "type": "open"}, {"id": "q_t12_21", "chapter": "t12", "q": "Dlaczego wypłata opcji jest asymetryczna, a forwardu symetryczna?", "a": "Bo nabywca opcji ma prawo, nie obowiązek — wykona ją tylko, gdy się opłaca, więc strata ogranicza się do premii. Forward zobowiązuje obie strony, więc zysk longa = strata shorta (gra o sumie zero).", "type": "open"}, {"id": "q_t12_22", "chapter": "t12", "q": "Jak swap IRS zabezpiecza firmę przed wzrostem stóp?", "a": "Firma płaci w swapie stałą stopę, a otrzymuje zmienną (WIBOR), którą przekazuje na kredyt; zmienne nogi się znoszą i zostaje przewidywalny koszt stały. Rozliczana jest tylko różnica odsetek, nominał nie jest wymieniany.", "type": "open"}, {"id": "q_t12_23", "chapter": "t12", "q": "Co podnosi wartość opcji?", "a": "Pięć czynników (S, K, T, \\sigma, r); w szczególności wzrost zmienności \\sigma i czasu T podnosi wartość każdej opcji, bo zwiększa szansę dużego korzystnego ruchu przy stracie ograniczonej do premii.", "type": "open"}, {"id": "q_k1_24", "chapter": "k1", "q": "Czym rozni sie ujecie memorialowe od kasowego?", "a": "Memorialowe ujmuje skutki zdarzen w momencie ich wystapienia (np. sprzedazy), kasowe — w momencie wplywu/wyplywu gotowki; rachunkowosc opiera sie na memoriale.", "type": "open"}, {"id": "q_k1_25", "chapter": "k1", "q": "Na czym polega zasada wspolmiernosci i z ktora zasada wystepuje w parze?", "a": "Nakazuje przypisac do przychodow okresu koszty ich uzyskania; dziala w parze z memorialem, dajac poprawny wynik finansowy.", "type": "open"}, {"id": "q_k1_26", "chapter": "k1", "q": "Wyjasnij zasade ostroznosci i podaj jej asymetrie.", "a": "Nakazuje uwzgledniac przewidywane straty i odpisy, a zakazuje ujmowac niezrealizowane zyski — chroni przed zawyzaniem aktywow i wyniku.", "type": "open"}, {"id": "q_k1_27", "chapter": "k1", "q": "Czym rozni sie ciaglosc od kontynuacji dzialania?", "a": "Ciaglosc = stosowanie tych samych zasad rachunkowosci rok do roku (porownywalnosc); kontynuacja = zalozenie, ze jednostka bedzie dzialac w przewidywalnej przyszlosci.", "type": "open"}, {"id": "q_k4_28", "chapter": "k4", "q": "Dlaczego RKP może zawyżać zysk przy rosnących zapasach?", "a": "Bo część stałych kosztów produkcji zostaje aktywowana w wartości zapasu i nie obciąża wyniku okresu, w którym powstała — wynik jest wyższy niż w RKZ.", "type": "open"}, {"id": "q_k4_29", "chapter": "k4", "q": "Co pokazuje wskaźnik marży pokrycia i do czego służy?", "a": "Pokazuje, jaka część każdej złotówki przychodu zostaje na pokrycie kosztów stałych i zysku; służy do liczenia BEP wartościowego i szybkich symulacji rentowności.", "type": "open"}, {"id": "q_k4_30", "chapter": "k4", "q": "Firma A ma wysokie koszty stałe, firma B niskie — która ma wyższy DOL i co to znaczy?", "a": "Firma A; jej zysk silniej reaguje na zmiany sprzedaży (większy potencjał zysku przy wzroście, większe ryzyko przy spadku).", "type": "open"}, {"id": "q_k4_31", "chapter": "k4", "q": "Jak policzyć margines bezpieczeństwa?", "a": "To różnica między planowaną sprzedażą a progiem rentowności (w szt., zł lub %): MB\\% = (S - BEP)/S — pokazuje, o ile może spaść sprzedaż, zanim pojawi się strata.", "type": "open"}, {"id": "q_k7_32", "chapter": "k7", "q": "Czym jest KON i jak go mierzymy?", "a": "To czesc aktywow obrotowych finansowana kapitalem stalym; mierzymy go jako AO - ZK (ujecie majatkowe) lub (KW + ZD) - AT (kapitalowe) — oba daja ten sam wynik.", "type": "open"}, {"id": "q_k7_33", "chapter": "k7", "q": "Jaki jest zwiazek KON z plynnoscia?", "a": "Dodatni KON oznacza nadwyzke aktywow obrotowych nad zobowiazaniami biezacymi, czyli bufor bezpieczenstwa plynnosci; zwykle towarzyszy mu CR > 1.", "type": "open"}, {"id": "q_k7_34", "chapter": "k7", "q": "Czym roznia sie trzy strategie KON?", "a": "Agresywna utrzymuje KON niski/ujemny (tani, ryzykowny kredyt krotki, wysoka rentownosc), konserwatywna wysoki (drogie bezpieczenstwo, niska rentownosc), umiarkowana posrednia.", "type": "open"}, {"id": "q_k7_35", "chapter": "k7", "q": "Co to cykl konwersji gotowki i po co go liczyc?", "a": "CCC = OZ + ON - OZob — liczba dni zamrozenia gotowki; im krotszy, tym mniej kapitalu obrotowego trzeba finansowac i tym lepsza efektywnosc.", "type": "open"}, {"id": "q_k10_36", "chapter": "k10", "q": "Czym rozni sie polityka monetarna od fiskalnej?", "a": "Monetarna prowadzona jest przez bank centralny (NBP) za pomoca stop procentowych, rezerwy obowiazkowej i OOR; fiskalna przez rzad za pomoca podatkow i wydatkow budzetowych.", "type": "open"}, {"id": "q_k10_37", "chapter": "k10", "q": "Wymien i opisz trzy podstawowe funkcje banku centralnego.", "a": "Bank emisyjny (monopol emisji), bank bankow (rachunki bankow, pozyczkodawca ostatniej instancji), bank panstwa (obsluga budzetu, rezerwy dewizowe).", "type": "open"}, {"id": "q_k10_38", "chapter": "k10", "q": "Jak wzrost stopy rezerwy obowiazkowej wplywa na podaz pieniadza?", "a": "Zmniejsza mnoznik kreacji pieniadza (m = 1/r), wiec banki moga udzielic mniej kredytow — podaz pieniadza spada (dzialanie restrykcyjne).", "type": "open"}, {"id": "q_k10_39", "chapter": "k10", "q": "Na czym polegaja operacje otwartego rynku jako narzedzie ekspansywne?", "a": "Bank centralny **kupuje** papiery wartosciowe od bankow, dostarczajac im plynnosc; rosnie podaz pieniadza i spadaja stopy rynkowe, co pobudza akcje kredytowa.", "type": "open"}, {"id": "q_k11_40", "chapter": "k11", "q": "Czym różni się dochód budżetowy od przychodu budżetowego?", "a": "Dochód to wpływ bezzwrotny i definitywny (podatki, cła), natomiast przychód jest zwrotny (kredyty, obligacje) i służy sfinansowaniu deficytu — nie zwiększa trwale zasobów państwa.", "type": "open"}, {"id": "q_k11_41", "chapter": "k11", "q": "Wymień i krótko scharakteryzuj funkcje podatków.", "a": "Fiskalna — dostarcza dochodów budżetowi; redystrybucyjna — przesuwa dochody między grupami społecznymi; stymulacyjna — zachęca lub zniechęca do określonych zachowań (ulgi, wyższe stawki).", "type": "open"}, {"id": "q_k11_42", "chapter": "k11", "q": "Na czym polega różnica między podatkiem bezpośrednim a pośrednim?", "a": "Bezpośredni obciąża wprost dochód lub majątek podatnika (PIT, CIT) i jest nieprzerzucalny; pośredni jest wliczony w cenę towaru (VAT, akcyza) i ekonomicznie ponosi go konsument.", "type": "open"}, {"id": "q_k11_43", "chapter": "k11", "q": "Jakie są główne etapy procedury budżetowej?", "a": "Przygotowanie projektu przez Radę Ministrów, uchwalenie ustawy budżetowej przez Sejm i Senat, wykonanie budżetu przez rząd oraz kontrola wykonania (m.in. przez NIK i absolutorium Sejmu).", "type": "open"}, {"id": "q_k12_44", "chapter": "k12", "q": "Czym rozni sie PKB od PNB?", "a": "PKB mierzy produkcje na terytorium kraju (kryterium geograficzne), PNB — dochody rezydentow niezaleznie od miejsca; roznica to dochody netto z zagranicy.", "type": "open"}, {"id": "q_k12_45", "chapter": "k12", "q": "Jak inflacja wplywa na realna stope zwrotu inwestora?", "a": "Obniza ja: realna stopa \\approx nominalna minus inflacja; przy wysokiej inflacji nominalny zysk moze oznaczac realna strate (zwlaszcza po podatku).", "type": "open"}, {"id": "q_k12_46", "chapter": "k12", "q": "Jak deprecjacja waluty dziala na bilans handlowy?", "a": "Czyni eksport tanszym, a import drozszym, co zwykle poprawia eksport netto (z opoznieniem — efekt krzywej J).", "type": "open"}, {"id": "q_k12_47", "chapter": "k12", "q": "Wymien fazy cyklu koniunkturalnego i znaczenie dla finansisty.", "a": "Ozywienie, szczyt, recesja, dno; faza decyduje o ryzyku kredytowym, popycie na finansowanie i wycenie aktywow — w recesji rosnie ryzyko, w boomie ryzyko przegrzania.", "type": "open"}, {"id": "qb_1_48", "chapter": "t1", "q": "Czym jest Value at Risk (VaR)? Podaj definicję, trzy parametry potrzebne do jego wyznaczenia oraz interpretację.", "a": "VaR to maksymalna oczekiwana strata wartości portfela w zadanym horyzoncie czasowym, która nie zostanie przekroczona z określonym prawdopodobieństwem (poziomem ufności). Wymaga trzech parametrów: poziomu ufności (np. 95% lub 99%), horyzontu czasowego (np. 1 dzień, 10 dni) oraz waluty pomiaru. Przykład interpretacji: 1-dniowy VaR = 1 mln zł przy 99% oznacza, że w ciągu jednego dnia z prawdopodobieństwem 99% strata nie przekroczy 1 mln zł (czyli średnio 1 dzień na 100 strata będzie większa). VaR mierzy więc kwantyl rozkładu strat, a nie stratę przeciętną.", "type": "definicyjne"}, {"id": "qb_1_49", "chapter": "t1", "q": "Portfel ma wartość 10 mln zł, dzienna zmienność (odchylenie standardowe stóp zwrotu) wynosi 1,5%. Oblicz 1-dniowy VaR przy 99% poziomie ufności metodą wariancji-kowariancji, a następnie przeskaluj go na 10 dni.", "a": "Metoda parametryczna: VaR = wartość × z × sigma. Kwantyl rozkładu normalnego dla 99% to z = 2,326. VaR(1d) = 10 000 000 × 2,326 × 0,015 = 348 900 zł (ok. 349 tys. zł). Skalowanie horyzontu przez pierwiastek z czasu (reguła square-root-of-time): VaR(10d) = VaR(1d) × pierwiastek(10) = 348 900 × 3,162 = 1 103 200 zł (ok. 1,10 mln zł). Dla 95% użylibyśmy z = 1,645.", "type": "obliczeniowe"}, {"id": "qb_1_50", "chapter": "t1", "q": "Porównaj trzy metody wyznaczania VaR: wariancji-kowariancji (parametryczną), symulacji historycznej i Monte Carlo. Wskaż główną zaletę i wadę każdej.", "a": "Wariancji-kowariancji: zakłada normalność rozkładu stóp zwrotu i liniowość pozycji; zaleta — prosta i szybka, wada — zaniża ryzyko przy grubych ogonach (leptokurtoza) i źle obsługuje opcje (nieliniowość). Symulacja historyczna: stosuje rzeczywiste historyczne zmiany czynników ryzyka, brak założenia o rozkładzie; zaleta — uwzględnia faktyczne grube ogony, wada — zależna od okna danych, zakłada że przeszłość reprezentuje przyszłość. Monte Carlo: generuje losowe scenariusze z założonego modelu; zaleta — radzi sobie z instrumentami nieliniowymi i dowolnymi rozkładami, wada — kosztowna obliczeniowo i wrażliwa na błąd specyfikacji modelu.", "type": "porownawcze"}, {"id": "qb_1_51", "chapter": "t1", "q": "Najczęstszy błąd przy VaR: dlaczego VaR nie jest pełną miarą ryzyka i czym różni się od Expected Shortfall (CVaR)? Wymień co najmniej dwie wady VaR.", "a": "Pułapka: VaR mówi tylko o progu straty, ale NIC nie mówi o tym, jak duża będzie strata, gdy ten próg zostanie przekroczony (ignoruje ogon poza kwantylem). Wady: (1) VaR nie jest miarą koherentną — nie spełnia subaddytywności, więc VaR portfela może być większy od sumy VaR składników, co zaprzecza dywersyfikacji; (2) niedoszacowuje ryzyka katastroficznych zdarzeń w ogonie. Expected Shortfall (CVaR) to średnia strata WARUNKOWA pod warunkiem przekroczenia VaR — jest koherentny i lepiej opisuje ogon, dlatego Bazylea (FRTB) przesunęła wymóg kapitałowy z VaR 99% na ES 97,5% [zweryfikuj].", "type": "pulapka"}, {"id": "qb_1_52", "chapter": "t1", "q": "Czym jest rezerwa obowiązkowa i jak wiąże się z ryzykiem portfela depozytowego oraz ryzykiem stopy procentowej banku? Podaj przykład wpływu na płynność.", "a": "Rezerwa obowiązkowa to procent zgromadzonych depozytów, który bank musi utrzymywać na rachunku w banku centralnym (w Polsce w NBP), będący instrumentem polityki pieniężnej i bufora płynności. Stopa rezerwy obowiązkowej w Polsce wynosi 3,5% [zweryfikuj]. Przykład: przy depozytach 100 mln zł i stopie 3,5% bank musi unieruchomić 3,5 mln zł, co zmniejsza środki dostępne do akcji kredytowej i inwestowania. Powiązanie z ryzykiem: portfel depozytowy generuje ryzyko stopy procentowej (luka między przeszacowaniem aktywów i pasywów, repricing gap) oraz ryzyko płynności — nagły odpływ depozytów przy niskiej rezerwie zagraża wypłacalności, dlatego rezerwa i VaR pozycji odsetkowych są elementami zarządzania ryzykiem bilansowym (ALM).", "type": "definicyjne"}, {"id": "qb_2_53", "chapter": "t2", "q": "Czym jest zdolnosc kredytowa i jaki przepis nakazuje bankowi jej badanie?", "a": "Zdolnosc kredytowa to zdolnosc kredytobiorcy do splaty zaciagnietego kredytu wraz z odsetkami w terminach okreslonych w umowie (art. 70 ustawy Prawo bankowe). Bank uzaleznia udzielenie kredytu od posiadania tej zdolnosci i ma prawo zadac dokumentow oraz informacji niezbednych do jej oceny. Badanie ma dwa wymiary: ilosciowy (sytuacja finansowa, dochody, zadluzenie, plynnosc) i jakosciowy (wiarygodnosc, historia kredytowa, jakosc zarzadzania, branza). Brak zdolnosci kredytowej co do zasady wyklucza udzielenie kredytu, chyba ze ustanowiono szczegolne zabezpieczenie lub jest to program naprawczy [zweryfikuj aktualne brzmienie ustawy].", "type": "definicyjne"}, {"id": "qb_2_54", "chapter": "t2", "q": "Wyjasnij metode 5C oceny kredytobiorcy i porownaj ja z miernikiem syntetycznym (scoringiem) - czym sie roznia jako podejscia do oceny zdolnosci kredytowej?", "a": "5C to jakosciowo-ilosciowa lista kryteriow: Character (charakter, wiarygodnosc, historia splat), Capacity (zdolnosc do generowania srodkow na splate, dochod/cash flow), Capital (kapital wlasny, zaangazowanie wlasnych srodkow), Collateral (zabezpieczenie) i Conditions (warunki makro/branzowe i cel kredytu). Scoring (miernik syntetyczny) to metoda statystyczno-punktowa: cechom klienta przypisuje sie wagi i punkty, a ich suma ponad progiem (cut-off) decyduje o akceptacji. Roznica: 5C jest jakosciowe, eksperckie, elastyczne, ale subiektywne i wolniejsze; scoring jest obiektywny, szybki, tani, zautomatyzowany i powtarzalny, lecz wymaga duzych zbiorow danych i moze pomijac nietypowe przypadki. W praktyce banki lacza oba - scoring do masowej detalicznej oceny, 5C/analiza ekspercka do ekspozycji korporacyjnych.", "type": "porownawcze"}, {"id": "qb_2_55", "chapter": "t2", "q": "Bank szacuje strate oczekiwana (EL) dla kredytu. Dane: kwota ekspozycji EAD = 500 000 zl, prawdopodobienstwo niewykonania zobowiazania PD = 2%, strata w przypadku defaultu LGD = 45%. Oblicz EL kwotowo i procentowo.", "a": "Wzor: EL = PD x LGD x EAD. Podstawiamy: EL = 0,02 x 0,45 x 500 000 zl = 0,009 x 500 000 zl = 4 500 zl. Procentowo wzgledem ekspozycji: EL/EAD = PD x LGD = 0,02 x 0,45 = 0,009 = 0,9%. Czyli oczekiwana strata to 4 500 zl, tj. 0,9% wartosci ekspozycji - taka kwote bank co do zasady pokrywa z marzy/odpisow (rezerw), a nie z kapitalu. Strate nieoczekiwana (UL) pokrywa kapital regulacyjny.", "type": "obliczeniowe"}, {"id": "qb_2_56", "chapter": "t2", "q": "Na czym polega model Altmana (Z-score) i jak interpretuje sie jego wynik w ocenie ryzyka upadlosci przedsiebiorstwa?", "a": "Model Altmana to wielowymiarowa analiza dyskryminacyjna laczaca piec wskaznikow finansowych w jeden syntetyczny wynik Z. Klasyczna wersja dla spolek gieldowych: Z = 1,2 X1 + 1,4 X2 + 3,3 X3 + 0,6 X4 + 1,0 X5, gdzie X1 = kapital obrotowy/aktywa, X2 = zysk zatrzymany/aktywa, X3 = EBIT/aktywa, X4 = wartosc rynkowa kapitalu wlasnego/zobowiazania, X5 = przychody/aktywa. Interpretacja stref: Z > 2,99 - bezpieczna (niskie ryzyko upadlosci); 1,81 < Z < 2,99 - szara strefa (niepewnosc); Z < 1,81 - wysokie ryzyko bankructwa. Istnieja warianty: Z' dla spolek niegieldowych i Z'' dla firm nieprodukcyjnych/rynkow wschodzacych (inne wagi i pominiety X5).", "type": "definicyjne"}, {"id": "qb_2_57", "chapter": "t2", "q": "Czesty blad: student twierdzi, ze 'wysokie PD = wysoka strata oczekiwana, a zabezpieczenie nie ma wplywu na EL'. Gdzie tkwi pulapka?", "a": "Blad polega na myleniu PD ze strata oraz pominieciu LGD i EAD. EL zalezy od iloczynu trzech parametrow (EL = PD x LGD x EAD), wiec wysokie PD nie oznacza wysokiej straty, jesli LGD jest niskie. Zabezpieczenie wprost obniza LGD (a wiec i EL), bo zmniejsza strate, jaka bank poniesie po defaulcie - np. przy PD = 30% i LGD = 5% strata jest mniejsza niz przy PD = 3% i LGD = 90%. Druga pulapka: EL to strata OCZEKIWANA (pokrywana odpisami/marza), a nie maksymalna - ryzyko skrajne mierzy strata nieoczekiwana (UL) pokrywana kapitalem. Trzecia: PD i LGD musza dotyczyc tego samego horyzontu (zwykle 12 miesiecy) i tej samej ekspozycji.", "type": "pulapka"}, {"id": "qb_3_58", "chapter": "t3", "q": "Na jakich aktach prawnych opiera sie rachunkowosc bankowa w Polsce i ktora grupa bankow obowiazkowo stosuje MSR/MSSF zamiast ustawy o rachunkowosci?", "a": "Podstawy: ustawa o rachunkowosci z 29.09.1994 (UoR), Prawo bankowe, rozporzadzenie Ministra Finansow w sprawie szczegolnych zasad rachunkowosci bankow [zweryfikuj], oraz rozporzadzenia UE wprowadzajace MSR/MSSF. Banki bedace emitentami papierow wartosciowych dopuszczonych do obrotu na rynku regulowanym UE sporzadzaja sprawozdania skonsolidowane OBOWIAZKOWO wg MSSF (rozporzadzenie WE 1606/2002); pozostale banki moga je stosowac fakultatywnie po decyzji organu zatwierdzajacego. Sprawozdanie banku obejmuje m.in. bilans, rachunek zyskow i strat, zestawienie zmian w kapitale wlasnym, rachunek przeplywow pienieznych i informacje dodatkowa. Nadzor sprawuje KNF, a uzupelniajaco obowiazuja wytyczne ostroznosciowe (np. CRR/CRD).", "type": "definicyjne"}, {"id": "qb_3_59", "chapter": "t3", "q": "Bank udzielil kredytu o wartosci bilansowej brutto 1 000 000 zl. Prawdopodobienstwo niewykonania zobowiazania (PD) w horyzoncie 12 miesiecy wynosi 2%, strata w przypadku niewykonania (LGD) 45%, a ekspozycja na moment niewyplacalnosci (EAD) rowna jest wartosci brutto. Oblicz oczekiwana strate kredytowa (ECL 12-miesieczna) wg MSSF 9.", "a": "Wzor: ECL = PD x LGD x EAD. Podstawiamy: ECL = 0,02 x 0,45 x 1 000 000 zl. ECL = 0,02 x 0,45 = 0,009; 0,009 x 1 000 000 = 9 000 zl. Odpis (ECL 12-miesieczny) wynosi 9 000 zl, co odpowiada Etapowi 1 (Stage 1) modelu MSSF 9. Gdyby ryzyko istotnie wzroslo (Stage 2/3), liczymy ECL w horyzoncie calego zycia (lifetime) z wieloletnimi PD, a w Stage 3 odsetki naliczamy od wartosci netto.", "type": "obliczeniowe"}, {"id": "qb_3_60", "chapter": "t3", "q": "Porownaj model utraty wartosci wedlug MSSF 9 z wczesniejszym podejsciem MSR 39 (model strat juz poniesionych).", "a": "MSR 39 stosowal model strat poniesionych (incurred loss): odpis tworzono dopiero po wystapieniu zdarzenia straty (obiektywnej przeslanki utraty wartosci), co opozniało rozpoznanie strat. MSSF 9 wprowadza model strat oczekiwanych (expected credit loss, ECL): odpis tworzy sie z gory, juz przy poczatkowym ujeciu, na bazie prognoz forward-looking. MSSF 9 dzieli ekspozycje na 3 etapy: Stage 1 - ECL 12-miesieczny, Stage 2 - ECL lifetime po istotnym wzroscie ryzyka kredytowego (SICR), Stage 3 - ekspozycje z utrata wartosci, gdzie odsetki liczy sie od wartosci netto. Efekt: wczesniejsze i wyzsze odpisy, mniejsza procyklicznosc niz w MSR 39.", "type": "porownawcze"}, {"id": "qb_3_61", "chapter": "t3", "q": "Czesty blad: jak MSSF 9 klasyfikuje aktywa finansowe i dlaczego nie kazdy kredyt wycenia sie w zamortyzowanym koszcie?", "a": "Pulapka: studenci twierdza, ze wszystkie kredyty wycenia sie w zamortyzowanym koszcie - to nieprawda. MSSF 9 stosuje DWA testy lacznie: (1) test modelu biznesowego (cel: trzymanie dla przeplywow, trzymanie i sprzedaz, lub inny) oraz (2) test charakterystyki przeplywow (test SPPI - czy przeplywy to wylacznie kapital i odsetki). Aktywo wycenia sie w zamortyzowanym koszcie tylko gdy model = 'trzymanie' I przejdzie SPPI; przy modelu 'trzymanie i sprzedaz' + SPPI jest to wartosc godziwa przez inne calkowite dochody (FVOCI); w pozostalych przypadkach (np. brak SPPI, instrumenty pochodne, portfel handlowy) - wartosc godziwa przez wynik finansowy (FVTPL). Bledem jest tez mylenie kategorii MSSF 9 ze starymi kategoriami MSR 39 (HTM, AFS, kredyty i naleznosci, FVTPL).", "type": "pulapka"}, {"id": "qb_3_62", "chapter": "t3", "q": "Wymien glowne roznice w sprawozdawczosci banku sporzadzonej wedlug polskiej ustawy o rachunkowosci a wedlug MSR/MSSF.", "a": "Roznice dotycza zakresu i nazewnictwa sprawozdan oraz zasad wyceny. Wg MSSF sprawozdanie obejmuje: sprawozdanie z sytuacji finansowej (bilans), sprawozdanie z calkowitych dochodow (z pozycjami OCI), sprawozdanie ze zmian w kapitale wlasnym, sprawozdanie z przeplywow pienieznych i noty; UoR operuje pojeciami bilans oraz rachunek zyskow i strat bez kategorii calkowitych dochodow. Wycena: MSSF szerzej stosuje wartosc godziwa i model ECL (MSSF 9), podczas gdy UoR czesciej bazuje na koszcie historycznym i wlasnych przepisach o rezerwach/odpisach. MSSF kladzie nacisk na tresc ekonomiczna nad forma prawna i obszerniejsze ujawnienia (MSSF 7). Banki gieldowe stosuja MSSF obowiazkowo w skonsolidowanych sprawozdaniach, pozostale moga pozostac przy UoR.", "type": "porownawcze"}, {"id": "qb_4_63", "chapter": "t4", "q": "Na czym opiera sie analiza techniczna i jakie sa trzy fundamentalne zalozenia teorii Dowa?", "a": "Analiza techniczna (AT) zaklada, ze przyszle ruchy cen mozna prognozowac na podstawie historycznych danych o cenie i wolumenie, bez badania wartosci fundamentalnej spolki. Opiera sie na trzech aksjomatach: (1) rynek dyskontuje wszystko - cena uwzglednia juz wszystkie dostepne informacje; (2) ceny poruszaja sie w trendach (wzrostowy, spadkowy, boczny), a trend trwa az do wyraznego sygnalu odwrocenia; (3) historia sie powtarza, bo psychologia inwestorow jest stala (formacje i wzorce sie powielaja). Teoria Dowa dodatkowo wyroznia trzy fazy trendu (akumulacja, partycypacja publiczna, dystrybucja) oraz wymaga potwierdzenia trendu przez dwa indeksy i przez wolumen.", "type": "definicyjne"}, {"id": "qb_4_64", "chapter": "t4", "q": "Akcja w ostatnich 14 dniach miala 9 sesji wzrostowych o lacznym ruchu +35 zl i 5 sesji spadkowych o lacznym ruchu -10 zl. Oblicz 14-dniowy RSI i zinterpretuj wynik.", "a": "RSI liczy sie ze wzoru RSI = 100 - 100/(1+RS), gdzie RS = srednia zyskow / srednia strat (z N okresow). Srednia zyskow = 35/14 = 2,5; srednia strat = 10/14 = 0,714. RS = 2,5 / 0,714 = 3,5. RSI = 100 - 100/(1+3,5) = 100 - 100/4,5 = 100 - 22,22 = 77,78. Wynik ~77,8 jest powyzej progu 70, co sygnalizuje stan wykupienia (overbought) i mozliwa korekte/odwrocenie w dol. Progi standardowe: >70 wykupienie, <30 wyprzedanie.", "type": "obliczeniowe"}, {"id": "qb_4_65", "chapter": "t4", "q": "Porownaj wskaznik MACD ze wskaznikiem RSI - czym sie roznia konstrukcyjnie i interpretacyjnie?", "a": "MACD jest wskaznikiem trendu i pedu (momentum) opartym na roznicy dwoch srednich wykladniczych: linia MACD = EMA(12) - EMA(26), linia sygnalu = EMA(9) z MACD, a histogram = MACD - sygnal; sygnaly to przeciecia linii oraz dywergencje, MACD jest nieograniczony (oscyluje wokol zera). RSI jest oscylatorem pedu ograniczonym do przedzialu 0-100, mierzacym sile ruchu przez relacje zyskow do strat, z progami wykupienia (70) i wyprzedania (30). Roznica kluczowa: MACD najlepiej dziala w wyraznym trendzie i wychwytuje jego zmiane, a RSI w rynku bocznym/wahaniowym sygnalizuje skrajnosci. RSI jest znormalizowany i porownywalny miedzy instrumentami, MACD wyrazony jest w jednostkach ceny i nie jest.", "type": "porownawcze"}, {"id": "qb_4_66", "chapter": "t4", "q": "Opisz formacje glowy i ramion (head and shoulders) - jej budowe, sygnal oraz sposob wyznaczenia zasiegu spadku (price target).", "a": "Glowa i ramiona to formacja odwrocenia trendu wzrostowego, sklada sie z trzech szczytow: lewego ramienia, wyzszej glowy i prawego ramienia (zblizonego wysokoscia do lewego), polaczonych linia szyi (neckline) laczaca dolki miedzy szczytami. Sygnal sprzedazy generuje przebicie linii szyi w dol, najlepiej potwierdzone wzrostem wolumenu (wolumen typowo maleje na kolejnych szczytach). Minimalny zasieg spadku (target) = wysokosc od szczytu glowy do linii szyi, odlozona w dol od punktu przebicia neckline. Wariant odwrocony (odwrocona glowa z ramionami) sygnalizuje odwrocenie trendu spadkowego na wzrostowy.", "type": "definicyjne"}, {"id": "qb_4_67", "chapter": "t4", "q": "Czesty blad: inwestor kupuje, gdy RSI spadnie ponizej 30 (wyprzedanie), zakladajac pewne odbicie. Dlaczego to pulapka i jak prawidlowo stosowac oscylatory?", "a": "Pulapka polega na traktowaniu sygnalow oscylatora w oderwaniu od trendu - w silnym trendzie spadkowym RSI moze utrzymywac sie ponizej 30 (lub MACD generowac falszywe przeciecia) przez dlugi czas, a 'wyprzedanie' nie oznacza dna; kupowanie wbrew trendowi to 'lapanie spadajacego noza'. Oscylatory dzialaja wiarygodnie w trendzie bocznym, a w silnym trendzie daja liczne falszywe sygnaly. Poprawne uzycie: filtrowac sygnaly kierunkiem trendu glownego (np. wedlug sredniej 200-sesyjnej), szukac dywergencji ceny i wskaznika oraz wymagac potwierdzenia (przebicie poziomu, wolumen, formacja swiecowa). Zasada Dowa: nie grac przeciw dominujacemu trendowi, dopoki nie ma sygnalu jego odwrocenia.", "type": "pulapka"}, {"id": "qb_5_68", "chapter": "t5", "q": "Co to jest instrument finansowy i jak klasyfikuje sie instrumenty wedlug rynku, na ktorym sa wyceniane? Podaj kryteria podzialu.", "a": "Instrument finansowy to kontrakt, ktory u jednej strony powoduje powstanie aktywow finansowych, a u drugiej zobowiazania finansowego lub instrumentu kapitalowego. Glowny podzial: instrumenty rynku pienieznego (zapadalnosc do 1 roku, np. bony skarbowe, certyfikaty depozytowe - wyceniane metoda dyskonta), instrumenty rynku kapitalowego (powyzej 1 roku, np. akcje i obligacje - wyceniane przez DCF/Gordona) oraz instrumenty pochodne/terminowe (forward, futures, opcje, swapy - wycena z ceny terminowej i instrumentu bazowego). Dodatkowo dzielimy je na udzialowe (akcje) i dluzne (obligacje). Z punktu widzenia wyceny kluczowa jest wartosc biezaca przyszlych przeplywow pienieznych dyskontowanych odpowiednia stopa.", "type": "definicyjne"}, {"id": "qb_5_69", "chapter": "t5", "q": "Akcja wyplaci za rok dywidende 4 zl, dywidendy rosna stale o 3% rocznie, a wymagana stopa zwrotu wynosi 11%. Wycen akcje modelem Gordona i wyjasnij, co stanie sie z wycena, gdy g wzrosnie do 8%.", "a": "Model Gordona: P0 = D1 / (r - g). Podstawiajac: P0 = 4 / (0,11 - 0,03) = 4 / 0,08 = 50 zl. Gdy g wzrosnie do 8%: P0 = 4 / (0,11 - 0,08) = 4 / 0,03 = 133,33 zl - wartosc rosnie silnie, bo mianownik (r-g) maleje. Warunek stosowalnosci: r > g, inaczej wzor daje wynik ujemny lub niedodatni i traci sens ekonomiczny.", "type": "obliczeniowe"}, {"id": "qb_5_70", "chapter": "t5", "q": "Porownaj wycene instrumentu rynku pienieznego metoda dyskonta z wycena obligacji kuponowej metoda DCF. Czym sie roznia?", "a": "Instrument rynku pienieznego (np. bon skarbowy) jest zerokuponowy i krotkoterminowy - wyceniany prostym dyskontem: P = FV / (1 + r * t/360) lub przy dyskoncie handlowym P = FV * (1 - d * t/360); jeden przeplyw na koncu, czesto baza 360 dni. Obligacja kuponowa (rynek kapitalowy) ma wiele przeplywow: P = suma C/(1+r)^t + N/(1+r)^n, gdzie dyskontujemy kazdy kupon C i nominal N osobno, zwykle procentem skladanym. Roznica: liczba i rozklad przeplywow (jeden vs. wiele), horyzont (do 1 roku vs. wieloletni) oraz technika (dyskonto proste/baza 360 vs. dyskonto zlozone i krzywa stop). Ryzyko stopy procentowej (duration) dotyczy glownie obligacji dlugoterminowych.", "type": "porownawcze"}, {"id": "qb_5_71", "chapter": "t5", "q": "Wyznacz teoretyczna cene forward na akcje, ktora kosztuje dzis 200 zl, przy stopie wolnej od ryzyka 5% rocznie (kapitalizacja ciagla), kontrakt na 1 rok, bez dywidendy. Jak zmieni sie wynik, gdy akcja wyplaci dywidende o wartosci biezacej 6 zl?", "a": "Cena forward bez dochodu: F0 = S0 * e^(rT) = 200 * e^(0,05*1) = 200 * 1,05127 = 210,25 zl. Z dywidenda o wartosci biezacej I = 6 zl: F0 = (S0 - I) * e^(rT) = (200 - 6) * 1,05127 = 194 * 1,05127 = 203,95 zl. Dywidenda obniza cene terminowa, bo posiadacz instrumentu bazowego otrzymuje dochod, ktorego nie ma strona dluga forwardu. Cena forward wynika z braku arbitrazu (cost of carry), a nie z prognozy ceny przyszlej. [zweryfikuj] aktualny poziom stopy wolnej od ryzyka.", "type": "obliczeniowe"}, {"id": "qb_5_72", "chapter": "t5", "q": "PULAPKA: Student twierdzi, ze wartosc godziwa kontraktu forward na dzien zawarcia jest rowna cenie forward (np. 210 zl), wiec strona dluga od razu placi te kwote. Gdzie blad?", "a": "Blad polega na myleniu CENY forward (F0) z WARTOSCIA kontraktu forward. W momencie zawarcia kontrakt jest tak skonstruowany, by jego wartosc poczatkowa byla rowna ZERO (zadna strona nic nie placi - cena dostawy jest ustalana wlasnie tak, by V=0). Cena forward to uzgodniona cena rozliczenia w przyszlosci, nie platnosc dzisiaj. Pozniej wartosc kontraktu dla strony dlugiej zmienia sie wg: V = (Ft - F0) * e^(-r(T-t)) i moze byc dodatnia lub ujemna. Drugi czesty blad: traktowanie ceny forward jak prognozy przyszlej ceny spot - to cena arbitrazowa z cost of carry, nie oczekiwanie rynku.", "type": "pulapka"}, {"id": "qb_8_73", "chapter": "t8", "q": "Czym rozni sie rachunkowosc zarzadcza od rachunkowosci finansowej? Podaj co najmniej trzy kryteria.", "a": "Rachunkowosc finansowa jest zewnetrzna, sformalizowana (regulowana ustawa o rachunkowosci / MSR-MSSF [zweryfikuj]), obowiazkowa, zorientowana na przeszlosc i adresowana do odbiorcow zewnetrznych (inwestorzy, banki, US). Rachunkowosc zarzadcza jest wewnetrzna, dobrowolna, nieskodyfikowana, zorientowana na przyszlosc (planowanie, decyzje) i sluzy kadrze kierowniczej. Finansowa obejmuje cala jednostke w okresach sprawozdawczych, zarzadcza dziala w dowolnych przekrojach (produkt, centrum kosztow) i czestotliwosci. Controlling to nadrzedny system koordynacji (planowanie + kontrola + zasilanie w informacje), korzystajacy gl. z danych rachunkowosci zarzadczej.", "type": "definicyjne"}, {"id": "qb_8_74", "chapter": "t8", "q": "Firma sprzedaje produkt po 50 zl/szt. Koszt zmienny jednostkowy = 30 zl, koszty stale = 80 000 zl/mies. Oblicz: jednostkowa marze pokrycia, BEP ilosciowy i wartosciowy oraz zysk przy sprzedazy 6000 szt.", "a": "Jednostkowa marza pokrycia = cena - KZ jedn. = 50 - 30 = 20 zl. BEP ilosciowy = koszty stale / marza jedn. = 80 000 / 20 = 4000 szt. Wskaznik marzy pokrycia = 20/50 = 40%, wiec BEP wartosciowy = 80 000 / 0,40 = 200 000 zl (= 4000 szt x 50 zl). Zysk przy 6000 szt = (6000 x 20) - 80 000 = 120 000 - 80 000 = 40 000 zl.", "type": "obliczeniowe"}, {"id": "qb_8_75", "chapter": "t8", "q": "Porownaj rachunek kosztow pelnych (absorption costing) z rachunkiem kosztow zmiennych (variable costing) — czym roznia sie w wycenie zapasow i wyniku?", "a": "W rachunku kosztow pelnych koszty stale produkcji sa wliczane do kosztu wytworzenia i 'osadzaja sie' w zapasie wyrobow gotowych, wiec aktywuja sie i odraczaja w czasie. W rachunku kosztow zmiennych koszty stale traktuje sie jako koszty okresu i odnosi w calosci do wyniku biezacego, a zapas wycenia sie tylko po kosztach zmiennych. Skutek: gdy produkcja > sprzedaz (rosnie zapas), wynik wg kosztow pelnych jest wyzszy; gdy sprzedaz > produkcja, nizszy. Sprawozdawczo obowiazuje rachunek pelny (MSR 2 / ustawa o rachunkowosci [zweryfikuj]), a koszty zmienne sluza decyzjom zarzadczym (marza pokrycia, BEP).", "type": "porownawcze"}, {"id": "qb_8_76", "chapter": "t8", "q": "Na czym polega rachunek kosztow dzialan (ABC) i jaki bledny rozklad kosztow posrednich koryguje wzgledem kalkulacji tradycyjnej?", "a": "ABC (Activity-Based Costing) przypisuje koszty posrednie najpierw do dzialan (np. przezbrojenia, kontrola jakosci, obsluga zamowien), a potem do produktow wedlug nosnikow kosztow (cost drivers) odzwierciedlajacych faktyczne zuzycie zasobow. Kalkulacja tradycyjna rozlicza koszty posrednie jednym kluczem ilosciowym (np. roboczogodziny, koszty bezposrednie), co przeszacowuje produkty wielkoseryjne i proste, a niedoszacowuje produkty maloseryjne, zlozone, generujace duzo dzialan. ABC daje wiec dokladniejsze koszty jednostkowe i lepsze decyzje cenowe/asortymentowe, ale jest drozszy i bardziej pracochlonny w utrzymaniu.", "type": "porownawcze"}, {"id": "qb_8_77", "chapter": "t8", "q": "Student liczy BEP i dzieli koszty stale przez cene jednostkowa zamiast przez marze pokrycia. Dlaczego to blad i jak poprawnie podejsc do progu rentownosci oraz pojecia marzy?", "a": "Blad polega na pominieciu kosztow zmiennych: BEP = koszty stale / jednostkowa marza pokrycia (cena - KZ jedn.), a nie koszty stale / cena. Dzielenie przez cene zaniza BEP, bo zaklada, ze cala cena pokrywa koszty stale, ignorujac koszt zmienny kazdej sztuki. Druga czesta pulapka to mylenie marzy pokrycia (cena - koszt zmienny) z marza zysku/narzutem brutto — marza pokrycia najpierw pokrywa koszty stale, a dopiero nadwyzka ponad BEP daje zysk. Trzecia pulapka: KZ jedn. mnozyc, a kosztow stalych NIE odnosic do sztuki — sa to koszty okresu (przy stalym przedziale istotnosci).", "type": "pulapka"}, {"id": "qb_9_78", "chapter": "t9", "q": "Czym jest kapitał obrotowy netto (KON) i jak go planuje się w budżecie? Podaj wzór i interpretację.", "a": "Kapitał obrotowy netto (working capital) = aktywa obrotowe - zobowiązania bieżące; w ujęciu zarządczym KON = zapasy + należności - zobowiązania handlowe. Mierzy nadwyżkę aktywów obrotowych finansowaną kapitałem stałym, czyli płynnościowy bufor firmy. W planowaniu prognozuje się każdy składnik przez wskaźniki rotacji (DSO, DIO, DPO) powiązane z prognozą sprzedaży/kosztów, a przyrost KON to wydatek pomniejszający przepływy operacyjne. KON dodatni oznacza, że część majątku obrotowego finansują źródła długoterminowe (bezpieczna struktura); ujemny bywa typowy dla handlu detalicznego (dostawcy finansują zapasy).", "type": "definicyjne"}, {"id": "qb_9_79", "chapter": "t9", "q": "Firma planuje sprzedaż: budżet 10 000 szt. po 50 zł = 500 000 zł. Faktycznie sprzedano 9 000 szt. po 54 zł = 486 000 zł. Rozłóż odchylenie przychodów na odchylenie ceny i ilości.", "a": "Odchylenie łączne = 486 000 - 500 000 = -14 000 zł (niekorzystne). Odchylenie cenowe = (cena rzecz. - cena plan.) x ilość rzecz. = (54 - 50) x 9 000 = +36 000 zł (korzystne). Odchylenie ilościowe = (ilość rzecz. - ilość plan.) x cena plan. = (9 000 - 10 000) x 50 = -50 000 zł (niekorzystne). Kontrola: +36 000 - 50 000 = -14 000 zł, zgadza się. Wniosek: wyższa cena nie skompensowała spadku wolumenu - problem leży po stronie ilości, nie ceny.", "type": "obliczeniowe"}, {"id": "qb_9_80", "chapter": "t9", "q": "Porównaj cykl konwersji gotówki (CCC) z cyklem operacyjnym - czym się różnią i jak je liczyć?", "a": "Cykl operacyjny = DIO + DSO (okres rotacji zapasów + okres ściągania należności) - czas od zakupu zapasu do inkasa gotówki ze sprzedaży. Cykl konwersji gotówki CCC = DIO + DSO - DPO, czyli cykl operacyjny pomniejszony o okres regulowania zobowiązań wobec dostawców. Różnica: cykl operacyjny ignoruje finansowanie przez dostawców, a CCC pokazuje, ile dni firma musi sama finansować działalność z własnej gotówki/kredytu. Im krótszy CCC tym lepiej (mniejsze zapotrzebowanie na kapitał obrotowy); CCC ujemny (np. Amazon, Dell) oznacza, że dostawcy finansują operacje, zanim firma zapłaci za towar.", "type": "porownawcze"}, {"id": "qb_9_81", "chapter": "t9", "q": "Pułapka: student twierdzi, że budżet wykazujący zysk netto 200 000 zł gwarantuje firmie wypłacalność w danym okresie. Gdzie błąd?", "a": "Błąd polega na mylenie zysku (memoriałowego) z gotówką (kasowym). Zysk netto zawiera przychody zafakturowane, ale jeszcze niezainkasowane (wzrost należności) i koszty memoriałowe niegotówkowe (amortyzacja), a pomija wydatki nieujmowane w RZiS: spłatę rat kredytu, CAPEX, przyrost zapasów i wypłatę dywidend. Firma rentowna może być niewypłacalna, gdy gotówka jest zamrożona w KON lub zaangażowana w inwestycje - dlatego konieczny jest budżet przepływów pieniężnych (cash flow), a nie tylko budżet wyników. Reguła: profit is an opinion, cash is a fact.", "type": "pulapka"}, {"id": "qb_9_82", "chapter": "t9", "q": "Wyjaśnij różnicę między budżetem statycznym a elastycznym (flexible budget) i jaką rolę pełni budżet elastyczny w analizie odchyleń.", "a": "Budżet statyczny jest sporządzony dla jednego, z góry założonego poziomu aktywności (np. 10 000 szt.) i nie zmienia się mimo innej rzeczywistej produkcji. Budżet elastyczny przelicza koszty zmienne na faktyczny poziom aktywności (koszt zmienny jednostkowy x ilość rzeczywista), pozostawiając koszty stałe bez zmian. Dzięki temu odchylenie łączne rozkłada się na odchylenie aktywności (statyczny vs elastyczny - skutek innej skali) oraz odchylenie wydajności/ceny (elastyczny vs rzeczywisty - skutek efektywności). Bez budżetu elastycznego porównywanie kosztów przy 9 000 szt. z planem na 10 000 szt. zniekształca ocenę, bo część odchylenia wynika tylko z innego wolumenu.", "type": "porownawcze"}, {"id": "qb_10_83", "chapter": "t10", "q": "Wyjasnij teorie parytetu sily nabywczej (PPP) oraz parytetu stop procentowych (IRP). Czym roznia sie wersja absolutna i wzgledna PPP?", "a": "PPP wynika z prawa jednej ceny: kurs walutowy wyrownuje sile nabywcza walut. Wersja absolutna: S = P_krajowa / P_zagraniczna (kurs = stosunek poziomow cen koszyka dobr). Wersja wzgledna: zmiana kursu w przyblizeniu rowna sie roznicy inflacji (deltaS approx pi_kraj - pi_zagr). IRP (pokryty, CIP) wiaze kurs terminowy z roznica stop procentowych: F/S = (1+i_kraj)/(1+i_zagr), czyli waluta o wyzszej stopie notuje dyskonto terminowe. PPP to teoria dlugookresowa (czesto nie spelniona krotkookresowo), IRP w wersji pokrytej jest wymuszany arbitrazem i trzyma sie niemal idealnie.", "type": "definicyjne"}, {"id": "qb_10_84", "chapter": "t10", "q": "Kurs spot EUR/PLN = 4,3000. Stopa roczna w strefie euro i_EUR = 2%, w Polsce i_PLN = 6%. Oblicz teoretyczny 12-miesieczny kurs forward EUR/PLN zgodny z parytetem stop procentowych (CIP).", "a": "Wzor CIP (waluta bazowa EUR, kwotowana PLN): F = S * (1+i_PLN)/(1+i_EUR). Podstawiamy: F = 4,3000 * (1,06/1,02) = 4,3000 * 1,039216 = 4,4686. Wynik: forward approx 4,4686 PLN za EUR. Poniewaz stopa PLN jest wyzsza, EUR notuje premie terminowa (PLN sie deprecjonuje na forwardzie) o okolo 0,1686 PLN, tj. ok. 3,92%.", "type": "obliczeniowe"}, {"id": "qb_10_85", "chapter": "t10", "q": "Porownaj kontrakt forward i kontrakt futures jako narzedzia zabezpieczenia ryzyka walutowego.", "a": "Forward jest pozagieldowy (OTC), dostosowany co do kwoty i daty, rozliczany jednorazowo w terminie, niesie ryzyko kontrahenta i zwykle bez depozytu. Futures jest standaryzowany, notowany na gieldzie (np. CME), z izba rozliczeniowa eliminujaca ryzyko kontrahenta, codziennym marking-to-market i depozytem zabezpieczajacym (margin). Forward daje doskonale dopasowanie ekspozycji (idealny hedge), ale gorsza plynnosc; futures jest plynny i bezpieczny kredytowo, lecz standaryzacja powoduje ryzyko bazy i wymogi przeplywow gotowki na uzupelnienia depozytu. Obie konstrukcje to zobowiazanie symetryczne (brak prawa wyboru), w przeciwienstwie do opcji.", "type": "porownawcze"}, {"id": "qb_10_86", "chapter": "t10", "q": "Pulapka: firma kupila opcje walutowa call na USD, by zabezpieczyc przyszla platnosc importowa. Jaki czesty blad popelnia sie, twierdzac, ze 'opcja jest tansza i lepsza od forwardu, bo nie trzeba nic placic'? Wyjasnij rowniez czesto mylone pojecia ekspozycji.", "a": "Blad 1: opcja nie jest darmowa - placi sie z gory premie opcyjna (koszt poniesiony niezaleznie od tego, czy opcja zostanie wykonana), wiec 'zerowy koszt' to mit; forward nie wymaga premii. Opcja daje prawo, nie obowiazek, wiec chroni przed niekorzystnym ruchem, zachowujac potencjal korzysci - to wlasnie za to placi sie premie. Blad 2: mylenie typow ekspozycji - ekspozycja transakcyjna (konkretne zakontraktowane przeplywy, np. faktura w USD) to nie to samo co ekspozycja ksiegowa/translacyjna (przeliczenie sprawozdan zagranicznej spolki) ani ekonomiczna/operacyjna (wplyw kursu na konkurencyjnosc i przyszle przeplywy). Hedging instrumentem terminowym zabezpiecza glownie ekspozycje transakcyjna, a nie ekonomiczna.", "type": "pulapka"}, {"id": "qb_10_87", "chapter": "t10", "q": "Opisz role MFW (IMF), Banku Swiatowego (BS) i Europejskiego Banku Centralnego (EBC) w systemie walutowym oraz wskaz roznice w ich misjach.", "a": "MFW (IMF) czuwa nad stabilnoscia miedzynarodowego systemu walutowego, prowadzi nadzor (surveillance), udziela pozyczek krajom z problemami bilansu platniczego i emituje SDR (jednostke rozrachunkowa). Bank Swiatowy (grupa: IBRD, IDA) finansuje rozwoj i redukcje ubostwa poprzez kredyty dlugoterminowe na projekty/reformy - cel rozwojowy, nie ratunkowo-walutowy. EBC prowadzi jednolita polityke pieniezna strefy euro, dba o stabilnosc cen (cel inflacyjny ok. 2% [zweryfikuj]) i emituje euro; nie ustala 'sztywnego' kursu euro, ktory jest plynny wzgledem innych walut. Roznica kluczowa: MFW = stabilnosc systemu/bilanse platnicze, BS = rozwoj/inwestycje, EBC = polityka monetarna jednego obszaru walutowego.", "type": "definicyjne"}, {"id": "qb_11_88", "chapter": "t11", "q": "Czym jest WACC i jak go obliczamy? Podaj wzor i wyjasnij role tarczy podatkowej.", "a": "WACC (sredni wazony koszt kapitalu) to stopa dyskontowa odzwierciedlajaca przecietny koszt finansowania firmy wszystkimi zrodlami, wazony ich udzialem w wartosci rynkowej. Wzor: WACC = (E/V)*Ke + (D/V)*Kd*(1-T), gdzie E to kapital wlasny, D to dlug, V=E+D, Ke koszt kapitalu wlasnego, Kd koszt dlugu brutto, T stopa podatkowa. Tarcza podatkowa (1-T) obniza efektywny koszt dlugu, bo odsetki sa kosztem uzyskania przychodu i zmniejszaja podstawe opodatkowania. WACC sluzy jako stopa progowa (hurdle rate) do oceny projektow i wyceny DCF; powinien byc liczony na wartosciach rynkowych, nie ksiegowych.", "type": "definicyjne"}, {"id": "qb_11_89", "chapter": "t11", "q": "Oblicz WACC dla spolki: E=600 mln, D=400 mln, Ke=12%, Kd=7%, stopa podatkowa T=19%.", "a": "V = E+D = 600+400 = 1000 mln. Wagi: E/V = 0,6; D/V = 0,4. Koszt dlugu po opodatkowaniu: Kd*(1-T) = 7%*(1-0,19) = 7%*0,81 = 5,67%. WACC = 0,6*12% + 0,4*5,67% = 7,2% + 2,268% = 9,468%, czyli ok. 9,47%. Stopa podatkowa CIT [zweryfikuj] - tu przyjeto 19%. Bez tarczy WACC bylby 0,6*12%+0,4*7% = 9,2%, wiec tarcza obniza koszt.", "type": "obliczeniowe"}, {"id": "qb_11_90", "chapter": "t11", "q": "Jak oblicza sie koszt kapitalu wlasnego metoda CAPM i jak uwzglednia sie premie za ryzyko kraju w inwestycji miedzynarodowej?", "a": "CAPM: Ke = Rf + beta*(Rm - Rf), gdzie Rf to stopa wolna od ryzyka, beta wrazliwosc akcji na rynek, (Rm-Rf) rynkowa premia za ryzyko (ERP, historycznie ok. 4-6% [zweryfikuj]). W ujeciu miedzynarodowym dodaje sie premie za ryzyko kraju (CRP): Ke = Rf + beta*(Rm-Rf) + CRP. CRP szacuje sie najczesciej ze spreadu obligacji rzadowych (rentownosc dlugu kraju vs USA/Niemcy) skorygowanego wskaznikiem zmiennosci rynku akcji do obligacji (metoda Damodarana). Przyklad: Rf=3%, beta=1,1, ERP=5%, CRP=2,5% -> Ke = 3% + 1,1*5% + 2,5% = 11%.", "type": "obliczeniowe"}, {"id": "qb_11_91", "chapter": "t11", "q": "Porownaj koszt dlugu i koszt kapitalu wlasnego - dlaczego dlug jest tanszy i co to oznacza dla struktury kapitalu?", "a": "Koszt dlugu (Kd) jest zwykle nizszy niz koszt kapitalu wlasnego (Ke) z dwoch powodow: (1) wierzyciele maja pierwszenstwo roszczen i zabezpieczenia, wiec ponosza mniejsze ryzyko niz akcjonariusze (rezydualni wlasciciele), wiec zadaja nizszej stopy; (2) odsetki daja tarcze podatkowa, wiec efektywny koszt to Kd*(1-T). Akcjonariusze wymagaja premii za ryzyko, dywidendy nie sa kosztem podatkowym. Implikacja: zwiekszanie udzialu dlugu poczatkowo obniza WACC, ale rosnace ryzyko bankructwa i finansowy lewar podnosza zarowno Ke (beta lewarowana) jak i Kd, co tworzy optymalna strukture kapitalu (teoria trade-off).", "type": "porownawcze"}, {"id": "qb_11_92", "chapter": "t11", "q": "PULAPKA: Student liczy WACC dla projektu w obcym kraju, dyskontujac przeplywy w EUR stopa WACC opartą o stope wolna od ryzyka USD i dokladajac premie za ryzyko kraju. Gdzie popelnia bledy?", "a": "Glowny blad to niespojnosc walutowa: przeplywy denominowane w EUR musza byc dyskontowane stopa wyrazona w EUR (z eurową Rf i euro inflacja), a nie stopa zbudowana na USD Rf - inaczej miesza sie roznice inflacji/parytet stop procentowych. Drugi czesty blad to podwojne liczenie ryzyka kraju: dodanie CRP do dyskonta ORAZ jednoczesne obnizenie prognozowanych przeplywow o to samo ryzyko polityczne. Poprawnie: albo ryzyko ujmuje sie w stopie (CRP), albo w scenariuszach przeplywow, nie dwukrotnie. Ryzyko walutowe nalezy ujmowac przez przeliczenie po forwardach/parytecie stop (warunki spojne), a nie przez arbitralne podbijanie WACC. Bledem jest tez uzycie wag ksiegowych zamiast rynkowych przy ustalaniu E/V i D/V.", "type": "pulapka"}, {"id": "qb_6_93", "chapter": "t6", "q": "Przedstaw klasyfikację produktów i usług bankowych według kryterium funkcjonalnego oraz scharakteryzuj krótko każdą z głównych grup.", "a": "Produkty bankowe dzieli się funkcjonalnie na cztery główne grupy. (1) Depozytowe (pasywne) - bank pozyskuje środki: rachunki bieżące, lokaty terminowe, rachunki oszczędnościowe; bank jest dłużnikiem klienta. (2) Kredytowe (aktywne) - bank udostępnia kapitał: kredyty (gotówkowe, hipoteczne, obrotowe, inwestycyjne), pożyczki, linie kredytowe, leasing, faktoring; bank jest wierzycielem. (3) Rozliczeniowe - obsługa płatności: prowadzenie rachunków, przelewy, polecenia zapłaty, karty, BLIK, instrumenty płatnicze. (4) Inwestycyjne/pozostałe - asset management, dystrybucja jednostek funduszy, obrót papierami wartościowymi (usługi maklerskie), underwriting (gwarantowanie emisji), doradztwo i bancassurance. Kryterium wyróżnia produkty po stronie pasywów, aktywów oraz usług prowizyjnych (off-balance).", "type": "definicyjne"}, {"id": "qb_6_94", "chapter": "t6", "q": "Klient wpłaca 50 000 zł na lokatę 12-miesięczną o oprocentowaniu nominalnym 6% w skali roku z kapitalizacją kwartalną. Oblicz kwotę odsetek brutto, kwotę netto po podatku Belki oraz efektywną stopę roczną (APY).", "a": "Kapitalizacja kwartalna: stopa okresowa = 6%/4 = 1,5% = 0,015, liczba okresów n = 4. Wartość końcowa = 50 000 x (1,015)^4 = 50 000 x 1,061364 = 53 068,18 zł. Odsetki brutto = 53 068,18 - 50 000 = 3 068,18 zł. Podatek od zysków kapitałowych (Belki) 19% [zweryfikuj stawkę]: 3 068,18 x 0,19 = 582,95 zł. Odsetki netto = 3 068,18 - 582,95 = 2 485,23 zł. Efektywna stopa roczna APY = (1,015)^4 - 1 = 6,1364%, czyli ok. 6,14% (wyższa od nominalnej 6% dzięki kapitalizacji). Po opodatkowaniu efektywna stopa netto wynosi ok. 4,97%.", "type": "obliczeniowe"}, {"id": "qb_6_95", "chapter": "t6", "q": "Porównaj pieniądz elektroniczny z depozytem bankowym płatnym na żądanie - wskaż różnice w istocie prawnej, gwarancjach i sposobie wykorzystania środków przez instytucję.", "a": "Pieniądz elektroniczny to wartość pieniężna przechowywana elektronicznie (w tym magnetycznie), wyemitowana w zamian za otrzymane środki w celu dokonywania transakcji płatniczych, akceptowana przez podmioty inne niż emitent. Różnice: (1) Emitent - pieniądz elektroniczny wydają instytucje pieniądza elektronicznego (EMI) lub banki, depozyt prowadzi bank. (2) Ochrona środków - środki za e-pieniądz NIE są objęte gwarancjami BFG/systemu gwarantowania depozytów (do 100 000 EUR [zweryfikuj]), lecz podlegają wymogowi zabezpieczenia (safeguarding) - oddzielenia od majątku emitenta. (3) Wykorzystanie - bank może środki z depozytu kredytować (transformacja terminów, kreacja pieniądza), EMI nie może obracać środkami klienta ani naliczać odsetek od e-pieniądza. (4) Cel - e-pieniądz służy wyłącznie płatnościom i podlega wykupowi na żądanie po wartości nominalnej. Depozyt jest umową przechowania/pożyczki z możliwym oprocentowaniem.", "type": "porownawcze"}, {"id": "qb_6_96", "chapter": "t6", "q": "Omów dyrektywę PSD2 i mechanizm silnego uwierzytelniania klienta (SCA) - na czym polega, jakie elementy obejmuje i jakie są dopuszczalne wyłączenia.", "a": "PSD2 (Payment Services Directive 2) to unijna dyrektywa o usługach płatniczych [zweryfikuj transpozycję krajową], która wprowadziła m.in. open banking (dostęp TPP do rachunków przez API: usługi AIS - dostęp do informacji o rachunku, PIS - inicjowanie płatności) oraz obowiązek SCA. Silne uwierzytelnianie klienta (Strong Customer Authentication) wymaga użycia co najmniej dwóch z trzech niezależnych elementów: (1) wiedza - coś, co klient wie (hasło, PIN); (2) posiadanie - coś, co klient ma (telefon, token, karta); (3) cecha - coś, czym klient jest (biometria: odcisk palca, twarz). Elementy muszą być niezależne (złamanie jednego nie kompromituje pozostałych), a dla płatności zdalnych stosuje się dynamiczne powiązanie kodu z kwotą i odbiorcą. Wyłączenia (exemptions): płatności niskokwotowe (zwykle do 30 EUR z limitami kumulacji [zweryfikuj]), płatności zbliżeniowe w POS do limitu, zaufani odbiorcy (whitelist), abonamenty/płatności cykliczne o stałej kwocie, transakcje MOTO oraz transakcje inicjowane przez akceptanta (MIT).", "type": "definicyjne"}, {"id": "qb_6_97", "chapter": "t6", "q": "PUŁAPKA: Klient twierdzi, że gdy bank przeprowadza emisję obligacji spółki w trybie underwritingu typu 'best efforts', bank gwarantuje pozyskanie całej kwoty emisji i przejmuje ryzyko niesprzedanych papierów. Czy ma rację? Wyjaśnij i rozróżnij modele gwarantowania emisji.", "a": "Klient NIE ma racji - myli dwa różne modele subemisji. W underwritingu typu 'best efforts' (subemisja usługowa w wariancie dołożenia starań) bank działa wyłącznie jako agent i zobowiązuje się jedynie do dołożenia najlepszych starań w plasowaniu papierów - NIE gwarantuje sprzedaży całości i NIE przejmuje ryzyka niesprzedanych walorów; ryzyko zostaje po stronie emitenta. Przejęcie ryzyka następuje w modelu 'firm commitment' (subemisja inwestycyjna/firm underwriting), gdzie bank nabywa całą emisję na własny rachunek po ustalonej cenie i odsprzedaje ją inwestorom, zarabiając na spreadzie (underwriting spread) i ponosząc ryzyko niesprzedania. Istnieje też wariant 'standby', gdzie bank obejmuje tylko niesprzedaną resztę. Pułapka polega na utożsamieniu 'best efforts' z gwarancją - tymczasem to właśnie brak gwarancji odróżnia ten model i przekłada się na niższą prowizję banku.", "type": "pulapka"}, {"id": "qb_7_98", "chapter": "t7", "q": "Zdefiniuj ubezpieczenie jako instytucję finansową i wymień jego trzy podstawowe funkcje oraz cechy konstytutywne.", "a": "Ubezpieczenie to urządzenie gospodarcze polegające na tworzeniu wspólnego funduszu ze składek wielu podmiotów narażonych na to samo ryzyko, z którego wypłaca się świadczenia tym, których dotknęło zdarzenie losowe (repartycja/redystrybucja ryzyka). Cechy konstytutywne: losowość zdarzenia, wzajemność (mutualizm), realność ochrony i planowość (kalkulacja składki na podstawie prawa wielkich liczb). Trzy funkcje: ochronna (kompensata szkód, redystrybucja ryzyka w czasie i przestrzeni), prewencyjna (ograniczanie ryzyka, finansowanie prewencji) oraz finansowa/akumulacyjna (gromadzenie rezerw techniczno-ubezpieczeniowych i ich lokowanie na rynku kapitałowym). Składka jest ceną za przejęcie ryzyka, a istotą jest przekształcenie niepewnej, dużej straty jednostkowej w pewny, mały koszt (składkę).", "type": "definicyjne"}, {"id": "qb_7_99", "chapter": "t7", "q": "Zakład ubezpieczeń ubezpiecza 10 000 jednorodnych ryzyk; prawdopodobieństwo szkody wynosi p = 0,02, a przeciętna szkoda 5 000 zł. Oblicz składkę netto (czystą) na jedno ryzyko, łączną oczekiwaną wartość szkód oraz uzasadnij rolę prawa wielkich liczb. Jak zmieni się względne odchylenie ryzyka, gdy portfel wzrośnie do 1 000 000 polis?", "a": "Składka netto = p × przeciętna szkoda = 0,02 × 5 000 = 100 zł na polisę. Oczekiwana liczba szkód = 0,02 × 10 000 = 200, więc łączna oczekiwana wartość szkód = 200 × 5 000 = 1 000 000 zł (= 10 000 × 100). Składka brutto (taryfowa) byłaby wyższa o dodatek na koszty, marżę i bezpieczeństwo. Prawo wielkich liczb: im większy portfel, tym rzeczywista częstość szkód jest bliższa p, więc faktyczne wyniki stabilizują się wokół wartości oczekiwanej. Względne odchylenie maleje proporcjonalnie do 1/√n: przy wzroście n z 10 000 do 1 000 000 (czyli ×100) odchylenie względne (współczynnik zmienności) spada √100 = 10-krotnie, co znacząco zmniejsza ryzyko ubezpieczyciela.", "type": "obliczeniowe"}, {"id": "qb_7_100", "chapter": "t7", "q": "Porównaj trzy filary polskiego systemu emerytalnego (I: ZUS, II: OFE, III: IKE/IKZE) pod kątem charakteru, obowiązkowości, sposobu finansowania i własności środków.", "a": "I filar (ZUS/FUS) jest obowiązkowy, repartycyjny (pay-as-you-go) i zdefiniowanej składki ewidencyjnej — bieżące składki finansują bieżące emerytury, a środki na koncie to zapis (nie kapitał inwestowany), waloryzowany ustawowo. II filar (OFE) jest kapitałowy, zarządzany przez prywatne PTE, inwestujący głównie w akcje; po reformie 2014 stał się dobrowolny (suwak bezpieczeństwa przenosi środki na subkonto ZUS na 10 lat przed emeryturą), a od 2014 obligacje skarbowe z OFE umorzono. III filar (IKE/IKZE) jest w pełni dobrowolny, kapitałowy i indywidualny: IKE daje zwolnienie z podatku Belki przy wypłacie po 60. r.ż., IKZE daje odliczenie wpłat od podstawy PIT, lecz wypłata jest opodatkowana ryczałtem 10% [zweryfikuj limity wpłat na dany rok]. Kluczowa różnica: I filar to zobowiązanie państwa (brak realnego majątku), II i III to realne aktywa na rynku kapitałowym, przy czym tylko III jest dobrowolny i dziedziczony bez ograniczeń konstrukcyjnych I filaru.", "type": "porownawcze"}, {"id": "qb_7_101", "chapter": "t7", "q": "Czym różni się dział I od działu II ubezpieczeń (wg ustawy o działalności ubezpieczeniowej) i jaka zasada wynika z tego podziału?", "a": "Dział I to ubezpieczenia na życie (osobowe o charakterze życiowym): na życie, posagowe, z ubezpieczeniowym funduszem kapitałowym (UFK), rentowe, wypadkowe i chorobowe jako uzupełniające. Dział II to pozostałe ubezpieczenia osobowe oraz majątkowe (m.in. komunikacyjne OC i AC, majątkowe, odpowiedzialności cywilnej, finansowe, NNW). Z podziału wynika zasada rozdzielności (specjalizacji): jeden zakład ubezpieczeń nie może jednocześnie prowadzić działalności w obu działach (zakaz łączenia działu I i II w jednym podmiocie), co chroni długoterminowe rezerwy życiowe przed ryzykiem katastroficznym majątkowym. Ubezpieczenia działu I cechuje długi horyzont i element oszczędnościowo-kapitałowy, a działu II krótki okres (zwykle roczny) i charakter czysto ochronny (odszkodowawczy).", "type": "definicyjne"}, {"id": "qb_7_102", "chapter": "t7", "q": "Egzaminowany twierdzi: 'Solvency II to wymóg, by zakład ubezpieczeń utrzymywał kapitał równy co najmniej 8% rezerw, a nadzór nad rynkiem sprawuje wyłącznie KNF na podstawie własnych polskich przepisów.' Wskaż błędy i podaj prawidłowy obraz.", "a": "To zlepek błędów. Po pierwsze, wskaźnik 8% kapitału do aktywów ważonych ryzykiem to Bazylea/CRR dla banków, a NIE Solvency II — w ubezpieczeniach nie ma stałego progu 8% rezerw. Solvency II opiera się na dwóch wymogach: SCR (Solvency Capital Requirement, kalibrowany na VaR 99,5% w horyzoncie 1 roku) i niższym MCR (Minimum Capital Requirement); wskaźnik wypłacalności = środki własne / SCR i powinien wynosić co najmniej 100%. Po drugie, Solvency II to dyrektywa UE oparta na trzech filarach (wymogi ilościowe, ład/ORSA, sprawozdawczość i przejrzystość), a nie 'własne polskie przepisy' — Polska ją implementowała, a koordynuje EIOPA. Po trzecie, KNF rzeczywiście sprawuje nadzór nad polskim rynkiem, ale w ramach europejskiego systemu nadzoru (ESFS/EIOPA), nie 'wyłącznie' i nie tylko na bazie krajowej. Dodatkowo gwarancje dla klientów zapewnia UFG (komunikacja) oraz fundusze gwarancyjne, a nie kapitał 8% [zweryfikuj aktualne progi i kalibracje SCR].", "type": "pulapka"}, {"id": "qb_12_103", "chapter": "t12", "q": "Czym jest instrument pochodny i jaka jest fundamentalna roznica miedzy kontraktem forward a kontraktem futures pod wzgledem konstrukcji i obrotu?", "a": "Instrument pochodny (derywat) to instrument finansowy, ktorego wartosc zalezy od ceny instrumentu bazowego (akcji, waluty, stopy procentowej, towaru). Forward to niestandaryzowany kontrakt OTC zawierany dwustronnie poza gielda: warunki (nominal, termin, cena) sa negocjowane indywidualnie, rozliczenie nastepuje raz, w terminie zapadalnosci, i wystepuje ryzyko kontrahenta. Futures to standaryzowany kontrakt gieldowy: ujednolicone parametry, gwarancja izby rozliczeniowej (clearing house) jako kontrahenta dla obu stron, codzienne rozliczanie zyskow i strat (mark-to-market) oraz obowiazek wnoszenia depozytu zabezpieczajacego (initial i maintenance margin). Dzieki izbie rozliczeniowej i mark-to-market futures praktycznie eliminuja ryzyko kredytowe kontrahenta, ktore w forwardach pozostaje istotne.", "type": "definicyjne"}, {"id": "qb_12_104", "chapter": "t12", "q": "Akcja kosztuje obecnie S=100 zl, roczna stopa wolna od ryzyka wynosi r=5%, akcja nie placi dywidendy. Wyznacz teoretyczna cene 6-miesiecznego (t=0,5) kontraktu forward na te akcje metoda cost of carry. Jaka bylaby okazja arbitrazowa, gdyby rynkowa cena forward wynosila 105 zl?", "a": "Wzor cost of carry: F = S(1+r)^t = 100 x (1,05)^0,5 = 100 x 1,02470 = 102,47 zl. Teoretyczna (godziwa) cena forward to ok. 102,47 zl. Gdyby rynek kwotowal forward na 105 zl, kontrakt bylby przewartosciowany o ok. 2,53 zl, co stwarza arbitraz typu cash-and-carry: sprzedajemy (zajmujemy krotka pozycje) drogi forward po 105, jednoczesnie kupujemy akcje za 100 finansujac zakup pozyczka na 5%. Po 6 miesiacach dostarczamy akcje, otrzymujemy 105 zl, splacamy 102,47 zl dlugu i inkasujemy bezryzykowny zysk ok. 2,53 zl na kontrakt. (Przy zlozeniu ciaglym F = S e^(rt) = 100 x e^(0,025) = 102,53 zl — wynik praktycznie ten sam.)", "type": "obliczeniowe"}, {"id": "qb_12_105", "chapter": "t12", "q": "Porownaj profile wyplaty i ryzyko nabywcy kontraktu forward/futures (pozycja dluga) z nabywca opcji kupna (long call). Czym rozni sie wyplata liniowa od asymetrycznej?", "a": "Forward/futures ma profil liniowy i symetryczny: wyplata = S_T - F, wiec nabywca zyskuje zlotowka za zlotowke przy wzroscie ceny i traci tyle samo przy spadku — strata jest nieograniczona az do zera ceny bazowej, a wejscie w pozycje nic nie kosztuje (poza depozytem). Opcja kupna ma profil asymetryczny: wyplata = max(S_T - K, 0), wiec posiadacz korzysta z pelnego wzrostu powyzej ceny wykonania K, ale jego maksymalna strata jest ograniczona do zaplaconej premii. Cena tej asymetrii (ograniczonego ryzyka) to wlasnie premia placona z gory — w forwardzie/futures jej nie ma, ale ryzyko jest dwustronne. W skrocie: derywat liniowy = pelna ekspozycja w obie strony za darmo; opcja = jednostronna ochrona kupiona za premie.", "type": "porownawcze"}, {"id": "qb_12_106", "chapter": "t12", "q": "Wyjasnij parytet put-call dla opcji europejskich oraz zastosuj go: opcja call ma cene C=8 zl, S=100 zl, K=100 zl, r=5% rocznie, T=1 rok. Ile powinna kosztowac odpowiadajaca opcja put?", "a": "Parytet put-call dla opcji europejskich na akcje bez dywidendy: C - P = S - K e^(-rT), gdzie C i P to ceny call i put o tej samej cenie wykonania K i terminie T. Wynika on z braku arbitrazu: portfel 'long call + gotowka K e^(-rT)' daje w T te sama wyplate co 'long put + akcja', wiec musza kosztowac tyle samo. Przeksztalcajac: P = C - S + K e^(-rT) = 8 - 100 + 100 x e^(-0,05) = 8 - 100 + 95,123 = 3,12 zl. Zatem opcja put powinna kosztowac ok. 3,12 zl; gdyby kosztowala inaczej, mozliwy bylby arbitraz przez zlozenie obu portfeli.", "type": "definicyjne"}, {"id": "qb_12_107", "chapter": "t12", "q": "Czesta teza studentow: 'Futures i opcje to to samo — oba pozwalaja kupic aktywo w przyszlosci po ustalonej cenie, a hedging zawsze gwarantuje zysk.' Wskaz bledy w tym twierdzeniu.", "a": "Twierdzenie laczy dwa bledy. Po pierwsze, futures to ZOBOWIAZANIE obu stron do transakcji po ustalonej cenie (profil liniowy, brak premii, ryzyko dwustronne), natomiast opcja daje posiadaczowi PRAWO, a nie obowiazek, wykonania — placi on premie i ma wyplate asymetryczna; to nie sa instrumenty rownowazne. Po drugie, hedging nie 'gwarantuje zysku' — jego celem jest redukcja ryzyka (stabilizacja wyniku), a nie jego maksymalizacja: zabezpieczajac sie, rezygnujemy z korzystnych ruchow rynku w zamian za ochrone przed niekorzystnymi, ponosimy koszty (premia, depozyty, baza/basis risk) i czesto osiagamy nizszy oczekiwany zysk niz pozycja niezabezpieczona. Zysk z derywatow w celach zarobkowych to spekulacja (gra kierunkowa) albo arbitraz (bezryzykowne wykorzystanie roznicy cen), a nie hedging. Mylenie zabezpieczenia ze spekulacja jest klasycznym bledem egzaminacyjnym.", "type": "pulapka"}], "formulas": [{"latex": "VaR = z_{\\alpha} \\cdot \\sigma \\cdot V", "legend": "VaR — wartość zagrożona (zł); z_{\\alpha} — kwantyl normalny (1,65 dla 95%, 2,33 dla 99%); \\sigma — dzienna zmienność (ułamek, np. 0,02 = 2%); V — wartość pozycji (zł).", "chapter": "t1", "id": "fm_t1_0"}, {"latex": "VaR_{t} = VaR \\cdot \\sqrt{t}", "legend": "VaR_t — VaR za t dni (zł); \\sqrt{t} — pierwiastek z liczby dni (\\sqrt{10} \\approx 3{,}16); t — horyzont w dniach. Reguła \\sqrt{t} (nie \\times t) wynika z dodawania się wariancji niezależnych zwrotów", "chapter": "t1", "id": "fm_t1_1"}, {"latex": "VaR_{port} = \\sqrt{VaR_1^2 + VaR_2^2 + 2\\rho \\cdot VaR_1 \\cdot VaR_2}", "legend": "VaR_{port} — VaR portfela (zł); VaR_1, VaR_2 — VaR składników (zł); \\rho (ro) — korelacja od −1 do +1. Przy \\rho < 1 wynik jest niższy od sumy prostej — to **efekt dywersyfikacji**.", "chapter": "t1", "id": "fm_t1_2"}, {"latex": "EL = PD \\times LGD \\times EAD", "legend": "PD — prawdopodobieństwo defaultu (0–1); LGD — frakcja nieodzyskana po defaulcie (0–1); EAD — ekspozycja w chwili defaultu (zł); EL — strata oczekiwana (zł/rok).", "chapter": "t2", "id": "fm_t2_3"}, {"latex": "UL = EAD \\times LGD \\times \\sqrt{PD \\cdot (1-PD)}", "legend": "UL — strata nieoczekiwana (zł); \\sqrt{PD \\cdot (1-PD)} — odchylenie standardowe zdarzenia „default/brak defaultu\" (największe przy PD = 0{,}5).", "chapter": "t2", "id": "fm_t2_4"}, {"latex": "Z = 1{,}2 X_1 + 1{,}4 X_2 + 3{,}3 X_3 + 0{,}6 X_4 + 1{,}0 X_5", "legend": "X_1 — kapitał obrotowy/aktywa (płynność); X_2 — zyski zatrzymane/aktywa (skumulowana rentowność); X_3 — EBIT/aktywa (rentowność operacyjna, najwyższa waga); X_4 — wartość rynkowa kapitału/zobowiązania; X", "chapter": "t2", "id": "fm_t2_5"}, {"latex": "DSCR = \\frac{CFADS}{\\text{rata kapitałowa} + \\text{odsetki}}, \\qquad DStI = \\frac{\\text{raty}}{\\text{dochód netto}}", "legend": "DSCR — ile razy gotówka operacyjna pokrywa obsługę długu (kowenant zwykle \\geq 1{,}2); CFADS — przepływy dostępne na obsługę długu (zł/rok); DStI — część dochodu idąca na raty (osoba fizyczna).", "chapter": "t2", "id": "fm_t2_6"}, {"latex": "ECL = PD \\cdot LGD \\cdot EAD", "legend": "PD — prawdopodobieństwo defaultu (ułamek, np. 0{,}02 = 2%; 12-miesięczne dla Stage 1, lifetime dla Stage 2/3); LGD — strata na jednostkę ekspozycji przy defaulcie (ułamek, LGD = 1 - RR, gdzie RR — stop", "chapter": "t3", "id": "fm_t3_7"}, {"latex": "ECL_{lifetime} = \\sum_{t=1}^{T} \\frac{PD_t \\cdot LGD_t \\cdot EAD_t}{(1 + EIR)^{t}}", "legend": "T — liczba okresów do końca kredytu; t — numer okresu; PD_t — marginalne prawdopodobieństwo defaultu w okresie t (ułamek); EIR — efektywna stopa procentowa, służy do dyskontowania (ułamek); (1 + EIR)^", "chapter": "t3", "id": "fm_t3_8"}, {"latex": "ECL_{Stage\\,3} = EAD_{brutto} - \\sum_{t=1}^{T} \\frac{CF_t}{(1 + EIR)^{t}}", "legend": "EAD_{brutto} — ekspozycja brutto, kapitał + odsetki przed odpisem (zł); CF_t — oczekiwany odzysk w okresie t (zł).", "chapter": "t3", "id": "fm_t3_9"}, {"latex": "ECL = 0{,}015 \\cdot 0{,}45 \\cdot 2\\,000\\,000 = 13\\,500", "legend": "", "chapter": "t3", "id": "fm_t3_10"}, {"latex": "ECL = 0{,}12 \\cdot 0{,}50 \\cdot 1\\,500\\,000 = 90\\,000", "legend": "", "chapter": "t3", "id": "fm_t3_11"}, {"latex": "PV = \\frac{470\\,000}{1{,}09^{3}} = \\frac{470\\,000}{1{,}295029} \\approx 362\\,927", "legend": "", "chapter": "t3", "id": "fm_t3_12"}, {"latex": "SMA_n = \\frac{P_1 + P_2 + \\dots + P_n}{n}", "legend": "SMA_n — średnia z n okresów (zł); P_i — cena zamknięcia okresu (zł); n — liczba sesji w oknie. (Przecięcie SMA_{50} i SMA_{200} od dołu = złoty krzyż / od góry = krzyż śmierci.)", "chapter": "t4", "id": "fm_t4_13"}, {"latex": "RSI = 100 - \\frac{100}{1 + RS}, \\qquad RS = \\frac{\\overline{U}}{\\overline{D}}", "legend": "RSI — skala 0–100; RS — siła względna; \\overline{U} — średni wzrost (zł); \\overline{D} — średni spadek (zł). Progi: >70 wykupienie, <30 wyprzedanie, 50 = równowaga.", "chapter": "t4", "id": "fm_t4_14"}, {"latex": "gorna = SMA_n + k\\sigma, \\qquad dolna = SMA_n - k\\sigma", "legend": "SMA_n — wstęga środkowa (zł); \\sigma — odchylenie standardowe cen (zł); k — mnożnik, standardowo k = 2, n = 20.", "chapter": "t4", "id": "fm_t4_15"}, {"latex": "\\overline{U} = \\frac{14{,}0}{14} = 1{,}00 \\qquad \\overline{D} = \\frac{3{,}5}{14} = 0{,}25", "legend": "", "chapter": "t4", "id": "fm_t4_16"}, {"latex": "RS = \\frac{1{,}00}{0{,}25} = 4{,}0 \\quad\\Rightarrow\\quad RSI = 100 - \\frac{100}{1 + 4} = 100 - 20 = 80{,}0", "legend": "", "chapter": "t4", "id": "fm_t4_17"}, {"latex": "P = \\frac{FV}{1 + r \\cdot \\frac{d}{360}}", "legend": "P — cena dziś (zł); FV — nominał wykupu (zł); r — roczna stopa rynkowa (ułamek); d — dni do wykupu; 360 — umowna liczba dni w roku.", "chapter": "t5", "id": "fm_t5_18"}, {"latex": "P = \\sum_{t=1}^{n} \\frac{C}{(1+r)^t} + \\frac{FV}{(1+r)^n}", "legend": "P — cena obligacji (zł); C — kupon za okres (zł); FV — nominał na koniec (zł); r — YTM za okres (ułamek); n — liczba okresów; t — numer okresu.", "chapter": "t5", "id": "fm_t5_19"}, {"latex": "P_0 = \\frac{D_1}{r - g}", "legend": "P_0 — cena akcji dziś (zł); D_1 — dywidenda za rok 1 (zł); r — koszt kapitału własnego (ułamek); g — stała stopa wzrostu dywidendy (ułamek). Warunek: r > g.", "chapter": "t5", "id": "fm_t5_20"}, {"latex": "F_0 = S_0 \\cdot (1 + r)^T", "legend": "F_0 — cena forward (zł); S_0 — cena spot bazy (zł); r — stopa wolna od ryzyka (ułamek); T — czas do rozliczenia (lata). Korekta: dochód z bazy (dywidenda) obniża F_0, koszt magazynowania go podnosi.", "chapter": "t5", "id": "fm_t5_21"}, {"latex": "P = \\frac{60}{1{,}08} + \\frac{60}{1{,}08^2} + \\frac{60}{1{,}08^3} + \\frac{1000}{1{,}08^3}", "legend": "", "chapter": "t5", "id": "fm_t5_22"}, {"latex": "P = 55{,}56 + 51{,}44 + 47{,}63 + 793{,}83 = 948{,}46 \\text{ zł}", "legend": "", "chapter": "t5", "id": "fm_t5_23"}, {"latex": "Oplata = WAN \\cdot s \\cdot \\frac{d}{365}", "legend": "WAN — wartość portfela klienta (zł); s — stawka roczna (ułamek, np. 1,5% = 0,015); d — liczba dni naliczania (dni); 365 — rok bazowy (actual/365).", "chapter": "t6", "id": "fm_t6_24"}, {"latex": "NIM = \\frac{przychody\\ odsetkowe - koszty\\ odsetkowe}{A}", "legend": "licznik — wynik odsetkowy (zł); A — średnie aktywa pracujące generujące odsetki (zł); wynik w %.", "chapter": "t6", "id": "fm_t6_25"}, {"latex": "P_{atak} = p_1 \\cdot p_2", "legend": "P_{atak} — prawdopodobieństwo złamania obu naraz (0–1); p_1, p_2 — prawdopodobieństwa złamania każdego czynnika. Dla p_1 = p_2 = 0{,}01: P_{atak} = 0{,}0001 → ryzyko spada 100-krotnie.", "chapter": "t6", "id": "fm_t6_26"}, {"latex": "P_{czysta} = q \\cdot S", "legend": "P_{czysta} — składka czysta / netto (zł), sam ekwiwalent ryzyka; q — prawdopodobieństwo szkody (bez jednostki); S — suma ubezpieczenia / wypłaty (zł).", "chapter": "t7", "id": "fm_t7_27"}, {"latex": "P_{brutto} = \\frac{P_{czysta}}{1-\\lambda}", "legend": "P_{brutto} — składka faktycznie płacona (zł); \\lambda — udział narzutu w składce brutto (np. 0,25); 1-\\lambda — część brutto na czyste ryzyko. Uwaga: **dzielimy**, nie mnożymy.", "chapter": "t7", "id": "fm_t7_28"}, {"latex": "CV = \\frac{\\sigma_X}{\\mu} \\cdot \\frac{1}{\\sqrt{n}}", "legend": "CV — współczynnik zmienności łącznej wypłaty (bez jednostki); \\sigma_X/\\mu — względna zmienność jednej polisy (stała); n — liczba polis (sztuk). Im większa pula, tym mniejszy procentowy rozrzut — i mniejszy", "chapter": "t7", "id": "fm_t7_29"}, {"latex": "wyplata = szkoda \\cdot \\frac{suma\\ ubezpieczenia}{wartosc\\ mienia}", "legend": "szkoda — rzeczywista wartość szkody (zł); ułamek — stopień pokrycia (np. 0,75).", "chapter": "t7", "id": "fm_t7_30"}, {"latex": "Wynik = (c - kz) \\cdot Q - KS", "legend": "c — cena jednostkowa (zł/szt.), kz — koszt zmienny jednostkowy (zł/szt.), Q — ilość (szt.), KS — koszty stałe okresu (zł).", "chapter": "t8", "id": "fm_t8_31"}, {"latex": "Q^{*} = \\frac{KS}{mj}", "legend": "mj = c - kz — marża pokrycia jednostkowa (zł/szt.), KS — koszty stałe (zł), Q^{*} — próg w sztukach (szt.).", "chapter": "t8", "id": "fm_t8_32"}, {"latex": "Q_{Z} = \\frac{KS + Z}{mj}", "legend": "Z — docelowy zysk operacyjny (zł), pozostałe jak wyżej.", "chapter": "t8", "id": "fm_t8_33"}, {"latex": "Roznica = \\Delta Zapas \\cdot ks_{prod}", "legend": "\\Delta Zapas — zmiana zapasu wyrobów (produkcja - sprzedaż, szt.), ks_{prod} — stały koszt produkcji na jednostkę (zł/szt.).", "chapter": "t8", "id": "fm_t8_34"}, {"latex": "CCC = DSO + DIO - DPO", "legend": "CCC — cykl konwersji gotówki (dni); DSO — dni inkasa należności; DIO — dni rotacji zapasów; DPO — dni spłaty zobowiązań.", "chapter": "t9", "id": "fm_t9_35"}, {"latex": "WCR = naleznosci + zapasy - zobowiazania\\ handlowe", "legend": "WCR — operacyjne zamrożenie gotówki (zł); pozycje w zł.", "chapter": "t9", "id": "fm_t9_36"}, {"latex": "FCF = NOPAT + D\\&A - CapEx - \\Delta KON", "legend": "FCF — wolny przepływ pieniężny (zł); NOPAT — zysk operacyjny po opodatkowaniu (zł); D\\&A — amortyzacja (zł); CapEx — nakłady inwestycyjne (zł); \\Delta KON — nakład na kapitał obrotowy (zł).", "chapter": "t9", "id": "fm_t9_37"}, {"latex": "BEP = \\frac{KS}{c - kz} \\qquad odchylenie\\ ceny = (c_{rz} - c_{pl}) \\cdot q_{rz} \\qquad odchylenie\\ ilosci = (q_{rz} - q_{pl}) \\cdot c_{pl}", "legend": "KS — koszty stałe (zł); c — cena (zł/szt.); kz — koszt zmienny jednostkowy (zł/szt.); indeks rz — rzeczywiste, pl — planowane; q — ilość (szt.).", "chapter": "t9", "id": "fm_t9_38"}, {"latex": "F = S \\cdot \\frac{1 + r_{kw} \\cdot \\frac{t}{360}}{1 + r_{baz} \\cdot \\frac{t}{360}}", "legend": "F — kurs forward (PLN za 1 EUR), S — kurs spot (PLN za 1 EUR), r_{kw} — roczna stopa waluty kwotowanej (PLN, ułamek dziesiętny), r_{baz} — roczna stopa waluty bazowej (EUR, ułamek), t — liczba dni, 36", "chapter": "t10", "id": "fm_t10_39"}, {"latex": "VaR_{1d} = W \\cdot \\sigma \\cdot z \\qquad VaR_{Nd} = VaR_{1d} \\cdot \\sqrt{N}", "legend": "VaR_{1d} — strata, której z danym prawdopodobieństwem nie przekroczymy w 1 dzień (PLN), W — wartość pozycji (PLN), \\sigma — dzienna zmienność kursu (odchylenie standardowe), z — mnożnik z rozkładu normal", "chapter": "t10", "id": "fm_t10_40"}, {"latex": "F = 4{,}30 \\cdot \\frac{1 + 0{,}06 \\cdot 0{,}25}{1 + 0{,}03 \\cdot 0{,}25} = 4{,}30 \\cdot \\frac{1{,}015}{1{,}0075} = 4{,}3320", "legend": "", "chapter": "t10", "id": "fm_t10_41"}, {"latex": "K_e = R_f + \\beta \\cdot (R_m - R_f) + CRP", "legend": "K_e — koszt kapitału własnego (%), R_f — stopa wolna od ryzyka (% rocznie), \\beta — beta (liczba bez jednostki), (R_m - R_f) — premia za ryzyko rynkowe MRP (%), CRP — premia za ryzyko kraju (%).", "chapter": "t11", "id": "fm_t11_42"}, {"latex": "WACC = \\frac{E}{V} \\cdot K_e + \\frac{D}{V} \\cdot K_d \\cdot (1 - T)", "legend": "E — wartość rynkowa kapitału własnego (zł), D — wartość rynkowa długu (zł), V = E + D — łączna wartość firmy (zł), K_d — koszt długu przed podatkiem (%), T — stawka podatku (ułamek, np. 0,19).", "chapter": "t11", "id": "fm_t11_43"}, {"latex": "CRP = \\text{spread}_{default} \\cdot \\frac{\\sigma_{akcje}}{\\sigma_{obligacje}}", "legend": "\\text{spread}_{default} — spread niewypłacalności kraju (%), \\sigma_{akcje} — zmienność lokalnego rynku akcji (%), \\sigma_{obligacje} — zmienność obligacji rządowych (%). Skalujemy, bo akcje są ryzykowniejs", "chapter": "t11", "id": "fm_t11_44"}, {"latex": "\\beta_L = \\beta_U \\cdot \\left[1 + (1 - T) \\cdot \\frac{D}{E}\\right]", "legend": "\\beta_L — beta lewarowana (z długiem), \\beta_U — beta nielewarowana (czysty biznes), \\frac{D}{E} — dźwignia. To **wzór Hamady** — przelicza betę między poziomami zadłużenia.", "chapter": "t11", "id": "fm_t11_45"}, {"latex": "F = S_0 \\cdot (1 + r)^{T}", "legend": "F — uczciwa cena forward (zł), S_0 — cena spot dziś (zł), r — stopa wolna od ryzyka rocznie (np. 0,05), T — czas do dostawy w latach.", "chapter": "t12", "id": "fm_t12_46"}, {"latex": "\\text{Wyplata} = S_T - F", "legend": "S_T — cena spot w dacie T (zł), F — umówiona cena forward (zł); wynik dodatni = zysk longa, ujemny = strata. Profil **symetryczny i liniowy**.", "chapter": "t12", "id": "fm_t12_47"}, {"latex": "\\text{Call} = \\max(S_T - K, 0) - \\text{premia} \\qquad \\text{Put} = \\max(K - S_T, 0) - \\text{premia}", "legend": "S_T — cena spot w dniu wygaśnięcia (zł), K — strike (zł), \\max(\\cdot,0) — wartość nigdy poniżej zera. Profil **asymetryczny** (złamany w punkcie K).", "chapter": "t12", "id": "fm_t12_48"}, {"latex": "A = K_{w} + Z", "legend": "A — aktywa (majatek, w zl); K_{w} — kapital wlasny (w zl); Z — zobowiazania, czyli kapital obcy (w zl).", "chapter": "k1", "id": "fm_k1_49"}, {"latex": "WF = P - K", "legend": "WF — wynik finansowy (zysk gdy WF \\geq 0, w zl); P — przychody okresu (w zl); K — koszty wspolmierne do tych przychodow (w zl).", "chapter": "k1", "id": "fm_k1_50"}, {"latex": "A = K_{w} + Z", "legend": "A — aktywa razem (PLN); K_{w} — kapital wlasny (PLN); Z — zobowiazania i rezerwy na zobowiazania (PLN).", "chapter": "k2", "id": "fm_k2_51"}, {"latex": "C_{n} = C_{z} + K_{d} - R", "legend": "C_{n} — cena nabycia (PLN); C_{z} — cena zakupu (PLN); K_{d} — koszty bezposrednie zakupu, np. transport, clo, montaz (PLN); R — rabaty/upusty (PLN).", "chapter": "k2", "id": "fm_k2_52"}, {"latex": "W_{b} = \\min(C_{n},\\ W_{r})", "legend": "W_{b} — wartosc bilansowa (PLN); C_{n} — koszt nabycia/wytworzenia (PLN); W_{r} — wartosc rynkowa/mozliwa do uzyskania (PLN).", "chapter": "k2", "id": "fm_k2_53"}, {"latex": "Z = 1{,}2 X_{1} + 1{,}4 X_{2} + 3{,}3 X_{3} + 0{,}6 X_{4} + 1{,}0 X_{5}", "legend": "X_{1} — kapitał obrotowy netto / aktywa; X_{2} — zysk zatrzymany / aktywa; X_{3} — zysk operacyjny (EBIT) / aktywa; X_{4} — wartość rynkowa kapitału własnego / zobowiązania ogółem; X_{5} — przychody ze", "chapter": "k3", "id": "fm_k3_54"}, {"latex": "cm = c - kz_j \\qquad wcm = \\frac{cm}{c}", "legend": "c — cena jednostkowa (zł/szt.); kz_j — jednostkowy koszt zmienny (zł/szt.); cm — marża pokrycia na sztukę (zł/szt.); wcm — wskaźnik marży (bezwymiarowy).", "chapter": "k4", "id": "fm_k4_55"}, {"latex": "BEP_{ilosc} = \\frac{KS}{cm} \\qquad BEP_{wartosc} = \\frac{KS}{wcm}", "legend": "KS — całkowite koszty stałe (zł); BEP_{ilosc} — próg w sztukach; BEP_{wartosc} — próg w zł przychodu.", "chapter": "k4", "id": "fm_k4_56"}, {"latex": "Q_{Z} = \\frac{KS + Z}{cm}", "legend": "Z — zysk operacyjny docelowy (zł); Q_Z — wymagana sprzedaż (szt.).", "chapter": "k4", "id": "fm_k4_57"}, {"latex": "DOL = \\frac{CM}{CM - KS} = \\frac{\\text{marża pokrycia łączna}}{\\text{zysk operacyjny}}", "legend": "CM — łączna marża pokrycia (zł); DOL — mnożnik (np. 2 oznacza: +10\\% sprzedaży \\to +20\\% zysku); ks_j — stały koszt produkcji na sztukę (zł);", "chapter": "k4", "id": "fm_k4_58"}, {"latex": "Zysk_{RKP} - Zysk_{RKZ} = ks_j \\cdot \\Delta Q_{zapasu}", "legend": "CM — łączna marża pokrycia (zł); DOL — mnożnik (np. 2 oznacza: +10\\% sprzedaży \\to +20\\% zysku); ks_j — stały koszt produkcji na sztukę (zł); \\Delta Q_{zapasu} — przyrost zapasu (produkcja − sprzeda", "chapter": "k4", "id": "fm_k4_59"}, {"latex": "FV = PV \\cdot (1+r)^{n}", "legend": "PV — kwota dzis (zl); r — stopa za okres (ulamek); n — liczba okresow (szt.); FV — wartosc przyszla (zl).", "chapter": "k5", "id": "fm_k5_60"}, {"latex": "PV = \\frac{FV}{(1+r)^{n}}", "legend": "A — rata (zl); pozostale jak wyzej. Renta wieczysta: PV = A / r.", "chapter": "k5", "id": "fm_k5_61"}, {"latex": "PV = A \\cdot \\frac{1-(1+r)^{-n}}{r}", "legend": "A — rata (zl); pozostale jak wyzej. Renta wieczysta: PV = A / r.", "chapter": "k5", "id": "fm_k5_62"}, {"latex": "NPV = \\sum_{t=0}^{n} \\frac{CF_t}{(1+r)^{t}}", "legend": "CF_t — przeplyw w okresie t (zl, CF_0 zwykle ujemny); r — stopa dyskontowa / koszt kapitalu (ulamek). Kryterium: przyjmij gdy NPV \\geq 0.", "chapter": "k5", "id": "fm_k5_63"}, {"latex": "PI = \\frac{\\sum_{t=1}^{n} CF_t/(1+r)^{t}}{|CF_0|}", "legend": "", "chapter": "k5", "id": "fm_k5_64"}, {"latex": "k_d = r_d \\cdot (1 - T)", "legend": "r_d — nominalne oprocentowanie dlugu (%); T — stopa podatku dochodowego CIT, 19\\% lub 9\\% dla malych podatnikow [zweryfikuj aktualna wartosc] (ulamek).", "chapter": "k6", "id": "fm_k6_65"}, {"latex": "k_e = r_f + \\beta \\cdot (r_m - r_f)", "legend": "r_f — stopa wolna od ryzyka (%, np. rentownosc obligacji skarbowych); \\beta — wrazliwosc akcji na rynek; (r_m - r_f) — premia za ryzyko rynkowe (%).", "chapter": "k6", "id": "fm_k6_66"}, {"latex": "WACC = \\frac{E}{E+D} \\cdot k_e + \\frac{D}{E+D} \\cdot r_d \\cdot (1-T)", "legend": "E — wartosc kapitalu wlasnego (zl); D — wartosc dlugu (zl); k_e — koszt kapitalu wlasnego (%); r_d — koszt dlugu (%); T — stopa CIT (ulamek).", "chapter": "k6", "id": "fm_k6_67"}, {"latex": "KON = AO - ZK", "legend": "AO — aktywa obrotowe (zl); ZK — zobowiazania krotkoterminowe (zl).", "chapter": "k7", "id": "fm_k7_68"}, {"latex": "KON = (KW + ZD) - AT", "legend": "KW — kapital wlasny (zl); ZD — zobowiazania dlugoterminowe (zl); AT — aktywa trwale (zl). Oba ujecia daja ten sam wynik.", "chapter": "k7", "id": "fm_k7_69"}, {"latex": "CR = \\frac{AO}{ZK}", "legend": "CR — current ratio; norma orientacyjna 1{,}2 \\leq CR \\leq 2{,}0. Gdy CR > 1, to KON > 0.", "chapter": "k7", "id": "fm_k7_70"}, {"latex": "CCC = OZ + ON - OZob", "legend": "OZ — okres rotacji zapasow (dni); ON — okres sciagania naleznosci (dni); OZob — okres splaty zobowiazan (dni).", "chapter": "k7", "id": "fm_k7_71"}, {"latex": "OZ = \\frac{Zapasy}{Koszt\\ sprzedazy} \\cdot 365", "legend": "", "chapter": "k7", "id": "fm_k7_72"}, {"latex": "ON = \\frac{Naleznosci}{Przychody} \\cdot 365", "legend": "", "chapter": "k7", "id": "fm_k7_73"}, {"latex": "FCFF = EBIT \\cdot (1 - T) + A - \\Delta KON - CAPEX", "legend": "EBIT — zysk operacyjny (zl), T — stopa podatku CIT (19%, dla malych 9% — [zweryfikuj aktualna wartosc]), A — amortyzacja (zl), \\Delta KON — zmiana kapitalu obrotowego netto (zl), CAPEX — naklady inwesty", "chapter": "k8", "id": "fm_k8_74"}, {"latex": "WACC = \\frac{E}{E+D} \\cdot r_e + \\frac{D}{E+D} \\cdot r_d \\cdot (1 - T)", "legend": "E — wartosc kapitalu wlasnego (zl), D — wartosc dlugu (zl), r_e — koszt kapitalu wlasnego (%), r_d — koszt dlugu (%), T — stopa podatkowa (tarcza podatkowa).", "chapter": "k8", "id": "fm_k8_75"}, {"latex": "TV = \\frac{FCFF_{n} \\cdot (1+g)}{WACC - g}", "legend": "FCFF_{n} — przeplyw ostatniego roku prognozy (zl), g — stala stopa wzrostu (%), warunek: g \\leq dlugookresowy wzrost gospodarki.", "chapter": "k8", "id": "fm_k8_76"}, {"latex": "EVA = NOPAT - WACC \\cdot IC", "legend": "NOPAT — zysk operacyjny po opodatkowaniu (zl), IC — kapital zaangazowany/invested capital (zl). EVA > 0 oznacza tworzenie wartosci.", "chapter": "k8", "id": "fm_k8_77"}, {"latex": "EV = \\frac{100 \\cdot (1{,}02)}{0{,}10 - 0{,}02} = \\frac{102}{0{,}08} = 1275 \\text{ tys. zl}.", "legend": "", "chapter": "k8", "id": "fm_k8_78"}, {"latex": "P = \\frac{N}{1 + r \\cdot \\frac{d}{365}}", "legend": "P — cena zakupu (PLN); N — wartosc nominalna (PLN); r — rentownosc roczna (ulamek dziesietny); d — liczba dni do wykupu (dni).", "chapter": "k9", "id": "fm_k9_79"}, {"latex": "P = \\sum_{t=1}^{n} \\frac{C}{(1+r)^{t}} + \\frac{N}{(1+r)^{n}}", "legend": "C — kupon okresowy (PLN); r — stopa dyskontowa/wymagana (ulamek); n — liczba okresow; N — nominal (PLN).", "chapter": "k9", "id": "fm_k9_80"}, {"latex": "Z = \\max(S_T - K,\\ 0) - p", "legend": "S_T — cena bazowego w terminie (PLN); K — cena wykonania/strike (PLN); p — zaplacona premia (PLN); Z — wynik (PLN).", "chapter": "k9", "id": "fm_k9_81"}, {"latex": "P = \\frac{1000}{1 + 0{,}05 \\cdot \\frac{182}{365}} = \\frac{1000}{1{,}02493} \\approx 975{,}68 \\text{ PLN}", "legend": "", "chapter": "k9", "id": "fm_k9_82"}, {"latex": "m = \\frac{1}{r}", "legend": "m — mnoznik (ile razy rosnie podaz pieniadza, bez jednostki); r — stopa rezerwy obowiazkowej (ulamek, np. 0{,}035).", "chapter": "k10", "id": "fm_k10_83"}, {"latex": "\\Delta D = \\Delta R \\cdot \\frac{1}{r}", "legend": "\\Delta D — przyrost depozytow (zl); \\Delta R — przyrost rezerw/wkladu poczatkowego (zl); r — stopa rezerwy obowiazkowej (ulamek).", "chapter": "k10", "id": "fm_k10_84"}, {"latex": "m = \\frac{1}{0{,}035} \\approx 28{,}6", "legend": "", "chapter": "k10", "id": "fm_k10_85"}, {"latex": "\\Delta D = 1000 \\cdot 28{,}6 = 28\\,600 \\text{ zl}", "legend": "", "chapter": "k10", "id": "fm_k10_86"}, {"latex": "W = D - Wy", "legend": "W — wynik budżetu (zł); D — dochody (zł); Wy — wydatki (zł). Gdy W < 0 → deficyt, gdy W > 0 → nadwyżka.", "chapter": "k11", "id": "fm_k11_87"}, {"latex": "\\frac{DP}{PKB} \\leq 0{,}6", "legend": "DP — państwowy dług publiczny (zł); PKB — produkt krajowy brutto (zł). Limit 60% wynika z art. 216 Konstytucji.", "chapter": "k11", "id": "fm_k11_88"}, {"latex": "T = p \\cdot D_{p}", "legend": "T — kwota podatku (zł); p — stawka (%); D_{p} — podstawa opodatkowania, czyli dochód (zł).", "chapter": "k11", "id": "fm_k11_89"}, {"latex": "T = 0{,}19 \\cdot 500\\,000 = 95\\,000 \\text{ zł}", "legend": "", "chapter": "k11", "id": "fm_k11_90"}, {"latex": "Y = C + I + G + (X - M)", "legend": "Y — PKB (zl); C — konsumpcja (zl); I — inwestycje (zl); G — wydatki rzadowe (zl); X — eksport (zl); M — import (zl); (X-M) — eksport netto (zl).", "chapter": "k12", "id": "fm_k12_91"}, {"latex": "PNB = PKB + \\text{dochody netto z zagranicy}", "legend": "", "chapter": "k12", "id": "fm_k12_92"}, {"latex": "r \\approx i - \\pi", "legend": "r — realna stopa procentowa (%); i — nominalna stopa procentowa (%); \\pi — stopa inflacji (%).", "chapter": "k12", "id": "fm_k12_93"}], "rates": [{"name": "Referencyjna", "value": "główna stopa, rentowność 7-dniowych operacji otwartego rynku; „cena pieniądza\" w gospodarce. ~5,75% [zweryfikuj].", "note": ""}, {"name": "Lombardowa", "value": "górny pułap; po niej NBP udziela bankom kredytu pod zastaw papierów. ≈ referencyjna + 1 pp [zweryfikuj].", "note": ""}, {"name": "Depozytowa", "value": "dolny pułap; oprocentowanie depozytu banków w NBP. ≈ referencyjna − 1 pp [zweryfikuj].", "note": ""}, {"name": "Redyskontowa weksli** i **dyskontowa", "value": "przy (re)dyskoncie weksli [zweryfikuj].", "note": ""}, {"name": "Stopa rezerwy obowiązkowej", "value": "% depozytów do utrzymania w NBP. 3,5% [zweryfikuj].", "note": ""}, {"name": "KNF", "value": "nadzór nad rynkiem finansowym; UFG — gwarancje ubezpieczeniowe.", "note": ""}]};